{
  "name": "@node/diet-tracker",
  "version": "1.0.0",
  "description": "Track meals, calories, and nutritional categories with daily goals and weekly charts",
  "modnet": {
    "contentType": "health",
    "structure": "list",
    "mechanics": ["track", "chart"],
    "boundary": "none",
    "scale": 2
  },
  "dependencies": {
    "plaited": "latest"
  }
}

export type FoodCategory = 'protein' | 'carbs' | 'fat' | 'fiber';

export type FoodItem = {
  name: string;
  calories: number;
  categories: FoodCategory[];
};

export type Meal = {
  id: string;
  name: string;
  items: FoodItem[];
  timestamp: string; // ISO 8601
  totalCalories: number;
};

export type DailySummary = {
  date: string; // YYYY-MM-DD
  totalCalories: number;
  goal: number;
  remaining: number;
  categoryBreakdown: Record<FoodCategory, number>;
  meals: Meal[];
};

export type WeeklyData = {
  days: {
    date: string;
    label: string; // e.g. "Mon"
    totalCalories: number;
  }[];
  goal: number;
};

export type Settings = {
  dailyGoal: number;
};

export type MealEntry = {
  name: string;
  items: FoodItem[];
  timestamp?: string;
};

import type { Meal, Settings } from './types';

const DATA_DIR = new URL('./data/', import.meta.url).pathname;
const MEALS_PATH = `${DATA_DIR}meals.jsonl`;
const SETTINGS_PATH = `${DATA_DIR}settings.json`;

const DEFAULT_SETTINGS: Settings = {
  dailyGoal: 2000,
};

export const loadSettings = async (): Promise<Settings> => {
  const file = Bun.file(SETTINGS_PATH);
  if (!(await file.exists())) {
    await Bun.write(SETTINGS_PATH, JSON.stringify(DEFAULT_SETTINGS, null, 2));
    return { ...DEFAULT_SETTINGS };
  }
  return file.json();
};

export const saveSettings = async (settings: Settings): Promise<void> => {
  await Bun.write(SETTINGS_PATH, JSON.stringify(settings, null, 2));
};

export const appendMeal = async (meal: Meal): Promise<void> => {
  const file = Bun.file(MEALS_PATH);
  const existing = (await file.exists()) ? await file.text() : '';
  const line = JSON.stringify(meal) + '\n';
  await Bun.write(MEALS_PATH, existing + line);
};

export const loadMeals = async (): Promise<Meal[]> => {
  const file = Bun.file(MEALS_PATH);
  if (!(await file.exists())) return [];
  const text = await file.text();
  return text
    .split('\n')
    .filter((line) => line.trim().length > 0)
    .map((line) => JSON.parse(line) as Meal);
};

export const deleteMeal = async (id: string): Promise<boolean> => {
  const meals = await loadMeals();
  const filtered = meals.filter((m) => m.id !== id);
  if (filtered.length === meals.length) return false;
  const content = filtered.map((m) => JSON.stringify(m)).join('\n') + (filtered.length > 0 ? '\n' : '');
  await Bun.write(MEALS_PATH, content);
  return true;
};

import type { DailySummary, FoodCategory, Meal, MealEntry, WeeklyData } from './types';
import { appendMeal, loadMeals, loadSettings, saveSettings, deleteMeal } from './store';

const generateId = (): string => crypto.randomUUID();

const toDateStr = (iso: string): string => iso.slice(0, 10);

const getDayLabel = (dateStr: string): string => {
  const d = new Date(dateStr + 'T00:00:00');
  return ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'][d.getDay()];
};

export const logMeal = async (entry: MealEntry): Promise<Meal> => {
  const timestamp = entry.timestamp ?? new Date().toISOString();
  const totalCalories = entry.items.reduce((sum, item) => sum + item.calories, 0);
  const meal: Meal = {
    id: generateId(),
    name: entry.name,
    items: entry.items,
    timestamp,
    totalCalories,
  };
  await appendMeal(meal);
  return meal;
};

export const removeMeal = async (id: string): Promise<boolean> => {
  return deleteMeal(id);
};

export const getDailySummary = async (date?: string): Promise<DailySummary> => {
  const targetDate = date ?? new Date().toISOString().slice(0, 10);
  const allMeals = await loadMeals();
  const settings = await loadSettings();

  const dayMeals = allMeals.filter((m) => toDateStr(m.timestamp) === targetDate);

  const totalCalories = dayMeals.reduce((sum, m) => sum + m.totalCalories, 0);

  const categoryBreakdown: Record<FoodCategory, number> = {
    protein: 0,
    carbs: 0,
    fat: 0,
    fiber: 0,
  };

  for (const meal of dayMeals) {
    for (const item of meal.items) {
      for (const cat of item.categories) {
        categoryBreakdown[cat] += item.calories;
      }
    }
  }

  return {
    date: targetDate,
    totalCalories,
    goal: settings.dailyGoal,
    remaining: settings.dailyGoal - totalCalories,
    categoryBreakdown,
    meals: dayMeals,
  };
};

export const getWeeklyData = async (endDate?: string): Promise<WeeklyData> => {
  const end = endDate ? new Date(endDate + 'T00:00:00') : new Date();
  const allMeals = await loadMeals();
  const settings = await loadSettings();

  const days: WeeklyData['days'] = [];

  for (let i = 6; i >= 0; i--) {
    const d = new Date(end);
    d.setDate(d.getDate() - i);
    const dateStr = d.toISOString().slice(0, 10);
    const dayMeals = allMeals.filter((m) => toDateStr(m.timestamp) === dateStr);
    const totalCalories = dayMeals.reduce((sum, m) => sum + m.totalCalories, 0);
    days.push({
      date: dateStr,
      label: getDayLabel(dateStr),
      totalCalories,
    });
  }

  return { days, goal: settings.dailyGoal };
};

export const setDailyGoal = async (goal: number): Promise<void> => {
  const settings = await loadSettings();
  settings.dailyGoal = goal;
  await saveSettings(settings);
};

export const getDailyGoal = async (): Promise<number> => {
  const settings = await loadSettings();
  return settings.dailyGoal;
};

import { h } from 'plaited';
import type { WeeklyData } from './types';

const CHART_HEIGHT = 200;
const BAR_WIDTH = 40;
const GAP = 12;
const PADDING = 40;

const styles = {
  container: {
    fontFamily: 'system-ui, sans-serif',
    padding: '16px',
  },
  svg: {
    display: 'block',
    margin: '0 auto',
  },
  title: {
    fontSize: '16px',
    fontWeight: '600',
    marginBottom: '12px',
    textAlign: 'center' as const,
  },
};

export const renderWeeklyChart = (data: WeeklyData) => {
  const maxCal = Math.max(data.goal, ...data.days.map((d) => d.totalCalories));
  const ceiling = Math.ceil(maxCal / 500) * 500;
  const scale = (val: number) => (val / ceiling) * CHART_HEIGHT;

  const chartWidth = data.days.length * (BAR_WIDTH + GAP) - GAP + PADDING * 2;
  const chartHeight = CHART_HEIGHT + 60;
  const goalY = CHART_HEIGHT - scale(data.goal) + 20;

  const bars = data.days.map((day, i) => {
    const barHeight = scale(day.totalCalories);
    const x = PADDING + i * (BAR_WIDTH + GAP);
    const y = CHART_HEIGHT - barHeight + 20;
    const overGoal = day.totalCalories > data.goal;
    const fill = overGoal ? '#ef4444' : '#22c55e';

    return h('g', {},
      h('rect', {
        x: String(x),
        y: String(y),
        width: String(BAR_WIDTH),
        height: String(Math.max(barHeight, 1)),
        fill,
        rx: '4',
      }),
      day.totalCalories > 0
        ? h('text', {
            x: String(x + BAR_WIDTH / 2),
            y: String(y - 6),
            'text-anchor': 'middle',
            'font-size': '11',
            fill: '#374151',
          }, String(day.totalCalories))
        : null,
      h('text', {
        x: String(x + BAR_WIDTH / 2),
        y: String(CHART_HEIGHT + 36),
        'text-anchor': 'middle',
        'font-size': '12',
        fill: '#6b7280',
      }, day.label),
      h('text', {
        x: String(x + BAR_WIDTH / 2),
        y: String(CHART_HEIGHT + 50),
        'text-anchor': 'middle',
        'font-size': '10',
        fill: '#9ca3af',
      }, day.date.slice(5)),
    );
  });

  const goalLine = h('g', {},
    h('line', {
      x1: String(PADDING - 10),
      y1: String(goalY),
      x2: String(chartWidth - PADDING + 10),
      y2: String(goalY),
      stroke: '#f59e0b',
      'stroke-width': '2',
      'stroke-dasharray': '6,4',
    }),
    h('text', {
      x: String(chartWidth - PADDING + 14),
      y: String(goalY + 4),
      'font-size': '11',
      fill: '#f59e0b',
    }, `${data.goal} goal`),
  );

  return h('div', { style: styles.container },
    h('div', { style: styles.title }, 'Weekly Calorie Intake'),
    h('svg', {
      width: String(chartWidth + 60),
      height: String(chartHeight + 10),
      style: styles.svg,
    },
      ...bars,
      goalLine,
    ),
  );
};

import { h } from 'plaited';
import type { DailySummary, FoodCategory } from './types';

const CATEGORY_COLORS: Record<FoodCategory, string> = {
  protein: '#3b82f6',
  carbs: '#f59e0b',
  fat: '#ef4444',
  fiber: '#22c55e',
};

const styles = {
  page: {
    fontFamily: 'system-ui, sans-serif',
    maxWidth: '600px',
    margin: '0 auto',
    padding: '20px',
    color: '#1f2937',
  },
  header: {
    fontSize: '24px',
    fontWeight: '700',
    marginBottom: '4px',
  },
  subheader: {
    fontSize: '14px',
    color: '#6b7280',
    marginBottom: '20px',
  },
  card: {
    background: '#ffffff',
    border: '1px solid #e5e7eb',
    borderRadius: '12px',
    padding: '16px',
    marginBottom: '16px',
  },
  cardTitle: {
    fontSize: '14px',
    fontWeight: '600',
    color: '#6b7280',
    textTransform: 'uppercase' as const,
    letterSpacing: '0.05em',
    marginBottom: '8px',
  },
  calorieTotal: {
    fontSize: '36px',
    fontWeight: '700',
  },
  goalText: {
    fontSize: '14px',
    color: '#6b7280',
    marginTop: '4px',
  },
  progressBar: {
    width: '100%',
    height: '8px',
    background: '#e5e7eb',
    borderRadius: '4px',
    marginTop: '8px',
    overflow: 'hidden',
  },
  tag: {
    display: 'inline-block',
    padding: '2px 8px',
    borderRadius: '9999px',
    fontSize: '11px',
    fontWeight: '500',
    color: '#ffffff',
    marginRight: '4px',
  },
  mealItem: {
    padding: '12px 0',
    borderBottom: '1px solid #f3f4f6',
  },
  mealName: {
    fontWeight: '600',
    fontSize: '15px',
  },
  mealTime: {
    fontSize: '12px',
    color: '#9ca3af',
  },
  foodItem: {
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center',
    padding: '4px 0',
    fontSize: '14px',
  },
  categoryRow: {
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center',
    padding: '6px 0',
  },
  categoryLabel: {
    display: 'flex',
    alignItems: 'center',
    gap: '8px',
  },
  categoryDot: {
    width: '10px',
    height: '10px',
    borderRadius: '50%',
    display: 'inline-block',
  },
  emptyState: {
    textAlign: 'center' as const,
    padding: '40px 20px',
    color: '#9ca3af',
  },
};

const formatTime = (iso: string): string => {
  const d = new Date(iso);
  return d.toLocaleTimeString('en-US', { hour: 'numeric', minute: '2-digit' });
};

export const renderDailySummary = (summary: DailySummary) => {
  const pct = Math.min((summary.totalCalories / summary.goal) * 100, 100);
  const overBudget = summary.totalCalories > summary.goal;
  const progressColor = overBudget ? '#ef4444' : '#22c55e';

  const calorieCard = h('div', { style: styles.card },
    h('div', { style: styles.cardTitle }, 'Daily Calories'),
    h('div', {
      style: {
        ...styles.calorieTotal,
        color: overBudget ? '#ef4444' : '#1f2937',
      },
    }, String(summary.totalCalories)),
    h('div', { style: styles.goalText },
      overBudget
        ? `${summary.totalCalories - summary.goal} over your ${summary.goal} cal goal`
        : `${summary.remaining} remaining of ${summary.goal} cal goal`,
    ),
    h('div', { style: styles.progressBar },
      h('div', {
        style: {
          width: `${pct}%`,
          height: '100%',
          background: progressColor,
          borderRadius: '4px',
          transition: 'width 0.3s ease',
        },
      }),
    ),
  );

  const categories: FoodCategory[] = ['protein', 'carbs', 'fat', 'fiber'];
  const categoryCard = h('div', { style: styles.card },
    h('div', { style: styles.cardTitle }, 'Category Breakdown'),
    ...categories.map((cat) =>
      h('div', { style: styles.categoryRow },
        h('span', { style: styles.categoryLabel },
          h('span', {
            style: {
              ...styles.categoryDot,
              background: CATEGORY_COLORS[cat],
            },
          }),
          h('span', {}, cat.charAt(0).toUpperCase() + cat.slice(1)),
        ),
        h('span', { style: { fontWeight: '600' } },
          `${summary.categoryBreakdown[cat]} cal`,
        ),
      ),
    ),
  );

  const mealsList = summary.meals.length > 0
    ? h('div', { style: styles.card },
        h('div', { style: styles.cardTitle }, 'Meals'),
        ...summary.meals.map((meal) =>
          h('div', { style: styles.mealItem },
            h('div', { style: { display: 'flex', justifyContent: 'space-between' } },
              h('span', { style: styles.mealName }, meal.name),
              h('span', { style: { fontWeight: '600' } }, `${meal.totalCalories} cal`),
            ),
            h('div', { style: styles.mealTime }, formatTime(meal.timestamp)),
            ...meal.items.map((item) =>
              h('div', { style: styles.foodItem },
                h('span', {},
                  item.name,
                  ...item.categories.map((cat) =>
                    h('span', {
                      style: {
                        ...styles.tag,
                        background: CATEGORY_COLORS[cat],
                      },
                    }, cat),
                  ),
                ),
                h('span', { style: { color: '#6b7280' } }, `${item.calories} cal`),
              ),
            ),
          ),
        ),
      )
    : h('div', { style: { ...styles.card, ...styles.emptyState } },
        h('div', {}, 'No meals logged yet today'),
        h('div', { style: { fontSize: '13px', marginTop: '4px' } }, 'Use logMeal() to add your first meal'),
      );

  return h('div', { style: styles.page },
    h('div', { style: styles.header }, 'Diet Tracker'),
    h('div', { style: styles.subheader }, summary.date),
    calorieCard,
    categoryCard,
    mealsList,
  );
};

export { logMeal, removeMeal, getDailySummary, getWeeklyData, setDailyGoal, getDailyGoal } from './tracker';
export { renderDailySummary } from './ui';
export { renderWeeklyChart } from './chart';
export type { FoodCategory, FoodItem, Meal, MealEntry, DailySummary, WeeklyData, Settings } from './types';

{
  "name": "@node/diet-tracker",
  "version": "1.0.0",
  "description": "Track daily meals, calorie intake, food categories, and weekly trends",
  "modnet": {
    "contentType": "health",
    "structure": "list",
    "mechanics": ["track", "chart"],
    "boundary": "none",
    "scale": 2
  },
  "dependencies": {
    "plaited": "latest"
  }
}

export type FoodCategory = 'protein' | 'carbs' | 'fat' | 'fiber';

export type FoodItem = {
  name: string;
  calories: number;
  categories: FoodCategory[];
};

export type Meal = {
  id: string;
  name: string;
  items: FoodItem[];
  timestamp: string; // ISO 8601
  totalCalories: number;
};

export type DailyGoal = {
  calories: number;
  updatedAt: string; // ISO 8601
};

export type DailySummary = {
  date: string; // YYYY-MM-DD
  meals: Meal[];
  totalCalories: number;
  categoryBreakdown: Record<FoodCategory, number>;
  goal: number | null;
  goalProgress: number | null; // percentage 0-100+
};

export type WeeklyData = {
  days: {
    date: string;
    totalCalories: number;
    goal: number | null;
  }[];
};

export type Settings = {
  dailyGoal: DailyGoal | null;
};

import type { Meal, Settings } from './types';

const DATA_DIR = new URL('./data/', import.meta.url).pathname;
const MEALS_FILE = `${DATA_DIR}meals.jsonl`;
const SETTINGS_FILE = `${DATA_DIR}settings.json`;

const ensureDataDir = async (): Promise<void> => {
  const dir = Bun.file(DATA_DIR);
  if (!await dir.exists()) {
    await Bun.$`mkdir -p ${DATA_DIR}`;
  }
};

export const loadMeals = async (): Promise<Meal[]> => {
  await ensureDataDir();
  const file = Bun.file(MEALS_FILE);
  if (!await file.exists()) return [];

  const text = await file.text();
  return text
    .trim()
    .split('\n')
    .filter(Boolean)
    .map((line) => JSON.parse(line) as Meal);
};

export const appendMeal = async (meal: Meal): Promise<void> => {
  await ensureDataDir();
  const file = Bun.file(MEALS_FILE);
  const existing = await file.exists() ? await file.text() : '';
  const newContent = existing + JSON.stringify(meal) + '\n';
  await Bun.write(MEALS_FILE, newContent);
};

export const deleteMeal = async (mealId: string): Promise<boolean> => {
  const meals = await loadMeals();
  const filtered = meals.filter((m) => m.id !== mealId);
  if (filtered.length === meals.length) return false;

  const content = filtered.map((m) => JSON.stringify(m)).join('\n') + (filtered.length > 0 ? '\n' : '');
  await Bun.write(MEALS_FILE, content);
  return true;
};

export const loadSettings = async (): Promise<Settings> => {
  await ensureDataDir();
  const file = Bun.file(SETTINGS_FILE);
  if (!await file.exists()) return { dailyGoal: null };

  const text = await file.text();
  return JSON.parse(text) as Settings;
};

export const saveSettings = async (settings: Settings): Promise<void> => {
  await ensureDataDir();
  await Bun.write(SETTINGS_FILE, JSON.stringify(settings, null, 2));
};

import type { FoodCategory, FoodItem, Meal, DailySummary, WeeklyData } from './types';
import { loadMeals, appendMeal, deleteMeal, loadSettings, saveSettings } from './data';

const generateId = (): string =>
  crypto.randomUUID();

const toDateString = (iso: string): string =>
  iso.slice(0, 10);

const todayString = (): string =>
  toDateString(new Date().toISOString());

export const logMeal = async (
  name: string,
  items: FoodItem[],
  timestamp?: string,
): Promise<Meal> => {
  const meal: Meal = {
    id: generateId(),
    name,
    items,
    timestamp: timestamp ?? new Date().toISOString(),
    totalCalories: items.reduce((sum, item) => sum + item.calories, 0),
  };
  await appendMeal(meal);
  return meal;
};

export const removeMeal = async (mealId: string): Promise<boolean> =>
  deleteMeal(mealId);

export const setDailyGoal = async (calories: number): Promise<void> => {
  const settings = await loadSettings();
  settings.dailyGoal = {
    calories,
    updatedAt: new Date().toISOString(),
  };
  await saveSettings(settings);
};

export const getDailyGoal = async (): Promise<number | null> => {
  const settings = await loadSettings();
  return settings.dailyGoal?.calories ?? null;
};

export const getDailySummary = async (date?: string): Promise<DailySummary> => {
  const targetDate = date ?? todayString();
  const allMeals = await loadMeals();
  const meals = allMeals.filter((m) => toDateString(m.timestamp) === targetDate);

  const totalCalories = meals.reduce((sum, m) => sum + m.totalCalories, 0);

  const categoryBreakdown: Record<FoodCategory, number> = {
    protein: 0,
    carbs: 0,
    fat: 0,
    fiber: 0,
  };

  for (const meal of meals) {
    for (const item of meal.items) {
      for (const cat of item.categories) {
        categoryBreakdown[cat] += item.calories;
      }
    }
  }

  const goal = await getDailyGoal();
  const goalProgress = goal ? Math.round((totalCalories / goal) * 100) : null;

  return {
    date: targetDate,
    meals,
    totalCalories,
    categoryBreakdown,
    goal,
    goalProgress,
  };
};

export const getWeeklyData = async (endDate?: string): Promise<WeeklyData> => {
  const end = endDate ? new Date(endDate) : new Date();
  const allMeals = await loadMeals();
  const goal = await getDailyGoal();

  const days: WeeklyData['days'] = [];

  for (let i = 6; i >= 0; i--) {
    const d = new Date(end);
    d.setDate(d.getDate() - i);
    const dateStr = toDateString(d.toISOString());
    const dayMeals = allMeals.filter((m) => toDateString(m.timestamp) === dateStr);
    const totalCalories = dayMeals.reduce((sum, m) => sum + m.totalCalories, 0);

    days.push({ date: dateStr, totalCalories, goal });
  }

  return { days };
};

import { h } from 'plaited';
import type { WeeklyData } from './types';

const BAR_MAX_HEIGHT = 200;
const BAR_WIDTH = 36;
const BAR_GAP = 12;
const CHART_PADDING = 40;

const COLORS = {
  bar: '#4ade80',
  barOver: '#f87171',
  goalLine: '#facc15',
  text: '#e2e8f0',
  axis: '#64748b',
  bg: '#1e293b',
};

export const renderWeeklyChart = (data: WeeklyData) => {
  const maxCalories = Math.max(
    ...data.days.map((d) => d.totalCalories),
    ...(data.days[0]?.goal ? [data.days[0].goal] : []),
    1,
  );

  const chartWidth = data.days.length * (BAR_WIDTH + BAR_GAP) + CHART_PADDING * 2;
  const chartHeight = BAR_MAX_HEIGHT + 80;

  const scale = (cal: number): number =>
    (cal / maxCalories) * BAR_MAX_HEIGHT;

  const goalY = data.days[0]?.goal
    ? chartHeight - 40 - scale(data.days[0].goal)
    : null;

  const bars = data.days.map((day, i) => {
    const barHeight = scale(day.totalCalories);
    const x = CHART_PADDING + i * (BAR_WIDTH + BAR_GAP);
    const y = chartHeight - 40 - barHeight;
    const isOver = day.goal !== null && day.totalCalories > day.goal;
    const label = day.date.slice(5); // MM-DD

    return h('g', {},
      h('rect', {
        x: String(x),
        y: String(y),
        width: String(BAR_WIDTH),
        height: String(Math.max(barHeight, 1)),
        fill: isOver ? COLORS.barOver : COLORS.bar,
        rx: '4',
      }),
      h('text', {
        x: String(x + BAR_WIDTH / 2),
        y: String(chartHeight - 24),
        fill: COLORS.text,
        'font-size': '11',
        'text-anchor': 'middle',
      }, label),
      h('text', {
        x: String(x + BAR_WIDTH / 2),
        y: String(y - 6),
        fill: COLORS.text,
        'font-size': '11',
        'text-anchor': 'middle',
      }, String(day.totalCalories)),
    );
  });

  const goalLine = goalY !== null
    ? h('line', {
        x1: String(CHART_PADDING - 10),
        y1: String(goalY),
        x2: String(chartWidth - CHART_PADDING + 10),
        y2: String(goalY),
        stroke: COLORS.goalLine,
        'stroke-width': '2',
        'stroke-dasharray': '6,4',
      })
    : null;

  const goalLabel = goalY !== null && data.days[0]?.goal
    ? h('text', {
        x: String(chartWidth - CHART_PADDING + 14),
        y: String(goalY + 4),
        fill: COLORS.goalLine,
        'font-size': '11',
      }, `Goal: ${data.days[0].goal}`)
    : null;

  return h('div', {
    style: `background:${COLORS.bg};border-radius:12px;padding:16px;`,
  },
    h('h3', {
      style: `color:${COLORS.text};margin:0 0 12px 0;font-size:16px;`,
    }, 'Weekly Calorie Intake'),
    h('svg', {
      width: String(chartWidth + 60),
      height: String(chartHeight),
      viewBox: `0 0 ${chartWidth + 60} ${chartHeight}`,
    },
      // x-axis
      h('line', {
        x1: String(CHART_PADDING - 10),
        y1: String(chartHeight - 40),
        x2: String(chartWidth - CHART_PADDING + 10),
        y2: String(chartHeight - 40),
        stroke: COLORS.axis,
        'stroke-width': '1',
      }),
      ...bars,
      ...(goalLine ? [goalLine] : []),
      ...(goalLabel ? [goalLabel] : []),
    ),
  );
};

