import type { Meal, DailyGoal } from './types'

const DATA_DIR = new URL('./data/', import.meta.url).pathname

const mealsPath = `${DATA_DIR}meals.jsonl`
const goalsPath = `${DATA_DIR}goals.json`

const generateId = (): string =>
  `${Date.now()}-${Math.random().toString(36).slice(2, 8)}`

export const loadMeals = async (): Promise<Meal[]> => {
  const file = Bun.file(mealsPath)
  const exists = await file.exists()
  if (!exists) return []

  const text = await file.text()
  return text
    .trim()
    .split('\n')
    .filter(Boolean)
    .map((line) => JSON.parse(line) as Meal)
}

export const saveMeal = async (
  label: string,
  items: Meal['items'],
  timestamp?: string
): Promise<Meal> => {
  const meal: Meal = {
    id: generateId(),
    timestamp: timestamp ?? new Date().toISOString(),
    label,
    items,
    totalCalories: items.reduce((sum, item) => sum + item.calories, 0),
  }

  const file = Bun.file(mealsPath)
  const exists = await file.exists()
  const existing = exists ? await file.text() : ''
  const newContent = existing + JSON.stringify(meal) + '\n'
  await Bun.write(mealsPath, newContent)

  return meal
}

export const deleteMeal = async (id: string): Promise<boolean> => {
  const meals = await loadMeals()
  const filtered = meals.filter((m) => m.id !== id)
  if (filtered.length === meals.length) return false

  const content = filtered.map((m) => JSON.stringify(m)).join('\n') + (filtered.length ? '\n' : '')
  await Bun.write(mealsPath, content)
  return true
}

export const loadGoal = async (): Promise<DailyGoal | null> => {
  const file = Bun.file(goalsPath)
  const exists = await file.exists()
  if (!exists) return null

  const text = await file.text()
  return JSON.parse(text) as DailyGoal
}

export const saveGoal = async (calories: number): Promise<DailyGoal> => {
  const goal: DailyGoal = {
    calories,
    updatedAt: new Date().toISOString(),
  }
  await Bun.write(goalsPath, JSON.stringify(goal, null, 2))
  return goal
}

import type { Meal, DailySummary, WeeklyData, FoodCategory } from './types'
import { loadMeals, loadGoal } from './data'

const toDateString = (iso: string): string => iso.slice(0, 10)

const getMealsForDate = (meals: Meal[], date: string): Meal[] =>
  meals.filter((m) => toDateString(m.timestamp) === date)

const computeCategoryBreakdown = (meals: Meal[]): Record<FoodCategory, number> => {
  const breakdown: Record<FoodCategory, number> = {
    protein: 0,
    carbs: 0,
    fat: 0,
    fiber: 0,
  }

  for (const meal of meals) {
    for (const item of meal.items) {
      for (const cat of item.categories) {
        breakdown[cat] += item.calories
      }
    }
  }

  return breakdown
}

export const getDailySummary = async (date?: string): Promise<DailySummary> => {
  const targetDate = date ?? toDateString(new Date().toISOString())
  const allMeals = await loadMeals()
  const dayMeals = getMealsForDate(allMeals, targetDate)
  const goal = await loadGoal()

  return {
    date: targetDate,
    meals: dayMeals.sort(
      (a, b) => new Date(a.timestamp).getTime() - new Date(b.timestamp).getTime()
    ),
    totalCalories: dayMeals.reduce((sum, m) => sum + m.totalCalories, 0),
    categoryBreakdown: computeCategoryBreakdown(dayMeals),
    goal,
  }
}

export const getWeeklyData = async (endDate?: string): Promise<WeeklyData> => {
  const end = endDate ? new Date(endDate) : new Date()
  const allMeals = await loadMeals()
  const goal = await loadGoal()

  const days: WeeklyData['days'] = []
  const dayNames = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat']

  for (let i = 6; i >= 0; i--) {
    const d = new Date(end)
    d.setDate(d.getDate() - i)
    const dateStr = toDateString(d.toISOString())
    const dayMeals = getMealsForDate(allMeals, dateStr)

    days.push({
      date: dateStr,
      dayLabel: dayNames[d.getDay()],
      totalCalories: dayMeals.reduce((sum, m) => sum + m.totalCalories, 0),
    })
  }

  const maxCalories = Math.max(
    ...days.map((d) => d.totalCalories),
    goal?.calories ?? 0,
    1
  )

  return { days, goal, maxCalories }
}

