import type { FoodCategory, FoodItem } from './types'
import { saveMeal, deleteMeal, saveGoal, loadGoal } from './data'
import { getDailySummary, getWeeklyData } from './tracker'
import {
  renderDailySummary,
  renderWeeklyChart,
  renderMealForm,
  renderGoalForm,
} from './render'

export type Action =
  | { type: 'view-today'; date?: string }
  | { type: 'view-week'; endDate?: string }
  | { type: 'show-meal-form' }
  | { type: 'show-goal-form' }
  | {
      type: 'log-meal'
      label: string
      items: { name: string; calories: number; categories: FoodCategory[] }[]
      timestamp?: string
    }
  | { type: 'delete-meal'; id: string }
  | { type: 'set-goal'; calories: number }

export type Result = {
  html: string
  data?: unknown
}

export const handleAction = async (action: Action): Promise<Result> => {
  switch (action.type) {
    case 'view-today': {
      const summary = await getDailySummary(action.date)
      return { html: renderDailySummary(summary), data: summary }
    }

    case 'view-week': {
      const weekly = await getWeeklyData(action.endDate)
      return { html: renderWeeklyChart(weekly), data: weekly }
    }

    case 'show-meal-form': {
      return { html: renderMealForm() }
    }

    case 'show-goal-form': {
      const goal = await loadGoal()
      return { html: renderGoalForm(goal?.calories ?? null) }
    }

    case 'log-meal': {
      const items: FoodItem[] = action.items.map((i) => ({
        name: i.name,
        calories: i.calories,
        categories: i.categories,
      }))
      const meal = await saveMeal(action.label, items, action.timestamp)
      const summary = await getDailySummary()
      return { html: renderDailySummary(summary), data: meal }
    }

    case 'delete-meal': {
      await deleteMeal(action.id)
      const summary = await getDailySummary()
      return { html: renderDailySummary(summary) }
    }

    case 'set-goal': {
      const goal = await saveGoal(action.calories)
      const summary = await getDailySummary()
      return { html: renderDailySummary(summary), data: goal }
    }
  }
}

// Default export for module entry
export default handleAction

