import type { Expense } from './types'

const DATA_PATH = './data/expenses.jsonl'

export const readExpenses = async (): Promise<Expense[]> => {
  const file = Bun.file(DATA_PATH)
  const exists = await file.exists()
  if (!exists) return []

  const text = await file.text()
  return text
    .trim()
    .split('\n')
    .filter(Boolean)
    .map((line) => JSON.parse(line) as Expense)
}

export const appendExpense = async (expense: Expense): Promise<void> => {
  const file = Bun.file(DATA_PATH)
  const exists = await file.exists()
  const line = JSON.stringify(expense) + '\n'

  if (exists) {
    const existing = await file.text()
    await Bun.write(DATA_PATH, existing + line)
  } else {
    await Bun.write(DATA_PATH, line)
  }
}

export const writeExpenses = async (expenses: Expense[]): Promise<void> => {
  const content = expenses.map((e) => JSON.stringify(e)).join('\n') + (expenses.length ? '\n' : '')
  await Bun.write(DATA_PATH, content)
}

export const deleteExpense = async (id: string): Promise<boolean> => {
  const expenses = await readExpenses()
  const filtered = expenses.filter((e) => e.id !== id)
  if (filtered.length === expenses.length) return false
  await writeExpenses(filtered)
  return true
}

