import type { Expense, FilterCriteria } from './types'

export const filterExpenses = (expenses: Expense[], criteria: FilterCriteria): Expense[] => {
  let result = expenses

  if (criteria.category) {
    result = result.filter((e) => e.category === criteria.category)
  }

  if (criteria.dateRange) {
    const { start, end } = criteria.dateRange
    result = result.filter((e) => e.date >= start && e.date <= end)
  }

  return result.sort((a, b) => b.date.localeCompare(a.date))
}

export const filterByMonth = (expenses: Expense[], month: string): Expense[] => {
  return expenses.filter((e) => e.date.startsWith(month))
}

export const getAvailableMonths = (expenses: Expense[]): string[] => {
  const months = new Set(expenses.map((e) => e.date.slice(0, 7)))
  return [...months].sort().reverse()
}

import type { Expense, Category, CategorySummary, MonthlySummary } from './types'
import { CATEGORIES } from './types'
import { filterByMonth } from './filter'

export const computeCategorySummaries = (expenses: Expense[]): CategorySummary[] => {
  const totalSpent = expenses.reduce((sum, e) => sum + e.amount, 0)

  return CATEGORIES
    .map((category) => {
      const items = expenses.filter((e) => e.category === category)
      const total = items.reduce((sum, e) => sum + e.amount, 0)
      return {
        category,
        total: Math.round(total * 100) / 100,
        count: items.length,
        percentage: totalSpent > 0 ? Math.round((total / totalSpent) * 1000) / 10 : 0,
      }
    })
    .filter((s) => s.count > 0)
    .sort((a, b) => b.total - a.total)
}

export const computeMonthlySummary = (expenses: Expense[], month: string): MonthlySummary => {
  const monthExpenses = filterByMonth(expenses, month)
  const totalSpent = Math.round(monthExpenses.reduce((sum, e) => sum + e.amount, 0) * 100) / 100
  const categories = computeCategorySummaries(monthExpenses)

  return { month, totalSpent, categories }
}

import { h } from 'plaited'
import type { CategorySummary } from './types'
import { CATEGORY_COLORS, CATEGORY_LABELS } from './types'

type PieSlice = {
  category: CategorySummary['category']
  startAngle: number
  endAngle: number
  color: string
}

const describeArc = (cx: number, cy: number, r: number, startAngle: number, endAngle: number): string => {
  const start = polarToCartesian(cx, cy, r, endAngle)
  const end = polarToCartesian(cx, cy, r, startAngle)
  const largeArc = endAngle - startAngle > 180 ? 1 : 0

  return [
    `M ${cx} ${cy}`,
    `L ${start.x} ${start.y}`,
    `A ${r} ${r} 0 ${largeArc} 0 ${end.x} ${end.y}`,
    'Z',
  ].join(' ')
}

const polarToCartesian = (cx: number, cy: number, r: number, angleDeg: number) => {
  const rad = ((angleDeg - 90) * Math.PI) / 180
  return {
    x: cx + r * Math.cos(rad),
    y: cy + r * Math.sin(rad),
  }
}

const computeSlices = (categories: CategorySummary[]): PieSlice[] => {
  let currentAngle = 0
  return categories.map((cat) => {
    const sweep = (cat.percentage / 100) * 360
    const slice: PieSlice = {
      category: cat.category,
      startAngle: currentAngle,
      endAngle: currentAngle + sweep,
      color: CATEGORY_COLORS[cat.category],
    }
    currentAngle += sweep
    return slice
  })
}

export const renderPieChart = (categories: CategorySummary[]) => {
  if (categories.length === 0) {
    return h('p', { style: { color: '#9ca3af', textAlign: 'center', padding: '2rem' } }, 'No expenses to chart')
  }

  const cx = 100
  const cy = 100
  const r = 90
  const slices = computeSlices(categories)

  const paths = slices.map((slice) => {
    if (slice.endAngle - slice.startAngle >= 359.99) {
      return h('circle', { cx: String(cx), cy: String(cy), r: String(r), fill: slice.color })
    }
    return h('path', {
      d: describeArc(cx, cy, r, slice.startAngle, slice.endAngle),
      fill: slice.color,
    })
  })

  const legend = categories.map((cat) =>
    h(
      'div',
      {
        style: {
          display: 'flex',
          alignItems: 'center',
          gap: '0.5rem',
          fontSize: '0.875rem',
        },
      },
      h('div', {
        style: {
          width: '12px',
          height: '12px',
          borderRadius: '2px',
          backgroundColor: CATEGORY_COLORS[cat.category],
          flexShrink: '0',
        },
      }),
      h('span', { style: { color: '#e5e7eb' } }, `${CATEGORY_LABELS[cat.category]}: $${cat.total.toFixed(2)} (${cat.percentage}%)`),
    ),
  )

  return h(
    'div',
    {
      style: {
        display: 'flex',
        alignItems: 'center',
        gap: '2rem',
        flexWrap: 'wrap',
        justifyContent: 'center',
      },
    },
    h(
      'svg',
      {
        viewBox: '0 0 200 200',
        width: '200',
        height: '200',
        style: { flexShrink: '0' },
      },
      ...paths,
    ),
    h(
      'div',
      { style: { display: 'flex', flexDirection: 'column', gap: '0.375rem' } },
      ...legend,
    ),
  )
}

import type { Expense } from './types'
import { CATEGORY_LABELS } from './types'

const escapeCSVField = (value: string): string => {
  if (value.includes(',') || value.includes('"') || value.includes('\n')) {
    return `"${value.replace(/"/g, '""')}"`
  }
  return value
}

export const toCSV = (expenses: Expense[]): string => {
  const header = 'Date,Category,Amount,Notes'
  const rows = expenses
    .sort((a, b) => a.date.localeCompare(b.date))
    .map((e) =>
      [
        e.date,
        CATEGORY_LABELS[e.category],
        e.amount.toFixed(2),
        escapeCSVField(e.notes),
      ].join(','),
    )

  return [header, ...rows].join('\n') + '\n'
}

export const exportCSV = async (expenses: Expense[], path = './data/expenses-export.csv'): Promise<string> => {
  const csv = toCSV(expenses)
  await Bun.write(path, csv)
  return path
}

