import type { Expense, ExpenseFilter, Category } from './types'

const DATA_PATH = `${import.meta.dir}/data/expenses.jsonl`

export const generateId = (): string =>
  crypto.randomUUID()

export const readExpenses = async (): Promise<Expense[]> => {
  const file = Bun.file(DATA_PATH)
  const exists = await file.exists()
  if (!exists) return []
  const text = await file.text()
  if (!text.trim()) return []
  return text
    .trim()
    .split('\n')
    .map((line) => JSON.parse(line) as Expense)
}

export const writeExpense = async (expense: Expense): Promise<void> => {
  const file = Bun.file(DATA_PATH)
  const exists = await file.exists()
  const existing = exists ? await file.text() : ''
  const newLine = JSON.stringify(expense) + '\n'
  await Bun.write(DATA_PATH, existing + newLine)
}

export const deleteExpense = async (id: string): Promise<boolean> => {
  const expenses = await readExpenses()
  const filtered = expenses.filter((e) => e.id !== id)
  if (filtered.length === expenses.length) return false
  const content = filtered.map((e) => JSON.stringify(e)).join('\n') + (filtered.length ? '\n' : '')
  await Bun.write(DATA_PATH, content)
  return true
}

export const filterExpenses = (
  expenses: Expense[],
  filter: ExpenseFilter,
): Expense[] => {
  return expenses.filter((e) => {
    if (filter.startDate && e.date < filter.startDate) return false
    if (filter.endDate && e.date > filter.endDate) return false
    if (filter.category && e.category !== filter.category) return false
    return true
  })
}

export const getExpensesForMonth = (
  expenses: Expense[],
  month: string, // YYYY-MM
): Expense[] => {
  return expenses.filter((e) => e.date.startsWith(month))
}

export const sumByCategory = (
  expenses: Expense[],
): Map<Category, number> => {
  const map = new Map<Category, number>()
  for (const e of expenses) {
    map.set(e.category, (map.get(e.category) ?? 0) + e.amount)
  }
  return map
}

import type { Expense } from './types'

const escapeCsv = (value: string): string => {
  if (value.includes(',') || value.includes('"') || value.includes('\n')) {
    return `"${value.replace(/"/g, '""')}"`
  }
  return value
}

export const toCsv = (expenses: Expense[]): string => {
  const header = 'date,category,amount,notes'
  const rows = expenses.map(
    (e) =>
      `${e.date},${e.category},${e.amount.toFixed(2)},${escapeCsv(e.notes)}`,
  )
  return [header, ...rows].join('\n')
}

import { h } from 'plaited'
import type { CategorySummary } from './types'

const COLORS: Record<string, string> = {
  food: '#ef4444',
  transport: '#3b82f6',
  housing: '#22c55e',
  entertainment: '#a855f7',
  utilities: '#f59e0b',
  other: '#6b7280',
}

type SlicePath = {
  d: string
  color: string
  category: string
  total: number
  percentage: number
}

const describeArc = (
  cx: number,
  cy: number,
  r: number,
  startAngle: number,
  endAngle: number,
): string => {
  const start = polarToCartesian(cx, cy, r, endAngle)
  const end = polarToCartesian(cx, cy, r, startAngle)
  const largeArc = endAngle - startAngle > 180 ? 1 : 0
  return [
    `M ${cx} ${cy}`,
    `L ${start.x} ${start.y}`,
    `A ${r} ${r} 0 ${largeArc} 0 ${end.x} ${end.y}`,
    'Z',
  ].join(' ')
}

const polarToCartesian = (
  cx: number,
  cy: number,
  r: number,
  angleDeg: number,
): { x: number; y: number } => {
  const rad = ((angleDeg - 90) * Math.PI) / 180
  return {
    x: cx + r * Math.cos(rad),
    y: cy + r * Math.sin(rad),
  }
}

const buildSlices = (categories: CategorySummary[]): SlicePath[] => {
  let currentAngle = 0
  return categories
    .filter((c) => c.percentage > 0)
    .map((c) => {
      const sweep = (c.percentage / 100) * 360
      const slice: SlicePath = {
        d: sweep >= 359.99
          ? describeFullCircle(120, 120, 100)
          : describeArc(120, 120, 100, currentAngle, currentAngle + sweep),
        color: COLORS[c.category] ?? '#6b7280',
        category: c.category,
        total: c.total,
        percentage: c.percentage,
      }
      currentAngle += sweep
      return slice
    })
}

const describeFullCircle = (cx: number, cy: number, r: number): string =>
  `M ${cx} ${cy - r} A ${r} ${r} 0 1 1 ${cx - 0.01} ${cy - r} Z`

export const renderPieChart = (categories: CategorySummary[]) => {
  const slices = buildSlices(categories)

  if (slices.length === 0) {
    return h('div', { style: { textAlign: 'center', padding: '2rem', color: '#9ca3af' } },
      h('p', {}, 'No expenses to chart'),
    )
  }

  return h('div', { style: { display: 'flex', gap: '2rem', alignItems: 'flex-start', flexWrap: 'wrap' } },
    h('svg', {
      viewBox: '0 0 240 240',
      width: '240',
      height: '240',
      style: { flexShrink: '0' },
    },
      ...slices.map((s) =>
        h('path', {
          d: s.d,
          fill: s.color,
          stroke: '#fff',
          'stroke-width': '2',
        }),
      ),
    ),
    h('ul', {
      style: {
        listStyle: 'none',
        padding: '0',
        margin: '0',
        display: 'flex',
        flexDirection: 'column',
        gap: '0.5rem',
      },
    },
      ...slices.map((s) =>
        h('li', {
          style: {
            display: 'flex',
            alignItems: 'center',
            gap: '0.5rem',
            fontSize: '0.875rem',
          },
        },
          h('span', {
            style: {
              width: '12px',
              height: '12px',
              borderRadius: '2px',
              backgroundColor: s.color,
              display: 'inline-block',
              flexShrink: '0',
            },
          }),
          h('span', {},
            `${s.category}: $${s.total.toFixed(2)} (${s.percentage.toFixed(1)}%)`,
          ),
        ),
      ),
    ),
  )
}

