import { createSSR } from 'plaited'
import type { Expense, ExpenseFilter, Category, CategorySummary, MonthlySummary } from './types'
import { CATEGORIES } from './types'
import {
  generateId,
  readExpenses,
  writeExpense,
  deleteExpense,
  filterExpenses,
  sumByCategory,
} from './store'
import { toCsv } from './export'
import { renderPage } from './view'

const ssr = createSSR()

const today = (): string => {
  const d = new Date()
  return d.toISOString().slice(0, 10)
}

const currentMonth = (): string => today().slice(0, 7)

const buildSummary = (expenses: Expense[], month: string): MonthlySummary => {
  const monthExpenses = expenses.filter((e) => e.date.startsWith(month))
  const categoryMap = sumByCategory(monthExpenses)
  const total = monthExpenses.reduce((sum, e) => sum + e.amount, 0)

  const categories: CategorySummary[] = CATEGORIES.map((cat) => ({
    category: cat,
    total: categoryMap.get(cat) ?? 0,
    percentage: total > 0 ? ((categoryMap.get(cat) ?? 0) / total) * 100 : 0,
  }))

  return { month, total, categories }
}

export const handleIndex = async (filter: ExpenseFilter = {}): Promise<string> => {
  const allExpenses = await readExpenses()
  const filtered = filterExpenses(allExpenses, filter)

  const month = filter.startDate?.slice(0, 7) ?? currentMonth()
  const summary = buildSummary(filtered, month)

  const template = renderPage({
    today: today(),
    filter,
    summary,
    expenses: filtered,
  })

  return ssr(template)
}

export const handleAddExpense = async (data: {
  amount: string
  category: string
  date: string
  notes?: string
}): Promise<Expense> => {
  const amount = parseFloat(data.amount)
  if (isNaN(amount) || amount <= 0) {
    throw new Error('Amount must be a positive number')
  }

  if (!CATEGORIES.includes(data.category as Category)) {
    throw new Error(`Invalid category: ${data.category}`)
  }

  if (!data.date || !/^\d{4}-\d{2}-\d{2}$/.test(data.date)) {
    throw new Error('Invalid date format. Use YYYY-MM-DD')
  }

  const expense: Expense = {
    id: generateId(),
    amount,
    category: data.category as Category,
    date: data.date,
    notes: data.notes?.trim() ?? '',
  }

  await writeExpense(expense)
  return expense
}

export const handleDeleteExpense = async (id: string): Promise<boolean> => {
  return deleteExpense(id)
}

export const handleExportCsv = async (filter: ExpenseFilter = {}): Promise<string> => {
  const allExpenses = await readExpenses()
  const filtered = filterExpenses(allExpenses, filter)
  return toCsv(filtered)
}

export const handleGetSummary = async (month?: string): Promise<MonthlySummary> => {
  const allExpenses = await readExpenses()
  return buildSummary(allExpenses, month ?? currentMonth())
}

export const serve = () => {
  return Bun.serve({
    port: 3000,
    fetch: async (req) => {
      const url = new URL(req.url)

      if (req.method === 'GET' && url.pathname === '/') {
        const filter: ExpenseFilter = {
          startDate: url.searchParams.get('startDate') ?? undefined,
          endDate: url.searchParams.get('endDate') ?? undefined,
          category: (url.searchParams.get('category') as Category) || undefined,
        }
        const html = await handleIndex(filter)
        return new Response(html, {
          headers: { 'Content-Type': 'text/html; charset=utf-8' },
        })
      }

      if (req.method === 'POST' && url.pathname === '/expenses') {
        const data = await req.json()
        const expense = await handleAddExpense(data)
        return Response.json(expense, { status: 201 })
      }

      if (req.method === 'DELETE' && url.pathname.startsWith('/expenses/')) {
        const id = url.pathname.split('/').pop()!
        const deleted = await handleDeleteExpense(id)
        return deleted
          ? new Response(null, { status: 204 })
          : Response.json({ error: 'Not found' }, { status: 404 })
      }

      if (req.method === 'GET' && url.pathname === '/export') {
        const filter: ExpenseFilter = {
          startDate: url.searchParams.get('startDate') ?? undefined,
          endDate: url.searchParams.get('endDate') ?? undefined,
          category: (url.searchParams.get('category') as Category) || undefined,
        }
        const csv = await handleExportCsv(filter)
        return new Response(csv, {
          headers: {
            'Content-Type': 'text/csv',
            'Content-Disposition': 'attachment; filename="expenses.csv"',
          },
        })
      }

      if (req.method === 'GET' && url.pathname === '/summary') {
        const month = url.searchParams.get('month') ?? undefined
        const summary = await handleGetSummary(month)
        return Response.json(summary)
      }

      return Response.json({ error: 'Not found' }, { status: 404 })
    },
  })
}

export default { handleIndex, handleAddExpense, handleDeleteExpense, handleExportCsv, handleGetSummary, serve }

