  amount: number
  category: Category
  date: string // ISO date YYYY-MM-DD
  notes: string
  createdAt: string // ISO datetime
}

export type ExpenseFilter = {
  startDate?: string
  endDate?: string
  category?: Category
}

export type CategorySummary = {
  category: Category
  total: number
  percentage: number
  count: number
}

export type MonthlySummary = {
  month: string // YYYY-MM
  total: number
  categories: CategorySummary[]
}

import { type Expense, type ExpenseFilter, type MonthlySummary, type CategorySummary, CATEGORIES } from './types'

const DATA_PATH = new URL('./data/expenses.jsonl', import.meta.url).pathname

const generateId = (): string => crypto.randomUUID()

export const readAllExpenses = async (): Promise<Expense[]> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) return []
  const text = await file.text()
  return text
    .split('\n')
    .filter((line) => line.trim().length > 0)
    .map((line) => JSON.parse(line) as Expense)
}

export const addExpense = async (input: {
  amount: number
  category: Expense['category']
  date: string
  notes?: string
}): Promise<Expense> => {
  const expense: Expense = {
    id: generateId(),
    amount: Math.round(input.amount * 100) / 100,
    category: input.category,
    date: input.date,
    notes: input.notes ?? '',
    createdAt: new Date().toISOString(),
  }
  const line = JSON.stringify(expense) + '\n'
  const file = Bun.file(DATA_PATH)
  const existing = (await file.exists()) ? await file.text() : ''
  await Bun.write(DATA_PATH, existing + line)
  return expense
}

export const deleteExpense = async (id: string): Promise<boolean> => {
  const expenses = await readAllExpenses()
  const filtered = expenses.filter((e) => e.id !== id)
  if (filtered.length === expenses.length) return false
  const content = filtered.map((e) => JSON.stringify(e)).join('\n') + (filtered.length > 0 ? '\n' : '')
  await Bun.write(DATA_PATH, content)
  return true
}

export const filterExpenses = (expenses: Expense[], filter: ExpenseFilter): Expense[] => {
  return expenses.filter((e) => {
    if (filter.startDate && e.date < filter.startDate) return false
    if (filter.endDate && e.date > filter.endDate) return false
    if (filter.category && e.category !== filter.category) return false
    return true
  })
}

export const getMonthlySummary = (expenses: Expense[], month: string): MonthlySummary => {
  const monthExpenses = expenses.filter((e) => e.date.startsWith(month))
  const total = monthExpenses.reduce((sum, e) => sum + e.amount, 0)

  const categories: CategorySummary[] = CATEGORIES.map((cat) => {
    const catExpenses = monthExpenses.filter((e) => e.category === cat)
    const catTotal = catExpenses.reduce((sum, e) => sum + e.amount, 0)
    return {
      category: cat,
      total: Math.round(catTotal * 100) / 100,
      percentage: total > 0 ? Math.round((catTotal / total) * 1000) / 10 : 0,
      count: catExpenses.length,
    }
  }).filter((c) => c.count > 0)

  return {
    month,
    total: Math.round(total * 100) / 100,
    categories,
  }
}

export const getAvailableMonths = (expenses: Expense[]): string[] => {
  const months = new Set(expenses.map((e) => e.date.slice(0, 7)))
  return [...months].sort().reverse()
}

import type { Expense } from './types'

const escapeCsvField = (value: string): string => {
  if (value.includes(',') || value.includes('"') || value.includes('\n')) {
    return `"${value.replace(/"/g, '""')}"`
  }
  return value
}

export const expensesToCsv = (expenses: Expense[]): string => {
  const header = 'date,category,amount,notes'
  const rows = expenses
    .sort((a, b) => a.date.localeCompare(b.date))
    .map((e) => [e.date, e.category, e.amount.toFixed(2), escapeCsvField(e.notes)].join(','))
  return [header, ...rows].join('\n')
}

import { h } from 'plaited'
import type { CategorySummary } from './types'

const CATEGORY_COLORS: Record<string, string> = {
  food: '#4CAF50',
  transport: '#2196F3',
  housing: '#FF9800',
  entertainment: '#E91E63',
  utilities: '#9C27B0',
  other: '#607D8B',
}

type PieSlice = {
  category: string
  percentage: number
  total: number
  color: string
  startAngle: number
  endAngle: number
}

const buildSlices = (categories: CategorySummary[]): PieSlice[] => {
  let currentAngle = -90 // Start from top
  return categories.map((cat) => {
    const sliceAngle = (cat.percentage / 100) * 360
    const slice: PieSlice = {
      category: cat.category,
      percentage: cat.percentage,
      total: cat.total,
      color: CATEGORY_COLORS[cat.category] ?? '#999',
      startAngle: currentAngle,
      endAngle: currentAngle + sliceAngle,
    }
    currentAngle += sliceAngle
    return slice
  })
}

const describeArc = (cx: number, cy: number, r: number, startAngle: number, endAngle: number): string => {
  const toRad = (deg: number) => (deg * Math.PI) / 180
  const start = {
    x: cx + r * Math.cos(toRad(startAngle)),
    y: cy + r * Math.sin(toRad(startAngle)),
  }
  const end = {
    x: cx + r * Math.cos(toRad(endAngle)),
    y: cy + r * Math.sin(toRad(endAngle)),
  }
  const largeArc = endAngle - startAngle > 180 ? 1 : 0
  return [
    `M ${cx} ${cy}`,
    `L ${start.x} ${start.y}`,
    `A ${r} ${r} 0 ${largeArc} 1 ${end.x} ${end.y}`,
    'Z',
  ].join(' ')
}

export const renderPieChart = (categories: CategorySummary[]) => {
  if (categories.length === 0) {
    return h('p', { style: { color: '#888', textAlign: 'center', padding: '2rem' } }, 'No expenses to chart')
  }

  const slices = buildSlices(categories)
  const cx = 100
  const cy = 100
  const r = 90

  // Handle single-category case (full circle)
  const paths =
    slices.length === 1
      ? [h('circle', { cx: String(cx), cy: String(cy), r: String(r), fill: slices[0].color })]
      : slices.map((slice) =>
          h('path', {
            d: describeArc(cx, cy, r, slice.startAngle, slice.endAngle),
            fill: slice.color,
          })
        )

  const svg = h(
    'svg',
    { viewBox: '0 0 200 200', width: '200', height: '200', style: { display: 'block', margin: '0 auto' } },
    ...paths
  )

  const legend = h(
    'div',
    { style: { display: 'flex', flexWrap: 'wrap', gap: '0.5rem', justifyContent: 'center', marginTop: '1rem' } },
    ...slices.map((slice) =>
      h(
        'div',
        { style: { display: 'flex', alignItems: 'center', gap: '0.25rem', fontSize: '0.85rem' } },
        h('span', {
          style: {
            width: '12px',
            height: '12px',
            borderRadius: '2px',
            backgroundColor: slice.color,
            display: 'inline-block',
          },
        }),
        h('span', {}, `${slice.category}: $${slice.total.toFixed(2)} (${slice.percentage}%)`)
      )
    )
  )

  return h('div', {}, svg, legend)
}

import { createSSR } from 'plaited'
import { type Category, type ExpenseFilter, CATEGORIES } from './types'
import { readAllExpenses, addExpense, deleteExpense, filterExpenses, getMonthlySummary, getAvailableMonths } from './store'
import { expensesToCsv } from './csv'
import { renderPage, renderFullPage } from './ui'

const parseFilter = (url: URL): ExpenseFilter => {
  const filter: ExpenseFilter = {}
  const startDate = url.searchParams.get('startDate')
  const endDate = url.searchParams.get('endDate')
  const category = url.searchParams.get('category')
  if (startDate) filter.startDate = startDate
  if (endDate) filter.endDate = endDate
  if (category && CATEGORIES.includes(category as Category)) {
    filter.category = category as Category
  }
  return filter
}

const isValidCategory = (value: string): value is Category =>
  CATEGORIES.includes(value as Category)

const handleAdd = async (formData: FormData): Promise<Response> => {
  const amount = parseFloat(formData.get('amount') as string)
  const category = formData.get('category') as string
  const date = formData.get('date') as string
  const notes = (formData.get('notes') as string) ?? ''

  if (isNaN(amount) || amount <= 0) {
    return new Response('Invalid amount', { status: 400 })
  }
  if (!isValidCategory(category)) {
    return new Response('Invalid category', { status: 400 })
  }
  if (!date || !/^\d{4}-\d{2}-\d{2}$/.test(date)) {
    return new Response('Invalid date', { status: 400 })
  }

  await addExpense({ amount, category, date, notes })
  return new Response(null, { status: 303, headers: { Location: '/' } })
}

const handleDelete = async (url: URL): Promise<Response> => {
  const id = url.searchParams.get('id')
  if (!id) return new Response('Missing id', { status: 400 })
  await deleteExpense(id)
  return new Response(null, { status: 303, headers: { Location: '/' } })
}

const handleExport = async (url: URL): Promise<Response> => {
  const filter = parseFilter(url)
  const all = await readAllExpenses()
  const filtered = filterExpenses(all, filter)
  const csv = expensesToCsv(filtered)

  return new Response(csv, {
    headers: {
      'Content-Type': 'text/csv',
      'Content-Disposition': 'attachment; filename="expenses.csv"',
    },
  })
}

const handleIndex = async (url: URL): Promise<Response> => {
  const filter = parseFilter(url)
  const month = url.searchParams.get('month') ?? ''
  const all = await readAllExpenses()
  const filtered = filterExpenses(all, filter)
  const months = getAvailableMonths(all)
  const selectedMonth = month || (months.length > 0 ? months[0] : '')
  const summary = selectedMonth ? getMonthlySummary(all, selectedMonth) : null

  const body = renderPage(filtered, filter, months, summary)
  const page = renderFullPage(body)
  const { render } = createSSR()
  const html = render(page)

  return new Response(`<!DOCTYPE html>${html}`, {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })
}

const server = Bun.serve({
  port: Number(process.env.PORT) || 3000,
  fetch: async (req) => {
    const url = new URL(req.url)

    if (req.method === 'POST' && url.pathname === '/add') {
      const formData = await req.formData()
      return handleAdd(formData)
    }
    if (req.method === 'POST' && url.pathname === '/delete') {
      return handleDelete(url)
    }
    if (url.pathname === '/export') {
      return handleExport(url)
    }
    if (url.pathname === '/') {
      return handleIndex(url)
    }

    return new Response('Not found', { status: 404 })
  },
})

