import type { InventoryData, InventoryItem } from './types'

const DATA_PATH = `${import.meta.dir}/data/inventory.json`

export const loadData = async (): Promise<InventoryData> => {
  const file = Bun.file(DATA_PATH)
  const exists = await file.exists()
  if (!exists) {
    const empty: InventoryData = { items: [] }
    await Bun.write(DATA_PATH, JSON.stringify(empty, null, 2))
    return empty
  }
  const text = await file.text()
  return JSON.parse(text) as InventoryData
}

export const saveData = async (data: InventoryData): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(data, null, 2))
}

export const generateId = (): string => {
  return crypto.randomUUID()
}

export const findItemById = (items: InventoryItem[], id: string): InventoryItem | undefined => {
  return items.find((item) => item.id === id)
}

export const findItemBySku = (items: InventoryItem[], sku: string): InventoryItem | undefined => {
  return items.find((item) => item.sku.toLowerCase() === sku.toLowerCase())
}

import type {
  InventoryItem,
  NewItemInput,
  UpdateItemInput,
  SearchResult,
  DashboardStats,
  BulkImportResult,
} from './types'
import { loadData, saveData, generateId, findItemById, findItemBySku } from './store'

export const addItem = async (input: NewItemInput): Promise<InventoryItem> => {
  const data = await loadData()
  const existing = findItemBySku(data.items, input.sku)
  if (existing) {
    throw new Error(`Item with SKU "${input.sku}" already exists: ${existing.name}`)
  }
  const now = new Date().toISOString()
  const item: InventoryItem = {
    id: generateId(),
    name: input.name.trim(),
    sku: input.sku.trim().toUpperCase(),
    quantity: Math.max(0, Math.floor(input.quantity)),
    category: input.category.trim(),
    reorderThreshold: Math.max(0, Math.floor(input.reorderThreshold)),
    createdAt: now,
    updatedAt: now,
  }
  data.items.push(item)
  await saveData(data)
  return item
}

export const updateItem = async (id: string, updates: UpdateItemInput): Promise<InventoryItem> => {
  const data = await loadData()
  const index = data.items.findIndex((item) => item.id === id)
  if (index === -1) {
    throw new Error(`Item with id "${id}" not found`)
  }
  const item = data.items[index]
  if (updates.sku) {
    const duplicate = data.items.find(
      (i) => i.sku.toLowerCase() === updates.sku!.toLowerCase() && i.id !== id
    )
    if (duplicate) {
      throw new Error(`SKU "${updates.sku}" is already in use by: ${duplicate.name}`)
    }
  }
  const updated: InventoryItem = {
    ...item,
    ...(updates.name !== undefined && { name: updates.name.trim() }),
    ...(updates.sku !== undefined && { sku: updates.sku.trim().toUpperCase() }),
    ...(updates.quantity !== undefined && { quantity: Math.max(0, Math.floor(updates.quantity)) }),
    ...(updates.category !== undefined && { category: updates.category.trim() }),
    ...(updates.reorderThreshold !== undefined && {
      reorderThreshold: Math.max(0, Math.floor(updates.reorderThreshold)),
    }),
    updatedAt: new Date().toISOString(),
  }
  data.items[index] = updated
  await saveData(data)
  return updated
}

export const removeItem = async (id: string): Promise<InventoryItem> => {
  const data = await loadData()
  const index = data.items.findIndex((item) => item.id === id)
  if (index === -1) {
    throw new Error(`Item with id "${id}" not found`)
  }
  const [removed] = data.items.splice(index, 1)
  await saveData(data)
  return removed
}

export const getItem = async (id: string): Promise<InventoryItem> => {
  const data = await loadData()
  const item = findItemById(data.items, id)
  if (!item) {
    throw new Error(`Item with id "${id}" not found`)
  }
  return item
}

export const getItemBySku = async (sku: string): Promise<InventoryItem> => {
  const data = await loadData()
  const item = findItemBySku(data.items, sku)
  if (!item) {
    throw new Error(`Item with SKU "${sku}" not found`)
  }
  return item
}

export const listItems = async (
  sortBy: keyof InventoryItem = 'name',
  ascending = true
): Promise<InventoryItem[]> => {
  const data = await loadData()
  return [...data.items].sort((a, b) => {
    const aVal = a[sortBy]
    const bVal = b[sortBy]
    if (typeof aVal === 'string' && typeof bVal === 'string') {
      return ascending ? aVal.localeCompare(bVal) : bVal.localeCompare(aVal)
    }
    if (typeof aVal === 'number' && typeof bVal === 'number') {
      return ascending ? aVal - bVal : bVal - aVal
    }
    return 0
  })
}

export const searchItems = async (query: string): Promise<SearchResult> => {
  const data = await loadData()
  const q = query.toLowerCase().trim()
  if (!q) {
    return { items: data.items, query, total: data.items.length }
  }
  const matched = data.items.filter(
    (item) => item.name.toLowerCase().includes(q) || item.sku.toLowerCase().includes(q)
  )
  return { items: matched, query, total: matched.length }
}

export const getLowStockItems = async (): Promise<InventoryItem[]> => {
  const data = await loadData()
  return data.items.filter((item) => item.quantity <= item.reorderThreshold)
}

export const getDashboardStats = async (): Promise<DashboardStats> => {
  const data = await loadData()
  const categoryMap = new Map<string, number>()
  let totalQuantity = 0
  const lowStockItems: InventoryItem[] = []

  for (const item of data.items) {
    totalQuantity += item.quantity
    categoryMap.set(item.category, (categoryMap.get(item.category) ?? 0) + 1)
    if (item.quantity <= item.reorderThreshold) {
      lowStockItems.push(item)
    }
  }

  const categories = Array.from(categoryMap.entries())
    .map(([name, count]) => ({ name, count }))
    .sort((a, b) => b.count - a.count)

  return {
    totalItems: data.items.length,
    totalQuantity,
    lowStockItems,
    categories,
  }
}

export const bulkImport = async (
  items: NewItemInput[]
): Promise<BulkImportResult> => {
  const data = await loadData()
  const result: BulkImportResult = { imported: 0, skipped: 0, errors: [] }
  const now = new Date().toISOString()

  for (let i = 0; i < items.length; i++) {
    const input = items[i]
    if (!input.name || !input.sku) {
      result.errors.push(`Row ${i + 1}: missing name or SKU`)
      result.skipped++
      continue
    }
    if (typeof input.quantity !== 'number' || input.quantity < 0) {
      result.errors.push(`Row ${i + 1}: invalid quantity for "${input.name}"`)
      result.skipped++
      continue
    }
    const existing = findItemBySku(data.items, input.sku)
    if (existing) {
      result.errors.push(`Row ${i + 1}: SKU "${input.sku}" already exists (${existing.name})`)
      result.skipped++
      continue
    }
    const item: InventoryItem = {
      id: generateId(),
      name: input.name.trim(),
      sku: input.sku.trim().toUpperCase(),
      quantity: Math.max(0, Math.floor(input.quantity)),
      category: (input.category ?? 'Uncategorized').trim(),
      reorderThreshold: Math.max(0, Math.floor(input.reorderThreshold ?? 0)),
      createdAt: now,
      updatedAt: now,
    }
    data.items.push(item)
    result.imported++
  }

  await saveData(data)
  return result
}

export const adjustQuantity = async (id: string, delta: number): Promise<InventoryItem> => {
  const data = await loadData()
  const item = findItemById(data.items, id)
  if (!item) {
    throw new Error(`Item with id "${id}" not found`)
  }
  return updateItem(id, { quantity: Math.max(0, item.quantity + delta) })
}

