export type Route =
  | { action: 'dashboard' }
  | { action: 'list'; sortBy?: keyof InventoryItem; ascending?: boolean }
  | { action: 'search'; query: string }
  | { action: 'barcode-lookup'; sku: string }
  | { action: 'low-stock' }
  | { action: 'add-form' }
  | { action: 'add'; item: NewItemInput }
  | { action: 'update'; id: string; updates: UpdateItemInput }
  | { action: 'remove'; id: string }
  | { action: 'adjust'; id: string; delta: number }
  | { action: 'import-form' }
  | { action: 'import'; items: NewItemInput[] }
  | { action: 'get'; id: string }

export const handleRoute = async (route: Route): Promise<string> => {
  switch (route.action) {
    case 'dashboard': {
      const stats = await getDashboardStats()
      return renderDashboard(stats)
    }

    case 'list': {
      const items = await listItems(route.sortBy, route.ascending)
      return renderItemTable(items, 'All Inventory')
    }

    case 'search': {
      const result = await searchItems(route.query)
      return renderSearchResults(result)
    }

    case 'barcode-lookup': {
      try {
        const item = await getItemBySku(route.sku)
        return renderItemTable([item], `Barcode Lookup: ${route.sku}`)
      } catch {
        return renderItemTable([], `No item found for barcode: ${route.sku}`)
      }
    }

    case 'low-stock': {
      const items = await getLowStockItems()
      return renderItemTable(items, 'Low Stock Items')
    }

    case 'add-form': {
      return renderAddItemForm()
    }

    case 'add': {
      const item = await addItem(route.item)
      const stats = await getDashboardStats()
      return renderDashboard(stats)
    }

    case 'update': {
      await updateItem(route.id, route.updates)
      const items = await listItems()
      return renderItemTable(items, 'All Inventory')
    }

    case 'remove': {
      await removeItem(route.id)
      const items = await listItems()
      return renderItemTable(items, 'All Inventory')
    }

    case 'adjust': {
      await adjustQuantity(route.id, route.delta)
      const stats = await getDashboardStats()
      return renderDashboard(stats)
    }

    case 'import-form': {
      return renderBulkImportForm()
    }

    case 'import': {
      const result = await bulkImport(route.items)
      return renderImportResult(result)
    }

    case 'get': {
      const item = await getItem(route.id)
      return renderItemTable([item], item.name)
    }
  }
}

