  lowStockCount: number
  categoryBreakdown: Record<string, number>
}

export type BulkImportResult = {
  imported: number
  skipped: number
  errors: string[]
}

import type { InventoryItem, NewItem, ItemUpdate, BulkImportResult } from './types'

const DATA_PATH = `${import.meta.dir}/data/inventory.json`

const generateId = (): string => crypto.randomUUID()

const now = (): string => new Date().toISOString()

export const loadItems = async (): Promise<InventoryItem[]> => {
  const file = Bun.file(DATA_PATH)
  const exists = await file.exists()
  if (!exists) {
    await Bun.write(DATA_PATH, '[]')
    return []
  }
  const text = await file.text()
  return JSON.parse(text) as InventoryItem[]
}

const saveItems = async (items: InventoryItem[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(items, null, 2))
}

export const addItem = async (item: NewItem): Promise<InventoryItem> => {
  const items = await loadItems()
  const existing = items.find((i) => i.sku === item.sku)
  if (existing) {
    throw new Error(`Item with SKU "${item.sku}" already exists`)
  }
  const newItem: InventoryItem = {
    id: generateId(),
    ...item,
    createdAt: now(),
    updatedAt: now(),
  }
  items.push(newItem)
  await saveItems(items)
  return newItem
}

export const updateItem = async (id: string, update: ItemUpdate): Promise<InventoryItem> => {
  const items = await loadItems()
  const index = items.findIndex((i) => i.id === id)
  if (index === -1) {
    throw new Error(`Item with id "${id}" not found`)
  }
  if (update.sku) {
    const duplicate = items.find((i) => i.sku === update.sku && i.id !== id)
    if (duplicate) {
      throw new Error(`Item with SKU "${update.sku}" already exists`)
    }
  }
  items[index] = { ...items[index], ...update, updatedAt: now() }
  await saveItems(items)
  return items[index]
}

export const removeItem = async (id: string): Promise<void> => {
  const items = await loadItems()
  const filtered = items.filter((i) => i.id !== id)
  if (filtered.length === items.length) {
    throw new Error(`Item with id "${id}" not found`)
  }
  await saveItems(filtered)
}

export const getItemBySku = async (sku: string): Promise<InventoryItem | undefined> => {
  const items = await loadItems()
  return items.find((i) => i.sku === sku)
}

export const getItemById = async (id: string): Promise<InventoryItem | undefined> => {
  const items = await loadItems()
  return items.find((i) => i.id === id)
}

export const adjustQuantity = async (id: string, delta: number): Promise<InventoryItem> => {
  const items = await loadItems()
  const index = items.findIndex((i) => i.id === id)
  if (index === -1) {
    throw new Error(`Item with id "${id}" not found`)
  }
  const newQuantity = items[index].quantity + delta
  if (newQuantity < 0) {
    throw new Error(`Cannot reduce quantity below 0 (current: ${items[index].quantity}, delta: ${delta})`)
  }
  items[index] = { ...items[index], quantity: newQuantity, updatedAt: now() }
  await saveItems(items)
  return items[index]
}

export const bulkImport = async (rawItems: unknown[]): Promise<BulkImportResult> => {
  const items = await loadItems()
  const existingSkus = new Set(items.map((i) => i.sku))
  const result: BulkImportResult = { imported: 0, skipped: 0, errors: [] }

  for (let idx = 0; idx < rawItems.length; idx++) {
    const raw = rawItems[idx] as Record<string, unknown>
    if (!raw || typeof raw !== 'object') {
      result.errors.push(`Row ${idx}: invalid object`)
      continue
    }
    const { name, sku, quantity, category, reorderThreshold } = raw
    if (typeof name !== 'string' || !name.trim()) {
      result.errors.push(`Row ${idx}: missing or invalid "name"`)
      continue
    }
    if (typeof sku !== 'string' || !sku.trim()) {
      result.errors.push(`Row ${idx}: missing or invalid "sku"`)
      continue
    }
    if (typeof quantity !== 'number' || quantity < 0) {
      result.errors.push(`Row ${idx}: missing or invalid "quantity"`)
      continue
    }
    if (typeof category !== 'string' || !category.trim()) {
      result.errors.push(`Row ${idx}: missing or invalid "category"`)
      continue
    }
    const threshold = typeof reorderThreshold === 'number' ? reorderThreshold : 0

    if (existingSkus.has(sku)) {
      result.skipped++
      result.errors.push(`Row ${idx}: SKU "${sku}" already exists, skipped`)
      continue
    }

    items.push({
      id: generateId(),
      name: name.trim(),
      sku: sku.trim(),
      quantity,
      category: category.trim(),
      reorderThreshold: threshold,
      createdAt: now(),
      updatedAt: now(),
    })
    existingSkus.add(sku)
    result.imported++
  }

  await saveItems(items)
  return result
}

import type { InventoryItem, SearchQuery, SortConfig } from './types'

export const searchItems = (items: InventoryItem[], query: SearchQuery): InventoryItem[] => {
  const term = query.term.toLowerCase().trim()
  return items.filter((item) => {
    const matchesTerm =
      !term || item.name.toLowerCase().includes(term) || item.sku.toLowerCase().includes(term)
    const matchesCategory = !query.category || item.category === query.category
    return matchesTerm && matchesCategory
  })
}

export const sortItems = (items: InventoryItem[], config: SortConfig): InventoryItem[] => {
  const sorted = [...items]
  const dir = config.direction === 'asc' ? 1 : -1
  sorted.sort((a, b) => {
    const aVal = a[config.field]
    const bVal = b[config.field]
    if (typeof aVal === 'string' && typeof bVal === 'string') {
      return dir * aVal.localeCompare(bVal)
    }
    if (typeof aVal === 'number' && typeof bVal === 'number') {
      return dir * (aVal - bVal)
    }
    return 0
  })
  return sorted
}

export const getLowStockItems = (items: InventoryItem[]): InventoryItem[] =>
  items.filter((item) => item.quantity <= item.reorderThreshold)

export const getCategories = (items: InventoryItem[]): string[] => {
  const cats = new Set(items.map((i) => i.category))
  return [...cats].sort()
}

import type { InventoryItem, DashboardStats } from './types'

export const computeStats = (items: InventoryItem[]): DashboardStats => {
  const totalItems = items.length
  const totalQuantity = items.reduce((sum, i) => sum + i.quantity, 0)
  const lowStockCount = items.filter((i) => i.quantity <= i.reorderThreshold).length
  const categoryBreakdown: Record<string, number> = {}
  for (const item of items) {
    categoryBreakdown[item.category] = (categoryBreakdown[item.category] ?? 0) + 1
  }
  return { totalItems, totalQuantity, lowStockCount, categoryBreakdown }
}

