const styleToString = (s: Record<string, string | number>): string =>
  Object.entries(s)
    .map(([k, v]) => `${k.replace(/[A-Z]/g, (m) => `-${m.toLowerCase()}`)}:${v}`)
    .join(';')

const stockBadge = (item: InventoryItem) => {
  if (item.quantity === 0) {
    return h('span', { style: styleToString({ ...styles.badge, ...styles.badgeDanger }) }, 'OUT OF STOCK')
  }
  if (item.quantity <= item.reorderThreshold) {
    return h('span', { style: styleToString({ ...styles.badge, ...styles.badgeWarning }) }, 'LOW STOCK')
  }
  return h('span', { style: styleToString({ ...styles.badge, ...styles.badgeOk }) }, 'In Stock')
}

const rowStyle = (item: InventoryItem): string => {
  if (item.quantity === 0) return styleToString(styles.criticalStockRow)
  if (item.quantity <= item.reorderThreshold) return styleToString(styles.lowStockRow)
  return ''
}

