  lastImportResult?: BulkImportResult
): Promise<string> => {
  const items = await loadItems()
  const stats = computeStats(items)
  const lowStockItems = getLowStockItems(items)
  const categories = getCategories(items)
  const filtered = sortItems(searchItems(items, query), sort)
  return renderDashboard(items, stats, lowStockItems, categories, filtered, lastImportResult)
}

export const handleBarcodeInput = async (sku: string): Promise<string> => {
  const item = await getItemBySku(sku.trim())
  if (item) {
    return JSON.stringify({ found: true, item })
  }
  return JSON.stringify({ found: false, sku: sku.trim() })
}

export const handleAddItem = async (item: NewItem): Promise<string> => {
  try {
    const created = await addItem(item)
    return JSON.stringify({ success: true, item: created })
  } catch (err) {
    return JSON.stringify({ success: false, error: (err as Error).message })
  }
}

export const handleRemoveItem = async (id: string): Promise<string> => {
  try {
    await removeItem(id)
    return JSON.stringify({ success: true })
  } catch (err) {
    return JSON.stringify({ success: false, error: (err as Error).message })
  }
}

export const handleAdjustQuantity = async (id: string, delta: number): Promise<string> => {
  try {
    const updated = await adjustQuantity(id, delta)
    return JSON.stringify({ success: true, item: updated })
  } catch (err) {
    return JSON.stringify({ success: false, error: (err as Error).message })
  }
}

export const handleBulkImport = async (jsonString: string): Promise<BulkImportResult> => {
  let parsed: unknown[]
  try {
    parsed = JSON.parse(jsonString)
  } catch {
    return { imported: 0, skipped: 0, errors: ['Invalid JSON format'] }
  }
  if (!Array.isArray(parsed)) {
    return { imported: 0, skipped: 0, errors: ['JSON must be an array of items'] }
  }
  return bulkImport(parsed)
}

