import type { InventoryItem, CreateItemInput, UpdateItemInput, BulkImportResult, DashboardData } from './types'

const DATA_PATH = `${import.meta.dir}/data/items.json`

const readItems = async (): Promise<InventoryItem[]> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) return []
  const text = await file.text()
  return text.trim() ? JSON.parse(text) : []
}

const writeItems = async (items: InventoryItem[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(items, null, 2))
}

const generateId = (): string => crypto.randomUUID()

const now = (): string => new Date().toISOString()

export const getAllItems = async (): Promise<InventoryItem[]> => {
  return readItems()
}

export const searchItems = async (query: string, category?: string): Promise<InventoryItem[]> => {
  const items = await readItems()
  const q = query.toLowerCase()
  return items.filter((item) => {
    const matchesQuery = !query || item.name.toLowerCase().includes(q) || item.sku.toLowerCase().includes(q)
    const matchesCategory = !category || item.category.toLowerCase() === category.toLowerCase()
    return matchesQuery && matchesCategory
  })
}

export const getItemById = async (id: string): Promise<InventoryItem | undefined> => {
  const items = await readItems()
  return items.find((item) => item.id === id)
}

export const getItemBySku = async (sku: string): Promise<InventoryItem | undefined> => {
  const items = await readItems()
  return items.find((item) => item.sku.toLowerCase() === sku.toLowerCase())
}

export const createItem = async (input: CreateItemInput): Promise<InventoryItem> => {
  const items = await readItems()
  const existing = items.find((item) => item.sku.toLowerCase() === input.sku.toLowerCase())
  if (existing) {
    throw new Error(`Item with SKU "${input.sku}" already exists`)
  }
  const timestamp = now()
  const newItem: InventoryItem = {
    id: generateId(),
    ...input,
    createdAt: timestamp,
    updatedAt: timestamp,
  }
  items.push(newItem)
  await writeItems(items)
  return newItem
}

export const updateItem = async (id: string, input: UpdateItemInput): Promise<InventoryItem> => {
  const items = await readItems()
  const index = items.findIndex((item) => item.id === id)
  if (index === -1) {
    throw new Error(`Item with id "${id}" not found`)
  }
  const updated: InventoryItem = {
    ...items[index],
    ...input,
    updatedAt: now(),
  }
  items[index] = updated
  await writeItems(items)
  return updated
}

export const deleteItem = async (id: string): Promise<boolean> => {
  const items = await readItems()
  const index = items.findIndex((item) => item.id === id)
  if (index === -1) return false
  items.splice(index, 1)
  await writeItems(items)
  return true
}

export const bulkImport = async (inputs: CreateItemInput[]): Promise<BulkImportResult> => {
  const items = await readItems()
  const existingSkus = new Set(items.map((item) => item.sku.toLowerCase()))
  const result: BulkImportResult = { imported: 0, skipped: 0, errors: [] }
  const timestamp = now()

  for (const input of inputs) {
    if (!input.name || !input.sku || input.quantity == null || !input.category || input.reorderThreshold == null) {
      result.errors.push(`Invalid item data: missing required fields for SKU "${input.sku || 'unknown'}"`)
      result.skipped++
      continue
    }
    if (existingSkus.has(input.sku.toLowerCase())) {
      result.errors.push(`SKU "${input.sku}" already exists — skipped`)
      result.skipped++
      continue
    }
    const newItem: InventoryItem = {
      id: generateId(),
      name: input.name,
      sku: input.sku,
      quantity: Number(input.quantity),
      category: input.category,
      reorderThreshold: Number(input.reorderThreshold),
      createdAt: timestamp,
      updatedAt: timestamp,
    }
    items.push(newItem)
    existingSkus.add(input.sku.toLowerCase())
    result.imported++
  }

  await writeItems(items)
  return result
}

export const getDashboardData = async (): Promise<DashboardData> => {
  const items = await readItems()
  const lowStockItems = items.filter((item) => item.quantity < item.reorderThreshold)
  const categoryCounts: Record<string, number> = {}
  let totalQuantity = 0

  for (const item of items) {
    totalQuantity += item.quantity
    categoryCounts[item.category] = (categoryCounts[item.category] || 0) + 1
  }

  return {
    totalItems: items.length,
    totalQuantity,
    lowStockItems: lowStockItems.sort((a, b) => a.quantity - b.quantity),
    categoryCounts,
  }
}

import { createSSR } from 'plaited'
import * as store from './store'
import {
  renderDashboard,
  renderItemList,
  renderItemDetail,
  renderAddForm,
  renderEditForm,
  renderBulkImport,
  renderBarcodeLookup,
} from './views'

const html = (template: unknown): Response =>
  new Response(`<!DOCTYPE html>${createSSR(template)}`, {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })

const json = (data: unknown, status = 200): Response =>
  new Response(JSON.stringify(data, null, 2), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

const redirect = (path: string): Response =>
  new Response(null, { status: 302, headers: { Location: path } })

const parseForm = async (req: Request): Promise<Record<string, string>> => {
  const text = await req.text()
  const params = new URLSearchParams(text)
  const result: Record<string, string> = {}
  for (const [key, value] of params.entries()) {
    result[key] = value
  }
  return result
}

export const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url)
  const path = url.pathname
  const method = req.method

  // Dashboard
  if (path === '/' && method === 'GET') {
    const data = await store.getDashboardData()
    return html(renderDashboard(data))
  }

  // Dashboard API (JSON)
  if (path === '/dashboard' && method === 'GET') {
    const data = await store.getDashboardData()
    return json(data)
  }

  // Barcode lookup (HTML)
  if (path === '/items/barcode' && method === 'GET') {
    const sku = url.searchParams.get('sku') || ''
    const item = sku ? await store.getItemBySku(sku) : undefined
    return html(renderBarcodeLookup(item, sku || undefined))
  }

  // Barcode lookup API (JSON)
  if (path.startsWith('/api/items/barcode/') && method === 'GET') {
    const sku = decodeURIComponent(path.split('/api/items/barcode/')[1])
    const item = await store.getItemBySku(sku)
    if (!item) return json({ error: 'Item not found' }, 404)
    return json(item)
  }

  // Add item form
  if (path === '/items/new' && method === 'GET') {
    return html(renderAddForm())
  }

  // Bulk import page
  if (path === '/items/import' && method === 'GET') {
    return html(renderBulkImport())
  }

  // Bulk import submit (form)
  if (path === '/items/import' && method === 'POST') {
    const contentType = req.headers.get('content-type') || ''
    if (contentType.includes('application/json')) {
      const body = await req.json()
      const result = await store.bulkImport(Array.isArray(body) ? body : body.items || [])
      return json(result)
    }
    const form = await parseForm(req)
    try {
      const items = JSON.parse(form.json)
      const result = await store.bulkImport(Array.isArray(items) ? items : [items])
      return html(renderBulkImport(result))
    } catch {
      return html(renderBulkImport({ imported: 0, skipped: 0, errors: ['Invalid JSON data'] }))
    }
  }

  // Bulk import API
  if (path === '/api/items/bulk' && method === 'POST') {
    const body = await req.json()
    const result = await store.bulkImport(Array.isArray(body) ? body : body.items || [])
    return json(result)
  }

  // Edit item form
  const editMatch = path.match(/^\/items\/([^/]+)\/edit$/)
  if (editMatch && method === 'GET') {
    const item = await store.getItemById(editMatch[1])
    if (!item) return html(renderAddForm('Item not found'))
    return html(renderEditForm(item))
  }

  // Delete item (form POST)
  const deleteMatch = path.match(/^\/items\/([^/]+)\/delete$/)
  if (deleteMatch && method === 'POST') {
    await store.deleteItem(deleteMatch[1])
    return redirect('/items')
  }

  // Item detail
  const detailMatch = path.match(/^\/items\/([0-9a-f-]{36})$/)
  if (detailMatch && method === 'GET') {
    const item = await store.getItemById(detailMatch[1])
    if (!item) return json({ error: 'Item not found' }, 404)
    return html(renderItemDetail(item))
  }

  // Update item (form POST)
  const updateMatch = path.match(/^\/items\/([0-9a-f-]{36})$/)
  if (updateMatch && method === 'POST') {
    const form = await parseForm(req)
    try {
      await store.updateItem(updateMatch[1], {
        name: form.name || undefined,
        quantity: form.quantity != null ? Number(form.quantity) : undefined,
        category: form.category || undefined,
        reorderThreshold: form.reorderThreshold != null ? Number(form.reorderThreshold) : undefined,
      })
      return redirect(`/items/${updateMatch[1]}`)
    } catch (err) {
      const item = await store.getItemById(updateMatch[1])
      if (!item) return redirect('/items')
      return html(renderEditForm(item, String(err)))
    }
  }

  // List / search items
  if (path === '/items' && method === 'GET') {
    const q = url.searchParams.get('q') || ''
    const category = url.searchParams.get('category') || ''
    const items = await store.searchItems(q, category)
    return html(renderItemList(items, q, category))
  }

  // Create item (form)
  if (path === '/items' && method === 'POST') {
    const contentType = req.headers.get('content-type') || ''
    if (contentType.includes('application/json')) {
      try {
        const body = await req.json()
        const item = await store.createItem(body)
        return json(item, 201)
      } catch (err) {
        return json({ error: String(err) }, 400)
      }
    }
    const form = await parseForm(req)
    try {
      await store.createItem({
        name: form.name,
        sku: form.sku,
        quantity: Number(form.quantity),
        category: form.category,
        reorderThreshold: Number(form.reorderThreshold),
      })
      return redirect('/items')
    } catch (err) {
      return html(renderAddForm(String(err)))
    }
  }

  // API: update item
  if (detailMatch && method === 'PUT') {
    try {
      const body = await req.json()
      const item = await store.updateItem(detailMatch[1], body)
      return json(item)
    } catch (err) {
      return json({ error: String(err) }, 400)
    }
  }

  // API: delete item
  if (detailMatch && method === 'DELETE') {
    const deleted = await store.deleteItem(detailMatch[1])
    return deleted ? json({ ok: true }) : json({ error: 'Not found' }, 404)
  }

  // API: all items
  if (path === '/api/items' && method === 'GET') {
    const q = url.searchParams.get('q') || ''
    const category = url.searchParams.get('category') || ''
    const items = await store.searchItems(q, category)
    return json(items)
  }

  return new Response('Not Found', { status: 404 })
}

