import type { BookInput, ReadingStatus, FilterOptions } from './types'
import { addBook, removeBook, updateProgress, updateStatus, getBooks, getGenres, getStats } from './store'
import { renderReadingList } from './render'

export const handleAddBook = async (input: BookInput) => {
  const book = await addBook(input)
  return book
}

export const handleRemoveBook = async (id: string) => {
  return removeBook(id)
}

export const handleUpdateProgress = async (id: string, currentPage: number) => {
  return updateProgress(id, currentPage)
}

export const handleUpdateStatus = async (id: string, status: ReadingStatus) => {
  return updateStatus(id, status)
}

export const handleRender = async (filters?: FilterOptions) => {
  const [books, stats, genres] = await Promise.all([
    getBooks(filters),
    getStats(),
    getGenres(),
  ])
  return renderReadingList(
    books,
    stats,
    genres,
    filters?.status ?? null,
    filters?.genre ?? null,
  )
}

import type { BookInput, ReadingStatus, FilterOptions } from './types'
import { handleAddBook, handleRemoveBook, handleUpdateProgress, handleUpdateStatus, handleRender } from './handlers'

export type { Book, BookInput, ReadingStatus, ReadingStats, FilterOptions } from './types'
export { addBook, removeBook, updateProgress, updateStatus, getBooks, getBook, getGenres, getStats } from './store'

type ActionMap = {
  'add-book': { input: BookInput }
  'remove-book': { id: string }
  'update-progress': { id: string; currentPage: number }
  'update-status': { id: string; status: ReadingStatus }
  'render': { filters?: FilterOptions }
}

type Action = {
  [K in keyof ActionMap]: { type: K } & ActionMap[K]
}[keyof ActionMap]

export const dispatch = async (action: Action) => {
  switch (action.type) {
    case 'add-book':
      return handleAddBook(action.input)
    case 'remove-book':
      return handleRemoveBook(action.id)
    case 'update-progress':
      return handleUpdateProgress(action.id, action.currentPage)
    case 'update-status':
      return handleUpdateStatus(action.id, action.status)
    case 'render':
      return handleRender(action.filters)
  }
}

const serve = () => {
  const parseQuery = (url: URL): FilterOptions => {
    const status = url.searchParams.get('status') as ReadingStatus | null
    const genre = url.searchParams.get('genre')
    const filters: FilterOptions = {}
    if (status) filters.status = status
    if (genre) filters.genre = genre
    return filters
  }

  return Bun.serve({
    port: 3000,
    fetch: async (req) => {
      const url = new URL(req.url)

      if (req.method === 'GET' && url.pathname === '/') {
        const filters = parseQuery(url)
        const html = await handleRender(filters)
        return new Response(html, { headers: { 'Content-Type': 'text/html' } })
      }

      if (req.method === 'POST' && url.pathname === '/api/books') {
        const body = await req.json() as BookInput
        const book = await handleAddBook(body)
        return Response.json(book, { status: 201 })
      }

      if (req.method === 'DELETE' && url.pathname.startsWith('/api/books/')) {
        const id = url.pathname.split('/').pop()!
        const removed = await handleRemoveBook(id)
        return removed ? new Response(null, { status: 204 }) : Response.json({ error: 'Not found' }, { status: 404 })
      }

      if (req.method === 'PATCH' && url.pathname.startsWith('/api/books/') && url.pathname.endsWith('/progress')) {
        const parts = url.pathname.split('/')
        const id = parts[parts.length - 2]
        const { currentPage } = await req.json() as { currentPage: number }
        const book = await handleUpdateProgress(id, currentPage)
        return book ? Response.json(book) : Response.json({ error: 'Not found' }, { status: 404 })
      }

      if (req.method === 'PATCH' && url.pathname.startsWith('/api/books/') && url.pathname.endsWith('/status')) {
        const parts = url.pathname.split('/')
        const id = parts[parts.length - 2]
        const { status } = await req.json() as { status: ReadingStatus }
        const book = await handleUpdateStatus(id, status)
        return book ? Response.json(book) : Response.json({ error: 'Not found' }, { status: 404 })
      }

      if (req.method === 'GET' && url.pathname === '/api/books') {
        const filters = parseQuery(url)
        const { getBooks } = await import('./store')
        const books = await getBooks(filters)
        return Response.json(books)
      }

      if (req.method === 'GET' && url.pathname === '/api/stats') {
        const { getStats } = await import('./store')
        const stats = await getStats()
        return Response.json(stats)
      }

      return Response.json({ error: 'Not found' }, { status: 404 })
    },
  })
}

if (import.meta.main) {
  serve()
  console.log('Reading List running on http://localhost:3000')
}

