import type { Book, AddBookInput, UpdateBookInput, Stats } from './types'

const DATA_PATH = `${import.meta.dir}/data/books.json`

const loadBooks = async (): Promise<Book[]> => {
  const file = Bun.file(DATA_PATH)
  const exists = await file.exists()
  if (!exists) return []
  const text = await file.text()
  return JSON.parse(text) as Book[]
}

const saveBooks = async (books: Book[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(books, null, 2))
}

const generateId = (): string =>
  crypto.randomUUID()

export const getBooks = async (
  status?: string,
  genre?: string,
): Promise<Book[]> => {
  let books = await loadBooks()
  if (status) {
    books = books.filter((b) => b.status === status)
  }
  if (genre) {
    books = books.filter((b) => b.genre.toLowerCase() === genre.toLowerCase())
  }
  return books
}

export const getBookById = async (id: string): Promise<Book | undefined> => {
  const books = await loadBooks()
  return books.find((b) => b.id === id)
}

export const addBook = async (input: AddBookInput): Promise<Book> => {
  const books = await loadBooks()
  const book: Book = {
    id: generateId(),
    title: input.title,
    author: input.author,
    genre: input.genre,
    pageCount: input.pageCount,
    currentPage: 0,
    coverUrl: input.coverUrl ?? '',
    status: 'want-to-read',
    addedAt: new Date().toISOString(),
    completedAt: null,
  }
  books.push(book)
  await saveBooks(books)
  return book
}

export const updateBook = async (
  id: string,
  input: UpdateBookInput,
): Promise<Book | null> => {
  const books = await loadBooks()
  const idx = books.findIndex((b) => b.id === id)
  if (idx === -1) return null

  const book = books[idx]

  if (input.currentPage !== undefined) {
    book.currentPage = Math.max(0, Math.min(input.currentPage, book.pageCount))
    if (book.currentPage >= book.pageCount) {
      book.status = 'completed'
      book.completedAt = book.completedAt ?? new Date().toISOString()
    }
  }

  if (input.status !== undefined) {
    book.status = input.status
    if (input.status === 'completed') {
      book.currentPage = book.pageCount
      book.completedAt = book.completedAt ?? new Date().toISOString()
    } else {
      book.completedAt = null
    }
  }

  books[idx] = book
  await saveBooks(books)
  return book
}

export const deleteBook = async (id: string): Promise<boolean> => {
  const books = await loadBooks()
  const filtered = books.filter((b) => b.id !== id)
  if (filtered.length === books.length) return false
  await saveBooks(filtered)
  return true
}

export const getStats = async (): Promise<Stats> => {
  const books = await loadBooks()
  const booksCompleted = books.filter((b) => b.status === 'completed').length
  const booksReading = books.filter((b) => b.status === 'reading').length
  const booksWantToRead = books.filter((b) => b.status === 'want-to-read').length
  const totalPagesRead = books.reduce((sum, b) => sum + b.currentPage, 0)
  const totalPages = books.reduce((sum, b) => sum + b.pageCount, 0)
  const averageProgress =
    books.length > 0
      ? books.reduce((sum, b) => sum + (b.pageCount > 0 ? b.currentPage / b.pageCount : 0), 0) / books.length
      : 0

  return {
    totalBooks: books.length,
    booksCompleted,
    booksReading,
    booksWantToRead,
    totalPagesRead,
    totalPages,
    averageProgress: Math.round(averageProgress * 100),
  }
}

export const getGenres = async (): Promise<string[]> => {
  const books = await loadBooks()
  const genres = new Set(books.map((b) => b.genre))
  return [...genres].sort()
}

