const parseFormData = async (req: Request): Promise<Record<string, string>> => {
  const ct = req.headers.get('content-type') ?? ''
  if (ct.includes('application/json')) {
    return await req.json()
  }
  const text = await req.text()
  const params = new URLSearchParams(text)
  const result: Record<string, string> = {}
  for (const [k, v] of params.entries()) {
    result[k] = v
  }
  return result
}

const jsonResponse = (data: unknown, status = 200) =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

const htmlResponse = (html: string, status = 200) =>
  new Response(`<!DOCTYPE html>${html}`, {
    status,
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })

const redirect = (url: string) =>
  new Response(null, { status: 303, headers: { Location: url } })

const extractId = (pathname: string): string | null => {
  const match = pathname.match(/^\/api\/books\/([^/]+)$/)
  return match ? match[1] : null
}

const resolveMethod = (req: Request, url: URL): string => {
  const override = url.searchParams.get('_method')
  if (override && req.method === 'POST') return override.toUpperCase()
  return req.method
}

export default {
  fetch: async (req: Request): Promise<Response> => {
    const url = new URL(req.url)
    const { pathname } = url
    const method = resolveMethod(req, url)

    // HTML page
    if (pathname === '/' && method === 'GET') {
      const status = url.searchParams.get('status') || undefined
      const genre = url.searchParams.get('genre') || undefined
      const [books, stats, genres] = await Promise.all([
        getBooks(status, genre),
        getStats(),
        getGenres(),
      ])
      const html = renderPage(books, stats, genres, status, genre)
      return htmlResponse(String(html))
    }

    // API: list books
    if (pathname === '/api/books' && method === 'GET') {
      const status = url.searchParams.get('status') || undefined
      const genre = url.searchParams.get('genre') || undefined
      const books = await getBooks(status, genre)
      return jsonResponse(books)
    }

    // API: add book
    if (pathname === '/api/books' && method === 'POST') {
      const data = await parseFormData(req)
      const input: AddBookInput = {
        title: data.title,
        author: data.author,
        genre: data.genre,
        pageCount: parseInt(data.pageCount, 10),
        coverUrl: data.coverUrl || undefined,
      }
      if (!input.title || !input.author || !input.genre || !input.pageCount) {
        const accept = req.headers.get('accept') ?? ''
        if (accept.includes('text/html') || req.headers.get('content-type')?.includes('form')) {
          return redirect('/')
        }
        return jsonResponse({ error: 'Missing required fields: title, author, genre, pageCount' }, 400)
      }
      const book = await addBook(input)
      const accept = req.headers.get('accept') ?? ''
      const ct = req.headers.get('content-type') ?? ''
      if (ct.includes('form') || accept.includes('text/html')) {
        return redirect('/')
      }
      return jsonResponse(book, 201)
    }

    // API: update book
    const bookId = extractId(pathname)
    if (bookId && method === 'PATCH') {
      const data = await parseFormData(req)
      const input: { currentPage?: number; status?: ReadingStatus } = {}
      if (data.currentPage !== undefined && data.currentPage !== '') {
        input.currentPage = parseInt(data.currentPage, 10)
      }
      if (data.status) {
        input.status = data.status as ReadingStatus
      }
      const book = await updateBook(bookId, input)
      if (!book) return jsonResponse({ error: 'Book not found' }, 404)
      const ct = req.headers.get('content-type') ?? ''
      if (ct.includes('form')) return redirect('/')
      return jsonResponse(book)
    }

    // API: delete book
    if (bookId && method === 'DELETE') {
      const deleted = await deleteBook(bookId)
      if (!deleted) return jsonResponse({ error: 'Book not found' }, 404)
      const ct = req.headers.get('content-type') ?? ''
      if (ct.includes('form')) return redirect('/')
      return jsonResponse({ ok: true })
    }

    // API: stats
    if (pathname === '/api/stats' && method === 'GET') {
      const stats = await getStats()
      return jsonResponse(stats)
    }

    return jsonResponse({ error: 'Not found' }, 404)
  },
}

