import { BskyAgent } from '@atproto/api'
import type { SessionData, AuthCredentials } from './types'

const SESSION_PATH = 'data/session.json'
const DEFAULT_SERVICE = 'https://bsky.social'

let agent: BskyAgent | null = null

const getSessionPath = (): string => {
  const base = import.meta.dir ?? process.cwd()
  return `${base}/../${SESSION_PATH}`
}

const saveSession = async (session: SessionData): Promise<void> => {
  const path = getSessionPath()
  await Bun.write(path, JSON.stringify(session, null, 2))
}

const loadSession = async (): Promise<SessionData | null> => {
  try {
    const path = getSessionPath()
    const file = Bun.file(path)
    const exists = await file.exists()
    if (!exists) return null
    const text = await file.text()
    return JSON.parse(text) as SessionData
  } catch {
    return null
  }
}

const clearSession = async (): Promise<void> => {
  try {
    const path = getSessionPath()
    await Bun.write(path, '{}')
  } catch {
    // ignore
  }
}

const createAgent = (service: string): BskyAgent => {
  return new BskyAgent({
    service,
    persistSession: (_evt, sess) => {
      if (sess) {
        saveSession({
          did: sess.did,
          handle: sess.handle,
          accessJwt: sess.accessJwt,
          refreshJwt: sess.refreshJwt,
          service,
        })
      }
    },
  })
}

export const login = async (credentials: AuthCredentials): Promise<SessionData> => {
  const service = credentials.service ?? DEFAULT_SERVICE
  const newAgent = createAgent(service)

  const response = await newAgent.login({
    identifier: credentials.identifier,
    password: credentials.password,
  })

  const session: SessionData = {
    did: response.data.did,
    handle: response.data.handle,
    accessJwt: newAgent.session?.accessJwt ?? '',
    refreshJwt: newAgent.session?.refreshJwt ?? '',
    service,
  }

  await saveSession(session)
  agent = newAgent
  return session
}

export const resumeSession = async (): Promise<SessionData | null> => {
  const stored = await loadSession()
  if (!stored || !stored.accessJwt) return null

  try {
    const newAgent = createAgent(stored.service)
    await newAgent.resumeSession({
      did: stored.did,
      handle: stored.handle,
      accessJwt: stored.accessJwt,
      refreshJwt: stored.refreshJwt,
      active: true,
    })
    agent = newAgent
    return stored
  } catch {
    await clearSession()
    return null
  }
}

export const logout = async (): Promise<void> => {
  agent = null
  await clearSession()
}

export const getAgent = (): BskyAgent => {
  if (!agent) {
    throw new Error('Not authenticated. Please log in first.')
  }
  return agent
}

export const isAuthenticated = (): boolean => agent !== null

import type { AppBskyFeedDefs } from '@atproto/api'
import { getAgent } from './client'
import type { FeedItem, PostView, TimelineResponse } from './types'

const mapPostView = (post: AppBskyFeedDefs.PostView): PostView => {
  const record = post.record as { text?: string; createdAt?: string }
  const viewer = post.viewer ?? {}

  return {
    uri: post.uri,
    cid: post.cid,
    author: {
      did: post.author.did,
      handle: post.author.handle,
      displayName: post.author.displayName ?? post.author.handle,
      avatar: post.author.avatar,
    },
    record: {
      text: record.text ?? '',
      createdAt: record.createdAt ?? new Date().toISOString(),
    },
    likeCount: post.likeCount ?? 0,
    repostCount: post.repostCount ?? 0,
    replyCount: post.replyCount ?? 0,
    isLiked: !!viewer.like,
    likeUri: viewer.like as string | undefined,
  }
}

const mapFeedItem = (item: AppBskyFeedDefs.FeedViewPost): FeedItem => {
  const isRepost = !!item.reason && item.reason.$type === 'app.bsky.feed.defs#reasonRepost'
  const repostBy = isRepost
    ? (item.reason as { by?: { displayName?: string; handle?: string } })?.by?.displayName ??
      (item.reason as { by?: { handle?: string } })?.by?.handle
    : undefined

  return {
    post: mapPostView(item.post),
    isRepost,
    repostBy,
  }
}

export const getTimeline = async (
  cursor?: string,
  limit: number = 30
): Promise<TimelineResponse> => {
  const agent = getAgent()
  const response = await agent.getTimeline({ cursor, limit })

  return {
    items: response.data.feed.map(mapFeedItem),
    cursor: response.data.cursor,
  }
}

export const getAuthorFeed = async (
  actor: string,
  cursor?: string,
  limit: number = 30
): Promise<TimelineResponse> => {
  const agent = getAgent()
  const response = await agent.getAuthorFeed({ actor, cursor, limit })

  return {
    items: response.data.feed.map(mapFeedItem),
    cursor: response.data.cursor,
  }
}

import { RichText } from '@atproto/api'
import { getAgent } from './client'
import type { ComposeInput } from './types'

const MAX_POST_LENGTH = 300

export const createPost = async (input: ComposeInput): Promise<{ uri: string; cid: string }> => {
  const agent = getAgent()
  const text = input.text.trim()

  if (text.length === 0) {
    throw new Error('Post text cannot be empty.')
  }

  if (text.length > MAX_POST_LENGTH) {
    throw new Error(`Post exceeds ${MAX_POST_LENGTH} character limit (${text.length} characters).`)
  }

  const rt = new RichText({ text })
  await rt.detectFacets(agent)

  const response = await agent.post({
    text: rt.text,
    facets: rt.facets,
    createdAt: new Date().toISOString(),
  })

  return { uri: response.uri, cid: response.cid }
}

export const likePost = async (uri: string, cid: string): Promise<string> => {
  const agent = getAgent()
  const response = await agent.like(uri, cid)
  return response.uri
}

export const unlikePost = async (likeUri: string): Promise<void> => {
  const agent = getAgent()
  await agent.deleteLike(likeUri)
}

export const toggleLike = async (
  uri: string,
  cid: string,
  currentLikeUri: string | undefined
): Promise<{ isLiked: boolean; likeUri: string | undefined }> => {
  if (currentLikeUri) {
    await unlikePost(currentLikeUri)
    return { isLiked: false, likeUri: undefined }
  }
  const likeUri = await likePost(uri, cid)
  return { isLiked: true, likeUri }
}

import { getAgent } from './client'
import type { ProfileView } from './types'

export const getProfile = async (actor: string): Promise<ProfileView> => {
  const agent = getAgent()
  const response = await agent.getProfile({ actor })
  const data = response.data
  const viewer = data.viewer ?? {}

  return {
    did: data.did,
    handle: data.handle,
    displayName: data.displayName ?? data.handle,
    description: data.description ?? '',
    avatar: data.avatar,
    banner: data.banner,
    followersCount: data.followersCount ?? 0,
    followsCount: data.followsCount ?? 0,
    postsCount: data.postsCount ?? 0,
    isFollowing: !!viewer.following,
    followUri: viewer.following as string | undefined,
    isFollowedBy: !!viewer.followedBy,
  }
}

export const followUser = async (did: string): Promise<string> => {
  const agent = getAgent()
  const response = await agent.follow(did)
  return response.uri
}

export const unfollowUser = async (followUri: string): Promise<void> => {
  const agent = getAgent()
  await agent.deleteFollow(followUri)
}

export const toggleFollow = async (
  did: string,
  currentFollowUri: string | undefined
): Promise<{ isFollowing: boolean; followUri: string | undefined }> => {
  if (currentFollowUri) {
    await unfollowUser(currentFollowUri)
    return { isFollowing: false, followUri: undefined }
  }
  const followUri = await followUser(did)
  return { isFollowing: true, followUri }
}

