  const avatarStyle = size === 'large' ? styles.profileAvatar : styles.avatar
  const placeholderStyle = size === 'large' ? styles.profileAvatarPlaceholder : styles.avatarPlaceholder

  if (avatar) {
    return h('img', { src: avatar, alt: name, style: avatarStyle })
