export { login, logout, resumeSession, isAuthenticated, getAgent } from './client'
export { getTimeline, getAuthorFeed } from './feed'
export { createPost, likePost, unlikePost, toggleLike } from './posts'
export { getProfile, followUser, unfollowUser, toggleFollow } from './profiles'
export { renderLoginForm, renderTimeline, renderProfile } from './render'
export type {
  SessionData,
  AuthCredentials,
  PostView,
  FeedItem,
  ProfileView,
  TimelineResponse,
  ComposeInput,
} from './types'

import { login, logout, resumeSession } from './client'
import { getTimeline, getAuthorFeed } from './feed'
import { createPost, toggleLike } from './posts'
import { getProfile, toggleFollow } from './profiles'
import { renderLoginForm, renderTimeline, renderProfile } from './render'
import type { AuthCredentials } from './types'

export type RouteAction =
  | { type: 'login'; credentials: AuthCredentials }
  | { type: 'logout' }
  | { type: 'timeline'; cursor?: string }
  | { type: 'post'; text: string }
  | { type: 'like'; uri: string; cid: string; likeUri?: string }
  | { type: 'profile'; actor: string }
  | { type: 'follow'; did: string; followUri?: string }

export type RouteResult = {
  html: string
  error?: string
}

export const handleAction = async (action: RouteAction): Promise<RouteResult> => {
  try {
    switch (action.type) {
      case 'login': {
        const session = await login(action.credentials)
        const feed = await getTimeline()
        return { html: renderTimeline(feed.items, session.handle, feed.cursor) }
      }

      case 'logout': {
        await logout()
        return { html: renderLoginForm() }
      }

      case 'timeline': {
        const session = await resumeSession()
        if (!session) {
          return { html: renderLoginForm() }
        }
        const feed = await getTimeline(action.cursor)
        return { html: renderTimeline(feed.items, session.handle, feed.cursor) }
      }

      case 'post': {
        await createPost({ text: action.text })
        const session = await resumeSession()
        const feed = await getTimeline()
        return { html: renderTimeline(feed.items, session?.handle ?? '', feed.cursor) }
      }

      case 'like': {
        await toggleLike(action.uri, action.cid, action.likeUri)
        const session = await resumeSession()
        const feed = await getTimeline()
        return { html: renderTimeline(feed.items, session?.handle ?? '', feed.cursor) }
      }

      case 'profile': {
        const profile = await getProfile(action.actor)
        const authorFeed = await getAuthorFeed(action.actor)
        return { html: renderProfile(profile, authorFeed.items) }
      }

      case 'follow': {
        const result = await toggleFollow(action.did, action.followUri)
        const profile = await getProfile(action.did)
        const authorFeed = await getAuthorFeed(action.did)
        return {
          html: renderProfile(
            { ...profile, isFollowing: result.isFollowing, followUri: result.followUri },
            authorFeed.items,
          ),
        }
      }

      default:
        return { html: renderLoginForm() }
    }
  } catch (err) {
    const message = err instanceof Error ? err.message : 'An unexpected error occurred'
    return { html: renderLoginForm(message), error: message }
  }
}

export const init = async (): Promise<RouteResult> => {
  const session = await resumeSession()
  if (session) {
    const feed = await getTimeline()
    return { html: renderTimeline(feed.items, session.handle, feed.cursor) }
  }
  return { html: renderLoginForm() }
}

