import { BskyAgent } from "@atproto/api";
import type {
  Credentials,
  SessionData,
  PostView,
  ProfileView,
  TimelineResponse,
} from "./types";

const SESSION_PATH = "data/session.json";

const saveSession = async (session: SessionData): Promise<void> => {
  await Bun.write(SESSION_PATH, JSON.stringify(session, null, 2));
};

const loadSession = async (): Promise<SessionData | null> => {
  const file = Bun.file(SESSION_PATH);
  if (!(await file.exists())) return null;
  try {
    return (await file.json()) as SessionData;
  } catch {
    return null;
  }
};

const clearSession = async (): Promise<void> => {
  const file = Bun.file(SESSION_PATH);
  if (await file.exists()) {
    await Bun.write(SESSION_PATH, "");
  }
};

export class BlueskyClient {
  private agent: BskyAgent;

  constructor() {
    this.agent = new BskyAgent({
      service: "https://bsky.social",
      persistSession: (_evt, session) => {
        if (session) {
          saveSession({
            did: session.did,
            handle: session.handle,
            accessJwt: session.accessJwt,
            refreshJwt: session.refreshJwt,
          });
        }
      },
    });
  }

  get isLoggedIn(): boolean {
    return this.agent.hasSession;
  }

  get currentUser(): { did: string; handle: string } | null {
    if (!this.agent.session) return null;
    return {
      did: this.agent.session.did,
      handle: this.agent.session.handle,
    };
  }

  login = async (credentials: Credentials): Promise<void> => {
    await this.agent.login(credentials);
  };

  resumeSession = async (): Promise<boolean> => {
    const session = await loadSession();
    if (!session) return false;
    try {
      await this.agent.resumeSession(session);
      return true;
    } catch {
      await clearSession();
      return false;
    }
  };

  logout = async (): Promise<void> => {
    await clearSession();
    this.agent = new BskyAgent({ service: "https://bsky.social" });
  };

  getTimeline = async (
    cursor?: string,
    limit = 25
  ): Promise<TimelineResponse> => {
    const response = await this.agent.getTimeline({ cursor, limit });
    const posts: PostView[] = response.data.feed.map((item) => {
      const post = item.post;
      const record = post.record as { text: string; createdAt: string };
      const viewer = post.viewer ?? {};

      return {
        uri: post.uri,
        cid: post.cid,
        author: {
          did: post.author.did,
          handle: post.author.handle,
          displayName: post.author.displayName ?? post.author.handle,
          avatar: post.author.avatar,
        },
        text: record.text,
        createdAt: record.createdAt,
        likeCount: post.likeCount ?? 0,
        repostCount: post.repostCount ?? 0,
        replyCount: post.replyCount ?? 0,
        isLiked: !!viewer.like,
        likeUri: viewer.like,
      };
    });

    return { posts, cursor: response.data.cursor };
  };

  createPost = async (text: string): Promise<{ uri: string; cid: string }> => {
    const response = await this.agent.post({
      text,
      createdAt: new Date().toISOString(),
    });
    return { uri: response.uri, cid: response.cid };
  };

  likePost = async (
    uri: string,
    cid: string
  ): Promise<{ uri: string }> => {
    const response = await this.agent.like(uri, cid);
    return { uri: response.uri };
  };

  unlikePost = async (likeUri: string): Promise<void> => {
    await this.agent.deleteLike(likeUri);
  };

  toggleLike = async (
    post: PostView
  ): Promise<{ isLiked: boolean; likeUri: string | undefined }> => {
    if (post.isLiked && post.likeUri) {
      await this.unlikePost(post.likeUri);
      return { isLiked: false, likeUri: undefined };
    }
    const result = await this.likePost(post.uri, post.cid);
    return { isLiked: true, likeUri: result.uri };
  };

  getProfile = async (actor: string): Promise<ProfileView> => {
    const response = await this.agent.getProfile({ actor });
    const profile = response.data;
    const viewer = profile.viewer ?? {};

    return {
      did: profile.did,
      handle: profile.handle,
      displayName: profile.displayName ?? profile.handle,
      description: profile.description ?? "",
      avatar: profile.avatar,
      banner: profile.banner,
      followersCount: profile.followersCount ?? 0,
      followsCount: profile.followsCount ?? 0,
      postsCount: profile.postsCount ?? 0,
      isFollowing: !!viewer.following,
      followUri: viewer.following,
    };
  };

  getAuthorFeed = async (
    actor: string,
    cursor?: string,
    limit = 25
  ): Promise<TimelineResponse> => {
    const response = await this.agent.getAuthorFeed({ actor, cursor, limit });
    const posts: PostView[] = response.data.feed.map((item) => {
      const post = item.post;
      const record = post.record as { text: string; createdAt: string };
      const viewer = post.viewer ?? {};

      return {
        uri: post.uri,
        cid: post.cid,
        author: {
          did: post.author.did,
          handle: post.author.handle,
          displayName: post.author.displayName ?? post.author.handle,
          avatar: post.author.avatar,
        },
        text: record.text,
        createdAt: record.createdAt,
        likeCount: post.likeCount ?? 0,
        repostCount: post.repostCount ?? 0,
        replyCount: post.replyCount ?? 0,
        isLiked: !!viewer.like,
        likeUri: viewer.like,
      };
    });

    return { posts, cursor: response.data.cursor };
  };

  followUser = async (did: string): Promise<{ uri: string }> => {
    const response = await this.agent.follow(did);
    return { uri: response.uri };
  };

  unfollowUser = async (followUri: string): Promise<void> => {
    await this.agent.deleteFollow(followUri);
  };

  toggleFollow = async (
    profile: ProfileView
  ): Promise<{ isFollowing: boolean; followUri: string | undefined }> => {
    if (profile.isFollowing && profile.followUri) {
      await this.unfollowUser(profile.followUri);
      return { isFollowing: false, followUri: undefined };
    }
    const result = await this.followUser(profile.did);
    return { isFollowing: true, followUri: result.uri };
  };
}

