import { BlueskyClient } from "./client";
import {
  renderLoginForm,
  renderAppShell,
  renderFeed,
  renderComposer,
  renderProfile,
  renderPost,
} from "./render";
import type { PostView, ProfileView, TimelineResponse } from "./types";

export type AppState = {
  client: BlueskyClient;
  currentView: "login" | "feed" | "compose" | "profile";
  feedPosts: PostView[];
  feedCursor: string | undefined;
  viewedProfile: ProfileView | null;
  error: string | undefined;
};

const createAppState = (): AppState => ({
  client: new BlueskyClient(),
  currentView: "login",
  feedPosts: [],
  feedCursor: undefined,
  viewedProfile: null,
  error: undefined,
});

export const createApp = () => {
  const state = createAppState();

  const initialize = async (): Promise<string> => {
    const resumed = await state.client.resumeSession();
    if (resumed) {
      state.currentView = "feed";
      return renderFeedView();
    }
    return renderLoginForm();
  };

  const login = async (
    identifier: string,
    password: string
  ): Promise<string> => {
    try {
      await state.client.login({ identifier, password });
      state.currentView = "feed";
      state.error = undefined;
      return renderFeedView();
    } catch (err) {
      const message =
        err instanceof Error ? err.message : "Login failed. Check your credentials.";
      state.error = message;
      return renderLoginForm(message);
    }
  };

  const logout = async (): Promise<string> => {
    await state.client.logout();
    state.currentView = "login";
    state.feedPosts = [];
    state.feedCursor = undefined;
    state.viewedProfile = null;
    state.error = undefined;
    return renderLoginForm();
  };

  const renderFeedView = async (): Promise<string> => {
    try {
      const timeline = await state.client.getTimeline();
      state.feedPosts = timeline.posts;
      state.feedCursor = timeline.cursor;
      state.currentView = "feed";
      return renderAppShell(renderFeed(state.feedPosts), "feed");
    } catch (err) {
      const message = err instanceof Error ? err.message : "Failed to load feed";
      return renderAppShell(`<div style="padding:16px;color:#dc2626">${message}</div>`, "feed");
    }
  };

  const loadMorePosts = async (): Promise<string> => {
    if (!state.feedCursor) return renderFeed(state.feedPosts);
    try {
      const timeline = await state.client.getTimeline(state.feedCursor);
      state.feedPosts = [...state.feedPosts, ...timeline.posts];
      state.feedCursor = timeline.cursor;
      return renderFeed(state.feedPosts);
    } catch (err) {
      return renderFeed(state.feedPosts);
    }
  };

  const showComposer = (): string => {
    state.currentView = "compose";
    return renderAppShell(renderComposer(), "compose");
  };

  const submitPost = async (text: string): Promise<string> => {
    if (!text.trim()) {
      return renderComposer();
    }
    try {
      await state.client.createPost(text.trim());
      state.currentView = "feed";
      return renderFeedView();
    } catch (err) {
      const message = err instanceof Error ? err.message : "Failed to create post";
      return renderAppShell(
        `<div style="padding:16px;color:#dc2626">${message}</div>` + renderComposer(),
        "compose"
      );
    }
  };

  const toggleLike = async (postUri: string): Promise<string> => {
    const post = state.feedPosts.find((p) => p.uri === postUri);
    if (!post) return renderFeed(state.feedPosts);

    try {
      const result = await state.client.toggleLike(post);
      post.isLiked = result.isLiked;
      post.likeUri = result.likeUri;
      post.likeCount += result.isLiked ? 1 : -1;
      return renderPost(post);
    } catch {
      return renderPost(post);
    }
  };

  const viewProfile = async (actor: string): Promise<string> => {
    try {
      const profile = await state.client.getProfile(actor);
      state.viewedProfile = profile;
      state.currentView = "profile";

      const authorFeed = await state.client.getAuthorFeed(actor);
      const profileHtml = renderProfile(profile);
      const feedHtml = renderFeed(authorFeed.posts);
      return renderAppShell(profileHtml + feedHtml, "profile");
    } catch (err) {
      const message = err instanceof Error ? err.message : "Failed to load profile";
      return renderAppShell(`<div style="padding:16px;color:#dc2626">${message}</div>`, "profile");
    }
  };

  const viewOwnProfile = async (): Promise<string> => {
    const user = state.client.currentUser;
    if (!user) return renderLoginForm();
    return viewProfile(user.handle);
  };

  const toggleFollow = async (did: string): Promise<string> => {
    if (!state.viewedProfile || state.viewedProfile.did !== did) {
      return "";
    }

    try {
      const result = await state.client.toggleFollow(state.viewedProfile);
      state.viewedProfile.isFollowing = result.isFollowing;
      state.viewedProfile.followUri = result.followUri;
      if (result.isFollowing) {
        state.viewedProfile.followersCount += 1;
      } else {
        state.viewedProfile.followersCount -= 1;
      }
      return renderProfile(state.viewedProfile);
    } catch {
      return renderProfile(state.viewedProfile);
    }
  };

  return {
    initialize,
    login,
    logout,
    renderFeedView,
    loadMorePosts,
    showComposer,
    submitPost,
    toggleLike,
    viewProfile,
    viewOwnProfile,
    toggleFollow,
    get state() {
      return state;
    },
  };
};

export { BlueskyClient } from "./client";
export {
  renderLoginForm,
  renderAppShell,
  renderFeed,
  renderComposer,
  renderProfile,
  renderPost,
} from "./render";
export type { PostView, ProfileView, TimelineResponse } from "./types";

{
  "name": "@node/bluesky-client",
  "version": "1.0.0",
  "description": "Bluesky social client for viewing feeds, posting, and interacting with profiles",
  "modnet": {
    "contentType": "social",
    "structure": "feed",
    "mechanics": ["post", "like", "follow"],
    "boundary": "ask",
    "scale": 2
  },
  "dependencies": {
    "@anthropic-ai/sdk": "latest",
    "@anthropic-ai/claude-agent-sdk": "latest",
    "@atproto/api": "^0.13.0"
  }
}

import { BskyAgent } from '@atproto/api'
import type {
  AuthCredentials,
  SessionData,
  FeedPost,
  ProfileView,
  TimelineResponse,
  PostAuthor,
} from './types'

const SESSION_PATH = './data/session.json'

const agent = new BskyAgent({ service: 'https://bsky.social' })

const saveSession = async (session: SessionData): Promise<void> => {
  await Bun.write(SESSION_PATH, JSON.stringify(session, null, 2))
}

const loadSession = async (): Promise<SessionData | null> => {
  const file = Bun.file(SESSION_PATH)
  if (!(await file.exists())) return null
  try {
    return (await file.json()) as SessionData
  } catch {
    return null
  }
}

const clearSession = async (): Promise<void> => {
  const file = Bun.file(SESSION_PATH)
  if (await file.exists()) {
    await Bun.write(SESSION_PATH, '{}')
  }
}

export const login = async (credentials: AuthCredentials): Promise<SessionData> => {
  const response = await agent.login({
    identifier: credentials.identifier,
    password: credentials.password,
  })

  const session: SessionData = {
    handle: response.data.handle,
    did: response.data.did,
    accessJwt: response.data.accessJwt,
    refreshJwt: response.data.refreshJwt,
  }

  await saveSession(session)
  return session
}

export const resumeSession = async (): Promise<SessionData | null> => {
  const saved = await loadSession()
  if (!saved || !saved.accessJwt) return null

  try {
    await agent.resumeSession({
      did: saved.did,
      handle: saved.handle,
      accessJwt: saved.accessJwt,
      refreshJwt: saved.refreshJwt,
      active: true,
    })
    return saved
  } catch {
    await clearSession()
    return null
  }
}

export const logout = async (): Promise<void> => {
  await clearSession()
}

const extractAuthor = (author: Record<string, unknown>): PostAuthor => ({
  did: author.did as string,
  handle: author.handle as string,
  displayName: (author.displayName as string) || (author.handle as string),
  avatar: author.avatar as string | undefined,
})

const extractFeedPost = (feedItem: Record<string, unknown>): FeedPost => {
  const post = feedItem.post as Record<string, unknown>
  const author = post.author as Record<string, unknown>
  const record = post.record as Record<string, unknown>
  const viewer = (post.viewer as Record<string, unknown>) ?? {}

  return {
    uri: post.uri as string,
    cid: post.cid as string,
    author: extractAuthor(author),
    text: (record.text as string) || '',
    createdAt: (record.createdAt as string) || new Date().toISOString(),
    likeCount: (post.likeCount as number) ?? 0,
    replyCount: (post.replyCount as number) ?? 0,
    repostCount: (post.repostCount as number) ?? 0,
    isLiked: !!viewer.like,
    likeUri: viewer.like as string | undefined,
  }
}

export const getTimeline = async (
  cursor?: string,
  limit = 25
): Promise<TimelineResponse> => {
  const response = await agent.getTimeline({ cursor, limit })

  const posts: FeedPost[] = response.data.feed.map((item) =>
    extractFeedPost(item as unknown as Record<string, unknown>)
  )

  return {
    posts,
    cursor: response.data.cursor,
  }
}

export const createPost = async (text: string): Promise<{ uri: string; cid: string }> => {
  if (text.length === 0) throw new Error('Post text cannot be empty')
  if (text.length > 300) throw new Error('Post text exceeds 300 character limit')

  const response = await agent.post({ text })
  return { uri: response.uri, cid: response.cid }
}

export const likePost = async (uri: string, cid: string): Promise<string> => {
  const response = await agent.like(uri, cid)
  return response.uri
}

export const unlikePost = async (likeUri: string): Promise<void> => {
  await agent.deleteLike(likeUri)
}

export const getProfile = async (actor: string): Promise<ProfileView> => {
  const response = await agent.getProfile({ actor })
  const data = response.data
  const viewer = (data.viewer as Record<string, unknown>) ?? {}

  return {
    did: data.did,
    handle: data.handle,
    displayName: data.displayName || data.handle,
    description: data.description || '',
    avatar: data.avatar,
    banner: data.banner,
    followersCount: data.followersCount ?? 0,
    followsCount: data.followsCount ?? 0,
    postsCount: data.postsCount ?? 0,
    isFollowing: !!viewer.following,
    followUri: viewer.following as string | undefined,
  }
}

export const followUser = async (did: string): Promise<string> => {
  const response = await agent.follow(did)
  return response.uri
}

export const unfollowUser = async (followUri: string): Promise<void> => {
  await agent.deleteFollow(followUri)
}

export const getAuthorFeed = async (
  actor: string,
  cursor?: string,
  limit = 25
): Promise<TimelineResponse> => {
  const response = await agent.getAuthorFeed({ actor, cursor, limit })

  const posts: FeedPost[] = response.data.feed.map((item) =>
    extractFeedPost(item as unknown as Record<string, unknown>)
  )

  return {
    posts,
    cursor: response.data.cursor,
  }
}

