import {
  login,
  resumeSession,
  logout,
  getTimeline,
  createPost,
  likePost,
  unlikePost,
  getProfile,
  followUser,
  unfollowUser,
  getAuthorFeed,
} from './client'
import { renderLoginForm, renderTimeline, renderProfile } from './render'
import type { AuthCredentials, SessionData } from './types'

type Action =
  | { type: 'login'; credentials: AuthCredentials }
  | { type: 'logout' }
  | { type: 'timeline'; cursor?: string }
  | { type: 'post'; text: string }
  | { type: 'like'; uri: string; cid: string }
  | { type: 'unlike'; likeUri: string }
  | { type: 'profile'; actor: string }
  | { type: 'follow'; did: string }
  | { type: 'unfollow'; followUri: string }

type Result = {
  html: string
  error?: string
}

let currentSession: SessionData | null = null

export const init = async (): Promise<Result> => {
  const session = await resumeSession()
  if (session) {
    currentSession = session
    return handleAction({ type: 'timeline' })
  }
  return { html: renderLoginForm() }
}

export const handleAction = async (action: Action): Promise<Result> => {
  try {
    switch (action.type) {
      case 'login': {
        const session = await login(action.credentials)
        currentSession = session
        const timeline = await getTimeline()
        return {
          html: renderTimeline(timeline.posts, session.handle, timeline.cursor),
        }
      }

      case 'logout': {
        await logout()
        currentSession = null
        return { html: renderLoginForm() }
      }

      case 'timeline': {
        if (!currentSession) return { html: renderLoginForm() }
        const timeline = await getTimeline(action.cursor)
        return {
          html: renderTimeline(timeline.posts, currentSession.handle, timeline.cursor),
        }
      }

      case 'post': {
        if (!currentSession) return { html: renderLoginForm() }
        await createPost(action.text)
        const timeline = await getTimeline()
        return {
          html: renderTimeline(timeline.posts, currentSession.handle, timeline.cursor),
        }
      }

      case 'like': {
        if (!currentSession) return { html: renderLoginForm() }
        await likePost(action.uri, action.cid)
        const timeline = await getTimeline()
        return {
          html: renderTimeline(timeline.posts, currentSession.handle, timeline.cursor),
        }
      }

      case 'unlike': {
        if (!currentSession) return { html: renderLoginForm() }
        await unlikePost(action.likeUri)
        const timeline = await getTimeline()
        return {
          html: renderTimeline(timeline.posts, currentSession.handle, timeline.cursor),
        }
      }

      case 'profile': {
        if (!currentSession) return { html: renderLoginForm() }
        const actor = action.actor === 'self' ? currentSession.handle : action.actor
        const [profile, feed] = await Promise.all([
          getProfile(actor),
          getAuthorFeed(actor),
        ])
        return {
          html: renderProfile(profile, feed.posts),
        }
      }

      case 'follow': {
        if (!currentSession) return { html: renderLoginForm() }
        await followUser(action.did)
        return handleAction({ type: 'timeline' })
      }

      case 'unfollow': {
        if (!currentSession) return { html: renderLoginForm() }
        await unfollowUser(action.followUri)
        return handleAction({ type: 'timeline' })
      }

      default:
        return { html: renderLoginForm() }
    }
  } catch (err) {
    const message = err instanceof Error ? err.message : 'An unknown error occurred'
    return {
      html: currentSession
        ? renderTimeline([], currentSession.handle)
        : renderLoginForm(),
      error: message,
    }
  }
}

export const parseEvent = (trigger: string): Action | null => {
  const parts = trigger.split(':')
  const command = parts[0]

  switch (command) {
    case 'login':
      return null // handled by form submission with credentials

    case 'auth':
      if (parts[1] === 'logout') return { type: 'logout' }
      return null

    case 'navigate':
      if (parts[1] === 'timeline') return { type: 'timeline' }
      if (parts[1] === 'profile-self') return { type: 'profile', actor: 'self' }
      return null

    case 'timeline':
      if (parts[1] === 'load-more') return { type: 'timeline', cursor: parts[2] }
      return null

    case 'post':
      if (parts[1] === 'create') return null // needs text from textarea
      return null

    case 'like':
      return { type: 'like', uri: parts[1], cid: parts[2] }

    case 'unlike':
      return { type: 'unlike', likeUri: `${parts[1]}:${parts[2]}:${parts[3]}` }

    case 'profile':
      return { type: 'profile', actor: parts[1] }

    case 'follow':
      return { type: 'follow', did: parts[1] }

    case 'unfollow':
      return { type: 'unfollow', followUri: `${parts[1]}:${parts[2]}:${parts[3]}` }

    case 'reply':
      return null // reply not yet implemented

    case 'repost':
      return null // repost not yet implemented

    default:
      return null
  }
}

