export type RoomState = {
  lastReadTimestamp: number
  typing: boolean
}

export type ChatData = {
  rooms: Room[]
  roomStates: Record<string, RoomState>
}

import { h } from 'plaited'
import type { TemplateObject } from 'plaited'

const BOLD_RE = /\*\*(.+?)\*\*/g
const ITALIC_RE = /\*(.+?)\*/g

export const formatMessage = (text: string): TemplateObject[] => {
  const parts: TemplateObject[] = []
  let remaining = text

  // Split on bold first, then handle italic within non-bold segments
  const boldSegments = remaining.split(BOLD_RE)
  for (let i = 0; i < boldSegments.length; i++) {
    const segment = boldSegments[i]
    if (i % 2 === 1) {
      // Bold match
      parts.push(h('strong', {}, segment))
    } else {
      // Check for italic in non-bold text
      const italicSegments = segment.split(ITALIC_RE)
      for (let j = 0; j < italicSegments.length; j++) {
        if (j % 2 === 1) {
          parts.push(h('em', {}, italicSegments[j]))
        } else if (italicSegments[j]) {
          parts.push(h('span', {}, italicSegments[j]))
        }
      }
    }
  }

  return parts
}

import type { Room, Message, RoomState, ChatData } from './types'

const ROOMS_PATH = './data/rooms.json'
const MESSAGES_DIR = './data/messages'

const generateId = (): string => crypto.randomUUID()

export const loadRooms = async (): Promise<ChatData> => {
  const file = Bun.file(ROOMS_PATH)
  if (await file.exists()) {
    return file.json() as Promise<ChatData>
  }
  return { rooms: [], roomStates: {} }
}

const saveRooms = async (data: ChatData): Promise<void> => {
  await Bun.write(ROOMS_PATH, JSON.stringify(data, null, 2))
}

export const createRoom = async (name: string): Promise<Room> => {
  const data = await loadRooms()
  const existing = data.rooms.find((r) => r.name === name)
  if (existing) {
    throw new Error(`Room "${name}" already exists`)
  }
  const room: Room = {
    id: generateId(),
    name,
    createdAt: Date.now(),
  }
  data.rooms.push(room)
  data.roomStates[room.id] = { lastReadTimestamp: Date.now(), typing: false }
  await saveRooms(data)
  return room
}

export const getRooms = async (): Promise<Room[]> => {
  const data = await loadRooms()
  return data.rooms
}

export const getRoomState = async (roomId: string): Promise<RoomState> => {
  const data = await loadRooms()
  return data.roomStates[roomId] ?? { lastReadTimestamp: 0, typing: false }
}

export const markRoomRead = async (roomId: string): Promise<void> => {
  const data = await loadRooms()
  if (!data.roomStates[roomId]) {
    data.roomStates[roomId] = { lastReadTimestamp: 0, typing: false }
  }
  data.roomStates[roomId].lastReadTimestamp = Date.now()
  await saveRooms(data)
}

export const setTyping = async (roomId: string, typing: boolean): Promise<void> => {
  const data = await loadRooms()
  if (data.roomStates[roomId]) {
    data.roomStates[roomId].typing = typing
  }
  await saveRooms(data)
}

const messagesPath = (roomId: string): string => `${MESSAGES_DIR}/${roomId}.jsonl`

export const loadMessages = async (roomId: string): Promise<Message[]> => {
  const file = Bun.file(messagesPath(roomId))
  if (!(await file.exists())) {
    return []
  }
  const text = await file.text()
  return text
    .trim()
    .split('\n')
    .filter(Boolean)
    .map((line) => JSON.parse(line) as Message)
}

export const postMessage = async (roomId: string, sender: string, text: string): Promise<Message> => {
  const message: Message = {
    id: generateId(),
    roomId,
    sender,
    text,
    timestamp: Date.now(),
  }
  const file = Bun.file(messagesPath(roomId))
  const existing = (await file.exists()) ? await file.text() : ''
  await Bun.write(messagesPath(roomId), existing + JSON.stringify(message) + '\n')
  return message
}

export const getUnreadCount = async (roomId: string): Promise<number> => {
  const state = await getRoomState(roomId)
  const messages = await loadMessages(roomId)
  return messages.filter((m) => m.timestamp > state.lastReadTimestamp).length
}

