import { createSSR } from 'plaited'
import {
  createRoom,
  getRooms,
  loadMessages,
  postMessage,
  getUnreadCount,
  markRoomRead,
  setTyping,
  getRoomState,
} from './store'
import { renderChatView } from './render'
import type { Room } from './types'

export type ChatAction =
  | { type: 'create-room'; name: string }
  | { type: 'select-room'; roomId: string }
  | { type: 'send-message'; roomId: string; sender: string; text: string }
  | { type: 'set-typing'; roomId: string; typing: boolean }

type ChatState = {
  activeRoomId: string | null
}

const state: ChatState = {
  activeRoomId: null,
}

const getUnreads = async (rooms: Room[]): Promise<Record<string, number>> => {
  const entries = await Promise.all(
    rooms.map(async (r) => [r.id, await getUnreadCount(r.id)] as const),
  )
  return Object.fromEntries(entries)
}

export const handleAction = async (action: ChatAction): Promise<string> => {
  switch (action.type) {
    case 'create-room': {
      const room = await createRoom(action.name)
      state.activeRoomId = room.id
      break
    }
    case 'select-room': {
      state.activeRoomId = action.roomId
      await markRoomRead(action.roomId)
      break
    }
    case 'send-message': {
      await postMessage(action.roomId, action.sender, action.text)
      break
    }
    case 'set-typing': {
      await setTyping(action.roomId, action.typing)
      break
    }
  }
  return render()
}

export const render = async (): Promise<string> => {
  const rooms = await getRooms()
  const activeRoomId = state.activeRoomId
  const messages = activeRoomId ? await loadMessages(activeRoomId) : []
  const unreads = await getUnreads(rooms)
  const roomState = activeRoomId ? await getRoomState(activeRoomId) : null
  const isTyping = roomState?.typing ?? false

  const template = renderChatView(rooms, activeRoomId, messages, unreads, isTyping)
  const ssr = createSSR(template)
  return ssr
}

