/**
 * Parses markdown-style bold/italic syntax into template elements.
 * Supports: **bold**, *italic*, ***bold italic***
 */
export const formatMessageText = (text: string): TemplateObject[] => {
  const parts: TemplateObject[] = [];
  const regex = /(\*{1,3})(.*?)\1/g;
  let lastIndex = 0;
  let match: RegExpExecArray | null;

  while ((match = regex.exec(text)) !== null) {
    // Add plain text before this match
    if (match.index > lastIndex) {
      parts.push(h('span', {}, text.slice(lastIndex, match.index)));
    }

    const stars = match[1].length;
    const content = match[2];

    if (stars === 3) {
      parts.push(h('strong', {}, h('em', {}, content)));
    } else if (stars === 2) {
      parts.push(h('strong', {}, content));
    } else {
      parts.push(h('em', {}, content));
    }

    lastIndex = match.index + match[0].length;
  }

  // Add remaining plain text
  if (lastIndex < text.length) {
    parts.push(h('span', {}, text.slice(lastIndex)));
  }

  return parts.length > 0 ? parts : [h('span', {}, text)];
};

/**
 * Formats a timestamp into a human-readable time string (HH:MM).
 */
export const formatTime = (timestamp: number): string => {
  const date = new Date(timestamp);
  const hours = date.getHours().toString().padStart(2, '0');
  const minutes = date.getMinutes().toString().padStart(2, '0');
  return `${hours}:${minutes}`;
};

import type { Message, Room, RoomState } from './types';

const DATA_DIR = './data';
const ROOMS_FILE = `${DATA_DIR}/rooms.json`;

const generateId = (): string => crypto.randomUUID();

// --- Room persistence ---

export const loadRooms = async (): Promise<Room[]> => {
  const file = Bun.file(ROOMS_FILE);
  if (!(await file.exists())) return [];
  const text = await file.text();
  return JSON.parse(text) as Room[];
};

const saveRooms = async (rooms: Room[]): Promise<void> => {
  await Bun.write(ROOMS_FILE, JSON.stringify(rooms, null, 2));
};

export const createRoom = async (name: string, createdBy: string): Promise<Room> => {
  const rooms = await loadRooms();
  const room: Room = {
    id: generateId(),
    name,
    createdAt: Date.now(),
    createdBy,
  };
  rooms.push(room);
  await saveRooms(rooms);
  return room;
};

export const deleteRoom = async (roomId: string): Promise<void> => {
  const rooms = await loadRooms();
  const filtered = rooms.filter((r) => r.id !== roomId);
  await saveRooms(filtered);
  // Remove message file
  const msgFile = Bun.file(roomMessagePath(roomId));
  if (await msgFile.exists()) {
    await Bun.write(roomMessagePath(roomId), '');
  }
};

// --- Message persistence (JSONL per room) ---

const roomMessagePath = (roomId: string): string => `${DATA_DIR}/room-${roomId}.jsonl`;

export const loadMessages = async (roomId: string): Promise<Message[]> => {
  const file = Bun.file(roomMessagePath(roomId));
  if (!(await file.exists())) return [];
  const text = await file.text();
  if (!text.trim()) return [];
  return text
    .trim()
    .split('\n')
    .map((line) => JSON.parse(line) as Message);
};

export const appendMessage = async (
  roomId: string,
  sender: string,
  text: string,
): Promise<Message> => {
  const message: Message = {
    id: generateId(),
    roomId,
    sender,
    text,
    timestamp: Date.now(),
  };
  const file = Bun.file(roomMessagePath(roomId));
  const existing = (await file.exists()) ? await file.text() : '';
  const newContent = existing + JSON.stringify(message) + '\n';
  await Bun.write(roomMessagePath(roomId), newContent);
  return message;
};

// --- Unread tracking ---

const READ_STATE_FILE = `${DATA_DIR}/read-state.json`;

type ReadState = Record<string, Record<string, number>>; // user -> roomId -> lastReadTimestamp

const loadReadState = async (): Promise<ReadState> => {
  const file = Bun.file(READ_STATE_FILE);
  if (!(await file.exists())) return {};
  const text = await file.text();
  return JSON.parse(text) as ReadState;
};

const saveReadState = async (state: ReadState): Promise<void> => {
  await Bun.write(READ_STATE_FILE, JSON.stringify(state, null, 2));
};

export const markRoomRead = async (user: string, roomId: string): Promise<void> => {
  const state = await loadReadState();
  if (!state[user]) state[user] = {};
  state[user][roomId] = Date.now();
  await saveReadState(state);
};

export const getUnreadCount = async (user: string, roomId: string): Promise<number> => {
  const state = await loadReadState();
  const lastRead = state[user]?.[roomId] ?? 0;
  const messages = await loadMessages(roomId);
  return messages.filter((m) => m.timestamp > lastRead && m.sender !== user).length;
};

export const getRoomStates = async (user: string): Promise<RoomState[]> => {
  const rooms = await loadRooms();
  const states: RoomState[] = [];
  for (const room of rooms) {
    const unreadCount = await getUnreadCount(user, room.id);
    const readState = await loadReadState();
    const lastReadTimestamp = readState[user]?.[room.id] ?? 0;
    states.push({ room, lastReadTimestamp, unreadCount });
  }
  return states;
};

