const TYPING_TIMEOUT_MS = 3000;

// In-memory typing state (not persisted)
let typingStates: TypingState[] = [];

const cleanExpiredTyping = (): void => {
  const now = Date.now();
  typingStates = typingStates.filter((t) => t.expiresAt > now);
};

const getTypingForRoom = (roomId: string, excludeUser?: string): TypingState[] => {
  cleanExpiredTyping();
  return typingStates.filter(
    (t) => t.roomId === roomId && t.user !== excludeUser,
  );
};

export const setTyping = (roomId: string, user: string): void => {
  cleanExpiredTyping();
  const existing = typingStates.find(
    (t) => t.roomId === roomId && t.user === user,
  );
  if (existing) {
    existing.expiresAt = Date.now() + TYPING_TIMEOUT_MS;
  } else {
    typingStates.push({
      roomId,
      user,
      expiresAt: Date.now() + TYPING_TIMEOUT_MS,
    });
  }
};

export const clearTyping = (roomId: string, user: string): void => {
  typingStates = typingStates.filter(
    (t) => !(t.roomId === roomId && t.user === user),
  );
};

export const handleCreateRoom = async (
  name: string,
  user: string,
): Promise<string> => {
  const room = await createRoom(name, user);
  return room.id;
};

export const handleJoinRoom = async (
  roomId: string,
  user: string,
): Promise<void> => {
  await markRoomRead(user, roomId);
};

export const handleSendMessage = async (
  roomId: string,
  sender: string,
  text: string,
): Promise<void> => {
  if (!text.trim()) return;
  await appendMessage(roomId, sender, text.trim());
  clearTyping(roomId, sender);
};

export const handleDeleteRoom = async (roomId: string): Promise<void> => {
  await deleteRoom(roomId);
};

export const getState = async (user: string, activeRoomId: string | null): Promise<ChatState> => {
  const roomStates = await getRoomStates(user);
  const activeTyping = activeRoomId
    ? getTypingForRoom(activeRoomId, user)
    : [];

  return {
    currentUser: user,
    activeRoomId,
    rooms: roomStates,
    typingUsers: activeTyping,
  };
};

export const renderView = async (
  user: string,
  activeRoomId: string | null,
): Promise<string> => {
  const state = await getState(user, activeRoomId);
  const messages = activeRoomId ? await loadMessages(activeRoomId) : [];

  return renderToHTML(
    state.rooms,
    state.activeRoomId,
    messages,
    state.typingUsers,
    state.currentUser,
  );
};

