export type MessageStore = {
  messages: Message[]
}

import type { Room, RoomStore, Message, MessageStore } from './types'

const ROOMS_PATH = './data/rooms.json'

const generateId = (): string => crypto.randomUUID()

const readJson = async <T>(path: string, fallback: T): Promise<T> => {
  const file = Bun.file(path)
  if (await file.exists()) {
    return file.json() as Promise<T>
  }
  return fallback
}

const writeJson = async <T>(path: string, data: T): Promise<void> => {
  await Bun.write(path, JSON.stringify(data, null, 2))
}

const messagesPath = (roomId: string): string => `./data/messages-${roomId}.json`

// Room operations

export const getRooms = async (): Promise<Room[]> => {
  const store = await readJson<RoomStore>(ROOMS_PATH, { rooms: [] })
  return store.rooms
}

export const getRoom = async (roomId: string): Promise<Room | undefined> => {
  const rooms = await getRooms()
  return rooms.find((r) => r.id === roomId)
}

export const createRoom = async (name: string): Promise<Room> => {
  const store = await readJson<RoomStore>(ROOMS_PATH, { rooms: [] })
  const room: Room = {
    id: generateId(),
    name,
    createdAt: new Date().toISOString(),
    unreadCount: 0,
    typingUsers: [],
  }
  store.rooms.push(room)
  await writeJson(ROOMS_PATH, store)
  await writeJson(messagesPath(room.id), { messages: [] })
  return room
}

export const deleteRoom = async (roomId: string): Promise<boolean> => {
  const store = await readJson<RoomStore>(ROOMS_PATH, { rooms: [] })
  const idx = store.rooms.findIndex((r) => r.id === roomId)
  if (idx === -1) return false
  store.rooms.splice(idx, 1)
  await writeJson(ROOMS_PATH, store)
  return true
}

// Message operations

export const getMessages = async (roomId: string): Promise<Message[]> => {
  const store = await readJson<MessageStore>(messagesPath(roomId), { messages: [] })
  return store.messages
}

export const sendMessage = async (roomId: string, sender: string, text: string): Promise<Message> => {
  const store = await readJson<MessageStore>(messagesPath(roomId), { messages: [] })
  const message: Message = {
    id: generateId(),
    roomId,
    sender,
    text,
    timestamp: new Date().toISOString(),
  }
  store.messages.push(message)
  await writeJson(messagesPath(roomId), store)

  // Increment unread count for the room
  const roomStore = await readJson<RoomStore>(ROOMS_PATH, { rooms: [] })
  const room = roomStore.rooms.find((r) => r.id === roomId)
  if (room) {
    room.unreadCount += 1
    await writeJson(ROOMS_PATH, roomStore)
  }

  return message
}

// Unread management

export const markRoomRead = async (roomId: string): Promise<void> => {
  const roomStore = await readJson<RoomStore>(ROOMS_PATH, { rooms: [] })
  const room = roomStore.rooms.find((r) => r.id === roomId)
  if (room) {
    room.unreadCount = 0
    await writeJson(ROOMS_PATH, roomStore)
  }
}

// Typing indicator management

export const setTyping = async (roomId: string, username: string, isTyping: boolean): Promise<void> => {
  const roomStore = await readJson<RoomStore>(ROOMS_PATH, { rooms: [] })
  const room = roomStore.rooms.find((r) => r.id === roomId)
  if (!room) return

  if (isTyping && !room.typingUsers.includes(username)) {
    room.typingUsers.push(username)
  } else if (!isTyping) {
    room.typingUsers = room.typingUsers.filter((u) => u !== username)
  }

  await writeJson(ROOMS_PATH, roomStore)
}

export const getTypingUsers = async (roomId: string): Promise<string[]> => {
  const room = await getRoom(roomId)
  return room?.typingUsers ?? []
}

import { h, type TemplateObject } from 'plaited'

/**
 * Parses markdown-style bold and italic formatting in text.
 * Supports: **bold**, *italic*, ***bold+italic***
 * Returns an array of template objects (h-nodes) and plain strings.
 */
export const formatMessageText = (text: string): (TemplateObject | string)[] => {
  const parts: (TemplateObject | string)[] = []
  // Match ***bold italic***, **bold**, or *italic*
  const regex = /(\*\*\*(.+?)\*\*\*|\*\*(.+?)\*\*|\*(.+?)\*)/g
  let lastIndex = 0
  let match: RegExpExecArray | null

  while ((match = regex.exec(text)) !== null) {
    // Add plain text before match
    if (match.index > lastIndex) {
      parts.push(text.slice(lastIndex, match.index))
    }

    if (match[2]) {
      // ***bold italic***
      parts.push(h('strong', null, h('em', null, match[2])))
    } else if (match[3]) {
      // **bold**
      parts.push(h('strong', null, match[3]))
    } else if (match[4]) {
      // *italic*
      parts.push(h('em', null, match[4]))
    }

    lastIndex = match.index + match[0].length
  }

  // Add remaining plain text
  if (lastIndex < text.length) {
    parts.push(text.slice(lastIndex))
  }

  return parts
}

/**
 * Formats an ISO timestamp to a human-readable time string.
 */
export const formatTimestamp = (iso: string): string => {
  const date = new Date(iso)
  return date.toLocaleTimeString(undefined, {
    hour: '2-digit',
    minute: '2-digit',
  })
}

