import type { Thread, Reply, CreateThreadInput, CreateReplyInput, VoteInput, SortMode, ThreadListItem } from './types'

const DATA_PATH = `${import.meta.dir}/data/threads.json`

const readThreads = async (): Promise<Thread[]> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) return []
  return file.json()
}

const writeThreads = async (threads: Thread[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(threads, null, 2))
}

const generateId = (): string =>
  `${Date.now()}-${Math.random().toString(36).slice(2, 9)}`

const countReplies = (replies: Reply[]): number =>
  replies.reduce((sum, r) => sum + 1 + r.children.length, 0)

const getVoteScore = (votes: { value: 1 | -1 }[]): number =>
  votes.reduce((sum, v) => sum + v.value, 0)

export const getThreadList = async (
  sort: SortMode = 'newest',
  search?: string
): Promise<ThreadListItem[]> => {
  let threads = await readThreads()

  if (search) {
    const query = search.toLowerCase()
    threads = threads.filter((t) => t.title.toLowerCase().includes(query))
  }

  const items: ThreadListItem[] = threads.map((t) => ({
    id: t.id,
    title: t.title,
    author: t.author,
    replyCount: countReplies(t.replies),
    voteScore: getVoteScore(t.votes),
    createdAt: t.createdAt,
    lastActivityAt: t.lastActivityAt,
  }))

  switch (sort) {
    case 'newest':
      items.sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime())
      break
    case 'top':
      items.sort((a, b) => b.voteScore - a.voteScore)
      break
    case 'active':
      items.sort(
        (a, b) =>
          new Date(b.lastActivityAt).getTime() - new Date(a.lastActivityAt).getTime()
      )
      break
  }

  return items
}

export const getThread = async (id: string): Promise<Thread | null> => {
  const threads = await readThreads()
  return threads.find((t) => t.id === id) ?? null
}

export const createThread = async (input: CreateThreadInput): Promise<Thread> => {
  const threads = await readThreads()
  const now = new Date().toISOString()
  const thread: Thread = {
    id: generateId(),
    title: input.title,
    body: input.body,
    author: input.author,
    votes: [],
    replies: [],
    createdAt: now,
    lastActivityAt: now,
  }
  threads.push(thread)
  await writeThreads(threads)
  return thread
}

export const createReply = async (input: CreateReplyInput): Promise<Reply | null> => {
  const threads = await readThreads()
  const thread = threads.find((t) => t.id === input.threadId)
  if (!thread) return null

  const now = new Date().toISOString()
  const reply: Reply = {
    id: generateId(),
    threadId: input.threadId,
    parentReplyId: input.parentReplyId,
    author: input.author,
    body: input.body,
    votes: [],
    children: [],
    createdAt: now,
  }

  if (input.parentReplyId) {
    const parentReply = thread.replies.find((r) => r.id === input.parentReplyId)
    if (!parentReply) return null
    parentReply.children.push(reply)
  } else {
    thread.replies.push(reply)
  }

  thread.lastActivityAt = now
  await writeThreads(threads)
  return reply
}

export const vote = async (input: VoteInput): Promise<boolean> => {
  const threads = await readThreads()
  const thread = threads.find((t) => t.id === input.threadId)
  if (!thread) return false

  let votes: { userId: string; value: 1 | -1 }[]

  if (input.replyId) {
    const findReply = (replies: Reply[]): Reply | undefined => {
      for (const r of replies) {
        if (r.id === input.replyId) return r
        const found = findReply(r.children)
        if (found) return found
      }
      return undefined
    }
    const reply = findReply(thread.replies)
    if (!reply) return false
    votes = reply.votes
  } else {
    votes = thread.votes
  }

  const existing = votes.findIndex((v) => v.userId === input.userId)
  if (existing >= 0) {
    if (votes[existing].value === input.value) {
      votes.splice(existing, 1)
    } else {
      votes[existing].value = input.value
    }
  } else {
    votes.push({ userId: input.userId, value: input.value })
  }

  await writeThreads(threads)
  return true
}

