import type { SortMode } from './types'
import { getThreadList, getThread, createThread, createReply, vote } from './data'
import { renderThreadList, renderThread, renderNewThreadForm, wrapHtml } from './render'

const parseFormBody = async (req: Request): Promise<Record<string, string>> => {
  const text = await req.text()
  const params = new URLSearchParams(text)
  const result: Record<string, string> = {}
  for (const [key, value] of params.entries()) {
    result[key] = value
  }
  return result
}

const htmlResponse = (html: string, status = 200): Response =>
  new Response(html, {
    status,
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })

const redirect = (location: string): Response =>
  new Response(null, { status: 303, headers: { Location: location } })

export const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url)
  const { pathname } = url

  // GET / — Thread list
  if (req.method === 'GET' && pathname === '/') {
    const sort = (url.searchParams.get('sort') as SortMode) || 'newest'
    const search = url.searchParams.get('search') || ''
    const threads = await getThreadList(sort, search || undefined)
    const body = renderThreadList(threads, sort, search)
    return htmlResponse(wrapHtml(body))
  }

  // GET /new — New thread form
  if (req.method === 'GET' && pathname === '/new') {
    const body = renderNewThreadForm()
    return htmlResponse(wrapHtml(body, 'New Thread'))
  }

  // POST /new — Create thread
  if (req.method === 'POST' && pathname === '/new') {
    const form = await parseFormBody(req)
    if (!form.title || !form.body || !form.author) {
      return htmlResponse(wrapHtml('<p>All fields are required.</p>'), 400)
    }
    const thread = await createThread({
      title: form.title,
      body: form.body,
      author: form.author,
    })
    return redirect(`/thread/${thread.id}`)
  }

  // GET /thread/:id — View thread
  const threadMatch = pathname.match(/^\/thread\/([^/]+)$/)
  if (req.method === 'GET' && threadMatch) {
    const thread = await getThread(threadMatch[1])
    if (!thread) {
      return htmlResponse(wrapHtml('<p>Thread not found.</p>'), 404)
    }
    const body = renderThread(thread)
    return htmlResponse(wrapHtml(body, thread.title))
  }

  // POST /thread/:id/reply — Add reply
  const replyMatch = pathname.match(/^\/thread\/([^/]+)\/reply$/)
  if (req.method === 'POST' && replyMatch) {
    const form = await parseFormBody(req)
    if (!form.author || !form.body) {
      return redirect(`/thread/${replyMatch[1]}`)
    }
    await createReply({
      threadId: replyMatch[1],
      parentReplyId: form.parentReplyId || null,
      author: form.author,
      body: form.body,
    })
    return redirect(`/thread/${replyMatch[1]}`)
  }

  // POST /thread/:id/vote — Vote on thread or reply
  const voteMatch = pathname.match(/^\/thread\/([^/]+)\/vote$/)
  if (req.method === 'POST' && voteMatch) {
    const form = await parseFormBody(req)
    const value = parseInt(form.value, 10) as 1 | -1
    if (value !== 1 && value !== -1) {
      return redirect(`/thread/${voteMatch[1]}`)
    }
    await vote({
      threadId: voteMatch[1],
      replyId: form.replyId || null,
      userId: form.userId || 'anonymous',
      value,
    })
    return redirect(`/thread/${voteMatch[1]}`)
  }

  return htmlResponse(wrapHtml('<p>Not found.</p>'), 404)
}

