import type { ForumData, Thread, Reply, Vote, SortMode } from './types'

const DATA_PATH = `${import.meta.dir}/data/forum.json`

const loadData = async (): Promise<ForumData> => {
  const file = Bun.file(DATA_PATH)
  const text = await file.text()
  return JSON.parse(text) as ForumData
}

const saveData = async (data: ForumData): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(data, null, 2))
}

const generateId = (): string =>
  `${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 8)}`

const getVoteScore = (votes: Vote[]): number =>
  votes.reduce((sum, v) => sum + (v.direction === 'up' ? 1 : -1), 0)

const getLatestActivity = (thread: Thread): string => {
  if (thread.replies.length === 0) return thread.createdAt
  return thread.replies.reduce((latest, r) =>
    r.createdAt > latest ? r.createdAt : latest
  , thread.createdAt)
}

export const createThread = async (title: string, body: string, author: string): Promise<Thread> => {
  const data = await loadData()
  const thread: Thread = {
    id: generateId(),
    title,
    body,
    author,
    createdAt: new Date().toISOString(),
    votes: [],
    replies: [],
  }
  data.threads.push(thread)
  await saveData(data)
  return thread
}

export const getThread = async (threadId: string): Promise<Thread | null> => {
  const data = await loadData()
  return data.threads.find(t => t.id === threadId) ?? null
}

export const listThreads = async (sort: SortMode = 'newest', query?: string): Promise<Thread[]> => {
  const data = await loadData()
  let threads = data.threads

  if (query) {
    const q = query.toLowerCase()
    threads = threads.filter(t => t.title.toLowerCase().includes(q))
  }

  const sorted = [...threads]
  switch (sort) {
    case 'newest':
      sorted.sort((a, b) => b.createdAt.localeCompare(a.createdAt))
      break
    case 'top':
      sorted.sort((a, b) => getVoteScore(b.votes) - getVoteScore(a.votes))
      break
    case 'active':
      sorted.sort((a, b) => getLatestActivity(b).localeCompare(getLatestActivity(a)))
      break
  }

  return sorted
}

export const addReply = async (
  threadId: string,
  body: string,
  author: string,
  parentReplyId?: string
): Promise<Reply | null> => {
  const data = await loadData()
  const thread = data.threads.find(t => t.id === threadId)
  if (!thread) return null

  if (parentReplyId) {
    const parentExists = thread.replies.some(r => r.id === parentReplyId && r.parentReplyId === null)
    if (!parentExists) return null
  }

  const reply: Reply = {
    id: generateId(),
    threadId,
    parentReplyId: parentReplyId ?? null,
    body,
    author,
    createdAt: new Date().toISOString(),
    votes: [],
  }
  thread.replies.push(reply)
  await saveData(data)
  return reply
}

export const voteOnThread = async (
  threadId: string,
  userId: string,
  direction: 'up' | 'down'
): Promise<Thread | null> => {
  const data = await loadData()
  const thread = data.threads.find(t => t.id === threadId)
  if (!thread) return null

  const existingIdx = thread.votes.findIndex(v => v.userId === userId)
  if (existingIdx >= 0) {
    if (thread.votes[existingIdx].direction === direction) {
      thread.votes.splice(existingIdx, 1)
    } else {
      thread.votes[existingIdx].direction = direction
    }
  } else {
    thread.votes.push({ userId, direction })
  }

  await saveData(data)
  return thread
}

export const voteOnReply = async (
  threadId: string,
  replyId: string,
  userId: string,
  direction: 'up' | 'down'
): Promise<Reply | null> => {
  const data = await loadData()
  const thread = data.threads.find(t => t.id === threadId)
  if (!thread) return null

  const reply = thread.replies.find(r => r.id === replyId)
  if (!reply) return null

  const existingIdx = reply.votes.findIndex(v => v.userId === userId)
  if (existingIdx >= 0) {
    if (reply.votes[existingIdx].direction === direction) {
      reply.votes.splice(existingIdx, 1)
    } else {
      reply.votes[existingIdx].direction = direction
    }
  } else {
    reply.votes.push({ userId, direction })
  }

  await saveData(data)
  return reply
}

