export const renderThreadDetail = (thread: Thread): string => {
  const topLevelReplies = thread.replies.filter(r => r.parentReplyId === null)
  const nestedReplies = (parentId: string) =>
    thread.replies.filter(r => r.parentReplyId === parentId)

  const replyElements = topLevelReplies.map(reply => {
    const children = nestedReplies(reply.id)
    return h(Fragment, {},
      renderReplyItem(reply, false),
      ...children.map(child => renderReplyItem(child, true)),
    )
  })

  return h('div', { style: styles.page },
    h('a', { href: '/', style: styles.backLink }, '\u2190 Back to threads'),
    h('div', { style: styles.header },
      h('h1', { style: { ...styles.title, fontSize: '24px' } }, thread.title),
