import type { SortMode } from './types'
import {
  createThread,
  getThread,
  listThreads,
  addReply,
  voteOnThread,
  voteOnReply,
} from './store'
import {
  renderThreadList,
  renderNewThreadForm,
  renderThreadDetail,
} from './render'

const html = (body: string): Response =>
  new Response(
    `<!DOCTYPE html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Discussion Forum</title></head><body>${body}</body></html>`,
    { headers: { 'Content-Type': 'text/html; charset=utf-8' } }
  )

const json = (data: unknown, status = 200): Response =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

const redirect = (path: string): Response =>
  new Response(null, { status: 302, headers: { Location: path } })

const parseForm = async (req: Request): Promise<Record<string, string>> => {
  const text = await req.text()
  const params = new URLSearchParams(text)
  const result: Record<string, string> = {}
  params.forEach((value, key) => {
    result[key] = value
  })
  return result
}

export const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url)
  const path = url.pathname
  const method = req.method

  // GET / — thread list page
  if (path === '/' && method === 'GET') {
    const sort = (url.searchParams.get('sort') as SortMode) || 'newest'
    const query = url.searchParams.get('q') || ''
    const threads = await listThreads(sort, query || undefined)
    return html(renderThreadList(threads, sort, query))
  }

  // GET /threads/new — new thread form
  if (path === '/threads/new' && method === 'GET') {
    return html(renderNewThreadForm())
  }

  // POST /threads — create thread (form or JSON)
  if (path === '/threads' && method === 'POST') {
    const contentType = req.headers.get('content-type') || ''

    if (contentType.includes('application/json')) {
      const body = await req.json() as { title: string; body: string; author: string }
      if (!body.title || !body.body || !body.author) {
        return json({ error: 'title, body, and author are required' }, 400)
      }
      const thread = await createThread(body.title, body.body, body.author)
      return json(thread, 201)
    }

    const form = await parseForm(req)
    if (!form.title || !form.body || !form.author) {
      return json({ error: 'title, body, and author are required' }, 400)
    }
    await createThread(form.title, form.body, form.author)
    return redirect('/')
  }

  // Thread detail & reply routes
  const threadMatch = path.match(/^\/threads\/([^/]+)$/)
  if (threadMatch) {
    const threadId = threadMatch[1]

    // GET /threads/:id — thread detail page
    if (method === 'GET') {
      const thread = await getThread(threadId)
      if (!thread) return json({ error: 'Thread not found' }, 404)
      return html(renderThreadDetail(thread))
    }
  }

  // POST /threads/:id/replies — add reply
  const replyMatch = path.match(/^\/threads\/([^/]+)\/replies$/)
  if (replyMatch && method === 'POST') {
    const threadId = replyMatch[1]
    const contentType = req.headers.get('content-type') || ''

    if (contentType.includes('application/json')) {
      const body = await req.json() as { body: string; author: string; parentReplyId?: string }
      if (!body.body || !body.author) {
        return json({ error: 'body and author are required' }, 400)
      }
      const reply = await addReply(threadId, body.body, body.author, body.parentReplyId)
      if (!reply) return json({ error: 'Thread or parent reply not found' }, 404)
      return json(reply, 201)
    }

    const form = await parseForm(req)
    if (!form.body || !form.author) {
      return json({ error: 'body and author are required' }, 400)
    }
    const parentReplyId = form.parentReplyId || undefined
    const reply = await addReply(threadId, form.body, form.author, parentReplyId)
    if (!reply) return json({ error: 'Thread not found' }, 404)
    return redirect(`/threads/${threadId}`)
  }

  // POST /threads/:id/vote — vote on thread
  const threadVoteMatch = path.match(/^\/threads\/([^/]+)\/vote$/)
  if (threadVoteMatch && method === 'POST') {
    const threadId = threadVoteMatch[1]
    const body = await req.json() as { userId: string; direction: 'up' | 'down' }
    if (!body.userId || !['up', 'down'].includes(body.direction)) {
      return json({ error: 'userId and direction (up/down) are required' }, 400)
    }
    const thread = await voteOnThread(threadId, body.userId, body.direction)
    if (!thread) return json({ error: 'Thread not found' }, 404)
    return json(thread)
  }

  // POST /threads/:id/replies/:replyId/vote — vote on reply
  const replyVoteMatch = path.match(/^\/threads\/([^/]+)\/replies\/([^/]+)\/vote$/)
  if (replyVoteMatch && method === 'POST') {
    const [, threadId, replyId] = replyVoteMatch
    const body = await req.json() as { userId: string; direction: 'up' | 'down' }
    if (!body.userId || !['up', 'down'].includes(body.direction)) {
      return json({ error: 'userId and direction (up/down) are required' }, 400)
    }
    const reply = await voteOnReply(threadId, replyId, body.userId, body.direction)
    if (!reply) return json({ error: 'Thread or reply not found' }, 404)
    return json(reply)
  }

  // API: GET /threads — list threads as JSON
  if (path === '/threads' && method === 'GET') {
    const sort = (url.searchParams.get('sort') as SortMode) || 'newest'
    const query = url.searchParams.get('q') || undefined
    const threads = await listThreads(sort, query)
    return json(threads)
  }

  return json({ error: 'Not found' }, 404)
}

