export type Reply = {
  id: string
  threadId: string
  parentReplyId: string | null
  body: string
  author: string
  votes: number
  createdAt: string
}

export type Thread = {
  id: string
  title: string
  body: string
  author: string
  votes: number
  replies: Reply[]
  createdAt: string
  lastActivityAt: string
}

export type SortMode = 'newest' | 'top' | 'active'

export type VoteDirection = 'up' | 'down'

export type CreateThreadInput = {
  title: string
  body: string
  author: string
}

export type CreateReplyInput = {
  body: string
  author: string
  parentReplyId?: string
}

export type VoteInput = {
  direction: VoteDirection
}

export type ThreadListParams = {
  sort?: SortMode
  q?: string
}

import type { Thread, Reply, CreateThreadInput, CreateReplyInput, VoteDirection, SortMode } from './types'

const DATA_PATH = `${import.meta.dir}/data/threads.json`

const generateId = (): string => crypto.randomUUID()

const now = (): string => new Date().toISOString()

export const loadThreads = async (): Promise<Thread[]> => {
  const file = Bun.file(DATA_PATH)
  const exists = await file.exists()
  if (!exists) return []
  const text = await file.text()
  return JSON.parse(text) as Thread[]
}

const saveThreads = async (threads: Thread[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(threads, null, 2))
}

export const getThreads = async (sort: SortMode = 'newest', query?: string): Promise<Thread[]> => {
  let threads = await loadThreads()

  if (query) {
    const lower = query.toLowerCase()
    threads = threads.filter((t) => t.title.toLowerCase().includes(lower))
  }

  const sorted = [...threads]
  switch (sort) {
    case 'newest':
      sorted.sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime())
      break
    case 'top':
      sorted.sort((a, b) => b.votes - a.votes)
      break
    case 'active':
      sorted.sort((a, b) => new Date(b.lastActivityAt).getTime() - new Date(a.lastActivityAt).getTime())
      break
  }

  return sorted
}

export const getThread = async (id: string): Promise<Thread | undefined> => {
  const threads = await loadThreads()
  return threads.find((t) => t.id === id)
}

export const createThread = async (input: CreateThreadInput): Promise<Thread> => {
  const threads = await loadThreads()
  const timestamp = now()
  const thread: Thread = {
    id: generateId(),
    title: input.title,
    body: input.body,
    author: input.author,
    votes: 0,
    replies: [],
    createdAt: timestamp,
    lastActivityAt: timestamp,
  }
  threads.push(thread)
  await saveThreads(threads)
  return thread
}

export const createReply = async (threadId: string, input: CreateReplyInput): Promise<Reply | null> => {
  const threads = await loadThreads()
  const thread = threads.find((t) => t.id === threadId)
  if (!thread) return null

  if (input.parentReplyId) {
    const parent = thread.replies.find((r) => r.id === input.parentReplyId)
    if (!parent || parent.parentReplyId !== null) return null
  }

  const reply: Reply = {
    id: generateId(),
    threadId,
    parentReplyId: input.parentReplyId ?? null,
    body: input.body,
    author: input.author,
    votes: 0,
    createdAt: now(),
  }

  thread.replies.push(reply)
  thread.lastActivityAt = reply.createdAt
  await saveThreads(threads)
  return reply
}

export const voteThread = async (threadId: string, direction: VoteDirection): Promise<Thread | null> => {
  const threads = await loadThreads()
  const thread = threads.find((t) => t.id === threadId)
  if (!thread) return null

  thread.votes += direction === 'up' ? 1 : -1
  await saveThreads(threads)
  return thread
}

export const voteReply = async (replyId: string, direction: VoteDirection): Promise<Reply | null> => {
  const threads = await loadThreads()
  for (const thread of threads) {
    const reply = thread.replies.find((r) => r.id === replyId)
    if (reply) {
      reply.votes += direction === 'up' ? 1 : -1
      await saveThreads(threads)
      return reply
    }
  }
  return null
}

