import { getThreads, getThread, createThread, createReply, voteThread, voteReply } from './data'
import { renderThreadList, renderNewThreadForm, renderThread } from './render'
import type { SortMode, VoteDirection } from './types'

const html = (body: string, status = 200) =>
  new Response(body, { status, headers: { 'Content-Type': 'text/html; charset=utf-8' } })

const redirect = (url: string) =>
  new Response(null, { status: 303, headers: { Location: url } })

const json = (data: unknown, status = 200) =>
  new Response(JSON.stringify(data), { status, headers: { 'Content-Type': 'application/json' } })

const parseFormBody = async (req: Request): Promise<Record<string, string>> => {
  const text = await req.text()
  const params = new URLSearchParams(text)
  const result: Record<string, string> = {}
  for (const [key, value] of params.entries()) {
    result[key] = value
  }
  return result
}

export const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url)
  const { pathname } = url
  const method = req.method

  // GET / -> redirect to /threads
  if (pathname === '/' && method === 'GET') {
    return redirect('/threads')
  }

  // GET /threads -> list threads
  if (pathname === '/threads' && method === 'GET') {
    const sort = (url.searchParams.get('sort') as SortMode) || 'newest'
    const query = url.searchParams.get('q') || ''
    const threads = await getThreads(sort, query || undefined)
    return html(renderThreadList(threads, sort, query))
  }

  // GET /threads/new -> new thread form
  if (pathname === '/threads/new' && method === 'GET') {
    return html(renderNewThreadForm())
  }

  // POST /threads -> create thread
  if (pathname === '/threads' && method === 'POST') {
    const contentType = req.headers.get('content-type') || ''
    if (contentType.includes('application/json')) {
      const body = await req.json() as { title: string; body: string; author: string }
      if (!body.title || !body.body || !body.author) {
        return json({ error: 'title, body, and author are required' }, 400)
      }
      const thread = await createThread(body)
      return json(thread, 201)
    }
    const form = await parseFormBody(req)
    if (!form.title || !form.body || !form.author) {
      return html('<p>All fields are required.</p>', 400)
    }
    const thread = await createThread({ title: form.title, body: form.body, author: form.author })
    return redirect(`/threads/${thread.id}`)
  }

  // GET /threads/:id -> view thread
  const threadMatch = pathname.match(/^\/threads\/([^/]+)$/)
  if (threadMatch && method === 'GET') {
    const thread = await getThread(threadMatch[1])
    if (!thread) return html('<p>Thread not found.</p>', 404)
    return html(renderThread(thread))
  }

  // POST /threads/:id/replies -> create reply
  const replyMatch = pathname.match(/^\/threads\/([^/]+)\/replies$/)
  if (replyMatch && method === 'POST') {
    const threadId = replyMatch[1]
    const contentType = req.headers.get('content-type') || ''
    if (contentType.includes('application/json')) {
      const body = await req.json() as { body: string; author: string; parentReplyId?: string }
      if (!body.body || !body.author) {
        return json({ error: 'body and author are required' }, 400)
      }
      const reply = await createReply(threadId, body)
      if (!reply) return json({ error: 'Thread not found or invalid parent reply' }, 404)
      return json(reply, 201)
    }
    const form = await parseFormBody(req)
    if (!form.body || !form.author) {
      return html('<p>Author and reply body are required.</p>', 400)
    }
    const reply = await createReply(threadId, {
      body: form.body,
      author: form.author,
      parentReplyId: form.parentReplyId || undefined,
    })
    if (!reply) return html('<p>Thread not found.</p>', 404)
    return redirect(`/threads/${threadId}`)
  }

  // POST /threads/:id/vote -> vote on thread
  const threadVoteMatch = pathname.match(/^\/threads\/([^/]+)\/vote$/)
  if (threadVoteMatch && method === 'POST') {
    const threadId = threadVoteMatch[1]
    const contentType = req.headers.get('content-type') || ''
    let direction: VoteDirection
    if (contentType.includes('application/json')) {
      const body = await req.json() as { direction: VoteDirection }
      direction = body.direction
    } else {
      const form = await parseFormBody(req)
      direction = form.direction as VoteDirection
    }
    if (direction !== 'up' && direction !== 'down') {
      return json({ error: 'direction must be "up" or "down"' }, 400)
    }
    const thread = await voteThread(threadId, direction)
    if (!thread) return json({ error: 'Thread not found' }, 404)
    if (contentType.includes('application/json')) return json(thread)
    const referer = req.headers.get('referer') || '/threads'
    return redirect(referer)
  }

  // POST /replies/:id/vote -> vote on reply
  const replyVoteMatch = pathname.match(/^\/replies\/([^/]+)\/vote$/)
  if (replyVoteMatch && method === 'POST') {
    const replyId = replyVoteMatch[1]
    const contentType = req.headers.get('content-type') || ''
    let direction: VoteDirection
    if (contentType.includes('application/json')) {
      const body = await req.json() as { direction: VoteDirection }
      direction = body.direction
    } else {
      const form = await parseFormBody(req)
      direction = form.direction as VoteDirection
    }
    if (direction !== 'up' && direction !== 'down') {
      return json({ error: 'direction must be "up" or "down"' }, 400)
    }
    const reply = await voteReply(replyId, direction)
    if (!reply) return json({ error: 'Reply not found' }, 404)
    if (contentType.includes('application/json')) return json(reply)
    const referer = req.headers.get('referer') || '/threads'
    return redirect(referer)
  }

  // API: GET /api/threads
  if (pathname === '/api/threads' && method === 'GET') {
    const sort = (url.searchParams.get('sort') as SortMode) || 'newest'
    const query = url.searchParams.get('q') || ''
    const threads = await getThreads(sort, query || undefined)
    return json(threads)
  }

  // API: GET /api/threads/:id
  const apiThreadMatch = pathname.match(/^\/api\/threads\/([^/]+)$/)
  if (apiThreadMatch && method === 'GET') {
    const thread = await getThread(apiThreadMatch[1])
    if (!thread) return json({ error: 'Thread not found' }, 404)
    return json(thread)
  }

  return html('<p>Not found.</p>', 404)
}

