import type { CurrentWeather, ForecastResponse, ForecastEntry, DayForecast, WeatherDashboardData } from './types'

const WEATHER_PRESETS: Record<string, { temp: number; humidity: number; wind: number; description: string; icon: string; country: string; lat: number; lon: number }> = {
  'new york': { temp: 12, humidity: 62, wind: 5.1, description: 'scattered clouds', icon: '03d', country: 'US', lat: 40.71, lon: -74.01 },
  'london': { temp: 9, humidity: 78, wind: 4.2, description: 'light rain', icon: '10d', country: 'GB', lat: 51.51, lon: -0.13 },
  'tokyo': { temp: 18, humidity: 55, wind: 3.6, description: 'clear sky', icon: '01d', country: 'JP', lat: 35.68, lon: 139.69 },
  'paris': { temp: 11, humidity: 70, wind: 3.8, description: 'overcast clouds', icon: '04d', country: 'FR', lat: 48.86, lon: 2.35 },
  'sydney': { temp: 24, humidity: 58, wind: 6.2, description: 'few clouds', icon: '02d', country: 'AU', lat: -33.87, lon: 151.21 },
}

const DEFAULT_PRESET = { temp: 15, humidity: 65, wind: 4.0, description: 'partly cloudy', icon: '02d', country: 'XX', lat: 0, lon: 0 }

const ICON_MAP: Record<string, string> = {
  '01d': '\u2600\uFE0F', '01n': '\uD83C\uDF11',
  '02d': '\u26C5', '02n': '\uD83C\uDF11',
  '03d': '\u2601\uFE0F', '03n': '\u2601\uFE0F',
  '04d': '\u2601\uFE0F', '04n': '\u2601\uFE0F',
  '09d': '\uD83C\uDF27\uFE0F', '09n': '\uD83C\uDF27\uFE0F',
  '10d': '\uD83C\uDF26\uFE0F', '10n': '\uD83C\uDF27\uFE0F',
  '11d': '\u26C8\uFE0F', '11n': '\u26C8\uFE0F',
  '13d': '\u2744\uFE0F', '13n': '\u2744\uFE0F',
  '50d': '\uD83C\uDF2B\uFE0F', '50n': '\uD83C\uDF2B\uFE0F',
}

export const getWeatherIcon = (iconCode: string): string => ICON_MAP[iconCode] ?? '\u2601\uFE0F'

const celsiusToFahrenheit = (c: number): number => Math.round((c * 9) / 5 + 32)

export const formatTemp = (celsius: number): string =>
  `${Math.round(celsius)}\u00B0C / ${celsiusToFahrenheit(celsius)}\u00B0F`

const DAY_NAMES = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat']

const generateForecastVariations = (baseTemp: number): number[] => {
  const offsets = [-2, 1, 3, -1, 2]
  return offsets.map((o) => baseTemp + o)
}

const buildCurrentWeather = (city: string, preset: typeof DEFAULT_PRESET): CurrentWeather => {
  const now = Math.floor(Date.now() / 1000)
  return {
    coord: { lon: preset.lon, lat: preset.lat },
    weather: [{ id: 802, main: 'Clouds', description: preset.description, icon: preset.icon }],
    main: {
      temp: preset.temp,
      feels_like: preset.temp - 2,
      temp_min: preset.temp - 3,
      temp_max: preset.temp + 2,
      pressure: 1013,
      humidity: preset.humidity,
    },
    wind: { speed: preset.wind, deg: 220 },
    clouds: { all: 40 },
    dt: now,
    sys: { country: preset.country, sunrise: now - 21600, sunset: now + 21600 },
    name: city.split(' ').map((w) => w.charAt(0).toUpperCase() + w.slice(1)).join(' '),
  }
}

const buildForecast = (city: string, preset: typeof DEFAULT_PRESET): ForecastResponse => {
  const now = Date.now()
  const temps = generateForecastVariations(preset.temp)
  const conditions: Array<{ desc: string; icon: string }> = [
    { desc: 'light rain', icon: '10d' },
    { desc: 'clear sky', icon: '01d' },
    { desc: 'few clouds', icon: '02d' },
    { desc: 'scattered clouds', icon: '03d' },
    { desc: 'overcast clouds', icon: '04d' },
  ]

  const list: ForecastEntry[] = temps.flatMap((baseTemp, dayIdx) => {
    const dayStart = new Date(now + (dayIdx + 1) * 86400000)
    dayStart.setHours(0, 0, 0, 0)
    const hours = [6, 9, 12, 15, 18, 21]
    return hours.map((hour) => {
      const dt = new Date(dayStart)
      dt.setHours(hour)
      const variation = hour <= 9 ? -3 : hour >= 18 ? -1 : 2
      const temp = baseTemp + variation
      const cond = conditions[dayIdx % conditions.length]
      return {
        dt: Math.floor(dt.getTime() / 1000),
        main: {
          temp,
          feels_like: temp - 1,
          temp_min: temp - 1,
          temp_max: temp + 1,
          pressure: 1013,
          humidity: preset.humidity + (dayIdx * 2 - 4),
        },
        weather: [{ id: 800, main: 'Clear', description: cond.desc, icon: cond.icon }],
        wind: { speed: preset.wind + dayIdx * 0.3, deg: 200 + dayIdx * 15 },
        dt_txt: dt.toISOString().replace('T', ' ').slice(0, 19),
      }
    })
  })

  return {
    city: {
      name: city.split(' ').map((w) => w.charAt(0).toUpperCase() + w.slice(1)).join(' '),
      country: preset.country,
    },
    list,
  }
}

const aggregateDailyForecasts = (forecast: ForecastResponse): DayForecast[] => {
  const byDay = new Map<string, ForecastEntry[]>()
  for (const entry of forecast.list) {
    const date = entry.dt_txt.slice(0, 10)
    const existing = byDay.get(date) ?? []
    existing.push(entry)
    byDay.set(date, existing)
  }

  const days: DayForecast[] = []
  for (const [date, entries] of byDay) {
    const temps = entries.map((e) => e.main.temp)
    const midday = entries.find((e) => e.dt_txt.includes('12:')) ?? entries[0]
    const d = new Date(date)
    days.push({
      date,
      dayName: DAY_NAMES[d.getDay()],
      tempHigh: Math.max(...temps),
      tempLow: Math.min(...temps),
      description: midday.weather[0].description,
      icon: midday.weather[0].icon,
    })
  }
  return days
}

export const getWeatherData = (city: string): WeatherDashboardData => {
  const key = city.toLowerCase().trim()
  const preset = WEATHER_PRESETS[key] ?? { ...DEFAULT_PRESET, lat: Math.random() * 180 - 90, lon: Math.random() * 360 - 180 }
  const current = buildCurrentWeather(city, preset)
  const forecast = buildForecast(city, preset)
  const dailyForecasts = aggregateDailyForecasts(forecast)
  return { current, forecast, dailyForecasts }
}

