const SVG_WIDTH = 600
const SVG_HEIGHT = 200
const PADDING = { top: 30, right: 40, bottom: 40, left: 50 }

const chartWidth = SVG_WIDTH - PADDING.left - PADDING.right
const chartHeight = SVG_HEIGHT - PADDING.top - PADDING.bottom

const mapPoints = (forecasts: DayForecast[], key: 'tempHigh' | 'tempLow'): ChartPoint[] => {
  const temps = forecasts.map((f) => f[key])
  const minTemp = Math.min(...temps) - 2
  const maxTemp = Math.max(...temps) + 2
  const range = maxTemp - minTemp || 1

  return forecasts.map((f, i) => ({
    x: PADDING.left + (i / Math.max(forecasts.length - 1, 1)) * chartWidth,
    y: PADDING.top + chartHeight - ((f[key] - minTemp) / range) * chartHeight,
    label: f.dayName,
    temp: f[key],
  }))
}

const polyline = (points: ChartPoint[]): string =>
  points.map((p) => `${p.x},${p.y}`).join(' ')

export const renderTempChart = (forecasts: DayForecast[]) => {
  if (forecasts.length === 0) return h('div', {}, 'No forecast data')

  const highPoints = mapPoints(forecasts, 'tempHigh')
  const lowPoints = mapPoints(forecasts, 'tempLow')

  const allTemps = [...forecasts.map((f) => f.tempHigh), ...forecasts.map((f) => f.tempLow)]
  const minTemp = Math.min(...allTemps) - 2
  const maxTemp = Math.max(...allTemps) + 2

  const gridLines = 4
  const gridElements = Array.from({ length: gridLines + 1 }, (_, i) => {
    const temp = minTemp + ((maxTemp - minTemp) * i) / gridLines
    const y = PADDING.top + chartHeight - (i / gridLines) * chartHeight
    return [
      h('line', { x1: String(PADDING.left), y1: String(y), x2: String(SVG_WIDTH - PADDING.right), y2: String(y), stroke: '#e0e0e0', 'stroke-width': '1' }),
      h('text', { x: String(PADDING.left - 8), y: String(y + 4), 'text-anchor': 'end', fill: '#888', 'font-size': '11' }, `${Math.round(temp)}\u00B0`),
    ]
  }).flat()

  const xLabels = highPoints.map((p) =>
    h('text', { x: String(p.x), y: String(SVG_HEIGHT - 8), 'text-anchor': 'middle', fill: '#888', 'font-size': '12' }, p.label)
  )

  const highDots = highPoints.map((p) =>
    h('circle', { cx: String(p.x), cy: String(p.y), r: '4', fill: '#e74c3c' })
  )

  const lowDots = lowPoints.map((p) =>
    h('circle', { cx: String(p.x), cy: String(p.y), r: '4', fill: '#3498db' })
  )

  const highLabels = highPoints.map((p) =>
    h('text', { x: String(p.x), y: String(p.y - 10), 'text-anchor': 'middle', fill: '#e74c3c', 'font-size': '10', 'font-weight': 'bold' }, `${Math.round(p.temp)}\u00B0`)
  )

  const lowLabels = lowPoints.map((p) =>
    h('text', { x: String(p.x), y: String(p.y + 18), 'text-anchor': 'middle', fill: '#3498db', 'font-size': '10', 'font-weight': 'bold' }, `${Math.round(p.temp)}\u00B0`)
  )

  const legend = h('g', { transform: `translate(${SVG_WIDTH - PADDING.right - 120}, 12)` },
    h('line', { x1: '0', y1: '0', x2: '20', y2: '0', stroke: '#e74c3c', 'stroke-width': '2' }),
    h('text', { x: '24', y: '4', fill: '#e74c3c', 'font-size': '11' }, 'High'),
    h('line', { x1: '60', y1: '0', x2: '80', y2: '0', stroke: '#3498db', 'stroke-width': '2' }),
    h('text', { x: '84', y: '4', fill: '#3498db', 'font-size': '11' }, 'Low'),
  )

  return h('svg', {
    viewBox: `0 0 ${SVG_WIDTH} ${SVG_HEIGHT}`,
    style: 'width:100%;max-width:600px;height:auto;background:#fafafa;border-radius:8px;border:1px solid #e0e0e0;',
  },
    ...gridElements,
    ...xLabels,
    h('polyline', { points: polyline(highPoints), fill: 'none', stroke: '#e74c3c', 'stroke-width': '2', 'stroke-linejoin': 'round' }),
    h('polyline', { points: polyline(lowPoints), fill: 'none', stroke: '#3498db', 'stroke-width': '2', 'stroke-linejoin': 'round' }),
    ...highDots,
    ...lowDots,
    ...highLabels,
    ...lowLabels,
    legend,
  )
}

import { createSSR } from 'plaited'
import { getWeatherData } from './weather-data'
import { renderDashboard } from './render'
import type { WeatherDashboardData } from './types'

const DATA_PATH = './data/last-search.json'

const loadLastSearch = async (): Promise<string> => {
  try {
    const file = Bun.file(DATA_PATH)
    if (await file.exists()) {
      const data = await file.json()
      return data.city ?? 'London'
    }
  } catch {
    // fall through
  }
  return 'London'
}

const saveLastSearch = async (city: string): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify({ city, timestamp: new Date().toISOString() }))
}

export const fetchWeather = (city: string): WeatherDashboardData => {
  return getWeatherData(city)
}

export const renderWeatherPage = (city: string): string => {
  const data = fetchWeather(city)
  const template = renderDashboard(data, city)
  const ssr = createSSR()
  return ssr(template)
}

const serve = () => {
  Bun.serve({
    port: 3000,
    fetch: async (req) => {
      const url = new URL(req.url)

      if (url.pathname === '/' || url.pathname === '/weather') {
        const city = url.searchParams.get('city') ?? await loadLastSearch()

        if (url.searchParams.has('city')) {
          await saveLastSearch(city)
        }

        const html = renderWeatherPage(city)
        const page = `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Weather Dashboard</title>
  <style>*{margin:0;padding:0;box-sizing:border-box;}</style>
</head>
<body>${html}</body>
</html>`
        return new Response(page, { headers: { 'Content-Type': 'text/html' } })
      }

      if (url.pathname === '/api/weather') {
        const city = url.searchParams.get('city') ?? 'London'
        const data = fetchWeather(city)
        return Response.json(data)
      }

      return new Response('Not Found', { status: 404 })
    },
  })

  console.log('Weather Dashboard running at http://localhost:3000')
}

export default serve

