const generateForecastEntries = (
  baseTemp: number,
  icon: string,
  dayOffset: number,
): ForecastResponse['list'] => {
  const baseTime = 1710600000 + dayOffset * 86400
  const hours = [6, 9, 12, 15, 18, 21, 0, 3]
  return hours.map((hour, i) => {
    const variation = (Math.sin(hour / 24 * Math.PI * 2) * 3) + (i % 3 - 1)
    const temp = baseTemp + variation
    const dt = baseTime + hour * 3600
    const date = new Date(dt * 1000)
    const pad = (n: number) => String(n).padStart(2, '0')
    return {
      dt,
      main: {
        temp: Math.round(temp * 10) / 10,
        feels_like: Math.round((temp - 1) * 10) / 10,
        temp_min: Math.round((temp - 2) * 10) / 10,
        temp_max: Math.round((temp + 2) * 10) / 10,
        pressure: 1015,
        humidity: 65,
      },
      weather: [{ id: 800, main: 'Clear', description: 'clear sky', icon }],
      wind: { speed: 3.5, deg: 200 },
      dt_txt: `${date.getUTCFullYear()}-${pad(date.getUTCMonth() + 1)}-${pad(date.getUTCDate())} ${pad(date.getUTCHours())}:00:00`,
    }
  })
}

function generateForecastList(
  baseTemp: number,
  dailyTemps: number[],
  icons: string[],
): ForecastResponse['list'] {
  return dailyTemps.flatMap((temp, i) => generateForecastEntries(temp, icons[i], i + 1))
}

export const getWeatherIcon = (iconCode: string): string =>
  WEATHER_ICONS[iconCode] ?? '🌡️'

export const celsiusToFahrenheit = (c: number): number =>
  Math.round((c * 9 / 5 + 32) * 10) / 10

export const getWindDirection = (deg: number): string => {
  const directions = ['N', 'NE', 'E', 'SE', 'S', 'SW', 'W', 'NW']
  return directions[Math.round(deg / 45) % 8]
}

export const getCurrentWeather = (city: string): CurrentWeather | null => {
  const key = city.toLowerCase().trim()
  return CITY_DATA[key]?.current ?? null
}

export const getForecast = (city: string): ForecastResponse | null => {
  const key = city.toLowerCase().trim()
  return CITY_DATA[key]?.forecast ?? null
}

export const getDailyForecasts = (forecast: ForecastResponse): DailyForecast[] => {
  const dailyMap = new Map<string, { temps: number[]; icons: string[]; descriptions: string[] }>()

  for (const entry of forecast.list) {
    const date = entry.dt_txt.split(' ')[0]
    const existing = dailyMap.get(date)
    if (existing) {
      existing.temps.push(entry.main.temp)
      existing.icons.push(entry.weather[0].icon)
      existing.descriptions.push(entry.weather[0].description)
    } else {
      dailyMap.set(date, {
        temps: [entry.main.temp],
        icons: [entry.weather[0].icon],
        descriptions: [entry.weather[0].description],
      })
    }
  }

  const dailies: DailyForecast[] = []
  for (const [date, data] of dailyMap) {
    const d = new Date(date + 'T12:00:00Z')
    const midIndex = Math.floor(data.icons.length / 2)
    dailies.push({
      date,
      dayName: DAY_NAMES[d.getUTCDay()],
      tempMin: Math.round(Math.min(...data.temps) * 10) / 10,
      tempMax: Math.round(Math.max(...data.temps) * 10) / 10,
      icon: data.icons[midIndex],
      description: data.descriptions[midIndex],
    })
  }

  return dailies.slice(0, 5)
}

export const getTemperaturePoints = (forecast: ForecastResponse): TemperaturePoint[] => {
  const dailies = getDailyForecasts(forecast)
  return dailies.map((d) => ({
    label: d.dayName,
    tempC: Math.round(((d.tempMin + d.tempMax) / 2) * 10) / 10,
  }))
}

