const renderCurrentWeather = (current: CurrentWeather) => {
  const weather = current.weather[0]
  const icon = getWeatherIcon(weather.icon)
  const tempC = Math.round(current.main.temp * 10) / 10
  const tempF = celsiusToFahrenheit(current.main.temp)
  const feelsLikeC = Math.round(current.main.feels_like * 10) / 10
  const feelsLikeF = celsiusToFahrenheit(current.main.feels_like)
  const windDir = getWindDirection(current.wind.deg)

  return h('div', { style: styles.currentCard },
    h('p', { style: styles.cityName }, current.name),
    h('p', { style: styles.country }, current.sys.country),
    h('div', { style: styles.currentMain },
      h('span', { style: styles.iconLarge }, icon),
      h('div', {},
        h('p', { style: styles.tempLarge }, `${tempC}°C`),
        h('p', { style: styles.tempAlt }, `${tempF}°F`),
      ),
      h('div', {},
        h('p', { style: styles.description }, weather.description),
        h('p', { style: { ...styles.tempAlt, marginTop: '8px' } }, `Feels like ${feelsLikeC}°C / ${feelsLikeF}°F`),
      ),
    ),
    h('div', { style: styles.detailsGrid },
      h('div', { style: styles.detailItem },
        h('p', { style: styles.detailLabel }, 'Humidity'),
        h('p', { style: styles.detailValue }, `${current.main.humidity}%`),
      ),
      h('div', { style: styles.detailItem },
        h('p', { style: styles.detailLabel }, 'Wind'),
        h('p', { style: styles.detailValue }, `${current.wind.speed} m/s ${windDir}`),
      ),
      h('div', { style: styles.detailItem },
        h('p', { style: styles.detailLabel }, 'Pressure'),
        h('p', { style: styles.detailValue }, `${current.main.pressure} hPa`),
      ),
      h('div', { style: styles.detailItem },
        h('p', { style: styles.detailLabel }, 'Clouds'),
        h('p', { style: styles.detailValue }, `${current.clouds.all}%`),
      ),
    ),
  )
}

const renderForecastCards = (dailies: DailyForecast[]) =>
  h('div', {},
    h('p', { style: styles.sectionTitle }, '5-Day Forecast'),
    h('div', { style: styles.forecastRow },
      ...dailies.map((day) =>
        h('div', { style: styles.forecastCard },
          h('p', { style: styles.forecastDay }, day.dayName),
          h('div', { style: styles.forecastIcon }, getWeatherIcon(day.icon)),
          h('p', { style: styles.forecastTemp }, `${Math.round(day.tempMax)}°`),
          h('p', { style: styles.forecastTempLow }, `${Math.round(day.tempMin)}°`),
        ),
      ),
    ),
  )

const renderLineChart = (points: TemperaturePoint[]) => {
  if (points.length < 2) return h('div', {})

  const width = 640
  const height = 200
  const paddingX = 50
  const paddingY = 30
  const chartW = width - paddingX * 2
  const chartH = height - paddingY * 2

  const temps = points.map((p) => p.tempC)
  const minT = Math.min(...temps) - 2
  const maxT = Math.max(...temps) + 2
  const rangeT = maxT - minT || 1

  const toX = (i: number) => paddingX + (i / (points.length - 1)) * chartW
  const toY = (t: number) => paddingY + chartH - ((t - minT) / rangeT) * chartH

  const pathD = points
    .map((p, i) => `${i === 0 ? 'M' : 'L'} ${toX(i).toFixed(1)} ${toY(p.tempC).toFixed(1)}`)
    .join(' ')

  const areaD = pathD +
    ` L ${toX(points.length - 1).toFixed(1)} ${(paddingY + chartH).toFixed(1)}` +
    ` L ${toX(0).toFixed(1)} ${(paddingY + chartH).toFixed(1)} Z`

  const gridLines = 5
  const gridStep = rangeT / gridLines

  return h('div', { style: styles.chartContainer },
    h('p', { style: styles.sectionTitle }, 'Temperature Trend'),
    h('svg', {
      viewBox: `0 0 ${width} ${height}`,
      width: '100%',
      height: 'auto',
      style: { display: 'block' },
    },
      // Grid lines
      ...Array.from({ length: gridLines + 1 }, (_, i) => {
        const temp = minT + i * gridStep
        const y = toY(temp)
        return h(Fragment, {},
          h('line', {
            x1: String(paddingX),
            y1: String(y.toFixed(1)),
            x2: String(width - paddingX),
            y2: String(y.toFixed(1)),
            stroke: '#334155',
            'stroke-width': '1',
          }),
          h('text', {
            x: String(paddingX - 8),
            y: String((y + 4).toFixed(1)),
            fill: '#64748b',
            'font-size': '11',
            'text-anchor': 'end',
          }, `${Math.round(temp)}°`),
        )
      }),
      // Area fill
      h('path', {
        d: areaD,
        fill: 'rgba(59, 130, 246, 0.15)',
      }),
      // Line
      h('path', {
        d: pathD,
        fill: 'none',
        stroke: '#3b82f6',
        'stroke-width': '3',
        'stroke-linecap': 'round',
        'stroke-linejoin': 'round',
      }),
      // Data points and labels
      ...points.flatMap((p, i) => [
        h('circle', {
          cx: String(toX(i).toFixed(1)),
          cy: String(toY(p.tempC).toFixed(1)),
          r: '5',
          fill: '#3b82f6',
          stroke: '#0f172a',
          'stroke-width': '2',
        }),
        h('text', {
          x: String(toX(i).toFixed(1)),
          y: String((toY(p.tempC) - 12).toFixed(1)),
          fill: '#e2e8f0',
          'font-size': '12',
          'font-weight': '600',
          'text-anchor': 'middle',
        }, `${p.tempC}°C`),
        h('text', {
          x: String(toX(i).toFixed(1)),
          y: String((paddingY + chartH + 18).toFixed(1)),
          fill: '#94a3b8',
          'font-size': '12',
          'text-anchor': 'middle',
        }, p.label),
      ]),
    ),
  )
}

export const renderDashboard = (city: string) => {
  const current = getCurrentWeather(city)
  const forecast = getForecast(city)
  const cities = getAvailableCities()

  const content = !current || !forecast
    ? h('div', {},
        h('div', { style: styles.error },
          h('p', { style: { margin: '0 0 8px 0' } }, `City "${city}" not found in demo data.`),
          h('p', { style: { margin: '0', fontSize: '14px', color: '#94a3b8' } },
            `Available cities: ${cities.join(', ')}`),
        ),
      )
    : h(Fragment, {},
        renderCurrentWeather(current),
        renderForecastCards(getDailyForecasts(forecast)),
        renderLineChart(getTemperaturePoints(forecast)),
      )

  return h('div', { style: styles.container },
    h('div', { style: styles.header },
      h('h1', { style: styles.title }, 'Weather Dashboard'),
      h('div', { style: styles.searchRow },
        h('input', {
          type: 'text',
          placeholder: 'Enter city name...',
          value: city,
          style: styles.input,
          'p-trigger': 'keyup:search',
        }),
        h('button', {
          style: styles.button,
          'p-trigger': 'click:search',
        }, 'Search'),
      ),
    ),
    content,
    h('p', { style: styles.hint }, `Demo data available: ${cities.join(', ')}`),
  )
}

