import type { CurrentWeather, ForecastResponse, DayForecast, WeatherDashboardData } from './types'

const WEATHER_PRESETS: Record<string, { tempBase: number; humidity: number; wind: number; condition: string; icon: string }> = {
  'new york': { tempBase: 12, humidity: 62, wind: 5.1, condition: 'partly cloudy', icon: '02d' },
  'london': { tempBase: 9, humidity: 78, wind: 4.2, condition: 'overcast clouds', icon: '04d' },
  'tokyo': { tempBase: 16, humidity: 55, wind: 3.8, condition: 'clear sky', icon: '01d' },
  'paris': { tempBase: 11, humidity: 71, wind: 3.5, condition: 'light rain', icon: '10d' },
  'sydney': { tempBase: 22, humidity: 65, wind: 6.2, condition: 'scattered clouds', icon: '03d' },
  'mumbai': { tempBase: 30, humidity: 72, wind: 4.8, condition: 'haze', icon: '50d' },
  'berlin': { tempBase: 8, humidity: 74, wind: 4.0, condition: 'broken clouds', icon: '04d' },
  'san francisco': { tempBase: 15, humidity: 68, wind: 5.5, condition: 'fog', icon: '50d' },
}

const DAY_NAMES = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat']

const celsiusToKelvin = (c: number): number => c + 273.15

const generateCurrentWeather = (city: string): CurrentWeather => {
  const key = city.toLowerCase()
  const preset = WEATHER_PRESETS[key] ?? {
    tempBase: 15 + Math.round((hashCode(city) % 20) - 10),
    humidity: 50 + (hashCode(city) % 40),
    wind: 2 + (hashCode(city) % 8),
    condition: 'few clouds',
    icon: '02d',
  }

  const tempK = celsiusToKelvin(preset.tempBase)

  return {
    coord: { lon: 0, lat: 0 },
    weather: [
      {
        id: 802,
        main: preset.condition.split(' ').map(w => w[0].toUpperCase() + w.slice(1)).join(' '),
        description: preset.condition,
        icon: preset.icon,
      },
    ],
    main: {
      temp: tempK,
      feels_like: tempK - 2,
      temp_min: tempK - 3,
      temp_max: tempK + 3,
      pressure: 1013,
      humidity: preset.humidity,
    },
    wind: { speed: preset.wind, deg: 220 },
    clouds: { all: 40 },
    dt: Math.floor(Date.now() / 1000),
    sys: { country: 'XX', sunrise: 1700000000, sunset: 1700040000 },
    name: capitalize(city),
  }
}

const generateForecastEntries = (city: string): ForecastResponse => {
  const key = city.toLowerCase()
  const preset = WEATHER_PRESETS[key] ?? {
    tempBase: 15 + Math.round((hashCode(city) % 20) - 10),
    humidity: 50 + (hashCode(city) % 40),
    wind: 2 + (hashCode(city) % 8),
    condition: 'few clouds',
    icon: '02d',
  }

  const list: ForecastResponse['list'] = []
  const now = new Date()

  for (let day = 0; day < 5; day++) {
    for (let hour = 0; hour < 24; hour += 3) {
      const date = new Date(now)
      date.setDate(date.getDate() + day + 1)
      date.setHours(hour, 0, 0, 0)

      const variation = Math.sin((hour / 24) * Math.PI * 2) * 5
      const dayVariation = (day - 2) * 1.5
      const tempC = preset.tempBase + variation + dayVariation
      const tempK = celsiusToKelvin(tempC)

      list.push({
        dt: Math.floor(date.getTime() / 1000),
        main: {
          temp: tempK,
          feels_like: tempK - 1,
          temp_min: tempK - 2,
          temp_max: tempK + 2,
          pressure: 1013,
          humidity: preset.humidity + (day * 2),
        },
        weather: [
          {
            id: 802,
            main: preset.condition.split(' ').map(w => w[0].toUpperCase() + w.slice(1)).join(' '),
            description: preset.condition,
            icon: preset.icon,
          },
        ],
        wind: { speed: preset.wind + day * 0.3, deg: 220 },
        dt_txt: date.toISOString().replace('T', ' ').slice(0, 19),
      })
    }
  }

  return {
    list,
    city: { name: capitalize(city), country: 'XX' },
  }
}

const aggregateForecast = (response: ForecastResponse): DayForecast[] => {
  const dayMap = new Map<string, { temps: number[]; entry: ForecastResponse['list'][0] }>()

  for (const entry of response.list) {
    const date = new Date(entry.dt * 1000)
    const dateKey = date.toISOString().slice(0, 10)

    const existing = dayMap.get(dateKey)
    if (existing) {
      existing.temps.push(entry.main.temp)
    } else {
      dayMap.set(dateKey, { temps: [entry.main.temp], entry })
    }
  }

  const forecasts: DayForecast[] = []
  for (const [dateKey, { temps, entry }] of dayMap) {
    const date = new Date(dateKey)
    forecasts.push({
      date: dateKey,
      dayName: DAY_NAMES[date.getDay()],
      high: Math.max(...temps),
      low: Math.min(...temps),
      description: entry.weather[0].description,
      icon: entry.weather[0].icon,
    })
  }

  return forecasts.slice(0, 5)
}

const hashCode = (str: string): number => {
  let hash = 0
  for (let i = 0; i < str.length; i++) {
    hash = ((hash << 5) - hash + str.charCodeAt(i)) | 0
  }
  return Math.abs(hash)
}

const capitalize = (str: string): string =>
  str.split(' ').map(w => w.charAt(0).toUpperCase() + w.slice(1).toLowerCase()).join(' ')

export const kelvinToCelsius = (k: number): number => Math.round((k - 273.15) * 10) / 10

export const celsiusToFahrenheit = (c: number): number => Math.round((c * 9) / 5 + 32)

export const getWeatherData = async (city: string): Promise<WeatherDashboardData> => {
  const current = generateCurrentWeather(city)
  const forecastRaw = generateForecastEntries(city)
  const forecast = aggregateForecast(forecastRaw)

  const dataPath = `data/${city.toLowerCase().replace(/\s+/g, '-')}.json`
  const payload = { current, forecast, city: capitalize(city), fetchedAt: new Date().toISOString() }

  await Bun.write(dataPath, JSON.stringify(payload, null, 2))

  return { current, forecast, city: capitalize(city) }
}

export const getWeatherIcon = (code: string): string => {
  const iconMap: Record<string, string> = {
    '01d': '\u2600\uFE0F', '01n': '\uD83C\uDF19',
    '02d': '\u26C5', '02n': '\uD83C\uDF19',
    '03d': '\u2601\uFE0F', '03n': '\u2601\uFE0F',
    '04d': '\uD83C\uDF25\uFE0F', '04n': '\uD83C\uDF25\uFE0F',
    '09d': '\uD83C\uDF27\uFE0F', '09n': '\uD83C\uDF27\uFE0F',
    '10d': '\uD83C\uDF26\uFE0F', '10n': '\uD83C\uDF26\uFE0F',
    '11d': '\u26C8\uFE0F', '11n': '\u26C8\uFE0F',
    '13d': '\u2744\uFE0F', '13n': '\u2744\uFE0F',
    '50d': '\uD83C\uDF2B\uFE0F', '50n': '\uD83C\uDF2B\uFE0F',
  }
  return iconMap[code] ?? '\u2601\uFE0F'
}

import { h } from 'plaited'
import type { DayForecast } from './types'
import { kelvinToCelsius } from './weather'

type ChartPoint = { x: number; y: number; label: string; value: number }

const SVG_WIDTH = 600
const SVG_HEIGHT = 200
const PADDING = { top: 30, right: 40, bottom: 40, left: 50 }

const plotWidth = SVG_WIDTH - PADDING.left - PADDING.right
const plotHeight = SVG_HEIGHT - PADDING.top - PADDING.bottom

const buildPoints = (
  values: number[],
  labels: string[],
): ChartPoint[] => {
  const min = Math.min(...values)
  const max = Math.max(...values)
  const range = max - min || 1

  return values.map((val, i) => ({
    x: PADDING.left + (i / (values.length - 1)) * plotWidth,
    y: PADDING.top + plotHeight - ((val - min) / range) * plotHeight,
    label: labels[i],
    value: val,
  }))
}

const polyline = (points: ChartPoint[]): string =>
  points.map(p => `${p.x},${p.y}`).join(' ')

export const renderTemperatureChart = (forecast: DayForecast[]) => {
  const highs = forecast.map(d => kelvinToCelsius(d.high))
  const lows = forecast.map(d => kelvinToCelsius(d.low))
  const labels = forecast.map(d => d.dayName)

  const allTemps = [...highs, ...lows]
  const minTemp = Math.floor(Math.min(...allTemps)) - 2
  const maxTemp = Math.ceil(Math.max(...allTemps)) + 2

  const highPoints = buildPoints(highs, labels)
  const lowPoints = buildPoints(lows, labels)

  // Recalculate Y with shared scale
  const tempRange = maxTemp - minTemp || 1
  const scaleY = (temp: number) =>
    PADDING.top + plotHeight - ((temp - minTemp) / tempRange) * plotHeight

  const scaledHighPoints = highs.map((t, i) => ({
    x: PADDING.left + (i / (highs.length - 1)) * plotWidth,
    y: scaleY(t),
    label: labels[i],
    value: t,
  }))

  const scaledLowPoints = lows.map((t, i) => ({
    x: PADDING.left + (i / (lows.length - 1)) * plotWidth,
    y: scaleY(t),
    label: labels[i],
    value: t,
  }))

  const yTicks = 5
  const yLabels = Array.from({ length: yTicks }, (_, i) => {
    const temp = minTemp + (i / (yTicks - 1)) * tempRange
    return { temp: Math.round(temp), y: scaleY(temp) }
  })

  return h('div', { style: 'width:100%;max-width:640px;margin:24px auto' },
    h('h3', { style: 'margin:0 0 8px;font-size:16px;color:#334155' }, 'Temperature Trend'),
    h('svg', {
      viewBox: `0 0 ${SVG_WIDTH} ${SVG_HEIGHT}`,
      style: 'width:100%;height:auto;background:#f8fafc;border-radius:8px;border:1px solid #e2e8f0',
    },
      // Grid lines + Y labels
      ...yLabels.map(({ temp, y }) =>
        h('g', {},
          h('line', {
            x1: String(PADDING.left), y1: String(y),
            x2: String(SVG_WIDTH - PADDING.right), y2: String(y),
            stroke: '#e2e8f0', 'stroke-width': '1',
          }),
          h('text', {
            x: String(PADDING.left - 8), y: String(y + 4),
            'text-anchor': 'end', 'font-size': '11', fill: '#94a3b8',
          }, `${temp}\u00B0`),
        ),
      ),
      // X labels
      ...scaledHighPoints.map((p) =>
        h('text', {
          x: String(p.x), y: String(SVG_HEIGHT - 10),
          'text-anchor': 'middle', 'font-size': '11', fill: '#94a3b8',
        }, p.label),
      ),
      // High line
      h('polyline', {
        points: polyline(scaledHighPoints),
        fill: 'none', stroke: '#ef4444', 'stroke-width': '2.5', 'stroke-linejoin': 'round',
      }),
      // Low line
      h('polyline', {
        points: polyline(scaledLowPoints),
        fill: 'none', stroke: '#3b82f6', 'stroke-width': '2.5', 'stroke-linejoin': 'round',
      }),
      // High dots + values
      ...scaledHighPoints.map((p) =>
        h('g', {},
          h('circle', { cx: String(p.x), cy: String(p.y), r: '4', fill: '#ef4444' }),
          h('text', {
            x: String(p.x), y: String(p.y - 10),
            'text-anchor': 'middle', 'font-size': '10', fill: '#ef4444', 'font-weight': '600',
          }, `${p.value}\u00B0`),
        ),
      ),
      // Low dots + values
      ...scaledLowPoints.map((p) =>
        h('g', {},
          h('circle', { cx: String(p.x), cy: String(p.y), r: '4', fill: '#3b82f6' }),
          h('text', {
            x: String(p.x), y: String(p.y + 16),
            'text-anchor': 'middle', 'font-size': '10', fill: '#3b82f6', 'font-weight': '600',
          }, `${p.value}\u00B0`),
        ),
      ),
      // Legend
      h('circle', { cx: String(SVG_WIDTH - PADDING.right - 80), cy: '14', r: '4', fill: '#ef4444' }),
      h('text', {
        x: String(SVG_WIDTH - PADDING.right - 72), y: '18',
        'font-size': '11', fill: '#64748b',
      }, 'High'),
      h('circle', { cx: String(SVG_WIDTH - PADDING.right - 30), cy: '14', r: '4', fill: '#3b82f6' }),
      h('text', {
        x: String(SVG_WIDTH - PADDING.right - 22), y: '18',
        'font-size': '11', fill: '#64748b',
      }, 'Low'),
    ),
  )
}

