import { createSSR } from 'plaited'
import { getWeatherData } from './weather'
import { renderDashboard, renderError } from './render'
import type { WeatherDashboardData } from './types'

export type { WeatherDashboardData } from './types'
export { getWeatherData, kelvinToCelsius, celsiusToFahrenheit, getWeatherIcon } from './weather'
export { renderDashboard, renderError } from './render'
export { renderTemperatureChart } from './chart'

const DEFAULT_CITY = 'New York'

export const handleRequest = async (request: Request): Promise<Response> => {
  const url = new URL(request.url)
  const city = url.searchParams.get('city')?.trim() || DEFAULT_CITY

  try {
    const data = await getWeatherData(city)
    const template = renderDashboard(data, city)
    const ssr = createSSR()
    const html = ssr(template)

    const page = `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Weather Dashboard - ${data.city}</title>
  <style>
    *, *::before, *::after { box-sizing: border-box; }
    body { margin: 0; background: #f1f5f9; min-height: 100vh; }
    input:focus { border-color: #3b82f6 !important; }
    button:hover { background: #2563eb !important; }
  </style>
</head>
<body>${html}</body>
</html>`

    return new Response(page, {
      headers: { 'Content-Type': 'text/html; charset=utf-8' },
    })
  } catch (err) {
    const message = err instanceof Error ? err.message : 'Failed to fetch weather data'
    const template = renderError(message, city)
    const ssr = createSSR()
    const html = ssr(template)

    const page = `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Weather Dashboard - Error</title>
  <style>
    *, *::before, *::after { box-sizing: border-box; }
    body { margin: 0; background: #f1f5f9; min-height: 100vh; }
  </style>
</head>
<body>${html}</body>
</html>`

    return new Response(page, {
      status: 500,
      headers: { 'Content-Type': 'text/html; charset=utf-8' },
    })
  }
}

export const serve = (port = 3000) => {
  return Bun.serve({
    port,
    fetch: handleRequest,
  })
}

// Auto-start when run directly
if (import.meta.main) {
  const port = Number(Bun.env.PORT) || 3000
  serve(port)
  console.log(`Weather Dashboard running at http://localhost:${port}`)
  console.log(`Try: http://localhost:${port}?city=London`)
}

{
  "name": "@node/chart-generator",
  "version": "1.0.0",
  "description": "Generate bar, line, and pie charts from JSON data with auto field detection",
  "main": "src/index.ts",
  "modnet": {
    "contentType": "science",
    "structure": "form",
    "mechanics": ["chart"],
    "boundary": "all",
    "scale": 2
  },
  "dependencies": {
    "plaited": "latest"
  }
}

export type ChartType = 'bar' | 'line' | 'pie'

export type FieldType = 'numeric' | 'categorical'

export type FieldInfo = {
  name: string
  type: FieldType
}

export type ChartConfig = {
  type: ChartType
  title?: string
  xLabel?: string
  yLabel?: string
  categoryField: string
  valueFields: string[]
  colors?: string[]
  width?: number
  height?: number
}

export type ChartRequest = {
  data: Record<string, unknown>[]
  config: ChartConfig
}

export type DetectedFields = {
  numeric: string[]
  categorical: string[]
}

export const DEFAULT_COLORS = [
  '#4e79a7', '#f28e2b', '#e15759', '#76b7b2',
  '#59a14f', '#edc948', '#b07aa1', '#ff9da7',
  '#9c755f', '#bab0ac',
]

export const CHART_DEFAULTS = {
  width: 640,
  height: 400,
  padding: { top: 50, right: 30, bottom: 60, left: 70 },
} as const

import type { DetectedFields, FieldInfo, FieldType } from './types'

export const detectFieldType = (values: unknown[]): FieldType => {
  const validValues = values.filter((v) => v !== null && v !== undefined && v !== '')
  if (validValues.length === 0) return 'categorical'

  const numericCount = validValues.filter((v) => {
    if (typeof v === 'number') return true
    if (typeof v === 'string') {
      const parsed = Number(v)
      return !Number.isNaN(parsed) && v.trim() !== ''
    }
    return false
  }).length

  return numericCount / validValues.length >= 0.8 ? 'numeric' : 'categorical'
}

export const detectFields = (data: Record<string, unknown>[]): DetectedFields => {
  if (data.length === 0) return { numeric: [], categorical: [] }

  const allKeys = [...new Set(data.flatMap((row) => Object.keys(row)))]

  const fields: FieldInfo[] = allKeys.map((name) => ({
    name,
    type: detectFieldType(data.map((row) => row[name])),
  }))

  return {
    numeric: fields.filter((f) => f.type === 'numeric').map((f) => f.name),
    categorical: fields.filter((f) => f.type === 'categorical').map((f) => f.name),
  }
}

export const parseNumeric = (value: unknown): number => {
  if (typeof value === 'number') return value
  if (typeof value === 'string') {
    const parsed = Number(value)
    return Number.isNaN(parsed) ? 0 : parsed
  }
  return 0
}

import { h } from 'plaited'
import type { ChartConfig, ChartRequest } from './types'
import { CHART_DEFAULTS, DEFAULT_COLORS } from './types'
import { parseNumeric } from './detect'

const getColors = (config: ChartConfig, count: number): string[] => {
  const palette = config.colors?.length ? config.colors : DEFAULT_COLORS
  return Array.from({ length: count }, (_, i) => palette[i % palette.length])
}

const svgRoot = (
  config: ChartConfig,
  children: unknown[],
) => {
  const w = config.width ?? CHART_DEFAULTS.width
  const ht = config.height ?? CHART_DEFAULTS.height

  return h('svg', {
    xmlns: 'http://www.w3.org/2000/svg',
    viewBox: `0 0 ${w} ${ht}`,
    width: String(w),
    height: String(ht),
    style: 'font-family: system-ui, -apple-system, sans-serif; background: #fff;',
  }, ...children)
}

const renderTitle = (config: ChartConfig) => {
  if (!config.title) return null
  const w = config.width ?? CHART_DEFAULTS.width
  return h('text', {
    x: String(w / 2),
    y: '28',
    'text-anchor': 'middle',
    'font-size': '16',
    'font-weight': 'bold',
    fill: '#333',
  }, config.title)
}

const renderAxisLabels = (config: ChartConfig) => {
  const w = config.width ?? CHART_DEFAULTS.width
  const ht = config.height ?? CHART_DEFAULTS.height
  const { padding } = CHART_DEFAULTS
  const elements: unknown[] = []

  if (config.xLabel) {
    elements.push(
      h('text', {
        x: String(padding.left + (w - padding.left - padding.right) / 2),
        y: String(ht - 10),
        'text-anchor': 'middle',
        'font-size': '12',
        fill: '#666',
      }, config.xLabel),
    )
  }

  if (config.yLabel) {
    elements.push(
      h('text', {
        x: '15',
        y: String(padding.top + (ht - padding.top - padding.bottom) / 2),
        'text-anchor': 'middle',
        'font-size': '12',
        fill: '#666',
        transform: `rotate(-90, 15, ${padding.top + (ht - padding.top - padding.bottom) / 2})`,
      }, config.yLabel),
    )
  }

  return elements
}

const formatTick = (value: number): string => {
  if (Math.abs(value) >= 1_000_000) return `${(value / 1_000_000).toFixed(1)}M`
  if (Math.abs(value) >= 1_000) return `${(value / 1_000).toFixed(1)}K`
  return Number.isInteger(value) ? String(value) : value.toFixed(1)
}

const computeNiceTicks = (min: number, max: number, targetCount = 5): number[] => {
  if (min === max) return [min]
  const range = max - min
  const roughStep = range / targetCount
  const magnitude = Math.pow(10, Math.floor(Math.log10(roughStep)))
  const residual = roughStep / magnitude

  let niceStep: number
  if (residual <= 1.5) niceStep = magnitude
  else if (residual <= 3) niceStep = 2 * magnitude
  else if (residual <= 7) niceStep = 5 * magnitude
  else niceStep = 10 * magnitude

  const niceMin = Math.floor(min / niceStep) * niceStep
  const niceMax = Math.ceil(max / niceStep) * niceStep
  const ticks: number[] = []
  for (let v = niceMin; v <= niceMax + niceStep * 0.5; v += niceStep) {
    ticks.push(Math.round(v * 1e10) / 1e10)
  }
  return ticks
}

export const renderBarChart = (request: ChartRequest): ReturnType<typeof h> => {
  const { data, config } = request
  const w = config.width ?? CHART_DEFAULTS.width
  const ht = config.height ?? CHART_DEFAULTS.height
  const { padding } = CHART_DEFAULTS

  const chartW = w - padding.left - padding.right
  const chartH = ht - padding.top - padding.bottom

  const categories = data.map((row) => String(row[config.categoryField] ?? ''))
  const valueFields = config.valueFields
  const colors = getColors(config, valueFields.length)

  const allValues = data.flatMap((row) =>
    valueFields.map((f) => parseNumeric(row[f])),
  )
  const dataMin = Math.min(0, ...allValues)
  const dataMax = Math.max(0, ...allValues)
  const ticks = computeNiceTicks(dataMin, dataMax)
  const scaleMin = ticks[0]
  const scaleMax = ticks[ticks.length - 1]
  const valueRange = scaleMax - scaleMin || 1

  const groupWidth = chartW / categories.length
  const barPadding = groupWidth * 0.15
  const barGroupWidth = groupWidth - barPadding * 2
  const barWidth = barGroupWidth / valueFields.length

  const scaleY = (v: number) =>
    padding.top + chartH - ((v - scaleMin) / valueRange) * chartH

  const zeroY = scaleY(0)

  const bars = data.flatMap((row, i) =>
    valueFields.map((field, fi) => {
      const val = parseNumeric(row[field])
      const x = padding.left + i * groupWidth + barPadding + fi * barWidth
      const y = val >= 0 ? scaleY(val) : zeroY
      const barH = Math.abs(val / valueRange) * chartH

      return h('rect', {
        x: String(x),
        y: String(y),
        width: String(barWidth - 1),
        height: String(Math.max(barH, 1)),
        fill: colors[fi],
        rx: '2',
      })
    }),
  )

  const xLabels = categories.map((cat, i) =>
    h('text', {
      x: String(padding.left + i * groupWidth + groupWidth / 2),
      y: String(ht - padding.bottom + 18),
      'text-anchor': 'middle',
      'font-size': '11',
      fill: '#666',
    }, cat.length > 12 ? `${cat.slice(0, 11)}…` : cat),
  )

  const yTickEls = ticks.map((tick) =>
    h('g', {},
      h('line', {
        x1: String(padding.left),
        x2: String(w - padding.right),
        y1: String(scaleY(tick)),
        y2: String(scaleY(tick)),
        stroke: '#e0e0e0',
        'stroke-width': '1',
      }),
      h('text', {
        x: String(padding.left - 8),
        y: String(scaleY(tick) + 4),
        'text-anchor': 'end',
        'font-size': '11',
        fill: '#666',
      }, formatTick(tick)),
    ),
  )

  const legend = valueFields.length > 1
    ? h('g', { transform: `translate(${padding.left}, ${ht - 12})` },
      ...valueFields.map((field, i) =>
        h('g', { transform: `translate(${i * 100}, 0)` },
          h('rect', { x: '0', y: '-8', width: '12', height: '12', fill: colors[i], rx: '2' }),
          h('text', { x: '16', y: '2', 'font-size': '11', fill: '#555' }, field),
        ),
      ),
    )
    : null

  return svgRoot(config, [
    renderTitle(config),
    ...yTickEls,
    h('line', {
      x1: String(padding.left),
      x2: String(w - padding.right),
      y1: String(zeroY),
      y2: String(zeroY),
      stroke: '#999',
      'stroke-width': '1',
    }),
    ...bars,
    ...xLabels,
    ...renderAxisLabels(config),
    legend,
  ].filter(Boolean))
}

export const renderLineChart = (request: ChartRequest): ReturnType<typeof h> => {
  const { data, config } = request
  const w = config.width ?? CHART_DEFAULTS.width
  const ht = config.height ?? CHART_DEFAULTS.height
  const { padding } = CHART_DEFAULTS

  const chartW = w - padding.left - padding.right
  const chartH = ht - padding.top - padding.bottom

  const categories = data.map((row) => String(row[config.categoryField] ?? ''))
  const valueFields = config.valueFields
  const colors = getColors(config, valueFields.length)

  const allValues = data.flatMap((row) =>
    valueFields.map((f) => parseNumeric(row[f])),
  )
  const dataMin = Math.min(...allValues)
  const dataMax = Math.max(...allValues)
  const ticks = computeNiceTicks(dataMin, dataMax)
  const scaleMin = ticks[0]
  const scaleMax = ticks[ticks.length - 1]
  const valueRange = scaleMax - scaleMin || 1

  const scaleX = (i: number) =>
    padding.left + (i / Math.max(categories.length - 1, 1)) * chartW

  const scaleY = (v: number) =>
    padding.top + chartH - ((v - scaleMin) / valueRange) * chartH

  const lines = valueFields.map((field, fi) => {
    const points = data.map((row, i) => {
      const x = scaleX(i)
      const y = scaleY(parseNumeric(row[field]))
      return `${x},${y}`
    })

    const dots = data.map((row, i) =>
      h('circle', {
        cx: String(scaleX(i)),
        cy: String(scaleY(parseNumeric(row[field]))),
        r: '4',
        fill: colors[fi],
        stroke: '#fff',
        'stroke-width': '2',
      }),
    )

    return [
      h('polyline', {
        points: points.join(' '),
        fill: 'none',
        stroke: colors[fi],
        'stroke-width': '2.5',
        'stroke-linejoin': 'round',
        'stroke-linecap': 'round',
      }),
      ...dots,
    ]
  })

  const xLabels = categories.map((cat, i) =>
    h('text', {
      x: String(scaleX(i)),
      y: String(ht - padding.bottom + 18),
      'text-anchor': 'middle',
      'font-size': '11',
      fill: '#666',
    }, cat.length > 12 ? `${cat.slice(0, 11)}…` : cat),
  )

  const yTickEls = ticks.map((tick) =>
    h('g', {},
      h('line', {
        x1: String(padding.left),
        x2: String(w - padding.right),
        y1: String(scaleY(tick)),
        y2: String(scaleY(tick)),
        stroke: '#e0e0e0',
        'stroke-width': '1',
      }),
      h('text', {
        x: String(padding.left - 8),
        y: String(scaleY(tick) + 4),
        'text-anchor': 'end',
        'font-size': '11',
        fill: '#666',
      }, formatTick(tick)),
    ),
  )

  const legend = valueFields.length > 1
    ? h('g', { transform: `translate(${padding.left}, ${ht - 12})` },
      ...valueFields.map((field, i) =>
        h('g', { transform: `translate(${i * 100}, 0)` },
          h('rect', { x: '0', y: '-8', width: '12', height: '12', fill: colors[i], rx: '2' }),
          h('text', { x: '16', y: '2', 'font-size': '11', fill: '#555' }, field),
        ),
      ),
    )
    : null

  return svgRoot(config, [
    renderTitle(config),
    ...yTickEls,
    ...lines.flat(),
    ...xLabels,
    ...renderAxisLabels(config),
    legend,
  ].filter(Boolean))
}

export const renderPieChart = (request: ChartRequest): ReturnType<typeof h> => {
  const { data, config } = request
  const w = config.width ?? CHART_DEFAULTS.width
  const ht = config.height ?? CHART_DEFAULTS.height

  const categories = data.map((row) => String(row[config.categoryField] ?? ''))
  const valueField = config.valueFields[0]
  const values = data.map((row) => Math.max(0, parseNumeric(row[valueField])))
  const total = values.reduce((sum, v) => sum + v, 0) || 1
  const colors = getColors(config, data.length)

  const cx = w / 2
  const cy = ht / 2 + 10
  const radius = Math.min(w, ht) / 2 - 60

  let currentAngle = -Math.PI / 2
  const slices = values.map((value, i) => {
    const sliceAngle = (value / total) * Math.PI * 2
    const startAngle = currentAngle
    const endAngle = currentAngle + sliceAngle
    currentAngle = endAngle

    const x1 = cx + radius * Math.cos(startAngle)
    const y1 = cy + radius * Math.sin(startAngle)
    const x2 = cx + radius * Math.cos(endAngle)
    const y2 = cy + radius * Math.sin(endAngle)
    const largeArc = sliceAngle > Math.PI ? 1 : 0

    const midAngle = startAngle + sliceAngle / 2
    const labelRadius = radius + 20
    const lx = cx + labelRadius * Math.cos(midAngle)
    const ly = cy + labelRadius * Math.sin(midAngle)

    const pct = ((value / total) * 100).toFixed(1)

    const pathD = sliceAngle >= Math.PI * 2 - 0.001
      ? `M ${cx - radius} ${cy} A ${radius} ${radius} 0 1 1 ${cx + radius} ${cy} A ${radius} ${radius} 0 1 1 ${cx - radius} ${cy}`
      : `M ${cx} ${cy} L ${x1} ${y1} A ${radius} ${radius} 0 ${largeArc} 1 ${x2} ${y2} Z`

    return h('g', {},
      h('path', {
        d: pathD,
        fill: colors[i],
        stroke: '#fff',
        'stroke-width': '2',
      }),
      sliceAngle > 0.15
        ? h('text', {
          x: String(lx),
          y: String(ly),
          'text-anchor': 'middle',
          'dominant-baseline': 'middle',
          'font-size': '11',
          fill: '#333',
        }, `${categories[i]} (${pct}%)`)
        : null,
    )
  })

  return svgRoot(config, [
    renderTitle(config),
    ...slices,
  ].filter(Boolean))
}

export const renderChart = (request: ChartRequest): ReturnType<typeof h> => {
  switch (request.config.type) {
    case 'bar':
      return renderBarChart(request)
    case 'line':
      return renderLineChart(request)
    case 'pie':
      return renderPieChart(request)
  }
}

