export const parseJsonInput = (text: string): { data: Record<string, unknown>[]; error: string | null } => {
  try {
    const parsed = JSON.parse(text)
    if (!Array.isArray(parsed)) {
      return { data: [], error: 'Input must be a JSON array of objects' }
    }
    if (parsed.length === 0) {
      return { data: [], error: 'Array must contain at least one object' }
    }
    if (typeof parsed[0] !== 'object' || parsed[0] === null) {
      return { data: [], error: 'Array items must be objects' }
    }
    return { data: parsed as Record<string, unknown>[], error: null }
  } catch (e) {
    const msg = e instanceof SyntaxError ? e.message : 'Invalid JSON'
    return { data: [], error: msg }
  }
}

export const autoConfigureFields = (
  data: Record<string, unknown>[],
  state: AppState,
): { categoryField: string; valueFields: string[] } => {
  const detected = detectFields(data)

  const categoryField = state.categoryField && detected.categorical.includes(state.categoryField)
    ? state.categoryField
    : detected.categorical[0] ?? detected.numeric[0] ?? Object.keys(data[0])[0]

  const validValueFields = state.valueFields.filter((f) => detected.numeric.includes(f))
  const valueFields = validValueFields.length > 0
    ? validValueFields
    : detected.numeric.length > 0
      ? detected.numeric
      : [Object.keys(data[0])[0]]

  return { categoryField, valueFields }
}

export const buildChartRequest = (
  data: Record<string, unknown>[],
  state: AppState,
): ChartRequest => {
  const { categoryField, valueFields } = autoConfigureFields(data, state)

  const config: ChartConfig = {
    type: state.chartType,
    categoryField,
    valueFields: state.chartType === 'pie' ? [valueFields[0]] : valueFields,
    ...(state.title && { title: state.title }),
    ...(state.xLabel && { xLabel: state.xLabel }),
    ...(state.yLabel && { yLabel: state.yLabel }),
    ...(state.colors.length > 0 && { colors: state.colors }),
  }

  return { data, config }
}

export const generateChartSvg = (state: AppState): { svg: string; error: string | null } => {
  const { data, error } = parseJsonInput(state.jsonText)
  if (error) return { svg: '', error }

  const request = buildChartRequest(data, state)
  const svgElement = renderChart(request)
  const ssr = createSSR()
  const rendered = ssr.render(svgElement)
  return { svg: rendered, error: null }
}

