    const valid = values.filter(v => v !== null && v !== undefined && v !== '');
    if (valid.length === 0) return 'categorical';
    const numCount = valid.filter(v => typeof v === 'number' || (typeof v === 'string' && !isNaN(Number(v)) && v.trim() !== '')).length;
    return numCount / valid.length >= 0.8 ? 'numeric' : 'categorical';
