      }).join('');

      vfContainer.querySelectorAll('input[type="checkbox"]').forEach(cb => {
        cb.addEventListener('change', () => {
          state.valueFields = [...vfContainer.querySelectorAll('input:checked')].map(c => c.value);
        });
