  document.querySelector('[p-target="y-label"]').addEventListener('input', (e) => {
    state.yLabel = e.target.value;
  });

  document.querySelector('[p-target="category-field"]').addEventListener('change', (e) => {
    state.categoryField = e.target.value;
  });

  document.querySelector('[p-target="color-input"]').addEventListener('input', (e) => {
    state.colors = e.target.value.split(',').map(c => c.trim()).filter(c => /^#[0-9a-fA-F]{3,8}$/.test(c));
  });

