    const output = document.querySelector('[p-target="chart-output"]');
    const dlBtn = document.querySelector('[p-target="download-btn"]');
    try {
      const data = JSON.parse(state.jsonText);
      if (!Array.isArray(data) || !data.length) {
        output.innerHTML = '<p style="color:#ef4444;">Invalid data: must be a non-empty array of objects</p>';
        return;
      }

      const resp = await fetch('/api/chart', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          data,
          config: {
            type: state.chartType,
            categoryField: state.categoryField || undefined,
            valueFields: state.valueFields.length ? state.valueFields : undefined,
            title: state.title || undefined,
            xLabel: state.xLabel || undefined,
            yLabel: state.yLabel || undefined,
            colors: state.colors.length ? state.colors : undefined,
          },
        }),
      });

      const result = await resp.json();
      if (result.error) {
        output.innerHTML = '<p style="color:#ef4444;">' + result.error + '</p>';
        dlBtn.style.display = 'none';
      } else {
        output.innerHTML = result.svg;
        dlBtn.style.display = 'block';
      }
    } catch(e) {
      output.innerHTML = '<p style="color:#ef4444;">' + e.message + '</p>';
      dlBtn.style.display = 'none';
    }
  });

  document.querySelector('[p-trigger="click:downloadSvg"]').addEventListener('click', () => {
    const svg = document.querySelector('[p-target="chart-output"] svg');
    if (!svg) return;
    const serializer = new XMLSerializer();
    const svgStr = serializer.serializeToString(svg);
    const blob = new Blob([svgStr], { type: 'image/svg+xml;charset=utf-8' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = (state.title || 'chart').replace(/[^a-zA-Z0-9-_]/g, '_') + '.svg';
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  });

  updateFieldSelectors();
})();
`

export const handleChartApi = (body: ChartRequest): { svg: string; error: string | null } => {
  try {
    const { data, config } = body

    if (!Array.isArray(data) || data.length === 0) {
      return { svg: '', error: 'Data must be a non-empty array of objects' }
    }

    const detected = detectFields(data)

    const categoryField = config.categoryField
      ?? detected.categorical[0]
      ?? detected.numeric[0]
      ?? Object.keys(data[0])[0]

    const valueFields = config.valueFields?.length
      ? config.valueFields
      : detected.numeric.length > 0
        ? detected.numeric
        : [Object.keys(data[0])[0]]

    const fullConfig: ChartConfig = {
      type: config.type ?? 'bar',
      categoryField,
      valueFields: config.type === 'pie' ? [valueFields[0]] : valueFields,
      ...(config.title && { title: config.title }),
      ...(config.xLabel && { xLabel: config.xLabel }),
      ...(config.yLabel && { yLabel: config.yLabel }),
      ...(config.colors?.length && { colors: config.colors }),
    }

    const svgElement = renderChart({ data, config: fullConfig })
    const ssr = createSSR()
    const svg = ssr.render(svgElement)
    return { svg, error: null }
  } catch (e) {
    return { svg: '', error: e instanceof Error ? e.message : 'Unknown error' }
  }
}

import { renderApp, handleChartApi } from './index'
import type { ChartRequest } from './types'

const PORT = Number(process.env.PORT) || 3000

const server = Bun.serve({
  port: PORT,
  fetch: async (req) => {
    const url = new URL(req.url)

    if (url.pathname === '/api/chart' && req.method === 'POST') {
      const body = (await req.json()) as ChartRequest
      const result = handleChartApi(body)
      return new Response(JSON.stringify(result), {
        headers: { 'Content-Type': 'application/json' },
      })
    }

    if (url.pathname === '/' || url.pathname === '/index.html') {
      const html = renderApp()
      return new Response(html, {
        headers: { 'Content-Type': 'text/html; charset=utf-8' },
      })
    }

    return new Response('Not Found', { status: 404 })
  },
})

