const SAMPLE_THRESHOLD = 0.8

const isNumericValue = (v: unknown): boolean => {
  if (typeof v === 'number') return true
  if (typeof v === 'string') {
    const trimmed = v.trim()
    return trimmed !== '' && !isNaN(Number(trimmed))
  }
  return false
}

const detectFieldType = (values: unknown[]): FieldType => {
  if (values.length === 0) return 'categorical'
  const numericCount = values.filter(isNumericValue).length
  return numericCount / values.length >= SAMPLE_THRESHOLD ? 'numeric' : 'categorical'
}

const coerceValue = (v: unknown, type: FieldType): string | number => {
  if (type === 'numeric') {
    const n = Number(v)
    return isNaN(n) ? 0 : n
  }
  return String(v ?? '')
}

export const parseData = (raw: string): ParsedData => {
  const parsed = JSON.parse(raw)
  if (!Array.isArray(parsed) || parsed.length === 0) {
    throw new Error('Data must be a non-empty array of objects')
  }

  const first = parsed[0]
  if (typeof first !== 'object' || first === null || Array.isArray(first)) {
    throw new Error('Each item must be a plain object')
  }

  const keys = Object.keys(first)
  if (keys.length === 0) {
    throw new Error('Objects must have at least one field')
  }

  const rawColumns = new Map<string, unknown[]>()
  for (const key of keys) {
    rawColumns.set(key, [])
  }

  for (const row of parsed) {
    for (const key of keys) {
      rawColumns.get(key)!.push(row[key])
    }
  }

  const fields: FieldInfo[] = keys.map((key) => {
    const rawValues = rawColumns.get(key)!
    const type = detectFieldType(rawValues)
    const values = rawValues.map((v) => coerceValue(v, type))
    return { name: key, type, values }
  })

  const rows: DataRow[] = parsed.map((item: Record<string, unknown>) => {
    const row: DataRow = {}
    for (const field of fields) {
      row[field.name] = coerceValue(item[field.name], field.type)
    }
    return row
  })

  return { rows, fields }
}

export const pickDefaults = (fields: FieldInfo[]): { categoryField: string; valueField: string } => {
  const categorical = fields.find((f) => f.type === 'categorical')
  const numeric = fields.find((f) => f.type === 'numeric')

  return {
    categoryField: categorical?.name ?? fields[0].name,
    valueField: numeric?.name ?? fields[fields.length > 1 ? 1 : 0].name,
  }
}

import type { ChartConfig, ChartPoint, DataRow } from './types'

const DEFAULT_COLORS = [
  '#4e79a7', '#f28e2b', '#e15759', '#76b7b2',
  '#59a14f', '#edc948', '#b07aa1', '#ff9da7',
  '#9c755f', '#bab0ac',
]

const escapeXml = (s: string): string =>
  s.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;')

const buildPoints = (rows: DataRow[], config: ChartConfig): ChartPoint[] => {
  const colors = config.colors.length > 0 ? config.colors : DEFAULT_COLORS
  return rows.map((row, i) => ({
    label: String(row[config.categoryField] ?? `Item ${i + 1}`),
    value: Number(row[config.valueField]) || 0,
    color: colors[i % colors.length],
  }))
}

const renderBarChart = (points: ChartPoint[], config: ChartConfig): string => {
  const { width, height, title, xLabel, yLabel } = config
  const margin = { top: 50, right: 20, bottom: 70, left: 60 }
  const plotW = width - margin.left - margin.right
  const plotH = height - margin.top - margin.bottom

  const maxVal = Math.max(...points.map((p) => p.value), 1)
  const barWidth = Math.max(1, plotW / points.length - 8)
  const gap = (plotW - barWidth * points.length) / (points.length + 1)

  const yTicks = 5
  const yStep = maxVal / yTicks

  let svg = `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${width} ${height}" width="${width}" height="${height}" style="font-family:system-ui,sans-serif">\n`
  svg += `  <rect width="${width}" height="${height}" fill="#fff"/>\n`

  if (title) {
    svg += `  <text x="${width / 2}" y="28" text-anchor="middle" font-size="16" font-weight="bold" fill="#333">${escapeXml(title)}</text>\n`
  }

  // Y-axis grid + labels
  for (let i = 0; i <= yTicks; i++) {
    const val = yStep * i
    const y = margin.top + plotH - (val / maxVal) * plotH
    svg += `  <line x1="${margin.left}" y1="${y}" x2="${margin.left + plotW}" y2="${y}" stroke="#e0e0e0" stroke-width="1"/>\n`
    svg += `  <text x="${margin.left - 8}" y="${y + 4}" text-anchor="end" font-size="11" fill="#666">${Math.round(val)}</text>\n`
  }

  // Bars
  points.forEach((p, i) => {
    const x = margin.left + gap + i * (barWidth + gap)
    const barH = (p.value / maxVal) * plotH
    const y = margin.top + plotH - barH
    svg += `  <rect x="${x}" y="${y}" width="${barWidth}" height="${barH}" fill="${p.color}" rx="2">\n`
    svg += `    <title>${escapeXml(p.label)}: ${p.value}</title>\n`
    svg += `  </rect>\n`
    // X-axis label
    const labelX = x + barWidth / 2
    svg += `  <text x="${labelX}" y="${margin.top + plotH + 16}" text-anchor="middle" font-size="10" fill="#666" transform="rotate(-30 ${labelX} ${margin.top + plotH + 16})">${escapeXml(p.label.length > 12 ? p.label.slice(0, 12) + '...' : p.label)}</text>\n`
  })

  // Axes
  svg += `  <line x1="${margin.left}" y1="${margin.top}" x2="${margin.left}" y2="${margin.top + plotH}" stroke="#333" stroke-width="1.5"/>\n`
  svg += `  <line x1="${margin.left}" y1="${margin.top + plotH}" x2="${margin.left + plotW}" y2="${margin.top + plotH}" stroke="#333" stroke-width="1.5"/>\n`

  if (xLabel) {
    svg += `  <text x="${margin.left + plotW / 2}" y="${height - 8}" text-anchor="middle" font-size="12" fill="#555">${escapeXml(xLabel)}</text>\n`
  }
  if (yLabel) {
    svg += `  <text x="14" y="${margin.top + plotH / 2}" text-anchor="middle" font-size="12" fill="#555" transform="rotate(-90 14 ${margin.top + plotH / 2})">${escapeXml(yLabel)}</text>\n`
  }

  svg += `</svg>`
  return svg
}

const renderLineChart = (points: ChartPoint[], config: ChartConfig): string => {
  const { width, height, title, xLabel, yLabel } = config
  const margin = { top: 50, right: 20, bottom: 70, left: 60 }
  const plotW = width - margin.left - margin.right
  const plotH = height - margin.top - margin.bottom

  const maxVal = Math.max(...points.map((p) => p.value), 1)
  const minVal = Math.min(...points.map((p) => p.value), 0)
  const range = maxVal - minVal || 1

  const xStep = points.length > 1 ? plotW / (points.length - 1) : plotW / 2
  const yTicks = 5
  const yStepVal = range / yTicks

  let svg = `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${width} ${height}" width="${width}" height="${height}" style="font-family:system-ui,sans-serif">\n`
  svg += `  <rect width="${width}" height="${height}" fill="#fff"/>\n`

  if (title) {
    svg += `  <text x="${width / 2}" y="28" text-anchor="middle" font-size="16" font-weight="bold" fill="#333">${escapeXml(title)}</text>\n`
  }

  // Y-axis grid
  for (let i = 0; i <= yTicks; i++) {
    const val = minVal + yStepVal * i
    const y = margin.top + plotH - ((val - minVal) / range) * plotH
    svg += `  <line x1="${margin.left}" y1="${y}" x2="${margin.left + plotW}" y2="${y}" stroke="#e0e0e0" stroke-width="1"/>\n`
    svg += `  <text x="${margin.left - 8}" y="${y + 4}" text-anchor="end" font-size="11" fill="#666">${Math.round(val * 10) / 10}</text>\n`
  }

  // Line path
  const lineColor = points[0]?.color ?? '#4e79a7'
  const coords = points.map((p, i) => {
    const x = margin.left + (points.length > 1 ? i * xStep : plotW / 2)
    const y = margin.top + plotH - ((p.value - minVal) / range) * plotH
    return { x, y }
  })

  if (coords.length > 1) {
    const pathD = coords.map((c, i) => `${i === 0 ? 'M' : 'L'} ${c.x} ${c.y}`).join(' ')
    svg += `  <path d="${pathD}" fill="none" stroke="${lineColor}" stroke-width="2.5" stroke-linejoin="round" stroke-linecap="round"/>\n`

    // Area fill
    const areaD = `M ${coords[0].x} ${margin.top + plotH} ${coords.map((c) => `L ${c.x} ${c.y}`).join(' ')} L ${coords[coords.length - 1].x} ${margin.top + plotH} Z`
    svg += `  <path d="${areaD}" fill="${lineColor}" opacity="0.1"/>\n`
  }

  // Data points
  coords.forEach((c, i) => {
    svg += `  <circle cx="${c.x}" cy="${c.y}" r="4" fill="${lineColor}" stroke="#fff" stroke-width="1.5">\n`
    svg += `    <title>${escapeXml(points[i].label)}: ${points[i].value}</title>\n`
    svg += `  </circle>\n`
  })

  // X-axis labels
  points.forEach((p, i) => {
    const x = margin.left + (points.length > 1 ? i * xStep : plotW / 2)
    svg += `  <text x="${x}" y="${margin.top + plotH + 16}" text-anchor="middle" font-size="10" fill="#666" transform="rotate(-30 ${x} ${margin.top + plotH + 16})">${escapeXml(p.label.length > 12 ? p.label.slice(0, 12) + '...' : p.label)}</text>\n`
  })

  // Axes
  svg += `  <line x1="${margin.left}" y1="${margin.top}" x2="${margin.left}" y2="${margin.top + plotH}" stroke="#333" stroke-width="1.5"/>\n`
  svg += `  <line x1="${margin.left}" y1="${margin.top + plotH}" x2="${margin.left + plotW}" y2="${margin.top + plotH}" stroke="#333" stroke-width="1.5"/>\n`

  if (xLabel) {
    svg += `  <text x="${margin.left + plotW / 2}" y="${height - 8}" text-anchor="middle" font-size="12" fill="#555">${escapeXml(xLabel)}</text>\n`
  }
  if (yLabel) {
    svg += `  <text x="14" y="${margin.top + plotH / 2}" text-anchor="middle" font-size="12" fill="#555" transform="rotate(-90 14 ${margin.top + plotH / 2})">${escapeXml(yLabel)}</text>\n`
  }

  svg += `</svg>`
  return svg
}

const renderPieChart = (points: ChartPoint[], config: ChartConfig): string => {
  const { width, height, title } = config
  const cx = width / 2
  const cy = height / 2 + (title ? 10 : 0)
  const radius = Math.min(width, height) / 2 - 60

  const total = points.reduce((sum, p) => sum + Math.abs(p.value), 0) || 1

  let svg = `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${width} ${height}" width="${width}" height="${height}" style="font-family:system-ui,sans-serif">\n`
  svg += `  <rect width="${width}" height="${height}" fill="#fff"/>\n`

  if (title) {
    svg += `  <text x="${width / 2}" y="28" text-anchor="middle" font-size="16" font-weight="bold" fill="#333">${escapeXml(title)}</text>\n`
  }

  let startAngle = -Math.PI / 2

  points.forEach((p) => {
    const sliceAngle = (Math.abs(p.value) / total) * 2 * Math.PI
    const endAngle = startAngle + sliceAngle

    if (sliceAngle < 0.001) {
      startAngle = endAngle
      return
    }

    const x1 = cx + radius * Math.cos(startAngle)
    const y1 = cy + radius * Math.sin(startAngle)
    const x2 = cx + radius * Math.cos(endAngle)
    const y2 = cy + radius * Math.sin(endAngle)
    const largeArc = sliceAngle > Math.PI ? 1 : 0

    const pct = Math.round((Math.abs(p.value) / total) * 100)

    svg += `  <path d="M ${cx} ${cy} L ${x1} ${y1} A ${radius} ${radius} 0 ${largeArc} 1 ${x2} ${y2} Z" fill="${p.color}" stroke="#fff" stroke-width="2">\n`
    svg += `    <title>${escapeXml(p.label)}: ${p.value} (${pct}%)</title>\n`
    svg += `  </path>\n`

    // Label
    if (pct >= 5) {
      const midAngle = startAngle + sliceAngle / 2
      const labelR = radius * 0.65
      const lx = cx + labelR * Math.cos(midAngle)
      const ly = cy + labelR * Math.sin(midAngle)
      svg += `  <text x="${lx}" y="${ly}" text-anchor="middle" dominant-baseline="central" font-size="11" fill="#fff" font-weight="bold">${pct}%</text>\n`
    }

    startAngle = endAngle
  })

  // Legend
  const legendX = 10
  let legendY = height - points.length * 18 - 5
  if (legendY < margin_top(title)) legendY = margin_top(title)

  points.forEach((p, i) => {
    const y = legendY + i * 18
    svg += `  <rect x="${legendX}" y="${y}" width="12" height="12" rx="2" fill="${p.color}"/>\n`
    svg += `  <text x="${legendX + 18}" y="${y + 10}" font-size="11" fill="#555">${escapeXml(p.label.length > 20 ? p.label.slice(0, 20) + '...' : p.label)}</text>\n`
  })

  svg += `</svg>`
  return svg
}

const margin_top = (title: string): number => (title ? 45 : 10)

export const renderChart = (rows: DataRow[], config: ChartConfig): string => {
  const points = buildPoints(rows, config)

  switch (config.type) {
    case 'bar':
      return renderBarChart(points, config)
    case 'line':
      return renderLineChart(points, config)
    case 'pie':
      return renderPieChart(points, config)
    default:
      return renderBarChart(points, config)
  }
}

export { DEFAULT_COLORS }

import type { JsonToken } from './types'

const TOKEN_COLORS: Record<JsonToken['type'], string> = {
  key: '#9876aa',
  string: '#6a8759',
  number: '#6897bb',
  boolean: '#cc7832',
  null: '#cc7832',
  brace: '#a9b7c6',
  bracket: '#a9b7c6',
  colon: '#a9b7c6',
  comma: '#a9b7c6',
  whitespace: '',
}

export const tokenizeJson = (json: string): JsonToken[] => {
  const tokens: JsonToken[] = []
  let i = 0
  let expectKey = false
  let braceDepth = 0

  while (i < json.length) {
    const ch = json[i]

    // Whitespace
    if (/\s/.test(ch)) {
      let start = i
      while (i < json.length && /\s/.test(json[i])) i++
      tokens.push({ type: 'whitespace', text: json.slice(start, i) })
      continue
    }

    // Braces
    if (ch === '{') {
      tokens.push({ type: 'brace', text: '{' })
      braceDepth++
      expectKey = true
      i++
      continue
    }
    if (ch === '}') {
      tokens.push({ type: 'brace', text: '}' })
      braceDepth--
      expectKey = false
      i++
      continue
    }

    // Brackets
    if (ch === '[') {
      tokens.push({ type: 'bracket', text: '[' })
      expectKey = false
      i++
      continue
    }
    if (ch === ']') {
      tokens.push({ type: 'bracket', text: ']' })
      expectKey = false
      i++
      continue
    }

    // Colon
    if (ch === ':') {
      tokens.push({ type: 'colon', text: ':' })
      expectKey = false
      i++
      continue
    }

    // Comma
    if (ch === ',') {
      tokens.push({ type: 'comma', text: ',' })
      expectKey = braceDepth > 0
      i++
      continue
    }

    // String
    if (ch === '"') {
      let end = i + 1
      while (end < json.length) {
        if (json[end] === '\\') {
          end += 2
          continue
        }
        if (json[end] === '"') {
          end++
          break
        }
        end++
      }
      const text = json.slice(i, end)
      tokens.push({ type: expectKey ? 'key' : 'string', text })
      if (expectKey) expectKey = false
      i = end
      continue
    }

    // Number
    if (/[-\d]/.test(ch)) {
      let end = i
      if (json[end] === '-') end++
      while (end < json.length && /[\d.]/.test(json[end])) end++
      if (end < json.length && /[eE]/.test(json[end])) {
        end++
        if (end < json.length && /[+-]/.test(json[end])) end++
        while (end < json.length && /\d/.test(json[end])) end++
      }
      tokens.push({ type: 'number', text: json.slice(i, end) })
      i = end
      continue
    }

    // Boolean / null
    if (json.slice(i, i + 4) === 'true') {
      tokens.push({ type: 'boolean', text: 'true' })
      i += 4
      continue
    }
    if (json.slice(i, i + 5) === 'false') {
      tokens.push({ type: 'boolean', text: 'false' })
      i += 5
      continue
    }
    if (json.slice(i, i + 4) === 'null') {
      tokens.push({ type: 'null', text: 'null' })
      i += 4
      continue
    }

    // Unknown character — skip
    tokens.push({ type: 'whitespace', text: ch })
    i++
  }

  return tokens
}

export const highlightJson = (json: string): string => {
  const tokens = tokenizeJson(json)
  return tokens
    .map((t) => {
      const escaped = t.text
        .replace(/&/g, '&amp;')
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;')
      if (t.type === 'whitespace' || !TOKEN_COLORS[t.type]) return escaped
      return `<span style="color:${TOKEN_COLORS[t.type]}">${escaped}</span>`
    })
    .join('')
}

export const formatJson = (raw: string): string => {
  try {
    return JSON.stringify(JSON.parse(raw), null, 2)
  } catch {
    return raw
  }
}

export const validateJson = (raw: string): { valid: boolean; error?: string } => {
  try {
    const parsed = JSON.parse(raw)
    if (!Array.isArray(parsed)) return { valid: false, error: 'Root must be an array' }
    if (parsed.length === 0) return { valid: false, error: 'Array must not be empty' }
    if (typeof parsed[0] !== 'object' || parsed[0] === null || Array.isArray(parsed[0])) {
      return { valid: false, error: 'Each element must be a plain object' }
    }
    return { valid: true }
  } catch (e) {
    return { valid: false, error: (e as Error).message }
  }
}

