import { parseData, pickDefaults } from './field-detector'
import { renderChart, DEFAULT_COLORS } from './chart-engine'
import { validateJson, formatJson } from './json-editor'
import { renderEditorPage } from './ui'
import { SAMPLE_DATA } from './sample-data'
import type { ChartConfig, ChartType } from './types'

const DATA_FILE = './data/last-session.json'

type SessionState = {
  jsonData: string
  config: ChartConfig
  lastSvg: string | null
}

const defaultConfig: ChartConfig = {
  type: 'bar',
  title: '',
  xLabel: '',
  yLabel: '',
  categoryField: '',
  valueField: '',
  colors: [...DEFAULT_COLORS],
  width: 700,
  height: 420,
}

const loadSession = async (): Promise<SessionState> => {
  try {
    const file = Bun.file(DATA_FILE)
    if (await file.exists()) {
      return await file.json()
    }
  } catch {
    // ignore
  }
  return { jsonData: SAMPLE_DATA, config: { ...defaultConfig }, lastSvg: null }
}

const saveSession = async (state: SessionState): Promise<void> => {
  await Bun.write(DATA_FILE, JSON.stringify(state, null, 2))
}

const parseFormBody = async (req: Request): Promise<Record<string, string>> => {
  const text = await req.text()
  const params = new URLSearchParams(text)
  const result: Record<string, string> = {}
  for (const [key, value] of params.entries()) {
    result[key] = value
  }
  return result
}

const buildConfigFromForm = (form: Record<string, string>, prev: ChartConfig): ChartConfig => {
  const colors: string[] = []
  for (let i = 0; i < DEFAULT_COLORS.length; i++) {
    colors.push(form[`color_${i}`] ?? prev.colors[i] ?? DEFAULT_COLORS[i])
  }

  return {
    type: (form.chartType as ChartType) ?? prev.type,
    title: form.title ?? prev.title,
    xLabel: form.xLabel ?? prev.xLabel,
    yLabel: form.yLabel ?? prev.yLabel,
    categoryField: form.categoryField ?? prev.categoryField,
    valueField: form.valueField ?? prev.valueField,
    colors,
    width: 700,
    height: 420,
  }
}

const server = Bun.serve({
  port: Number(process.env.PORT) || 3000,

  fetch: async (req) => {
    const url = new URL(req.url)

    // Serve the main page
    if (url.pathname === '/' && req.method === 'GET') {
      const session = await loadSession()
      let fields = []
      let error: string | null = null

      const validation = validateJson(session.jsonData)
      if (validation.valid) {
        try {
          const parsed = parseData(session.jsonData)
          fields = parsed.fields
          if (!session.config.categoryField || !session.config.valueField) {
            const defaults = pickDefaults(parsed.fields)
            session.config.categoryField = defaults.categoryField
            session.config.valueField = defaults.valueField
          }
        } catch (e) {
          error = (e as Error).message
        }
      }

      const html = renderEditorPage(
        session.jsonData,
        session.config,
        fields,
        session.lastSvg,
        error,
      )
      return new Response(html, { headers: { 'Content-Type': 'text/html; charset=utf-8' } })
    }

    // Generate chart
    if (url.pathname === '/generate' && req.method === 'POST') {
      const session = await loadSession()
      const form = await parseFormBody(req)
      const jsonData = form.jsonData ?? session.jsonData
      const config = buildConfigFromForm(form, session.config)

      let error: string | null = null
      let chartSvg: string | null = null
      let fields = session.config.categoryField ? [] : []

      const validation = validateJson(jsonData)
      if (!validation.valid) {
        error = validation.error ?? 'Invalid JSON'
      } else {
        try {
          const parsed = parseData(jsonData)
          fields = parsed.fields

          if (!config.categoryField) {
            const defaults = pickDefaults(parsed.fields)
            config.categoryField = defaults.categoryField
            config.valueField = defaults.valueField
          }

          chartSvg = renderChart(parsed.rows, config)
        } catch (e) {
          error = (e as Error).message
        }
      }

      const state: SessionState = { jsonData, config, lastSvg: chartSvg }
      await saveSession(state)

      if (fields.length === 0 && !error) {
        try {
          fields = parseData(jsonData).fields
        } catch {
          // ignore
        }
      }

      const html = renderEditorPage(jsonData, config, fields, chartSvg, error)
      return new Response(html, { headers: { 'Content-Type': 'text/html; charset=utf-8' } })
    }

    // Download SVG
    if (url.pathname === '/download') {
      const session = await loadSession()
      if (!session.lastSvg) {
        return new Response('No chart generated yet', { status: 404 })
      }
      return new Response(session.lastSvg, {
        headers: {
          'Content-Type': 'image/svg+xml',
          'Content-Disposition': `attachment; filename="chart.svg"`,
        },
      })
    }

    // Format JSON endpoint
    if (url.pathname === '/format' && req.method === 'POST') {
      const form = await parseFormBody(req)
      const formatted = formatJson(form.jsonData ?? '')
      return new Response(JSON.stringify({ formatted }), {
        headers: { 'Content-Type': 'application/json' },
      })
    }

    // Sample data endpoint
    if (url.pathname === '/sample') {
      return new Response(JSON.stringify({ data: SAMPLE_DATA }), {
        headers: { 'Content-Type': 'application/json' },
      })
    }

    return new Response('Not Found', { status: 404 })
  },
})

