import type { DataRow, FieldInfo, FieldType } from './types'

const isNumeric = (value: unknown): boolean => {
  if (typeof value === 'number') return true
  if (typeof value === 'string') {
    const trimmed = value.trim()
    return trimmed !== '' && !isNaN(Number(trimmed))
  }
  return false
}

export const detectFields = (data: DataRow[]): FieldInfo[] => {
  if (data.length === 0) return []

  const allKeys = new Set<string>()
  for (const row of data) {
    for (const key of Object.keys(row)) {
      allKeys.add(key)
    }
  }

  return Array.from(allKeys).map((name) => {
    const values = data.map((row) => row[name]).filter((v) => v !== undefined && v !== null)
    const numericCount = values.filter(isNumeric).length
    const type: FieldType = values.length > 0 && numericCount / values.length >= 0.8
      ? 'numeric'
      : 'categorical'
    return { name, type }
  })
}

export const getNumericFields = (fields: FieldInfo[]): FieldInfo[] =>
  fields.filter((f) => f.type === 'numeric')

export const getCategoricalFields = (fields: FieldInfo[]): FieldInfo[] =>
  fields.filter((f) => f.type === 'categorical')

export const parseNumeric = (value: unknown): number => {
  if (typeof value === 'number') return value
  return Number(value)
}

export const parseData = (json: string): { data: DataRow[] | null; error: string | null } => {
  try {
    const parsed = JSON.parse(json)
    if (!Array.isArray(parsed)) {
      return { data: null, error: 'Input must be a JSON array' }
    }
    if (parsed.length === 0) {
      return { data: null, error: 'Array must contain at least one object' }
    }
    if (typeof parsed[0] !== 'object' || parsed[0] === null) {
      return { data: null, error: 'Array items must be objects' }
    }
    return { data: parsed as DataRow[], error: null }
  } catch (e) {
    return { data: null, error: `Invalid JSON: ${(e as Error).message}` }
  }
}

import { h } from '@plaited/jsx'
import type { ChartConfig, DataRow, ChartMargins } from '../types'
import { DEFAULT_COLORS, DEFAULT_WIDTH, DEFAULT_HEIGHT, DEFAULT_MARGINS } from '../types'
import { parseNumeric } from '../detect'

export const renderBarChart = (
  data: DataRow[],
  config: ChartConfig,
  margins: ChartMargins = DEFAULT_MARGINS,
) => {
  const width = config.width ?? DEFAULT_WIDTH
  const height = config.height ?? DEFAULT_HEIGHT
  const colors = config.colors ?? DEFAULT_COLORS
  const xField = config.xField ?? ''
  const yField = config.yField ?? ''

  const chartWidth = width - margins.left - margins.right
  const chartHeight = height - margins.top - margins.bottom

  const labels = data.map((row) => String(row[xField] ?? ''))
  const values = data.map((row) => parseNumeric(row[yField]))

  const maxValue = Math.max(...values, 0)
  const yMax = maxValue === 0 ? 1 : maxValue * 1.1
  const barCount = data.length
  const barGap = Math.max(4, chartWidth * 0.05 / barCount)
  const barWidth = (chartWidth - barGap * (barCount + 1)) / barCount

  const yTicks = generateYTicks(0, yMax, 5)

  const bars = data.map((_, i) => {
    const x = margins.left + barGap + i * (barWidth + barGap)
    const barHeight = (values[i] / yMax) * chartHeight
    const y = margins.top + chartHeight - barHeight
    const color = colors[i % colors.length]

    return h('g', { key: String(i) },
      h('rect', {
        x: String(x),
        y: String(y),
        width: String(barWidth),
        height: String(barHeight),
        fill: color,
        rx: '2',
      }),
      h('text', {
        x: String(x + barWidth / 2),
        y: String(margins.top + chartHeight + 16),
        'text-anchor': 'middle',
        'font-size': '11',
        'font-family': 'system-ui, sans-serif',
        fill: '#555',
      }, labels[i].length > 12 ? labels[i].slice(0, 11) + '\u2026' : labels[i]),
    )
  })

  const yAxisTicks = yTicks.map((tick) => {
    const y = margins.top + chartHeight - (tick / yMax) * chartHeight
    return h('g', { key: String(tick) },
      h('line', {
        x1: String(margins.left),
        y1: String(y),
        x2: String(margins.left + chartWidth),
        y2: String(y),
        stroke: '#e0e0e0',
        'stroke-width': '1',
      }),
      h('text', {
        x: String(margins.left - 8),
        y: String(y + 4),
        'text-anchor': 'end',
        'font-size': '11',
        'font-family': 'system-ui, sans-serif',
        fill: '#555',
      }, formatTickValue(tick)),
    )
  })

  return h('svg', {
    xmlns: 'http://www.w3.org/2000/svg',
    width: String(width),
    height: String(height),
    viewBox: `0 0 ${width} ${height}`,
  },
    h('rect', { width: String(width), height: String(height), fill: '#ffffff' }),
    // Title
    config.title ? h('text', {
      x: String(width / 2),
      y: '24',
      'text-anchor': 'middle',
      'font-size': '16',
      'font-weight': 'bold',
      'font-family': 'system-ui, sans-serif',
      fill: '#333',
    }, config.title) : null,
    // Y axis line
    h('line', {
      x1: String(margins.left),
      y1: String(margins.top),
      x2: String(margins.left),
      y2: String(margins.top + chartHeight),
      stroke: '#333',
      'stroke-width': '1',
    }),
    // X axis line
    h('line', {
      x1: String(margins.left),
      y1: String(margins.top + chartHeight),
      x2: String(margins.left + chartWidth),
      y2: String(margins.top + chartHeight),
      stroke: '#333',
      'stroke-width': '1',
    }),
    // Grid lines and tick labels
    ...yAxisTicks,
    // Bars
    ...bars,
    // X axis label
    config.xLabel ? h('text', {
      x: String(margins.left + chartWidth / 2),
      y: String(height - 8),
      'text-anchor': 'middle',
      'font-size': '13',
      'font-family': 'system-ui, sans-serif',
      fill: '#333',
    }, config.xLabel) : null,
    // Y axis label
    config.yLabel ? h('text', {
      x: '16',
      y: String(margins.top + chartHeight / 2),
      'text-anchor': 'middle',
      'font-size': '13',
      'font-family': 'system-ui, sans-serif',
      fill: '#333',
      transform: `rotate(-90, 16, ${margins.top + chartHeight / 2})`,
    }, config.yLabel) : null,
  )
}

const generateYTicks = (min: number, max: number, count: number): number[] => {
  const range = max - min
  const rawStep = range / count
  const magnitude = Math.pow(10, Math.floor(Math.log10(rawStep)))
  const normalized = rawStep / magnitude

  let step: number
  if (normalized <= 1.5) step = 1 * magnitude
  else if (normalized <= 3.5) step = 2.5 * magnitude
  else if (normalized <= 7.5) step = 5 * magnitude
  else step = 10 * magnitude

  const ticks: number[] = []
  let current = Math.ceil(min / step) * step
  while (current <= max) {
    ticks.push(current)
    current += step
  }
  return ticks
}

const formatTickValue = (value: number): string => {
  if (Math.abs(value) >= 1_000_000) return `${(value / 1_000_000).toFixed(1)}M`
  if (Math.abs(value) >= 1_000) return `${(value / 1_000).toFixed(1)}K`
  if (Number.isInteger(value)) return String(value)
  return value.toFixed(1)
}

import { h } from '@plaited/jsx'
import type { ChartConfig, DataRow, ChartMargins } from '../types'
import { DEFAULT_COLORS, DEFAULT_WIDTH, DEFAULT_HEIGHT, DEFAULT_MARGINS } from '../types'
import { parseNumeric } from '../detect'

export const renderLineChart = (
  data: DataRow[],
  config: ChartConfig,
  margins: ChartMargins = DEFAULT_MARGINS,
) => {
  const width = config.width ?? DEFAULT_WIDTH
  const height = config.height ?? DEFAULT_HEIGHT
  const colors = config.colors ?? DEFAULT_COLORS
  const xField = config.xField ?? ''
  const yField = config.yField ?? ''

  const chartWidth = width - margins.left - margins.right
  const chartHeight = height - margins.top - margins.bottom

  const labels = data.map((row) => String(row[xField] ?? ''))
  const values = data.map((row) => parseNumeric(row[yField]))

  const maxValue = Math.max(...values, 0)
  const minValue = Math.min(...values, 0)
  const yMin = minValue < 0 ? minValue * 1.1 : 0
  const yMax = maxValue === 0 ? 1 : maxValue * 1.1
  const yRange = yMax - yMin

  const points = values.map((v, i) => {
    const x = margins.left + (i / Math.max(data.length - 1, 1)) * chartWidth
    const y = margins.top + chartHeight - ((v - yMin) / yRange) * chartHeight
    return { x, y }
  })

  const pathData = points
    .map((p, i) => `${i === 0 ? 'M' : 'L'} ${p.x.toFixed(2)} ${p.y.toFixed(2)}`)
    .join(' ')

  const areaPathData = points.length > 0
    ? `${pathData} L ${points[points.length - 1].x.toFixed(2)} ${margins.top + chartHeight} L ${points[0].x.toFixed(2)} ${margins.top + chartHeight} Z`
    : ''

  const yTicks = generateYTicks(yMin, yMax, 5)
  const lineColor = colors[0]

  const yAxisTicks = yTicks.map((tick) => {
    const y = margins.top + chartHeight - ((tick - yMin) / yRange) * chartHeight
    return h('g', { key: String(tick) },
      h('line', {
        x1: String(margins.left),
        y1: String(y),
        x2: String(margins.left + chartWidth),
        y2: String(y),
        stroke: '#e0e0e0',
        'stroke-width': '1',
      }),
      h('text', {
        x: String(margins.left - 8),
        y: String(y + 4),
        'text-anchor': 'end',
        'font-size': '11',
        'font-family': 'system-ui, sans-serif',
        fill: '#555',
      }, formatTickValue(tick)),
    )
  })

  const xLabels = data.map((_, i) => {
    const x = margins.left + (i / Math.max(data.length - 1, 1)) * chartWidth
    const showLabel = data.length <= 20 || i % Math.ceil(data.length / 20) === 0
    return showLabel
      ? h('text', {
          key: String(i),
          x: String(x),
          y: String(margins.top + chartHeight + 16),
          'text-anchor': 'middle',
          'font-size': '11',
          'font-family': 'system-ui, sans-serif',
          fill: '#555',
        }, labels[i].length > 10 ? labels[i].slice(0, 9) + '\u2026' : labels[i])
      : null
  }).filter(Boolean)

  const dots = points.map((p, i) =>
    h('circle', {
      key: String(i),
      cx: String(p.x),
      cy: String(p.y),
      r: data.length > 50 ? '2' : '4',
      fill: lineColor,
      stroke: '#fff',
      'stroke-width': '1.5',
    }),
  )

  return h('svg', {
    xmlns: 'http://www.w3.org/2000/svg',
    width: String(width),
    height: String(height),
    viewBox: `0 0 ${width} ${height}`,
  },
    h('rect', { width: String(width), height: String(height), fill: '#ffffff' }),
    config.title ? h('text', {
      x: String(width / 2),
      y: '24',
      'text-anchor': 'middle',
      'font-size': '16',
      'font-weight': 'bold',
      'font-family': 'system-ui, sans-serif',
      fill: '#333',
    }, config.title) : null,
    h('line', {
      x1: String(margins.left),
      y1: String(margins.top),
      x2: String(margins.left),
      y2: String(margins.top + chartHeight),
      stroke: '#333',
      'stroke-width': '1',
    }),
    h('line', {
      x1: String(margins.left),
      y1: String(margins.top + chartHeight),
      x2: String(margins.left + chartWidth),
      y2: String(margins.top + chartHeight),
      stroke: '#333',
      'stroke-width': '1',
    }),
    ...yAxisTicks,
    ...xLabels,
    // Area fill
    areaPathData ? h('path', {
      d: areaPathData,
      fill: lineColor,
      opacity: '0.08',
    }) : null,
    // Line
    h('path', {
      d: pathData,
      fill: 'none',
      stroke: lineColor,
      'stroke-width': '2.5',
      'stroke-linejoin': 'round',
      'stroke-linecap': 'round',
    }),
    // Dots
    ...dots,
    config.xLabel ? h('text', {
      x: String(margins.left + chartWidth / 2),
      y: String(height - 8),
      'text-anchor': 'middle',
      'font-size': '13',
      'font-family': 'system-ui, sans-serif',
      fill: '#333',
    }, config.xLabel) : null,
    config.yLabel ? h('text', {
      x: '16',
      y: String(margins.top + chartHeight / 2),
      'text-anchor': 'middle',
      'font-size': '13',
      'font-family': 'system-ui, sans-serif',
      fill: '#333',
      transform: `rotate(-90, 16, ${margins.top + chartHeight / 2})`,
    }, config.yLabel) : null,
  )
}

const generateYTicks = (min: number, max: number, count: number): number[] => {
  const range = max - min
  if (range === 0) return [min]
  const rawStep = range / count
  const magnitude = Math.pow(10, Math.floor(Math.log10(rawStep)))
  const normalized = rawStep / magnitude

  let step: number
  if (normalized <= 1.5) step = 1 * magnitude
  else if (normalized <= 3.5) step = 2.5 * magnitude
  else if (normalized <= 7.5) step = 5 * magnitude
  else step = 10 * magnitude

  const ticks: number[] = []
  let current = Math.ceil(min / step) * step
  while (current <= max) {
    ticks.push(current)
    current += step
  }
  return ticks
}

const formatTickValue = (value: number): string => {
  if (Math.abs(value) >= 1_000_000) return `${(value / 1_000_000).toFixed(1)}M`
  if (Math.abs(value) >= 1_000) return `${(value / 1_000).toFixed(1)}K`
  if (Number.isInteger(value)) return String(value)
  return value.toFixed(1)
}

import { h } from '@plaited/jsx'
import type { ChartConfig, DataRow } from '../types'
import { DEFAULT_COLORS, DEFAULT_WIDTH, DEFAULT_HEIGHT } from '../types'
import { parseNumeric } from '../detect'

export const renderPieChart = (data: DataRow[], config: ChartConfig) => {
  const width = config.width ?? DEFAULT_WIDTH
  const height = config.height ?? DEFAULT_HEIGHT
  const colors = config.colors ?? DEFAULT_COLORS
  const labelField = config.xField ?? ''
  const valueField = config.yField ?? ''

  const labels = data.map((row) => String(row[labelField] ?? ''))
  const rawValues = data.map((row) => parseNumeric(row[valueField]))
  const values = rawValues.map((v) => Math.max(v, 0))
  const total = values.reduce((sum, v) => sum + v, 0)

  if (total === 0) {
    return h('svg', {
      xmlns: 'http://www.w3.org/2000/svg',
      width: String(width),
      height: String(height),
      viewBox: `0 0 ${width} ${height}`,
    },
      h('rect', { width: String(width), height: String(height), fill: '#ffffff' }),
      h('text', {
        x: String(width / 2),
        y: String(height / 2),
        'text-anchor': 'middle',
        'font-size': '14',
        'font-family': 'system-ui, sans-serif',
        fill: '#999',
      }, 'No data to display'),
    )
  }

  const titleOffset = config.title ? 30 : 0
  const legendWidth = 160
  const availableWidth = width - legendWidth
  const cx = availableWidth / 2
  const cy = titleOffset + (height - titleOffset) / 2
  const radius = Math.min(availableWidth, height - titleOffset) / 2 - 20

  let startAngle = -Math.PI / 2
  const slices = values.map((value, i) => {
    const sliceAngle = (value / total) * 2 * Math.PI
    const endAngle = startAngle + sliceAngle
    const largeArc = sliceAngle > Math.PI ? 1 : 0

    const x1 = cx + radius * Math.cos(startAngle)
    const y1 = cy + radius * Math.sin(startAngle)
    const x2 = cx + radius * Math.cos(endAngle)
    const y2 = cy + radius * Math.sin(endAngle)

    const pathD = values.length === 1
      ? [
          `M ${cx} ${cy - radius}`,
          `A ${radius} ${radius} 0 1 1 ${cx - 0.001} ${cy - radius}`,
          'Z',
        ].join(' ')
      : [
          `M ${cx} ${cy}`,
          `L ${x1.toFixed(2)} ${y1.toFixed(2)}`,
          `A ${radius} ${radius} 0 ${largeArc} 1 ${x2.toFixed(2)} ${y2.toFixed(2)}`,
          'Z',
        ].join(' ')

    const color = colors[i % colors.length]
    const result = { pathD, color, startAngle, endAngle, sliceAngle }
    startAngle = endAngle
    return result
  })

  const svgSlices = slices.map((slice, i) =>
    h('path', {
      key: String(i),
      d: slice.pathD,
      fill: slice.color,
      stroke: '#ffffff',
      'stroke-width': '2',
    }),
  )

  const percentLabels = slices.map((slice, i) => {
    const percent = (values[i] / total) * 100
    if (percent < 3) return null
    const midAngle = slice.startAngle + slice.sliceAngle / 2
    const labelRadius = radius * 0.65
    const lx = cx + labelRadius * Math.cos(midAngle)
    const ly = cy + labelRadius * Math.sin(midAngle)
    return h('text', {
      key: `label-${i}`,
      x: String(lx),
      y: String(ly),
      'text-anchor': 'middle',
      'dominant-baseline': 'central',
      'font-size': '12',
      'font-weight': 'bold',
      'font-family': 'system-ui, sans-serif',
      fill: '#ffffff',
    }, `${percent.toFixed(1)}%`)
  }).filter(Boolean)

  const legendX = availableWidth + 10
  const legendStartY = titleOffset + 30
  const legendItems = labels.map((label, i) => {
    const y = legendStartY + i * 22
    const color = colors[i % colors.length]
    const displayLabel = label.length > 16 ? label.slice(0, 15) + '\u2026' : label
    return h('g', { key: `legend-${i}` },
      h('rect', {
        x: String(legendX),
        y: String(y),
        width: '12',
        height: '12',
        rx: '2',
        fill: color,
      }),
      h('text', {
        x: String(legendX + 18),
        y: String(y + 10),
        'font-size': '11',
        'font-family': 'system-ui, sans-serif',
        fill: '#555',
      }, `${displayLabel} (${values[i]})`),
    )
  })

  return h('svg', {
    xmlns: 'http://www.w3.org/2000/svg',
    width: String(width),
    height: String(height),
    viewBox: `0 0 ${width} ${height}`,
  },
    h('rect', { width: String(width), height: String(height), fill: '#ffffff' }),
    config.title ? h('text', {
      x: String(width / 2),
      y: '24',
      'text-anchor': 'middle',
      'font-size': '16',
      'font-weight': 'bold',
      'font-family': 'system-ui, sans-serif',
      fill: '#333',
    }, config.title) : null,
    ...svgSlices,
    ...percentLabels,
    ...legendItems,
  )
}

import { h } from '@plaited/jsx'
import type { Token, TokenType } from './types'

const TOKEN_COLORS: Record<TokenType, string> = {
  string: '#22863a',
  number: '#005cc5',
  boolean: '#d73a49',
  null: '#6f42c1',
  key: '#6f42c1',
  punctuation: '#586069',
}

export const tokenizeJson = (json: string): Token[] => {
  const tokens: Token[] = []
  let i = 0

  const peek = (): string => json[i] ?? ''
  const advance = (): string => json[i++] ?? ''

  while (i < json.length) {
    const ch = peek()

    if (/\s/.test(ch)) {
      let ws = ''
      while (i < json.length && /\s/.test(json[i])) {
        ws += advance()
      }
      tokens.push({ type: 'punctuation', value: ws })
      continue
    }

    if (ch === '{' || ch === '}' || ch === '[' || ch === ']' || ch === ',' || ch === ':') {
      tokens.push({ type: 'punctuation', value: advance() })
      continue
    }

    if (ch === '"') {
      let str = advance()
      while (i < json.length && json[i] !== '"') {
        if (json[i] === '\\') str += advance()
        str += advance()
      }
      if (i < json.length) str += advance()

      const isKey = isNextNonWhitespaceColon(json, i)
      tokens.push({ type: isKey ? 'key' : 'string', value: str })
      continue
    }

    if (ch === '-' || (ch >= '0' && ch <= '9')) {
      let num = advance()
      while (i < json.length && /[0-9.eE+\-]/.test(json[i])) {
        num += advance()
      }
      tokens.push({ type: 'number', value: num })
      continue
    }

    if (json.slice(i, i + 4) === 'true') {
      tokens.push({ type: 'boolean', value: 'true' })
      i += 4
      continue
    }
    if (json.slice(i, i + 5) === 'false') {
      tokens.push({ type: 'boolean', value: 'false' })
      i += 5
      continue
    }
    if (json.slice(i, i + 4) === 'null') {
      tokens.push({ type: 'null', value: 'null' })
      i += 4
      continue
    }

    tokens.push({ type: 'punctuation', value: advance() })
  }

  return tokens
}

const isNextNonWhitespaceColon = (json: string, startIndex: number): boolean => {
  for (let j = startIndex; j < json.length; j++) {
    if (/\s/.test(json[j])) continue
    return json[j] === ':'
  }
  return false
}

export const renderHighlightedJson = (json: string) => {
  const tokens = tokenizeJson(json)

  const spans = tokens.map((token, i) =>
    h('span', {
      key: String(i),
      style: `color: ${TOKEN_COLORS[token.type]}`,
    }, token.value),
  )

  return h('pre', {
    style: [
      'margin: 0',
      'padding: 12px',
      'font-family: "SF Mono", "Fira Code", "Consolas", monospace',
      'font-size: 13px',
      'line-height: 1.5',
      'white-space: pre-wrap',
      'word-wrap: break-word',
      'background: #f6f8fa',
      'border: 1px solid #d0d7de',
      'border-radius: 6px',
      'overflow-x: auto',
      'max-height: 400px',
    ].join('; '),
  }, h('code', {}, ...spans))
}

