import type { Marker, Circle, Category } from './types'

const DATA_DIR = new URL('./data/', import.meta.url).pathname

const readJson = async <T>(filename: string): Promise<T> => {
  const file = Bun.file(`${DATA_DIR}${filename}`)
  const text = await file.text()
  return JSON.parse(text) as T
}

const writeJson = async <T>(filename: string, data: T): Promise<void> => {
  await Bun.write(`${DATA_DIR}${filename}`, JSON.stringify(data, null, 2))
}

export const getMarkers = (): Promise<Marker[]> => readJson<Marker[]>('markers.json')

export const addMarker = async (marker: Marker): Promise<Marker> => {
  const markers = await getMarkers()
  markers.push(marker)
  await writeJson('markers.json', markers)
  return marker
}

export const removeMarker = async (id: string): Promise<boolean> => {
  const markers = await getMarkers()
  const filtered = markers.filter((m) => m.id !== id)
  if (filtered.length === markers.length) return false
  await writeJson('markers.json', filtered)
  return true
}

export const getCircles = (): Promise<Circle[]> => readJson<Circle[]>('circles.json')

export const addCircle = async (circle: Circle): Promise<Circle> => {
  const circles = await getCircles()
  circles.push(circle)
  await writeJson('circles.json', circles)
  return circle
}

export const removeCircle = async (id: string): Promise<boolean> => {
  const circles = await getCircles()
  const filtered = circles.filter((c) => c.id !== id)
  if (filtered.length === circles.length) return false
  await writeJson('circles.json', filtered)
  return true
}

export const getCategories = (): Promise<Category[]> => readJson<Category[]>('categories.json')

