const styleToStr = (s: Record<string, string>): string =>
  Object.entries(s)
    .map(([k, v]) => `${k.replace(/[A-Z]/g, (c) => `-${c.toLowerCase()}`)}:${v}`)
    .join(';')

export const renderPage = (
  markers: Marker[],
  circles: Circle[],
  categories: Category[],
): string => {
  const categoryMap = new Map(categories.map((c) => [c.id, c]))
  const grouped = new Map<string, Marker[]>()
  for (const cat of categories) grouped.set(cat.id, [])
  for (const m of markers) {
    const list = grouped.get(m.categoryId) ?? []
    list.push(m)
    grouped.set(m.categoryId, list)
  }

  const { render } = createSSR()

  const template = h('html', { lang: 'en' },
    h('head', {},
      h('meta', { charset: 'utf-8' }),
      h('meta', { name: 'viewport', content: 'width=device-width, initial-scale=1' }),
      h('title', {}, 'Interactive Map'),
      h('link', {
        rel: 'stylesheet',
        href: 'https://unpkg.com/leaflet@1.9.4/dist/leaflet.css',
      }),
      h('script', { src: 'https://unpkg.com/leaflet@1.9.4/dist/leaflet.js' }),
      h('style', {}, `
        * { box-sizing: border-box; }
        body { margin: 0; }
        .marker-item:hover { background: #0f3460 !important; }
        .leaflet-popup-content-wrapper { background: #1a1a2e; color: #eee; border: 1px solid #0f3460; }
        .leaflet-popup-tip { background: #1a1a2e; }
        .leaflet-popup-content h3 { margin: 0 0 4px 0; font-size: 15px; }
        .leaflet-popup-content p { margin: 0; font-size: 13px; color: #aaa; }
        .search-results { position: absolute; top: 100%; left: 0; right: 0; background: #1a1a2e; border: 1px solid #0f3460; border-radius: 0 0 6px 6px; max-height: 200px; overflow-y: auto; z-index: 10; display: none; }
        .search-results div { padding: 8px 12px; cursor: pointer; font-size: 13px; }
        .search-results div:hover { background: #0f3460; }
        .filter-chip.active { outline: 2px solid #fff; outline-offset: 1px; }
      `),
    ),
    h('body', { style: styleToStr(styles.page) },
      // Sidebar
      h('div', { style: styleToStr(styles.sidebar), id: 'sidebar' },
        h('div', { style: styleToStr(styles.sidebarHeader) },
          h('h2', { style: styleToStr(styles.sidebarTitle) }, 'Interactive Map'),
          h('div', { style: 'position:relative' },
            h('input', {
              type: 'text',
              id: 'search-input',
              placeholder: 'Search location...',
              style: styleToStr(styles.searchBox),
              autocomplete: 'off',
            }),
            h('div', { id: 'search-results', class: 'search-results' }),
          ),
        ),
        // Category filter chips
        h('div', { style: styleToStr(styles.filterBar) },
          h('button', {
            class: 'filter-chip active',
            style: styleToStr({ ...styles.filterChip, background: '#555', color: '#fff' }),
            'data-category': 'all',
            onclick: 'filterCategory("all", this)',
          }, 'All'),
          ...categories.map((cat) =>
            h('button', {
              class: 'filter-chip',
              style: styleToStr({ ...styles.filterChip, background: cat.color, color: '#fff' }),
              'data-category': cat.id,
              onclick: `filterCategory("${cat.id}", this)`,
            }, cat.name),
          ),
        ),
        // Marker list
        h('div', { style: styleToStr(styles.markerList), id: 'marker-list' },
          ...categories.map((cat) => {
            const catMarkers = grouped.get(cat.id) ?? []
            if (catMarkers.length === 0) return h(Fragment, {})
            return h('div', {
              class: 'category-group',
              'data-category-group': cat.id,
              style: styleToStr(styles.categoryGroup),
            },
              h('div', {
                style: styleToStr({ ...styles.categoryLabel, background: cat.color + '33', color: cat.color }),
              }, cat.name),
              ...catMarkers.map((m) =>
                h('div', {
                  class: 'marker-item',
                  style: styleToStr(styles.markerItem),
                  onclick: `centerOnMarker("${m.id}")`,
                  'data-marker-id': m.id,
                  'data-marker-cat': m.categoryId,
                },
                  h('div', {
                    style: styleToStr({ ...styles.markerTitle, color: cat.color }),
                  }, m.title),
                  h('div', { style: styleToStr(styles.markerDesc) }, m.description || 'No description'),
                ),
              ),
            )
          }),
        ),
        // Add buttons
        h('div', { style: styleToStr(styles.addPanel) },
          h('button', {
            style: styleToStr(styles.addBtn),
            onclick: 'showAddMarkerForm()',
          }, '+ Add Marker'),
          h('button', {
            style: styleToStr({ ...styles.addBtn, background: '#0f3460', marginTop: '6px' }),
            onclick: 'showAddCircleForm()',
          }, '+ Draw Circle'),
        ),
      ),
      // Map
      h('div', { id: 'map', style: styleToStr(styles.mapContainer) }),

      // Add Marker Form Overlay
      h('div', { id: 'marker-form-overlay', style: styleToStr(styles.formOverlay) },
        h('div', { style: styleToStr(styles.formCard) },
          h('h3', { style: 'margin:0 0 16px 0;color:#e94560' }, 'Add Marker'),
          h('label', { style: styleToStr(styles.formLabel) }, 'Title'),
          h('input', { type: 'text', id: 'fm-title', style: styleToStr(styles.formInput), placeholder: 'Marker title' }),
          h('label', { style: styleToStr(styles.formLabel) }, 'Description'),
          h('input', { type: 'text', id: 'fm-desc', style: styleToStr(styles.formInput), placeholder: 'Short description' }),
          h('label', { style: styleToStr(styles.formLabel) }, 'Category'),
          h('select', { id: 'fm-category', style: styleToStr(styles.formInput) },
            ...categories.map((c) => h('option', { value: c.id }, c.name)),
          ),
          h('label', { style: styleToStr(styles.formLabel) }, 'Latitude'),
          h('input', { type: 'number', id: 'fm-lat', style: styleToStr(styles.formInput), step: 'any' }),
          h('label', { style: styleToStr(styles.formLabel) }, 'Longitude'),
          h('input', { type: 'number', id: 'fm-lng', style: styleToStr(styles.formInput), step: 'any' }),
          h('p', { style: 'font-size:11px;color:#666;margin:0 0 8px 0' }, 'Tip: Click the map to auto-fill coordinates'),
          h('div', { style: styleToStr(styles.formBtnRow) },
            h('button', { style: styleToStr(styles.formCancel), onclick: 'hideOverlays()' }, 'Cancel'),
            h('button', { style: styleToStr(styles.formSubmit), onclick: 'submitMarker()' }, 'Add'),
          ),
        ),
      ),

      // Add Circle Form Overlay
      h('div', { id: 'circle-form-overlay', style: styleToStr(styles.formOverlay) },
        h('div', { style: styleToStr(styles.formCard) },
          h('h3', { style: 'margin:0 0 16px 0;color:#0f3460' }, 'Draw Circle'),
          h('label', { style: styleToStr(styles.formLabel) }, 'Label'),
          h('input', { type: 'text', id: 'fc-label', style: styleToStr(styles.formInput), placeholder: 'Area label' }),
          h('label', { style: styleToStr(styles.formLabel) }, 'Color'),
          h('input', { type: 'color', id: 'fc-color', style: styleToStr({ ...styles.formInput, padding: '4px', height: '40px' }), value: '#e94560' }),
          h('label', { style: styleToStr(styles.formLabel) }, 'Radius (meters)'),
          h('input', { type: 'number', id: 'fc-radius', style: styleToStr(styles.formInput), value: '500', min: '50' }),
          h('label', { style: styleToStr(styles.formLabel) }, 'Latitude'),
          h('input', { type: 'number', id: 'fc-lat', style: styleToStr(styles.formInput), step: 'any' }),
          h('label', { style: styleToStr(styles.formLabel) }, 'Longitude'),
          h('input', { type: 'number', id: 'fc-lng', style: styleToStr(styles.formInput), step: 'any' }),
          h('p', { style: 'font-size:11px;color:#666;margin:0 0 8px 0' }, 'Tip: Click the map to auto-fill coordinates'),
          h('div', { style: styleToStr(styles.formBtnRow) },
            h('button', { style: styleToStr(styles.formCancel), onclick: 'hideOverlays()' }, 'Cancel'),
            h('button', { style: styleToStr({ ...styles.formSubmit, background: '#0f3460' }), onclick: 'submitCircle()' }, 'Draw'),
          ),
        ),
      ),

      // Client-side JS
      h('script', {}, `
        const MARKERS_DATA = ${JSON.stringify(markers)};
        const CIRCLES_DATA = ${JSON.stringify(circles)};
        const CATEGORIES = ${JSON.stringify(categories)};
        const catColors = {};
        CATEGORIES.forEach(c => catColors[c.id] = c.color);

        // Init map
        const map = L.map('map').setView([40.7128, -74.006], 12);
        L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
          attribution: '&copy; OpenStreetMap contributors',
          maxZoom: 19,
        }).addTo(map);

        // Marker icon factory
        const makeIcon = (color) => L.divIcon({
          className: '',
          html: '<svg width="28" height="40" viewBox="0 0 28 40"><path d="M14 0C6.27 0 0 6.27 0 14c0 10.5 14 26 14 26s14-15.5 14-26C28 6.27 21.73 0 14 0z" fill="' + color + '"/><circle cx="14" cy="14" r="6" fill="#fff" opacity="0.9"/></svg>',
          iconSize: [28, 40],
          iconAnchor: [14, 40],
          popupAnchor: [0, -36],
        });

        // Store leaflet objects keyed by id
        const markerLayers = {};
        const circleLayers = {};
        let activeFilter = 'all';

        // Add existing markers
        MARKERS_DATA.forEach(m => {
          const color = catColors[m.categoryId] || '#2196F3';
          const lm = L.marker([m.lat, m.lng], { icon: makeIcon(color) })
            .bindPopup('<h3>' + escHtml(m.title) + '</h3><p>' + escHtml(m.description) + '</p><button onclick="deleteMarker(\\'' + m.id + '\\')" style="margin-top:6px;background:#e94560;border:none;color:#fff;padding:4px 10px;border-radius:4px;cursor:pointer;font-size:12px">Delete</button>')
            .addTo(map);
          markerLayers[m.id] = lm;
        });

        // Add existing circles
        CIRCLES_DATA.forEach(c => {
          const lc = L.circle([c.lat, c.lng], {
            radius: c.radius,
            color: c.color,
            fillColor: c.color,
            fillOpacity: 0.15,
            weight: 2,
          }).bindPopup('<h3>' + escHtml(c.label) + '</h3><button onclick="deleteCircle(\\'' + c.id + '\\')" style="margin-top:6px;background:#e94560;border:none;color:#fff;padding:4px 10px;border-radius:4px;cursor:pointer;font-size:12px">Delete</button>').addTo(map);
          circleLayers[c.id] = lc;
        });

        function escHtml(s) {
          const d = document.createElement('div');
          d.textContent = s || '';
          return d.innerHTML;
        }

        // Click map to fill lat/lng in open form
        map.on('click', (e) => {
          const mfo = document.getElementById('marker-form-overlay');
          const cfo = document.getElementById('circle-form-overlay');
          if (mfo.style.display === 'flex') {
            document.getElementById('fm-lat').value = e.latlng.lat.toFixed(6);
            document.getElementById('fm-lng').value = e.latlng.lng.toFixed(6);
          } else if (cfo.style.display === 'flex') {
            document.getElementById('fc-lat').value = e.latlng.lat.toFixed(6);
            document.getElementById('fc-lng').value = e.latlng.lng.toFixed(6);
          }
        });

        // Category filter
        function filterCategory(catId, btn) {
          activeFilter = catId;
          document.querySelectorAll('.filter-chip').forEach(c => c.classList.remove('active'));
          btn.classList.add('active');
          // Toggle marker visibility
          MARKERS_DATA.forEach(m => {
            const layer = markerLayers[m.id];
            if (!layer) return;
            if (catId === 'all' || m.categoryId === catId) {
              map.addLayer(layer);
            } else {
              map.removeLayer(layer);
            }
          });
          // Toggle sidebar groups
          document.querySelectorAll('.category-group').forEach(g => {
            if (catId === 'all' || g.dataset.categoryGroup === catId) {
              g.style.display = '';
            } else {
              g.style.display = 'none';
            }
          });
        }

        // Center on marker
        function centerOnMarker(id) {
          const lm = markerLayers[id];
          if (!lm) return;
          map.flyTo(lm.getLatLng(), 15, { duration: 0.8 });
          lm.openPopup();
        }

        // Forms
        function showAddMarkerForm() {
          const center = map.getCenter();
          document.getElementById('fm-lat').value = center.lat.toFixed(6);
          document.getElementById('fm-lng').value = center.lng.toFixed(6);
          document.getElementById('fm-title').value = '';
          document.getElementById('fm-desc').value = '';
          document.getElementById('marker-form-overlay').style.display = 'flex';
        }

        function showAddCircleForm() {
          const center = map.getCenter();
          document.getElementById('fc-lat').value = center.lat.toFixed(6);
          document.getElementById('fc-lng').value = center.lng.toFixed(6);
          document.getElementById('fc-label').value = '';
          document.getElementById('circle-form-overlay').style.display = 'flex';
        }

        function hideOverlays() {
          document.getElementById('marker-form-overlay').style.display = 'none';
          document.getElementById('circle-form-overlay').style.display = 'none';
        }

        async function submitMarker() {
          const title = document.getElementById('fm-title').value.trim();
          const description = document.getElementById('fm-desc').value.trim();
          const categoryId = document.getElementById('fm-category').value;
          const lat = parseFloat(document.getElementById('fm-lat').value);
          const lng = parseFloat(document.getElementById('fm-lng').value);
          if (!title || isNaN(lat) || isNaN(lng)) return alert('Title and valid coordinates are required');
          const res = await fetch('/api/markers', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ title, description, categoryId, lat, lng }),
          });
          if (res.ok) location.reload();
          else alert('Failed to add marker');
        }

        async function submitCircle() {
          const label = document.getElementById('fc-label').value.trim();
          const color = document.getElementById('fc-color').value;
          const radius = parseFloat(document.getElementById('fc-radius').value);
          const lat = parseFloat(document.getElementById('fc-lat').value);
          const lng = parseFloat(document.getElementById('fc-lng').value);
          if (!label || isNaN(lat) || isNaN(lng) || isNaN(radius)) return alert('Label, radius, and valid coordinates are required');
          const res = await fetch('/api/circles', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ label, color, radius, lat, lng }),
          });
          if (res.ok) location.reload();
          else alert('Failed to add circle');
        }

        async function deleteMarker(id) {
          if (!confirm('Delete this marker?')) return;
          const res = await fetch('/api/markers/' + id, { method: 'DELETE' });
          if (res.ok) location.reload();
        }

        async function deleteCircle(id) {
          if (!confirm('Delete this circle?')) return;
          const res = await fetch('/api/circles/' + id, { method: 'DELETE' });
          if (res.ok) location.reload();
        }

        // Location search with debounce
        let searchTimeout;
        const searchInput = document.getElementById('search-input');
        const searchResults = document.getElementById('search-results');

        searchInput.addEventListener('input', () => {
          clearTimeout(searchTimeout);
          const q = searchInput.value.trim();
          if (q.length < 3) { searchResults.style.display = 'none'; return; }
          searchTimeout = setTimeout(async () => {
            const res = await fetch('/api/search?q=' + encodeURIComponent(q));
            if (!res.ok) return;
            const data = await res.json();
            searchResults.innerHTML = '';
            if (data.length === 0) {
              searchResults.innerHTML = '<div style="color:#666">No results</div>';
            }
            data.forEach(r => {
              const div = document.createElement('div');
              div.textContent = r.displayName;
              div.onclick = () => {
                map.flyTo([r.lat, r.lng], 14, { duration: 1 });
                searchResults.style.display = 'none';
                searchInput.value = r.displayName;
              };
              searchResults.appendChild(div);
            });
            searchResults.style.display = 'block';
          }, 400);
        });

        searchInput.addEventListener('keydown', (e) => {
          if (e.key === 'Escape') {
            searchResults.style.display = 'none';
          }
        });

        document.addEventListener('click', (e) => {
          if (!searchInput.contains(e.target) && !searchResults.contains(e.target)) {
            searchResults.style.display = 'none';
          }
        });
      `),
    ),
  )

  return '<!DOCTYPE html>' + render(template)
}

import { getMarkers, addMarker, removeMarker, getCircles, addCircle, removeCircle, getCategories } from './store'
import { renderPage } from './render'
import type { Marker, Circle, SearchResult } from './types'

const generateId = (): string => crypto.randomUUID()

const searchLocation = async (query: string): Promise<SearchResult[]> => {
  const url = `https://nominatim.openstreetmap.org/search?format=json&limit=5&q=${encodeURIComponent(query)}`
  const res = await fetch(url, {
    headers: { 'User-Agent': 'interactive-map-module/1.0' },
  })
  if (!res.ok) return []
  const data = (await res.json()) as Array<{ lat: string; lon: string; display_name: string }>
  return data.map((item) => ({
    lat: parseFloat(item.lat),
    lng: parseFloat(item.lon),
    displayName: item.display_name,
  }))
}

const parseJsonBody = async (req: Request): Promise<unknown> => {
  try {
    return await req.json()
  } catch {
    return null
  }
}

const jsonResponse = (data: unknown, status = 200): Response =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

const server = Bun.serve({
  port: Number(process.env.PORT) || 3000,
  fetch: async (req) => {
    const url = new URL(req.url)
    const path = url.pathname
    const method = req.method

    // Serve main page
    if (path === '/' && method === 'GET') {
      const [markers, circles, categories] = await Promise.all([
        getMarkers(),
        getCircles(),
        getCategories(),
      ])
      const html = renderPage(markers, circles, categories)
      return new Response(html, {
        headers: { 'Content-Type': 'text/html; charset=utf-8' },
      })
    }

    // Markers API
    if (path === '/api/markers' && method === 'GET') {
      return jsonResponse(await getMarkers())
    }

    if (path === '/api/markers' && method === 'POST') {
      const body = (await parseJsonBody(req)) as Partial<Marker> | null
      if (!body || !body.title || body.lat == null || body.lng == null) {
        return jsonResponse({ error: 'title, lat, lng are required' }, 400)
      }
      const marker: Marker = {
        id: generateId(),
        lat: body.lat,
        lng: body.lng,
        title: body.title,
        description: body.description ?? '',
        categoryId: body.categoryId ?? 'default',
      }
      await addMarker(marker)
      return jsonResponse(marker, 201)
    }

    if (path.startsWith('/api/markers/') && method === 'DELETE') {
      const id = path.slice('/api/markers/'.length)
      const removed = await removeMarker(id)
      return removed ? jsonResponse({ ok: true }) : jsonResponse({ error: 'not found' }, 404)
    }

    // Circles API
    if (path === '/api/circles' && method === 'GET') {
      return jsonResponse(await getCircles())
    }

    if (path === '/api/circles' && method === 'POST') {
      const body = (await parseJsonBody(req)) as Partial<Circle> | null
      if (!body || !body.label || body.lat == null || body.lng == null || body.radius == null) {
        return jsonResponse({ error: 'label, lat, lng, radius are required' }, 400)
      }
      const circle: Circle = {
        id: generateId(),
        lat: body.lat,
        lng: body.lng,
        radius: body.radius,
        label: body.label,
        color: body.color ?? '#e94560',
      }
      await addCircle(circle)
      return jsonResponse(circle, 201)
    }

    if (path.startsWith('/api/circles/') && method === 'DELETE') {
      const id = path.slice('/api/circles/'.length)
      const removed = await removeCircle(id)
      return removed ? jsonResponse({ ok: true }) : jsonResponse({ error: 'not found' }, 404)
    }

    // Categories API
    if (path === '/api/categories' && method === 'GET') {
      return jsonResponse(await getCategories())
    }

    // Search API (proxied Nominatim)
    if (path === '/api/search' && method === 'GET') {
      const q = url.searchParams.get('q') ?? ''
      if (q.length < 2) return jsonResponse([])
      const results = await searchLocation(q)
      return jsonResponse(results)
    }

    return jsonResponse({ error: 'not found' }, 404)
  },
})

