import type { MapMarker, MapCircle } from './types'

const MARKERS_PATH = './data/markers.json'
const CIRCLES_PATH = './data/circles.json'

const readJson = async <T>(path: string): Promise<T[]> => {
  const file = Bun.file(path)
  if (!(await file.exists())) return []
  const text = await file.text()
  return JSON.parse(text) as T[]
}

const writeJson = async <T>(path: string, data: T[]): Promise<void> => {
  await Bun.write(path, JSON.stringify(data, null, 2))
}

export const getMarkers = (): Promise<MapMarker[]> => readJson<MapMarker>(MARKERS_PATH)

export const addMarker = async (marker: MapMarker): Promise<MapMarker> => {
  const markers = await getMarkers()
  markers.push(marker)
  await writeJson(MARKERS_PATH, markers)
  return marker
}

export const deleteMarker = async (id: string): Promise<boolean> => {
  const markers = await getMarkers()
  const filtered = markers.filter((m) => m.id !== id)
  if (filtered.length === markers.length) return false
  await writeJson(MARKERS_PATH, filtered)
  return true
}

export const getCircles = (): Promise<MapCircle[]> => readJson<MapCircle>(CIRCLES_PATH)

export const addCircle = async (circle: MapCircle): Promise<MapCircle> => {
  const circles = await getCircles()
  circles.push(circle)
  await writeJson(CIRCLES_PATH, circles)
  return circle
}

export const deleteCircle = async (id: string): Promise<boolean> => {
  const circles = await getCircles()
  const filtered = circles.filter((c) => c.id !== id)
  if (filtered.length === circles.length) return false
  await writeJson(CIRCLES_PATH, filtered)
  return true
}

import type { SearchResult } from './types'

const NOMINATIM_URL = 'https://nominatim.openstreetmap.org/search'

export const geocode = async (query: string): Promise<SearchResult[]> => {
  const params = new URLSearchParams({
    q: query,
    format: 'json',
    limit: '5',
  })

  const response = await fetch(`${NOMINATIM_URL}?${params}`, {
    headers: {
      'User-Agent': 'interactive-map-module/1.0',
    },
  })

  if (!response.ok) {
    throw new Error(`Geocoding failed: ${response.statusText}`)
  }

  const data = (await response.json()) as Array<{
    lat: string
    lon: string
    display_name: string
  }>

  return data.map((item) => ({
    lat: parseFloat(item.lat),
    lng: parseFloat(item.lon),
    displayName: item.display_name,
  }))
}

