const CATEGORY_COLORS = ${JSON.stringify(CATEGORY_COLORS)};

let map, markerLayer, circleLayer;
let allMarkers = [];
let allCircles = [];
let activeFilter = 'all';
let leafletMarkers = {};

const init = () => {
  map = L.map('map').setView([40.7128, -74.0060], 12);
  L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
    attribution: '&copy; OpenStreetMap contributors',
    maxZoom: 19,
  }).addTo(map);

  markerLayer = L.layerGroup().addTo(map);
  circleLayer = L.layerGroup().addTo(map);

  map.on('click', (e) => {
    document.getElementById('marker-lat').value = e.latlng.lat.toFixed(6);
    document.getElementById('marker-lng').value = e.latlng.lng.toFixed(6);
    document.getElementById('circle-lat').value = e.latlng.lat.toFixed(6);
    document.getElementById('circle-lng').value = e.latlng.lng.toFixed(6);
  });

  loadData();
};

const loadData = async () => {
  const [markersRes, circlesRes] = await Promise.all([
    fetch('/api/markers'),
    fetch('/api/circles'),
  ]);
  allMarkers = await markersRes.json();
  allCircles = await circlesRes.json();
  renderMarkers();
  renderCircles();
  renderSidebar();
};

const createMarkerIcon = (category) => {
  const cat = CATEGORY_COLORS[category] || CATEGORY_COLORS.custom;
  return L.divIcon({
    className: '',
    html: '<div style="width:28px;height:28px;border-radius:50% 50% 50% 0;background:' + cat.color + ';transform:rotate(-45deg);display:flex;align-items:center;justify-content:center;border:2px solid white;box-shadow:0 2px 6px rgba(0,0,0,0.3)"><span style="transform:rotate(45deg);font-size:14px">' + cat.icon + '</span></div>',
    iconSize: [28, 28],
    iconAnchor: [14, 28],
    popupAnchor: [0, -28],
  });
};

const renderMarkers = () => {
  markerLayer.clearLayers();
  leafletMarkers = {};
  const filtered = activeFilter === 'all'
    ? allMarkers
    : allMarkers.filter(m => m.category === activeFilter);

  filtered.forEach((m) => {
    const marker = L.marker([m.lat, m.lng], { icon: createMarkerIcon(m.category) })
      .bindPopup('<h3>' + escapeHtml(m.title) + '</h3><p>' + escapeHtml(m.description || 'No description') + '</p><div class="popup-category">' + (CATEGORY_COLORS[m.category]?.icon || '📍') + ' ' + m.category + '</div><button class="popup-delete" onclick="deleteMarkerById(\\''+m.id+'\\')">Delete</button>')
      .addTo(markerLayer);
    leafletMarkers[m.id] = marker;
  });
};

const renderCircles = () => {
  circleLayer.clearLayers();
  allCircles.forEach((c) => {
    L.circle([c.lat, c.lng], {
      radius: c.radius,
      color: c.color,
      fillColor: c.color,
      fillOpacity: 0.15,
      weight: 2,
    })
      .bindPopup('<h3>' + escapeHtml(c.label || 'Area') + '</h3><p>Radius: ' + c.radius + 'm</p><button class="popup-delete" onclick="deleteCircleById(\\''+c.id+'\\')">Delete</button>')
      .addTo(circleLayer);
  });
};

const renderSidebar = () => {
  const list = document.getElementById('marker-list');
  const filtered = activeFilter === 'all'
    ? allMarkers
    : allMarkers.filter(m => m.category === activeFilter);

  const grouped = {};
  filtered.forEach((m) => {
    if (!grouped[m.category]) grouped[m.category] = [];
    grouped[m.category].push(m);
  });

  let html = '';
  Object.entries(grouped).forEach(([cat, markers]) => {
    const catInfo = CATEGORY_COLORS[cat] || CATEGORY_COLORS.custom;
    html += '<div style="margin-bottom:12px">';
    html += '<div style="padding:6px 10px;font-size:12px;font-weight:600;text-transform:uppercase;letter-spacing:0.5px;color:#a0a0a0;display:flex;align-items:center;gap:6px">';
    html += '<span style="width:8px;height:8px;border-radius:50%;background:' + catInfo.color + ';display:inline-block"></span>';
    html += catInfo.icon + ' ' + cat + ' (' + markers.length + ')';
    html += '</div>';
    markers.forEach((m) => {
      html += '<div class="marker-item" style="padding:10px 12px;margin-bottom:4px;border-radius:6px;cursor:pointer;background-color:#16213e" onclick="centerOn(' + m.lat + ',' + m.lng + ',\\'' + m.id + '\\')">';
      html += '<div style="font-size:14px;font-weight:500">' + escapeHtml(m.title) + '</div>';
      if (m.description) {
        html += '<div style="font-size:12px;color:#a0a0a0;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">' + escapeHtml(m.description) + '</div>';
      }
      html += '</div>';
    });
    html += '</div>';
  });

  if (filtered.length === 0) {
    html = '<div style="padding:24px 16px;text-align:center;color:#666;font-size:14px">No markers yet. Click the map to set coordinates, then click "+ Marker".</div>';
  }

  list.innerHTML = html;
};

const centerOn = (lat, lng, id) => {
  map.flyTo([lat, lng], 16, { duration: 0.8 });
  if (id && leafletMarkers[id]) {
