import { getMarkers, addMarker, deleteMarker, getCircles, addCircle, deleteCircle } from './store'
import { geocode } from './search'
import { renderPage } from './ui'
import type { MapMarker, MapCircle, MarkerCategory } from './types'
import { ALL_CATEGORIES } from './categories'

const generateId = (): string => crypto.randomUUID()

const jsonResponse = (data: unknown, status = 200): Response =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

const errorResponse = (message: string, status = 400): Response =>
  jsonResponse({ error: message }, status)

const server = Bun.serve({
  port: 3000,
  fetch: async (req) => {
    const url = new URL(req.url)
    const { pathname } = url
    const method = req.method

    // Serve UI
    if (pathname === '/' && method === 'GET') {
      return new Response(renderPage(), {
        headers: { 'Content-Type': 'text/html' },
      })
    }

    // Markers API
    if (pathname === '/api/markers' && method === 'GET') {
      const category = url.searchParams.get('category')
      let markers = await getMarkers()
      if (category && ALL_CATEGORIES.includes(category as MarkerCategory)) {
        markers = markers.filter((m) => m.category === category)
      }
      return jsonResponse(markers)
    }

    if (pathname === '/api/markers' && method === 'POST') {
      const body = (await req.json()) as Partial<MapMarker>
      if (!body.title || body.lat == null || body.lng == null) {
        return errorResponse('title, lat, and lng are required')
      }
      const marker: MapMarker = {
        id: generateId(),
        title: body.title,
        description: body.description || '',
        lat: body.lat,
        lng: body.lng,
        category: ALL_CATEGORIES.includes(body.category as MarkerCategory)
          ? (body.category as MarkerCategory)
          : 'custom',
        createdAt: new Date().toISOString(),
      }
      await addMarker(marker)
      return jsonResponse(marker, 201)
    }

    if (pathname.startsWith('/api/markers/') && method === 'DELETE') {
      const id = pathname.split('/').pop()
      if (!id) return errorResponse('Marker ID required')
      const deleted = await deleteMarker(id)
      if (!deleted) return errorResponse('Marker not found', 404)
      return jsonResponse({ success: true })
    }

    // Circles API
    if (pathname === '/api/circles' && method === 'GET') {
      const circles = await getCircles()
      return jsonResponse(circles)
    }

    if (pathname === '/api/circles' && method === 'POST') {
      const body = (await req.json()) as Partial<MapCircle>
      if (body.lat == null || body.lng == null || body.radius == null) {
        return errorResponse('lat, lng, and radius are required')
      }
      const circle: MapCircle = {
        id: generateId(),
        lat: body.lat,
        lng: body.lng,
        radius: body.radius,
        color: body.color || '#3498db',
        label: body.label || '',
        createdAt: new Date().toISOString(),
      }
      await addCircle(circle)
      return jsonResponse(circle, 201)
    }

    if (pathname.startsWith('/api/circles/') && method === 'DELETE') {
      const id = pathname.split('/').pop()
      if (!id) return errorResponse('Circle ID required')
      const deleted = await deleteCircle(id)
      if (!deleted) return errorResponse('Circle not found', 404)
      return jsonResponse({ success: true })
    }

    // Search API
    if (pathname === '/api/search' && method === 'GET') {
      const q = url.searchParams.get('q')
      if (!q) return errorResponse('q parameter required')
      const results = await geocode(q)
      return jsonResponse(results)
    }

    return new Response('Not Found', { status: 404 })
  },
})

