const clientScript = (
  markers: MapMarker[],
  circles: MapCircle[],
  categories: MarkerCategory[],
) => `
(function() {
  const initialMarkers = ${JSON.stringify(markers)};
  const initialCircles = ${JSON.stringify(circles)};
  const categories = ${JSON.stringify(categories)};
  const catMap = {};
  categories.forEach(function(c) { catMap[c.id] = c; });

  // Initialize map
  const map = L.map('map').setView([20, 0], 2);
  L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
    attribution: '&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors',
    maxZoom: 19,
  }).addTo(map);

  const leafletMarkers = {};
  const leafletCircles = {};

  // Create colored marker icon
  const createIcon = function(color) {
    return L.divIcon({
      className: 'custom-marker',
      html: '<div style="background:' + color + ';width:24px;height:24px;border-radius:50%;border:3px solid white;box-shadow:0 2px 6px rgba(0,0,0,0.3);"></div>',
      iconSize: [24, 24],
      iconAnchor: [12, 12],
      popupAnchor: [0, -14],
    });
  };

  // Add marker to map
  const addMarkerToMap = function(m) {
    const cat = catMap[m.categoryId] || { color: '#6b7280' };
    const marker = L.marker([m.lat, m.lng], { icon: createIcon(cat.color) })
      .addTo(map)
      .bindPopup('<b>' + escapeHtml(m.title) + '</b><br>' + escapeHtml(m.description));
    leafletMarkers[m.id] = marker;
    return marker;
  };

  // Add circle to map
  const addCircleToMap = function(c) {
    const circle = L.circle([c.lat, c.lng], {
      radius: c.radius,
      color: c.color,
      fillColor: c.color,
      fillOpacity: 0.15,
      weight: 2,
    }).addTo(map);
    if (c.label) {
      circle.bindPopup('<b>' + escapeHtml(c.label) + '</b>');
    }
    leafletCircles[c.id] = circle;
    return circle;
  };

  const escapeHtml = function(str) {
    if (!str) return '';
    const div = document.createElement('div');
    div.textContent = str;
    return div.innerHTML;
  };

  // Load initial data
  initialMarkers.forEach(addMarkerToMap);
  initialCircles.forEach(addCircleToMap);

  // Category filtering
  let activeCategory = 'all';
  document.getElementById('category-filters').addEventListener('click', function(e) {
    const btn = e.target.closest('.category-btn');
    if (!btn) return;
    document.querySelectorAll('.category-btn').forEach(function(b) { b.classList.remove('active'); });
    btn.classList.add('active');
    activeCategory = btn.dataset.category;
    // Filter sidebar
    document.querySelectorAll('.marker-item').forEach(function(item) {
      if (activeCategory === 'all' || item.dataset.category === activeCategory) {
        item.style.display = '';
      } else {
        item.style.display = 'none';
      }
    });
    // Filter map markers
    Object.keys(leafletMarkers).forEach(function(id) {
      const item = document.querySelector('.marker-item[data-id="' + id + '"]');
      if (item) {
        if (activeCategory === 'all' || item.dataset.category === activeCategory) {
          map.addLayer(leafletMarkers[id]);
        } else {
          map.removeLayer(leafletMarkers[id]);
        }
      }
    });
  });

  // Click sidebar marker to center
  document.getElementById('marker-list').addEventListener('click', function(e) {
    const deleteBtn = e.target.closest('.delete-marker-btn');
    if (deleteBtn) {
      const id = deleteBtn.dataset.id;
      fetch('/api/markers/' + id, { method: 'DELETE' }).then(function(res) {
        if (res.ok) {
          if (leafletMarkers[id]) { map.removeLayer(leafletMarkers[id]); delete leafletMarkers[id]; }
          const item = document.querySelector('.marker-item[data-id="' + id + '"]');
          if (item) item.remove();
        }
      });
      return;
    }
    const item = e.target.closest('.marker-item');
    if (!item) return;
    const lat = parseFloat(item.dataset.lat);
    const lng = parseFloat(item.dataset.lng);
    map.setView([lat, lng], 13);
    const marker = leafletMarkers[item.dataset.id];
    if (marker) marker.openPopup();
  });

  // Click map to populate add-marker form
  map.on('click', function(e) {
    const form = document.getElementById('add-marker-form');
    form.lat.value = e.latlng.lat.toFixed(6);
    form.lng.value = e.latlng.lng.toFixed(6);
  });

  // Add marker form
  document.getElementById('add-marker-form').addEventListener('submit', function(e) {
    e.preventDefault();
    const fd = new FormData(e.target);
    const data = {
      lat: parseFloat(fd.get('lat')),
      lng: parseFloat(fd.get('lng')),
      title: fd.get('title'),
      description: fd.get('description') || '',
      categoryId: fd.get('categoryId'),
    };
    fetch('/api/markers', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    })
    .then(function(res) { return res.json(); })
    .then(function(marker) {
      addMarkerToMap(marker);
      const cat = catMap[marker.categoryId] || { color: '#6b7280' };
      const li = document.createElement('li');
      li.className = 'marker-item';
      li.dataset.id = marker.id;
      li.dataset.category = marker.categoryId;
      li.dataset.lat = marker.lat;
      li.dataset.lng = marker.lng;
      li.innerHTML = '<span class="marker-dot" style="background:' + cat.color + '"></span>'
        + '<div class="marker-info"><strong>' + escapeHtml(marker.title) + '</strong>'
        + '<small>' + escapeHtml(marker.description) + '</small></div>'
        + '<button class="delete-marker-btn" data-id="' + marker.id + '" type="button" title="Delete marker">&times;</button>';
      document.getElementById('marker-list').appendChild(li);
      e.target.reset();
      map.setView([marker.lat, marker.lng], 13);
    });
  });

  // Add circle form
  document.getElementById('add-circle-form').addEventListener('submit', function(e) {
    e.preventDefault();
    const fd = new FormData(e.target);
    const data = {
      lat: parseFloat(fd.get('lat')),
      lng: parseFloat(fd.get('lng')),
      radius: parseFloat(fd.get('radius')),
      color: fd.get('color'),
      label: fd.get('label') || '',
    };
    fetch('/api/circles', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    })
    .then(function(res) { return res.json(); })
    .then(function(circle) {
      addCircleToMap(circle);
      e.target.reset();
      map.setView([circle.lat, circle.lng], 13);
    });
  });

  // Search
  const doSearch = function() {
    const q = document.getElementById('search-input').value.trim();
    if (!q) return;
    fetch('/api/search?q=' + encodeURIComponent(q))
      .then(function(res) { return res.json(); })
      .then(function(results) {
        const container = document.getElementById('search-results');
        container.innerHTML = '';
        if (results.length === 0) {
          container.innerHTML = '<div class="search-empty">No results found</div>';
          return;
        }
        results.forEach(function(r) {
          const div = document.createElement('div');
          div.className = 'search-result-item';
          div.textContent = r.displayName;
          div.addEventListener('click', function() {
            map.setView([r.lat, r.lng], 13);
            container.innerHTML = '';
            document.getElementById('search-input').value = '';
          });
          container.appendChild(div);
        });
      });
  };
  document.getElementById('search-btn').addEventListener('click', doSearch);
  document.getElementById('search-input').addEventListener('keydown', function(e) {
    if (e.key === 'Enter') { e.preventDefault(); doSearch(); }
  });
})();
`

const styles = `
