import { getMarkers, addMarker, deleteMarker, getCircles, addCircle, deleteCircle, getCategories } from './store'
import { geocode } from './search'
import { MapPage } from './ui'
import { createSSR } from '@plaited/temple'

const PORT = 3000

const jsonResponse = (data: unknown, status = 200) =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

const server = Bun.serve({
  port: PORT,
  fetch: async (req) => {
    const url = new URL(req.url)
    const path = url.pathname
    const method = req.method

    // API: Markers
    if (path === '/api/markers' && method === 'GET') {
      const category = url.searchParams.get('category') ?? undefined
      const markers = await getMarkers(category)
      return jsonResponse(markers)
    }

    if (path === '/api/markers' && method === 'POST') {
      const body = await req.json()
      const marker = await addMarker(body)
      return jsonResponse(marker, 201)
    }

    if (path.startsWith('/api/markers/') && method === 'DELETE') {
      const id = path.split('/').pop()!
      const deleted = await deleteMarker(id)
      return deleted
        ? jsonResponse({ ok: true })
        : jsonResponse({ error: 'Not found' }, 404)
    }

    // API: Circles
    if (path === '/api/circles' && method === 'GET') {
      const circles = await getCircles()
      return jsonResponse(circles)
    }

    if (path === '/api/circles' && method === 'POST') {
      const body = await req.json()
      const circle = await addCircle(body)
      return jsonResponse(circle, 201)
    }

    if (path.startsWith('/api/circles/') && method === 'DELETE') {
      const id = path.split('/').pop()!
      const deleted = await deleteCircle(id)
      return deleted
        ? jsonResponse({ ok: true })
        : jsonResponse({ error: 'Not found' }, 404)
    }

    // API: Categories
    if (path === '/api/categories' && method === 'GET') {
      const categories = await getCategories()
      return jsonResponse(categories)
    }

    // API: Search
    if (path === '/api/search' && method === 'GET') {
      const q = url.searchParams.get('q') ?? ''
      if (!q) return jsonResponse([])
      const results = await geocode(q)
      return jsonResponse(results)
    }

    // Main page
    if (path === '/' && method === 'GET') {
      const [markers, circles, categories] = await Promise.all([
        getMarkers(),
        getCircles(),
        getCategories(),
      ])
      const ssr = createSSR()
      const html = ssr(MapPage({ markers, circles, categories }))
      return new Response('<!DOCTYPE html>' + html, {
        headers: { 'Content-Type': 'text/html; charset=utf-8' },
      })
    }

    return jsonResponse({ error: 'Not found' }, 404)
  },
})

