export type Category = "Length" | "Weight" | "Temperature" | "Volume" | "Time";

export type UnitDef = {
  symbol: string;
  name: string;
};

export type ConversionResult = {
  value: number;
  formula: string;
};

// Base-unit factor maps: each unit maps to its factor relative to the base unit
// Length base: meter
const lengthFactors: Record<string, number> = {
  mm: 0.001,
  cm: 0.01,
  m: 1,
  km: 1000,
  in: 0.0254,
  ft: 0.3048,
  yd: 0.9144,
  mi: 1609.344,
};

// Weight base: gram
const weightFactors: Record<string, number> = {
  mg: 0.001,
  g: 1,
  kg: 1000,
  lb: 453.592,
  oz: 28.3495,
};

// Volume base: milliliter
const volumeFactors: Record<string, number> = {
  ml: 1,
  l: 1000,
  gal: 3785.41,
  qt: 946.353,
  pt: 473.176,
  cup: 236.588,
  tbsp: 14.7868,
  tsp: 4.92892,
};

// Time base: second
const timeFactors: Record<string, number> = {
  ms: 0.001,
  s: 1,
  min: 60,
  hr: 3600,
  day: 86400,
  week: 604800,
};

export const categories: Record<Category, UnitDef[]> = {
  Length: [
    { symbol: "mm", name: "Millimeters" },
    { symbol: "cm", name: "Centimeters" },
    { symbol: "m", name: "Meters" },
    { symbol: "km", name: "Kilometers" },
    { symbol: "in", name: "Inches" },
    { symbol: "ft", name: "Feet" },
    { symbol: "yd", name: "Yards" },
    { symbol: "mi", name: "Miles" },
  ],
  Weight: [
    { symbol: "mg", name: "Milligrams" },
    { symbol: "g", name: "Grams" },
    { symbol: "kg", name: "Kilograms" },
    { symbol: "lb", name: "Pounds" },
    { symbol: "oz", name: "Ounces" },
  ],
  Temperature: [
    { symbol: "C", name: "Celsius" },
    { symbol: "F", name: "Fahrenheit" },
    { symbol: "K", name: "Kelvin" },
  ],
  Volume: [
    { symbol: "ml", name: "Milliliters" },
    { symbol: "l", name: "Liters" },
    { symbol: "gal", name: "Gallons" },
    { symbol: "qt", name: "Quarts" },
    { symbol: "pt", name: "Pints" },
    { symbol: "cup", name: "Cups" },
    { symbol: "tbsp", name: "Tablespoons" },
    { symbol: "tsp", name: "Teaspoons" },
  ],
  Time: [
    { symbol: "ms", name: "Milliseconds" },
    { symbol: "s", name: "Seconds" },
    { symbol: "min", name: "Minutes" },
    { symbol: "hr", name: "Hours" },
    { symbol: "day", name: "Days" },
    { symbol: "week", name: "Weeks" },
  ],
};

const factorMaps: Record<string, Record<string, number>> = {
  Length: lengthFactors,
  Weight: weightFactors,
  Volume: volumeFactors,
  Time: timeFactors,
};

const baseUnitNames: Record<string, string> = {
  Length: "m",
  Weight: "g",
  Volume: "ml",
  Time: "s",
};

const formatNumber = (n: number): string => {
  if (Number.isInteger(n)) return n.toString();
  const str = n.toPrecision(10);
  return parseFloat(str).toString();
};

const convertTemperature = (value: number, from: string, to: string): ConversionResult => {
  if (from === to) return { value, formula: `${from} = ${to}` };

  const formulaMap: Record<string, { calc: (v: number) => number; formula: string }> = {
    "C->F": { calc: (v) => v * 9 / 5 + 32, formula: "(C x 9/5) + 32 = F" },
    "C->K": { calc: (v) => v + 273.15, formula: "C + 273.15 = K" },
    "F->C": { calc: (v) => (v - 32) * 5 / 9, formula: "(F - 32) x 5/9 = C" },
    "F->K": { calc: (v) => (v - 32) * 5 / 9 + 273.15, formula: "(F - 32) x 5/9 + 273.15 = K" },
    "K->C": { calc: (v) => v - 273.15, formula: "K - 273.15 = C" },
    "K->F": { calc: (v) => (v - 273.15) * 9 / 5 + 32, formula: "(K - 273.15) x 9/5 + 32 = F" },
  };

  const key = `${from}->${to}`;
  const entry = formulaMap[key];
  if (!entry) return { value: NaN, formula: "Unknown conversion" };

  return { value: entry.calc(value), formula: entry.formula };
};

const convertByFactor = (
  value: number,
  from: string,
  to: string,
  category: string,
): ConversionResult => {
  const factors = factorMaps[category];
  if (!factors || !(from in factors) || !(to in factors)) {
    return { value: NaN, formula: "Unknown conversion" };
  }

  if (from === to) return { value, formula: `${from} = ${to}` };

  const fromFactor = factors[from];
  const toFactor = factors[to];
  const ratio = fromFactor / toFactor;
  const result = value * ratio;
  const base = baseUnitNames[category];

  const formula = `1 ${from} = ${formatNumber(fromFactor)} ${base}, 1 ${to} = ${formatNumber(toFactor)} ${base} => multiply by ${formatNumber(ratio)}`;

  return { value: result, formula };
};

export const convert = (
  value: number,
  from: string,
  to: string,
  category: Category,
): ConversionResult => {
  if (category === "Temperature") {
    return convertTemperature(value, from, to);
  }
  return convertByFactor(value, from, to, category);
};

