const styleToStr = (obj: Record<string, string | number>): string =>
  Object.entries(obj)
    .map(([k, v]) => {
      const prop = k.replace(/[A-Z]/g, (m) => `-${m.toLowerCase()}`);
      return `${prop}:${typeof v === "number" ? `${v}px` : v}`;
    })
    .join(";");

const formatResult = (n: number): string => {
  if (isNaN(n)) return "—";
  if (Number.isInteger(n)) return n.toLocaleString();
  if (Math.abs(n) < 0.0001 || Math.abs(n) > 1e10) return n.toExponential(6);
  return parseFloat(n.toPrecision(10)).toLocaleString(undefined, { maximumFractionDigits: 8 });
};

export const renderConverter = (state: ConverterState): string => {
  const units = categories[state.category];
  const numValue = parseFloat(state.value);
  const hasValue = state.value !== "" && !isNaN(numValue);
  const result = hasValue ? convert(numValue, state.from, state.to, state.category) : null;

  const tabsHtml = categoryList
    .map((cat) => {
      const isActive = cat === state.category;
      const st = isActive ? styles.tabActive : styles.tab;
      return `<button style="${styleToStr(st)}" p-trigger="click:selectCategory" data-category="${cat}">${cat}</button>`;
    })
    .join("");

  const optionsFrom = units
    .map(
      (u) =>
        `<option value="${u.symbol}" ${u.symbol === state.from ? "selected" : ""}>${u.symbol} — ${u.name}</option>`,
    )
    .join("");

  const optionsTo = units
    .map(
      (u) =>
        `<option value="${u.symbol}" ${u.symbol === state.to ? "selected" : ""}>${u.symbol} — ${u.name}</option>`,
    )
    .join("");

  const resultHtml = result
    ? `<div style="${styleToStr(styles.resultBox)}">
        <p style="${styleToStr(styles.resultValue)}">${formatResult(result.value)} ${state.to}</p>
        <p style="${styleToStr(styles.formula)}">${result.formula}</p>
      </div>`
    : "";

  return `<div style="${styleToStr(styles.container)}">
    <h2 style="${styleToStr(styles.title)}">Unit Converter</h2>
    <div style="${styleToStr(styles.tabs)}">${tabsHtml}</div>
    <div style="${styleToStr(styles.inputGroup)}">
      <label style="${styleToStr(styles.label)}">Value</label>
      <input
        type="number"
        style="${styleToStr(styles.input)}"
        value="${state.value}"
        placeholder="Enter a value"
        p-trigger="input:updateValue"
        p-target="valueInput"
      />
    </div>
    <div style="${styleToStr(styles.row)}">
      <div style="${styleToStr(styles.col)}">
        <label style="${styleToStr(styles.label)}">From</label>
        <select style="${styleToStr(styles.select)}" p-trigger="change:updateFrom" p-target="fromSelect">
          ${optionsFrom}
        </select>
      </div>
      <button style="${styleToStr(styles.swapBtn)}" p-trigger="click:swapUnits" title="Swap units">&#8646;</button>
      <div style="${styleToStr(styles.col)}">
        <label style="${styleToStr(styles.label)}">To</label>
        <select style="${styleToStr(styles.select)}" p-trigger="change:updateTo" p-target="toSelect">
          ${optionsTo}
        </select>
      </div>
    </div>
    ${resultHtml}
  </div>`;
};

export const getDefaultState = (category: Category = "Length"): ConverterState => {
  const units = categories[category];
  return {
    category,
    value: "",
    from: units[0].symbol,
    to: units.length > 1 ? units[1].symbol : units[0].symbol,
  };
};

import { type Category, categories, convert } from "./converter.ts";
import { renderConverter, getDefaultState } from "./ui.ts";

type ConverterState = {
  category: Category;
  value: string;
  from: string;
  to: string;
};

let state: ConverterState = getDefaultState();

const handlers: Record<string, (payload: Record<string, string>) => void> = {
  selectCategory: (payload) => {
    const cat = payload.category as Category;
    if (cat && cat in categories) {
      state = getDefaultState(cat);
    }
  },
  updateValue: (payload) => {
    state = { ...state, value: payload.value ?? "" };
  },
  updateFrom: (payload) => {
    state = { ...state, from: payload.value ?? state.from };
  },
  updateTo: (payload) => {
    state = { ...state, to: payload.value ?? state.to };
  },
  swapUnits: () => {
    state = { ...state, from: state.to, to: state.from };
  },
};

export const handleEvent = (action: string, payload: Record<string, string> = {}): string => {
  const handler = handlers[action];
  if (handler) handler(payload);
  return renderConverter(state);
};

export const render = (): string => renderConverter(state);

export const convertValue = (
  value: number,
  from: string,
  to: string,
  category: Category,
) => convert(value, from, to, category);

