const formatNumber = (n: number): number => {
  return Math.abs(n) < 0.0001 && n !== 0
    ? parseFloat(n.toExponential(6))
    : parseFloat(n.toPrecision(10))
}

const getTemperatureFormula = (from: string, to: string): string => {
  const formulas: Record<string, string> = {
    'C→F': '°F = °C × 9/5 + 32',
    'F→C': '°C = (°F − 32) × 5/9',
    'C→K': 'K = °C + 273.15',
    'K→C': '°C = K − 273.15',
    'F→K': 'K = (°F − 32) × 5/9 + 273.15',
    'K→F': '°F = (K − 273.15) × 9/5 + 32',
  }
  const key = `${from}→${to}`
  return formulas[key] ?? `${from} = ${to}`
}

const getStandardFormula = (
  from: string,
  to: string,
  cat: CategoryDefinition,
  value: number,
  result: number,
): string => {
  const fromFactor = cat.toBase[from]!(1)
  const toFactor = cat.fromBase[to]!(1)
  const combinedFactor = fromFactor * toFactor

  if (combinedFactor === 1) {
    return `${value} ${from} = ${result} ${to}`
  }

  return `${value} ${from} × ${formatNumber(combinedFactor)} = ${formatNumber(result)} ${to}`
}

export const convert = (value: number, fromUnit: string, toUnit: string): ConversionResult => {
  let category: Category | undefined
  for (const [cat, def] of Object.entries(categories)) {
    const symbols = def.units.map((u) => u.symbol)
    if (symbols.includes(fromUnit) && symbols.includes(toUnit)) {
      category = cat as Category
      break
    }
  }

  if (!category) {
    return { result: NaN, formula: 'Incompatible units' }
  }

  if (fromUnit === toUnit) {
    return { result: value, formula: `${value} ${fromUnit} = ${value} ${toUnit}` }
  }

  const cat = categories[category]
  const baseValue = cat.toBase[fromUnit]!(value)
  const result = formatNumber(cat.fromBase[toUnit]!(baseValue))

  const formula =
    category === 'Temperature'
      ? getTemperatureFormula(fromUnit, toUnit)
      : getStandardFormula(fromUnit, toUnit, cat, value, result)

  return { result, formula }
}

export const getCategories = (): Category[] =>
  Object.keys(categories) as Category[]

export const getUnits = (category: Category): UnitDefinition[] =>
  categories[category]?.units ?? []

