import { renderConverter } from './ui.js'
import { convert } from './converter.js'
import type { Category } from './converter.js'

type ServerState = {
  activeCategory: Category
  value: string
  fromUnit?: string
  toUnit?: string
}

export const createServer = () => {
  const state: ServerState = {
    activeCategory: 'Length',
    value: '1',
  }

  const handleRequest = (req: Request): Response => {
    const url = new URL(req.url)

    if (url.pathname === '/api/convert') {
      const value = parseFloat(url.searchParams.get('value') ?? '0')
      const from = url.searchParams.get('from') ?? ''
      const to = url.searchParams.get('to') ?? ''
      const result = convert(value, from, to)
      return new Response(JSON.stringify(result), {
        headers: { 'Content-Type': 'application/json' },
      })
    }

    if (url.pathname === '/api/render') {
      const category = (url.searchParams.get('category') as Category) ?? state.activeCategory
      const value = url.searchParams.get('value') ?? state.value
      const from = url.searchParams.get('from') ?? undefined
      const to = url.searchParams.get('to') ?? undefined

      state.activeCategory = category
      state.value = value
      state.fromUnit = from
      state.toUnit = to

      const html = renderConverter(category, value, from, to)
      return new Response(html, {
        headers: { 'Content-Type': 'text/html' },
      })
    }

    const html = `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Unit Converter</title>
  <style>
    body { margin: 0; padding: 24px; background: #f4f4f8; min-height: 100vh; }
  </style>
</head>
<body>
  ${renderConverter(state.activeCategory, state.value, state.fromUnit, state.toUnit)}
</body>
</html>`

    return new Response(html, {
      headers: { 'Content-Type': 'text/html' },
    })
  }

  return { handleRequest }
}

export const serve = () => {
  const { handleRequest } = createServer()
  return Bun.serve({
    port: 3000,
    fetch: handleRequest,
  })
}

