const factorTables: Record<string, Record<string, number>> = {
  length: lengthToBase,
  weight: weightToBase,
  volume: volumeToBase,
  time: timeToBase,
};

const convertTemperature = (value: number, from: string, to: string): ConversionResult => {
  if (from === to) {
    return { value, formula: `${from} = ${to}`, fromUnit: from, toUnit: to };
  }

  const formulas: Record<string, { calc: (v: number) => number; formula: string }> = {
    "C->F": { calc: (v) => v * 9 / 5 + 32, formula: "(C * 9/5) + 32 = F" },
    "C->K": { calc: (v) => v + 273.15, formula: "C + 273.15 = K" },
    "F->C": { calc: (v) => (v - 32) * 5 / 9, formula: "(F - 32) * 5/9 = C" },
    "F->K": { calc: (v) => (v - 32) * 5 / 9 + 273.15, formula: "(F - 32) * 5/9 + 273.15 = K" },
    "K->C": { calc: (v) => v - 273.15, formula: "K - 273.15 = C" },
    "K->F": { calc: (v) => (v - 273.15) * 9 / 5 + 32, formula: "(K - 273.15) * 9/5 + 32 = F" },
  };

  const key = `${from}->${to}`;
  const entry = formulas[key];

  if (!entry) {
    return { value: NaN, formula: "Unknown conversion", fromUnit: from, toUnit: to };
  }

  return {
    value: entry.calc(value),
    formula: entry.formula,
    fromUnit: from,
    toUnit: to,
  };
};

const convertWithFactors = (
  value: number,
  from: string,
  to: string,
  table: Record<string, number>,
): ConversionResult => {
  if (from === to) {
    return { value, formula: `1 ${from} = 1 ${to}`, fromUnit: from, toUnit: to };
  }

  const fromFactor = table[from];
  const toFactor = table[to];

  if (fromFactor === undefined || toFactor === undefined) {
    return { value: NaN, formula: "Unknown unit", fromUnit: from, toUnit: to };
  }

  const result = value * (fromFactor / toFactor);
  const ratio = fromFactor / toFactor;

  return {
    value: result,
    formula: `1 ${from} = ${formatNumber(ratio)} ${to}`,
    fromUnit: from,
    toUnit: to,
  };
};

export const formatNumber = (n: number): string => {
  if (Number.isNaN(n)) return "NaN";
  if (!Number.isFinite(n)) return "Infinity";
  if (n === 0) return "0";

  const abs = Math.abs(n);
  if (abs >= 0.01 && abs < 1e12) {
    const str = n.toPrecision(10);
    return parseFloat(str).toString();
  }
  return n.toExponential(6);
};

export const convert = (
  category: Category,
  value: number,
  from: string,
  to: string,
): ConversionResult => {
  if (category === "temperature") {
    return convertTemperature(value, from, to);
  }

  const table = factorTables[category];
  if (!table) {
    return { value: NaN, formula: "Unknown category", fromUnit: from, toUnit: to };
  }

  return convertWithFactors(value, from, to, table);
};

