const styleToString = (style: Record<string, string | number>): string =>
  Object.entries(style)
    .map(([key, val]) => {
      const cssKey = key.replace(/[A-Z]/g, (m) => `-${m.toLowerCase()}`);
      const cssVal = typeof val === "number" ? `${val}px` : val;
      return `${cssKey}: ${cssVal}`;
    })
    .join("; ");

const renderSelect = (
  label: string,
  name: string,
  units: { symbol: string; name: string }[],
  selected: string,
): string => {
  const options = units
    .map(
      (u) =>
        h("option", { value: u.symbol, ...(u.symbol === selected ? { selected: "selected" } : {}) },
          `${u.symbol} — ${u.name}`,
        ),
    )
    .join("");

  return `<div style="${styleToString(styles.selectWrapper)}">
    <label style="${styleToString(styles.label)}">${label}</label>
    <select name="${name}" style="${styleToString(styles.select)}" p-trigger="change:onUnitChange">${options}</select>
  </div>`;
};

export const renderConverter = (state: ConverterState = defaultState): string => {
  const cat = categories[state.category];
  const numValue = parseFloat(state.value);
  const hasValidInput = !Number.isNaN(numValue);

  const result = hasValidInput
    ? convert(state.category, numValue, state.fromUnit, state.toUnit)
    : null;

  const tabsHtml = (Object.keys(categories) as Category[])
    .map((key) => {
      const isActive = key === state.category;
      const tabStyle = isActive ? styles.tabActive : styles.tab;
      return `<button
        style="${styleToString(tabStyle)}"
        p-trigger="click:onCategoryChange"
        data-category="${key}"
      >${categories[key].label}</button>`;
    })
    .join("");

  const resultHtml = result
    ? `<div style="${styleToString(styles.resultBox)}">
        <p style="${styleToString(styles.resultValue)}" p-target="result">
          ${formatNumber(result.value)} ${state.toUnit}
        </p>
        <p style="${styleToString(styles.formula)}" p-target="formula">
          ${result.formula}
        </p>
