import type { CalendarEvent } from './types';

const DATA_PATH = `${import.meta.dir}/data/events.json`;

export const loadEvents = async (): Promise<CalendarEvent[]> => {
  const file = Bun.file(DATA_PATH);
  const exists = await file.exists();
  if (!exists) {
    await Bun.write(DATA_PATH, '[]');
    return [];
  }
  const text = await file.text();
  return JSON.parse(text) as CalendarEvent[];
};

export const saveEvents = async (events: CalendarEvent[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(events, null, 2));
};

import type { CalendarEvent, Recurrence } from './types';

const parseDate = (dateStr: string): Date => {
  const [year, month, day] = dateStr.split('-').map(Number);
  return new Date(year, month - 1, day);
};

const formatDate = (d: Date): string => {
  const y = d.getFullYear();
  const m = String(d.getMonth() + 1).padStart(2, '0');
  const day = String(d.getDate()).padStart(2, '0');
  return `${y}-${m}-${day}`;
};

const matchesDaily = (eventDate: string, targetDate: string): boolean => {
  return parseDate(targetDate) >= parseDate(eventDate);
};

const matchesWeekly = (eventDate: string, targetDate: string): boolean => {
  const event = parseDate(eventDate);
  const target = parseDate(targetDate);
  if (target < event) return false;
  const diffDays = Math.round((target.getTime() - event.getTime()) / (1000 * 60 * 60 * 24));
  return diffDays % 7 === 0;
};

const matchesMonthly = (eventDate: string, targetDate: string): boolean => {
  const event = parseDate(eventDate);
  const target = parseDate(targetDate);
  if (target < event) return false;
  return target.getDate() === event.getDate();
};

export const eventOccursOnDate = (event: CalendarEvent, targetDate: string): boolean => {
  if (event.date === targetDate) return true;

  switch (event.recurrence) {
    case 'none':
      return false;
    case 'daily':
      return matchesDaily(event.date, targetDate);
    case 'weekly':
      return matchesWeekly(event.date, targetDate);
    case 'monthly':
      return matchesMonthly(event.date, targetDate);
    default:
      return false;
  }
};

export const getEventsForDate = (events: CalendarEvent[], targetDate: string): CalendarEvent[] => {
  return events.filter((event) => eventOccursOnDate(event, targetDate));
};

import type { CalendarEvent, CalendarDay, MonthGrid } from './types';
import { getEventsForDate } from './recurrence';

const MONTH_NAMES = [
  'January', 'February', 'March', 'April', 'May', 'June',
  'July', 'August', 'September', 'October', 'November', 'December',
];

const formatDate = (d: Date): string => {
  const y = d.getFullYear();
  const m = String(d.getMonth() + 1).padStart(2, '0');
  const day = String(d.getDate()).padStart(2, '0');
  return `${y}-${m}-${day}`;
};

const getTodayStr = (): string => formatDate(new Date());

export const buildMonthGrid = (year: number, month: number, events: CalendarEvent[]): MonthGrid => {
  const firstDay = new Date(year, month, 1);
  const startDow = firstDay.getDay(); // 0=Sun
  const daysInMonth = new Date(year, month + 1, 0).getDate();
  const todayStr = getTodayStr();

  // Build flat list of day cells including leading/trailing days from adjacent months
  const days: CalendarDay[] = [];

  // Leading days from previous month
  const prevMonthDays = new Date(year, month, 0).getDate();
  for (let i = startDow - 1; i >= 0; i--) {
    const d = new Date(year, month - 1, prevMonthDays - i);
    const dateStr = formatDate(d);
    days.push({
      date: dateStr,
      dayOfMonth: d.getDate(),
      isCurrentMonth: false,
      isToday: dateStr === todayStr,
      events: getEventsForDate(events, dateStr),
    });
  }

  // Current month days
  for (let day = 1; day <= daysInMonth; day++) {
    const d = new Date(year, month, day);
    const dateStr = formatDate(d);
    days.push({
      date: dateStr,
      dayOfMonth: day,
      isCurrentMonth: true,
      isToday: dateStr === todayStr,
      events: getEventsForDate(events, dateStr),
    });
  }

  // Trailing days to complete final week
  const remaining = 7 - (days.length % 7);
  if (remaining < 7) {
    for (let i = 1; i <= remaining; i++) {
      const d = new Date(year, month + 1, i);
      const dateStr = formatDate(d);
      days.push({
        date: dateStr,
        dayOfMonth: i,
        isCurrentMonth: false,
        isToday: dateStr === todayStr,
        events: getEventsForDate(events, dateStr),
      });
    }
  }

  // Chunk into weeks
  const weeks: CalendarDay[][] = [];
  for (let i = 0; i < days.length; i += 7) {
    weeks.push(days.slice(i, i + 7));
  }

  return {
    year,
    month,
    label: `${MONTH_NAMES[month]} ${year}`,
    weeks,
  };
};

export const navigateMonth = (year: number, month: number, delta: number): { year: number; month: number } => {
  const d = new Date(year, month + delta, 1);
  return { year: d.getFullYear(), month: d.getMonth() };
};

import type { CalendarEvent, CreateEventInput, UpdateEventInput } from './types';
import { loadEvents, saveEvents } from './store';

const generateId = (): string => crypto.randomUUID();

const now = (): string => new Date().toISOString();

export const createEvent = async (input: CreateEventInput): Promise<CalendarEvent> => {
  const events = await loadEvents();

  if (!input.title.trim()) throw new Error('Title is required');
  if (!input.date) throw new Error('Date is required');
  if (!input.startTime) throw new Error('Start time is required');
  if (!input.endTime) throw new Error('End time is required');
  if (input.startTime >= input.endTime) throw new Error('Start time must be before end time');

  const event: CalendarEvent = {
    id: generateId(),
    title: input.title.trim(),
    date: input.date,
    startTime: input.startTime,
    endTime: input.endTime,
    description: input.description?.trim() ?? '',
    category: input.category ?? 'personal',
    recurrence: input.recurrence ?? 'none',
    createdAt: now(),
    updatedAt: now(),
  };

  events.push(event);
  await saveEvents(events);
  return event;
};

export const updateEvent = async (id: string, input: UpdateEventInput): Promise<CalendarEvent> => {
  const events = await loadEvents();
  const idx = events.findIndex((e) => e.id === id);
  if (idx === -1) throw new Error(`Event not found: ${id}`);

  if (input.startTime && input.endTime && input.startTime >= input.endTime) {
    throw new Error('Start time must be before end time');
  }

  const existing = events[idx];
  const startTime = input.startTime ?? existing.startTime;
  const endTime = input.endTime ?? existing.endTime;
  if (startTime >= endTime) throw new Error('Start time must be before end time');

  const updated: CalendarEvent = {
    ...existing,
    title: input.title?.trim() ?? existing.title,
    date: input.date ?? existing.date,
    startTime,
    endTime,
    description: input.description?.trim() ?? existing.description,
    category: input.category ?? existing.category,
    recurrence: input.recurrence ?? existing.recurrence,
    updatedAt: now(),
  };

  events[idx] = updated;
  await saveEvents(events);
  return updated;
};

export const deleteEvent = async (id: string): Promise<void> => {
  const events = await loadEvents();
  const idx = events.findIndex((e) => e.id === id);
  if (idx === -1) throw new Error(`Event not found: ${id}`);
  events.splice(idx, 1);
  await saveEvents(events);
};

export const getEvent = async (id: string): Promise<CalendarEvent | undefined> => {
  const events = await loadEvents();
  return events.find((e) => e.id === id);
};

export const listEvents = async (): Promise<CalendarEvent[]> => {
  return loadEvents();
};

export const listEventsByCategory = async (category: string): Promise<CalendarEvent[]> => {
  const events = await loadEvents();
  return events.filter((e) => e.category === category);
};

