const styleToStr = (s: Record<string, string | number>): string =>
  Object.entries(s)
    .map(([k, v]) => {
      const prop = k.replace(/[A-Z]/g, (m) => `-${m.toLowerCase()}`);
      return `${prop}:${typeof v === 'number' ? `${v}px` : v}`;
    })
    .join(';');

export const renderCategoryLegend = () =>
  h('div', { style: styleToStr(styles.categoryLegend) },
    ...Object.entries(CATEGORY_COLORS).map(([cat, color]) =>
      h('span', { style: styleToStr(styles.legendItem(color)) },
        h('span', { style: styleToStr(styles.legendDot(color)) }),
        cat,
      ),
    ),
  );

