const renderDayCell = (day: CalendarDay) => {
  const cellStyle = day.isToday
    ? styles.dayCellToday
    : day.isCurrentMonth
      ? styles.dayCell
      : styles.dayCellMuted;

  const numStyle = day.isToday ? styles.dayNumberToday : styles.dayNumber;

  const maxPills = 2;
  const visibleEvents = day.events.slice(0, maxPills);
  const overflow = day.events.length - maxPills;

  return h('div', {
      style: styleToStr(cellStyle),
      'p-trigger': 'click:selectDay',
      'data-date': day.date,
    },
    h('div', { style: styleToStr(numStyle) }, String(day.dayOfMonth)),
    ...visibleEvents.map((evt) =>
      h('div', {
        style: styleToStr(styles.eventPill(CATEGORY_COLORS[evt.category])),
      }, evt.title),
    ),
    ...(overflow > 0
      ? [h('div', { style: 'font-size:10px;color:#9CA3AF' }, `+${overflow} more`)]
      : []),
  );
};

export const renderDayView = (dateStr: string, events: CalendarEvent[]) => {
  const dateLabel = new Date(dateStr + 'T00:00:00').toLocaleDateString('en-US', {
    weekday: 'long',
    year: 'numeric',
    month: 'long',
    day: 'numeric',
  });

  const sorted = [...events].sort((a, b) => a.startTime.localeCompare(b.startTime));

  return h('div', { style: styleToStr(styles.container) },
    h('div', { style: styleToStr(styles.dayViewHeader) },
      h('button', {
        style: styleToStr(styles.backBtn),
        'p-trigger': 'click:backToMonth',
      }, 'Back to Month'),
      h('span', { style: styleToStr(styles.dayViewDate) }, dateLabel),
      h('button', {
        style: styleToStr(styles.submitBtn),
        'p-trigger': 'click:showCreateForm',
      }, '+ New Event'),
    ),
    ...(sorted.length === 0
      ? [h('div', { style: styleToStr(styles.emptyState) }, 'No events scheduled for this day')]
      : sorted.map((evt) => renderEventCard(evt))),
  );
};

