import { createEvent, updateEvent, deleteEvent, getEvent, listEvents } from './events';
import { renderMonthView, renderDayView, renderEventForm } from './views';

const today = new Date();

const state: ViewState = {
  mode: 'month',
  year: today.getFullYear(),
  month: today.getMonth(),
  selectedDate: null,
};

const formatDate = (d: Date): string => {
  const y = d.getFullYear();
  const m = String(d.getMonth() + 1).padStart(2, '0');
  const day = String(d.getDate()).padStart(2, '0');
  return `${y}-${m}-${day}`;
};

export const renderCurrentView = async (): Promise<string> => {
  const ssr = createSSR();
  const events = await listEvents();

  if (state.mode === 'month') {
    const grid = buildMonthGrid(state.year, state.month, events);
    return ssr(renderMonthView(grid));
  }

  if (state.mode === 'day' && state.selectedDate) {
    const dayEvents = getEventsForDate(events, state.selectedDate);
    return ssr(renderDayView(state.selectedDate, dayEvents));
  }

  return '';
};

export const renderCreateForm = async (dateStr?: string): Promise<string> => {
  const ssr = createSSR();
  const date = dateStr ?? state.selectedDate ?? formatDate(today);
  return ssr(renderEventForm(date));
};

export const renderEditForm = async (eventId: string): Promise<string> => {
  const ssr = createSSR();
  const event = await getEvent(eventId);
  if (!event) throw new Error(`Event not found: ${eventId}`);
  return ssr(renderEventForm(event.date, event));
};

// Navigation actions
export const goToMonth = (year: number, month: number) => {
  state.mode = 'month';
  state.year = year;
  state.month = month;
  state.selectedDate = null;
};

export const goToPrevMonth = () => {
  const { year, month } = navigateMonth(state.year, state.month, -1);
  goToMonth(year, month);
};

export const goToNextMonth = () => {
  const { year, month } = navigateMonth(state.year, state.month, 1);
  goToMonth(year, month);
};

export const goToToday = () => {
  const now = new Date();
  goToMonth(now.getFullYear(), now.getMonth());
};

export const selectDay = (dateStr: string) => {
  state.mode = 'day';
  state.selectedDate = dateStr;
  // Set year/month to match selected date for back-navigation
  const [y, m] = dateStr.split('-').map(Number);
  state.year = y;
  state.month = m - 1;
};

export const backToMonth = () => {
  state.mode = 'month';
  state.selectedDate = null;
};

// Event CRUD wrappers
export const handleCreateEvent = async (input: CreateEventInput) => {
  const event = await createEvent(input);
  selectDay(event.date);
  return event;
};

export const handleUpdateEvent = async (id: string, input: UpdateEventInput) => {
  const event = await updateEvent(id, input);
  selectDay(event.date);
  return event;
};

export const handleDeleteEvent = async (id: string) => {
  const event = await getEvent(id);
  await deleteEvent(id);
  if (event && state.selectedDate) {
    // Stay on the same day view
    selectDay(state.selectedDate);
  }
};

// Filtering
export const filterByCategory = async (category: EventCategory) => {
  const events = await listEvents();
  return events.filter((e) => e.category === category);
};

// Get current view state (useful for clients)
export const getViewState = (): ViewState => ({ ...state });

