import type { CalendarEvent, RecurrenceRule } from './types'

const DATA_PATH = `${import.meta.dir}/data/events.jsonl`

const generateId = (): string => crypto.randomUUID()

const readEvents = async (): Promise<CalendarEvent[]> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) return []
  const text = await file.text()
  return text
    .trim()
    .split('\n')
    .filter(Boolean)
    .map((line) => JSON.parse(line) as CalendarEvent)
}

const writeEvents = async (events: CalendarEvent[]): Promise<void> => {
  const content = events.map((e) => JSON.stringify(e)).join('\n')
  await Bun.write(DATA_PATH, content + (content ? '\n' : ''))
}

export const getAllEvents = async (): Promise<CalendarEvent[]> => {
  return readEvents()
}

export const getEventsForDate = async (date: string): Promise<CalendarEvent[]> => {
  const events = await readEvents()
  return events.filter((event) => {
    if (event.date === date) return true
    if (event.recurrence) return matchesRecurrence(event, date)
    return false
  })
}

export const getEventsForMonth = async (year: number, month: number): Promise<CalendarEvent[]> => {
  const events = await readEvents()
  const daysInMonth = new Date(year, month + 1, 0).getDate()
  const matchingEvents: CalendarEvent[] = []

  for (let day = 1; day <= daysInMonth; day++) {
    const dateStr = formatDate(year, month, day)
    for (const event of events) {
      if (event.date === dateStr || matchesRecurrence(event, dateStr)) {
        if (!matchingEvents.some((e) => e.id === event.id && e.date === dateStr)) {
          matchingEvents.push({ ...event, date: dateStr })
        }
      }
    }
  }

  return matchingEvents
}

export const createEvent = async (
  data: Omit<CalendarEvent, 'id' | 'createdAt' | 'updatedAt'>
): Promise<CalendarEvent> => {
  const events = await readEvents()
  const now = new Date().toISOString()
  const event: CalendarEvent = {
    ...data,
    id: generateId(),
    createdAt: now,
    updatedAt: now,
  }
  events.push(event)
  await writeEvents(events)
  return event
}

export const updateEvent = async (
  id: string,
  data: Partial<Omit<CalendarEvent, 'id' | 'createdAt' | 'updatedAt'>>
): Promise<CalendarEvent | null> => {
  const events = await readEvents()
  const index = events.findIndex((e) => e.id === id)
  if (index === -1) return null
  events[index] = {
    ...events[index],
    ...data,
    updatedAt: new Date().toISOString(),
  }
  await writeEvents(events)
  return events[index]
}

export const deleteEvent = async (id: string): Promise<boolean> => {
  const events = await readEvents()
  const filtered = events.filter((e) => e.id !== id)
  if (filtered.length === events.length) return false
  await writeEvents(filtered)
  return true
}

const formatDate = (year: number, month: number, day: number): string => {
  const m = String(month + 1).padStart(2, '0')
  const d = String(day).padStart(2, '0')
  return `${year}-${m}-${d}`
}

const matchesRecurrence = (event: CalendarEvent, targetDate: string): boolean => {
  if (!event.recurrence) return false

  const eventDate = new Date(event.date + 'T00:00:00')
  const target = new Date(targetDate + 'T00:00:00')

  if (target < eventDate) return false

  if (event.recurrenceEndDate) {
    const endDate = new Date(event.recurrenceEndDate + 'T00:00:00')
    if (target > endDate) return false
  }

  return checkRecurrenceMatch(event.recurrence, eventDate, target)
}

const checkRecurrenceMatch = (rule: RecurrenceRule, eventDate: Date, target: Date): boolean => {
  switch (rule) {
    case 'daily':
      return true
    case 'weekly': {
      return eventDate.getDay() === target.getDay()
    }
    case 'monthly': {
      return eventDate.getDate() === target.getDate()
    }
    default:
      return false
  }
}

import type { DayCell, CalendarEvent } from './types'

export const getMonthName = (month: number): string => {
  const names = [
    'January', 'February', 'March', 'April', 'May', 'June',
    'July', 'August', 'September', 'October', 'November', 'December',
  ]
  return names[month]
}

export const getDayNames = (): string[] => ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat']

export const getDaysInMonth = (year: number, month: number): number =>
  new Date(year, month + 1, 0).getDate()

export const getFirstDayOfMonth = (year: number, month: number): number =>
  new Date(year, month, 1).getDay()

export const formatDateStr = (year: number, month: number, day: number): string => {
  const m = String(month + 1).padStart(2, '0')
  const d = String(day).padStart(2, '0')
  return `${year}-${m}-${d}`
}

export const buildMonthGrid = (
  year: number,
  month: number,
  events: CalendarEvent[]
): DayCell[][] => {
  const daysInMonth = getDaysInMonth(year, month)
  const firstDay = getFirstDayOfMonth(year, month)
  const today = new Date()
  const todayStr = formatDateStr(today.getFullYear(), today.getMonth(), today.getDate())

  const prevMonth = month === 0 ? 11 : month - 1
  const prevYear = month === 0 ? year - 1 : year
  const daysInPrevMonth = getDaysInMonth(prevYear, prevMonth)

  const cells: DayCell[] = []

  // Previous month trailing days
  for (let i = firstDay - 1; i >= 0; i--) {
    const day = daysInPrevMonth - i
    const dateStr = formatDateStr(prevYear, prevMonth, day)
    cells.push({
      date: dateStr,
      day,
      isCurrentMonth: false,
      isToday: dateStr === todayStr,
      events: events.filter((e) => e.date === dateStr),
    })
  }

  // Current month days
  for (let day = 1; day <= daysInMonth; day++) {
    const dateStr = formatDateStr(year, month, day)
    cells.push({
      date: dateStr,
      day,
      isCurrentMonth: true,
      isToday: dateStr === todayStr,
      events: events.filter((e) => e.date === dateStr),
    })
  }

  // Next month leading days
  const nextMonth = month === 11 ? 0 : month + 1
  const nextYear = month === 11 ? year + 1 : year
  const remaining = 42 - cells.length
  for (let day = 1; day <= remaining; day++) {
    const dateStr = formatDateStr(nextYear, nextMonth, day)
    cells.push({
      date: dateStr,
      day,
      isCurrentMonth: false,
      isToday: dateStr === todayStr,
      events: events.filter((e) => e.date === dateStr),
    })
  }

  // Split into weeks
  const weeks: DayCell[][] = []
  for (let i = 0; i < cells.length; i += 7) {
    weeks.push(cells.slice(i, i + 7))
  }
  return weeks
}

export const sortEventsByTime = (events: CalendarEvent[]): CalendarEvent[] =>
  [...events].sort((a, b) => a.startTime.localeCompare(b.startTime))

export const formatTime12h = (time24: string): string => {
  const [hStr, mStr] = time24.split(':')
  let h = parseInt(hStr, 10)
  const period = h >= 12 ? 'PM' : 'AM'
  if (h === 0) h = 12
  else if (h > 12) h -= 12
  return `${h}:${mStr} ${period}`
}

export const navigateMonth = (
  year: number,
  month: number,
  direction: 'prev' | 'next'
): { year: number; month: number } => {
  if (direction === 'prev') {
    return month === 0 ? { year: year - 1, month: 11 } : { year, month: month - 1 }
  }
  return month === 11 ? { year: year + 1, month: 0 } : { year, month: month + 1 }
}

export const parseDate = (dateStr: string): { year: number; month: number; day: number } => {
  const [y, m, d] = dateStr.split('-').map(Number)
  return { year: y, month: m - 1, day: d }
}

