import type { CalendarEvent, CalendarState, EventCategory, RecurrenceRule } from './types'
import { navigateMonth, parseDate } from './calendar'
import { createEvent, updateEvent, deleteEvent, getAllEvents, getEventsForDate } from './store'
import { renderMonthView, renderDayView, renderEventForm } from './render'

export type { CalendarEvent, CalendarState, EventCategory, RecurrenceRule }

const createInitialState = (): CalendarState => {
  const now = new Date()
  return {
    view: 'month',
    selectedDate: now.toISOString().split('T')[0],
    currentMonth: now.getMonth(),
    currentYear: now.getFullYear(),
  }
}

let state = createInitialState()

export const getState = (): CalendarState => ({ ...state })

export const setState = (partial: Partial<CalendarState>): void => {
  state = { ...state, ...partial }
}

// --- Actions ---

export const goToPrevMonth = (): void => {
  const { year, month } = navigateMonth(state.currentYear, state.currentMonth, 'prev')
  state.currentYear = year
  state.currentMonth = month
}

export const goToNextMonth = (): void => {
  const { year, month } = navigateMonth(state.currentYear, state.currentMonth, 'next')
  state.currentYear = year
  state.currentMonth = month
}

export const selectDay = (dateStr: string): void => {
  const { year, month } = parseDate(dateStr)
  state.selectedDate = dateStr
  state.currentYear = year
  state.currentMonth = month
  state.view = 'day'
}

export const backToMonth = (): void => {
  state.view = 'month'
}

export const goToToday = (): void => {
  const now = new Date()
  state.currentYear = now.getFullYear()
  state.currentMonth = now.getMonth()
  state.selectedDate = now.toISOString().split('T')[0]
}

// --- Event CRUD ---

export const addEvent = async (data: {
  title: string
  date: string
  startTime: string
  endTime: string
  description: string
  category: EventCategory
  recurrence: RecurrenceRule
  recurrenceEndDate: string | null
}): Promise<CalendarEvent> => {
  return createEvent(data)
}

export const editEvent = async (
  id: string,
  data: Partial<Omit<CalendarEvent, 'id' | 'createdAt' | 'updatedAt'>>
): Promise<CalendarEvent | null> => {
  return updateEvent(id, data)
}

export const removeEvent = async (id: string): Promise<boolean> => {
  return deleteEvent(id)
}

export const listAllEvents = async (): Promise<CalendarEvent[]> => {
  return getAllEvents()
}

export const listEventsForDate = async (date: string): Promise<CalendarEvent[]> => {
  return getEventsForDate(date)
}

// --- Rendering ---

export const render = async (): Promise<string> => {
  if (state.view === 'day') {
    return renderDayView(state.selectedDate)
  }
  return renderMonthView(state.currentYear, state.currentMonth)
}

export const renderForm = (event?: CalendarEvent): string => {
  return renderEventForm(event, state.selectedDate)
}

{
  "name": "@node/calendar",
  "version": "1.0.0",
  "description": "Scheduling and calendar module with monthly grid, day view, event management, and recurrence support",
  "modnet": {
