import type { CalendarEvent, EventFormData, RecurrenceRule } from './types'

const DATA_PATH = new URL('./data/events.json', import.meta.url).pathname

const generateId = (): string =>
  crypto.randomUUID()

export const loadEvents = async (): Promise<CalendarEvent[]> => {
  const file = Bun.file(DATA_PATH)
  const exists = await file.exists()
  if (!exists) return []
  const text = await file.text()
  return JSON.parse(text) as CalendarEvent[]
}

export const saveEvents = async (events: CalendarEvent[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(events, null, 2))
}

export const createEvent = async (form: EventFormData): Promise<CalendarEvent> => {
  const events = await loadEvents()
  const seriesId = form.recurrence !== 'none' ? generateId() : null
  const newEvent: CalendarEvent = {
    id: generateId(),
    ...form,
    seriesId,
  }
  events.push(newEvent)
  await saveEvents(events)
  return newEvent
}

export const updateEvent = async (
  id: string,
  updates: Partial<EventFormData>,
  updateSeries: boolean = false,
): Promise<CalendarEvent | null> => {
  const events = await loadEvents()
  const index = events.findIndex((e) => e.id === id)
  if (index === -1) return null

  if (updateSeries && events[index].seriesId) {
    const seriesId = events[index].seriesId
    for (let i = 0; i < events.length; i++) {
      if (events[i].seriesId === seriesId) {
        events[i] = { ...events[i], ...updates }
      }
    }
  } else {
    events[index] = { ...events[index], ...updates }
    // If editing a single occurrence, detach from series
    if (events[index].seriesId && !updateSeries) {
      events[index].seriesId = null
      events[index].recurrence = 'none'
    }
  }

  await saveEvents(events)
  return events[index]
}

export const deleteEvent = async (
  id: string,
  deleteSeries: boolean = false,
): Promise<boolean> => {
  const events = await loadEvents()
  const target = events.find((e) => e.id === id)
  if (!target) return false

  let filtered: CalendarEvent[]
  if (deleteSeries && target.seriesId) {
    filtered = events.filter((e) => e.seriesId !== target.seriesId)
  } else {
    filtered = events.filter((e) => e.id !== id)
  }

  await saveEvents(filtered)
  return true
}

export const getEventsForDate = async (dateStr: string): Promise<CalendarEvent[]> => {
  const events = await loadEvents()
  const matching = events.filter((e) => e.date === dateStr)
  return matching.sort((a, b) => a.startTime.localeCompare(b.startTime))
}

export const getEventsForMonth = async (
  year: number,
  month: number,
): Promise<Map<string, CalendarEvent[]>> => {
  const events = await loadEvents()
  const map = new Map<string, CalendarEvent[]>()

  const monthStr = String(month + 1).padStart(2, '0')
  const prefix = `${year}-${monthStr}`

  for (const event of events) {
    if (event.date.startsWith(prefix)) {
      const existing = map.get(event.date) ?? []
      existing.push(event)
      map.set(event.date, existing)
    }
  }

  return map
}

/** Expand a recurring event into concrete occurrences over a date range */
export const expandRecurrences = (
  events: CalendarEvent[],
  rangeStart: Date,
  rangeEnd: Date,
): CalendarEvent[] => {
  const result: CalendarEvent[] = []

  for (const event of events) {
    if (event.recurrence === 'none') {
      result.push(event)
      continue
    }

    const eventDate = new Date(event.date + 'T00:00:00')
    let current = new Date(eventDate)

    while (current <= rangeEnd) {
      if (current >= rangeStart) {
        const dateStr = formatDate(current)
        // Avoid duplicating the original date entry
        if (dateStr !== event.date) {
          result.push({
            ...event,
            id: `${event.id}_${dateStr}`,
            date: dateStr,
          })
        } else {
          result.push(event)
        }
      }
      current = advanceDate(current, event.recurrence)
    }
  }

  return result
}

const advanceDate = (date: Date, rule: RecurrenceRule): Date => {
  const next = new Date(date)
  switch (rule) {
    case 'daily':
      next.setDate(next.getDate() + 1)
      break
    case 'weekly':
      next.setDate(next.getDate() + 7)
      break
    case 'monthly':
      next.setMonth(next.getMonth() + 1)
      break
    default:
      next.setFullYear(next.getFullYear() + 100) // effectively stop
  }
  return next
}

export const formatDate = (date: Date): string => {
  const y = date.getFullYear()
  const m = String(date.getMonth() + 1).padStart(2, '0')
  const d = String(date.getDate()).padStart(2, '0')
  return `${y}-${m}-${d}`
}

/** Pure calendar grid computation utilities */

export type DayCell = {
  date: number       // day of month (1-31)
  dateStr: string    // YYYY-MM-DD
  isCurrentMonth: boolean
  isToday: boolean
  isSelected: boolean
}

export type MonthGrid = {
  year: number
  month: number
  label: string
  dayNames: string[]
  weeks: DayCell[][]
}

const DAY_NAMES = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat']
const MONTH_NAMES = [
  'January', 'February', 'March', 'April', 'May', 'June',
  'July', 'August', 'September', 'October', 'November', 'December',
]

const pad = (n: number): string => String(n).padStart(2, '0')

const toDateStr = (y: number, m: number, d: number): string =>
  `${y}-${pad(m + 1)}-${pad(d)}`

export const buildMonthGrid = (
  year: number,
  month: number,
  selectedDate: string | null,
): MonthGrid => {
  const today = new Date()
  const todayStr = toDateStr(today.getFullYear(), today.getMonth(), today.getDate())

  const firstDay = new Date(year, month, 1)
  const startDow = firstDay.getDay() // 0=Sun

  const daysInMonth = new Date(year, month + 1, 0).getDate()
  const daysInPrevMonth = new Date(year, month, 0).getDate()

  const cells: DayCell[] = []

  // Previous month padding
  const prevMonth = month === 0 ? 11 : month - 1
  const prevYear = month === 0 ? year - 1 : year
  for (let i = startDow - 1; i >= 0; i--) {
    const d = daysInPrevMonth - i
    const ds = toDateStr(prevYear, prevMonth, d)
    cells.push({
      date: d,
      dateStr: ds,
      isCurrentMonth: false,
      isToday: ds === todayStr,
      isSelected: ds === selectedDate,
    })
  }

  // Current month
  for (let d = 1; d <= daysInMonth; d++) {
    const ds = toDateStr(year, month, d)
    cells.push({
      date: d,
      dateStr: ds,
      isCurrentMonth: true,
      isToday: ds === todayStr,
      isSelected: ds === selectedDate,
    })
  }

  // Next month padding to fill last week
  const nextMonth = month === 11 ? 0 : month + 1
  const nextYear = month === 11 ? year + 1 : year
  const remaining = 7 - (cells.length % 7)
  if (remaining < 7) {
    for (let d = 1; d <= remaining; d++) {
      const ds = toDateStr(nextYear, nextMonth, d)
      cells.push({
        date: d,
        dateStr: ds,
        isCurrentMonth: false,
        isToday: ds === todayStr,
        isSelected: ds === selectedDate,
      })
    }
  }

  // Chunk into weeks
  const weeks: DayCell[][] = []
  for (let i = 0; i < cells.length; i += 7) {
    weeks.push(cells.slice(i, i + 7))
  }

  return {
    year,
    month,
    label: `${MONTH_NAMES[month]} ${year}`,
    dayNames: DAY_NAMES,
    weeks,
  }
}

export const prevMonth = (year: number, month: number): { year: number; month: number } =>
  month === 0 ? { year: year - 1, month: 11 } : { year, month: month - 1 }

export const nextMonth = (year: number, month: number): { year: number; month: number } =>
  month === 11 ? { year: year + 1, month: 0 } : { year, month: month + 1 }

export const formatDisplayDate = (dateStr: string): string => {
  const [y, m, d] = dateStr.split('-').map(Number)
  const date = new Date(y, m - 1, d)
  const dow = DAY_NAMES[date.getDay()]
  return `${dow}, ${MONTH_NAMES[m - 1]} ${d}, ${y}`
}

export const formatTime = (time24: string): string => {
  const [h, m] = time24.split(':').map(Number)
  const ampm = h >= 12 ? 'PM' : 'AM'
  const h12 = h === 0 ? 12 : h > 12 ? h - 12 : h
  return `${h12}:${String(m).padStart(2, '0')} ${ampm}`
}

