          ...styles.eventDot,
          backgroundColor: CATEGORY_COLORS[cat],
        },
      }),
    ),
  )
}

const renderDayCell = (
  cell: DayCell,
  events: CalendarEvent[],
) => {
  const cellStyle = {
    ...styles.dayCell,
    ...(!cell.isCurrentMonth ? styles.dayCellOtherMonth : {}),
    ...(cell.isToday ? styles.dayCellToday : {}),
    ...(cell.isSelected ? styles.dayCellSelected : {}),
  }

  const numberStyle = cell.isToday
    ? { ...styles.dayNumber, ...styles.dayNumberToday }
    : styles.dayNumber

  return h(
    'div',
    {
      style: cellStyle,
      'p-trigger': `click:selectDate:${cell.dateStr}`,
    },
    h('span', { style: numberStyle }, String(cell.date)),
    events.length > 0 ? renderEventDots(events) : null,
  )
}

export const renderMonthView = (
  state: CalendarState,
  eventsByDate: Map<string, CalendarEvent[]>,
): string => {
  const grid: MonthGrid = buildMonthGrid(state.year, state.month, state.selectedDate)

  const headerEl = h(
    'div',
    { style: styles.header },
    h(
      'button',
      { style: styles.navButton, 'p-trigger': 'click:prevMonth' },
      '\u25C0 Prev',
    ),
    h('h2', { style: styles.headerTitle }, grid.label),
    h(
      'button',
      { style: styles.navButton, 'p-trigger': 'click:nextMonth' },
      'Next \u25B6',
    ),
  )

  const addBtn = h(
    'div',
    { style: { textAlign: 'right', marginBottom: '12px' } },
    h(
      'button',
      { style: styles.addButton, 'p-trigger': 'click:showForm' },
      '+ Add Event',
    ),
  )

  const dayHeaders = grid.dayNames.map((name) =>
    h('div', { style: styles.dayHeader }, name),
  )

  const dayCells = grid.weeks.flatMap((week) =>
    week.map((cell) => renderDayCell(cell, eventsByDate.get(cell.dateStr) ?? [])),
  )

  const gridEl = h(
    'div',
    { style: styles.grid },
    ...dayHeaders,
    ...dayCells,
  )

  return h(
    'div',
    { style: styles.container },
    headerEl,
    addBtn,
    gridEl,
  ).toString()
}

