import type { CalendarState, CalendarEvent, EventFormData, EventCategory, RecurrenceRule } from './types'
import {
  loadEvents,
  createEvent,
  updateEvent,
  deleteEvent,
  getEventsForDate,
  getEventsForMonth,
  expandRecurrences,
  formatDate,
} from './data'
import { prevMonth, nextMonth } from './calendar'
import {
  renderMonthView,
  renderDayView,
  renderEventForm,
  renderSeriesPrompt,
} from './views'

// --- State ---

const now = new Date()

const state: CalendarState = {
  view: 'month',
  year: now.getFullYear(),
  month: now.getMonth(),
  selectedDate: null,
  editingEventId: null,
}

// --- Render Helpers ---

const getRangeForMonth = (year: number, month: number): { start: Date; end: Date } => ({
  start: new Date(year, month, 1),
  end: new Date(year, month + 1, 0),
})

const renderCurrentView = async (): Promise<string> => {
  if (state.view === 'month') {
    const allEvents = await loadEvents()
    const { start, end } = getRangeForMonth(state.year, state.month)
    const expanded = expandRecurrences(allEvents, start, end)

    const byDate = new Map<string, CalendarEvent[]>()
    for (const ev of expanded) {
      const list = byDate.get(ev.date) ?? []
      list.push(ev)
      byDate.set(ev.date, list)
    }

    return renderMonthView(state, byDate)
  }

  if (state.view === 'day' && state.selectedDate) {
    const allEvents = await loadEvents()
    const d = new Date(state.selectedDate + 'T00:00:00')
    const expanded = expandRecurrences(allEvents, d, d)
    const dayEvents = expanded
      .filter((e) => e.date === state.selectedDate)
      .sort((a, b) => a.startTime.localeCompare(b.startTime))
    return renderDayView(state, dayEvents)
  }

  return renderMonthView(state, new Map())
}

// --- Action Handlers ---

export const handleSelectDate = async (dateStr: string): Promise<string> => {
  state.selectedDate = dateStr
  state.view = 'day'
  return renderCurrentView()
}

export const handlePrevMonth = async (): Promise<string> => {
  const nav = prevMonth(state.year, state.month)
  state.year = nav.year
  state.month = nav.month
  state.view = 'month'
  return renderCurrentView()
}

export const handleNextMonth = async (): Promise<string> => {
  const nav = nextMonth(state.year, state.month)
  state.year = nav.year
  state.month = nav.month
  state.view = 'month'
  return renderCurrentView()
}

export const handleBackToMonth = async (): Promise<string> => {
  state.view = 'month'
  state.editingEventId = null
  return renderCurrentView()
}

export const handleShowForm = async (eventId?: string): Promise<string> => {
  if (eventId) {
    const events = await loadEvents()
    const event = events.find((e) => e.id === eventId) ?? null
    const defaultDate = state.selectedDate ?? formatDate(now)
    return renderEventForm(event, defaultDate)
  }
  const defaultDate = state.selectedDate ?? formatDate(now)
  return renderEventForm(null, defaultDate)
}

export const handleCreateEvent = async (form: EventFormData): Promise<string> => {
  await createEvent(form)
  // Navigate to the day of the new event
  state.selectedDate = form.date
  state.view = 'day'
  return renderCurrentView()
}

export const handleSelectEvent = async (eventId: string): Promise<string> => {
  const events = await loadEvents()
  const event = events.find((e) => e.id === eventId)
  // For generated recurring IDs like "uuid_2026-03-20", find the base event
  const baseId = eventId.includes('_2') ? eventId.split('_').slice(0, 5).join('_') : eventId
  const baseEvent = events.find((e) => e.id === baseId)
  const target = event ?? baseEvent

  if (!target) return renderCurrentView()

  const defaultDate = state.selectedDate ?? formatDate(now)
  return renderEventForm(target, defaultDate)
}

export const handleEditEvent = async (
  eventId: string,
  updates: Partial<EventFormData>,
  updateSeries: boolean = false,
): Promise<string> => {
  await updateEvent(eventId, updates, updateSeries)
  state.view = 'day'
  return renderCurrentView()
}

export const handleDeleteEvent = async (
  eventId: string,
  deleteSeries: boolean = false,
): Promise<string> => {
  await deleteEvent(eventId, deleteSeries)
  state.view = 'day'
  return renderCurrentView()
}

export const handleSeriesPrompt = (
  eventId: string,
  action: 'edit' | 'delete',
): string =>
  renderSeriesPrompt(eventId, action)

// --- Main Entry ---

export const render = async (): Promise<string> =>
  renderCurrentView()

