// Markdown parser — converts markdown text to HTML string

type Rule = {
  pattern: RegExp
  replace: string | ((...args: string[]) => string)
}

const escapeHtml = (text: string): string =>
  text
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')

const parseInline = (text: string): string => {
  let result = text
  // Images (before links so ![...](...) isn't caught by link rule)
  result = result.replace(/!\[([^\]]*)\]\(([^)]+)\)/g, '<img src="$2" alt="$1" />')
  // Links
  result = result.replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<a href="$2">$1</a>')
  // Bold + italic
  result = result.replace(/\*\*\*(.+?)\*\*\*/g, '<strong><em>$1</em></strong>')
  result = result.replace(/___(.+?)___/g, '<strong><em>$1</em></strong>')
  // Bold
  result = result.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
  result = result.replace(/__(.+?)__/g, '<strong>$1</strong>')
  // Italic
  result = result.replace(/\*(.+?)\*/g, '<em>$1</em>')
  result = result.replace(/_(.+?)_/g, '<em>$1</em>')
  // Strikethrough
  result = result.replace(/~~(.+?)~~/g, '<del>$1</del>')
  // Inline code
  result = result.replace(/`([^`]+)`/g, (_match, code) => `<code>${escapeHtml(code)}</code>`)
  return result
}

const parseTable = (lines: string[]): { html: string; consumed: number } => {
  if (lines.length < 2) return { html: '', consumed: 0 }

  const headerLine = lines[0]
  const separatorLine = lines[1]

  if (!/^\|(.+\|)+\s*$/.test(headerLine.trim() + '|') || !/^\|[\s\-:|]+\|/.test(separatorLine)) {
    return { html: '', consumed: 0 }
  }

  const parseCells = (line: string): string[] =>
    line.trim().replace(/^\|/, '').replace(/\|$/, '').split('|').map(c => c.trim())

  const headers = parseCells(headerLine)
  const separators = parseCells(separatorLine)

  const alignments: ('left' | 'center' | 'right' | null)[] = separators.map(sep => {
    const left = sep.startsWith(':')
    const right = sep.endsWith(':')
    if (left && right) return 'center'
    if (right) return 'right'
    if (left) return 'left'
    return null
  })

  const alignAttr = (i: number): string => {
    const a = alignments[i]
    return a ? ` style="text-align:${a}"` : ''
  }

  let html = '<table>\n<thead>\n<tr>\n'
  headers.forEach((h, i) => {
    html += `<th${alignAttr(i)}>${parseInline(h)}</th>\n`
  })
  html += '</tr>\n</thead>\n<tbody>\n'

  let consumed = 2
  for (let i = 2; i < lines.length; i++) {
    const line = lines[i]
    if (!/^\|/.test(line.trim())) break
    const cells = parseCells(line)
    html += '<tr>\n'
    headers.forEach((_, ci) => {
      html += `<td${alignAttr(ci)}>${parseInline(cells[ci] ?? '')}</td>\n`
    })
    html += '</tr>\n'
    consumed++
  }
  html += '</tbody>\n</table>\n'
  return { html, consumed }
}

export const parseMarkdown = (markdown: string): string => {
  const lines = markdown.split('\n')
  const output: string[] = []
  let i = 0

  while (i < lines.length) {
    const line = lines[i]

    // Fenced code block
    if (/^```(\w*)/.test(line)) {
      const lang = line.match(/^```(\w*)/)?.[1] ?? ''
      const codeLines: string[] = []
      i++
      while (i < lines.length && !lines[i].startsWith('```')) {
        codeLines.push(escapeHtml(lines[i]))
        i++
      }
      i++ // skip closing ```
      const langAttr = lang ? ` class="language-${lang}"` : ''
      output.push(`<pre><code${langAttr}>${codeLines.join('\n')}</code></pre>`)
      continue
    }

    // Table
    if (/^\|/.test(line.trim())) {
      const { html, consumed } = parseTable(lines.slice(i))
      if (consumed > 0) {
        output.push(html)
        i += consumed
        continue
      }
    }

    // Heading
    const headingMatch = line.match(/^(#{1,6})\s+(.+)$/)
    if (headingMatch) {
      const level = headingMatch[1].length
      output.push(`<h${level}>${parseInline(headingMatch[2])}</h${level}>`)
      i++
      continue
    }

    // Horizontal rule
    if (/^(\*{3,}|-{3,}|_{3,})\s*$/.test(line)) {
      output.push('<hr />')
      i++
      continue
    }

    // Blockquote
    if (/^>\s?/.test(line)) {
      const quoteLines: string[] = []
      while (i < lines.length && /^>\s?/.test(lines[i])) {
        quoteLines.push(lines[i].replace(/^>\s?/, ''))
        i++
      }
      output.push(`<blockquote>${parseMarkdown(quoteLines.join('\n'))}</blockquote>`)
      continue
    }

    // Unordered list
    if (/^[\-\*\+]\s+/.test(line)) {
      const items: string[] = []
      while (i < lines.length && /^[\-\*\+]\s+/.test(lines[i])) {
        items.push(lines[i].replace(/^[\-\*\+]\s+/, ''))
        i++
      }
      output.push('<ul>' + items.map(it => `<li>${parseInline(it)}</li>`).join('') + '</ul>')
      continue
    }

    // Ordered list
    if (/^\d+\.\s+/.test(line)) {
      const items: string[] = []
      while (i < lines.length && /^\d+\.\s+/.test(lines[i])) {
        items.push(lines[i].replace(/^\d+\.\s+/, ''))
        i++
      }
      output.push('<ol>' + items.map(it => `<li>${parseInline(it)}</li>`).join('') + '</ol>')
      continue
    }

    // Empty line
    if (line.trim() === '') {
      i++
      continue
    }

    // Paragraph — collect consecutive non-empty lines
    const paraLines: string[] = []
    while (i < lines.length && lines[i].trim() !== '' && !/^(#{1,6}\s|```|>|[\-\*\+]\s|\d+\.\s|(\*{3,}|-{3,}|_{3,})\s*$|\|)/.test(lines[i])) {
      paraLines.push(lines[i])
      i++
    }
    if (paraLines.length > 0) {
      output.push(`<p>${parseInline(paraLines.join('\n'))}</p>`)
    }
  }

  return output.join('\n')
}

// Document persistence layer using Bun file APIs

const DATA_PATH = new URL('./data/documents.json', import.meta.url).pathname

export type Document = {
  id: string
  title: string
  content: string
  createdAt: string
  updatedAt: string
}

const generateId = (): string =>
  Date.now().toString(36) + Math.random().toString(36).slice(2, 8)

export const loadDocuments = async (): Promise<Document[]> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) {
    await Bun.write(DATA_PATH, '[]')
    return []
  }
  const text = await file.text()
  return JSON.parse(text) as Document[]
}

const saveDocuments = async (docs: Document[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(docs, null, 2))
}

export const createDocument = async (title: string, content: string): Promise<Document> => {
  const docs = await loadDocuments()
  const now = new Date().toISOString()
  const doc: Document = {
    id: generateId(),
    title,
    content,
    createdAt: now,
    updatedAt: now,
  }
  docs.push(doc)
  await saveDocuments(docs)
  return doc
}

export const updateDocument = async (id: string, title: string, content: string): Promise<Document | null> => {
  const docs = await loadDocuments()
  const index = docs.findIndex(d => d.id === id)
  if (index === -1) return null
  docs[index] = {
    ...docs[index],
    title,
    content,
    updatedAt: new Date().toISOString(),
  }
  await saveDocuments(docs)
  return docs[index]
}

export const deleteDocument = async (id: string): Promise<boolean> => {
  const docs = await loadDocuments()
  const filtered = docs.filter(d => d.id !== id)
  if (filtered.length === docs.length) return false
  await saveDocuments(filtered)
  return true
}

export const getDocument = async (id: string): Promise<Document | null> => {
  const docs = await loadDocuments()
  return docs.find(d => d.id === id) ?? null
}

