// Editor page renderer — builds the full split-pane HTML

import { h, Fragment } from 'plaited'
import { parseMarkdown } from './markdown'
import { editorStyles } from './styles'
import { toolbarButtonsHtml, toolbarActions } from './toolbar'
import type { Document } from './documents'

export const renderEditorPage = (docs: Document[], activeDoc?: Document | null): string => {
  const content = activeDoc?.content ?? ''
  const title = activeDoc?.title ?? ''
  const docId = activeDoc?.id ?? ''
  const preview = parseMarkdown(content)

  return `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <title>Markdown Editor</title>
  <style>${editorStyles}</style>
</head>
<body>
  <div class="header">
    <h1>Markdown Editor</h1>
    <input
      type="hidden"
      id="doc-id"
      value="${docId}"
    />
    <input
      type="text"
      id="doc-title"
      class="doc-title-input"
      placeholder="Document title..."
      value="${escapeAttr(title)}"
    />
    <button class="btn btn-primary" id="save-btn">Save</button>
    <button class="btn btn-secondary" id="new-btn">New</button>
  </div>

  <div class="toolbar" id="toolbar">
    ${toolbarButtonsHtml()}
  </div>

  <div class="main">
    <div class="editor-pane">
      <textarea id="editor" placeholder="Write your markdown here...">${escapeHtmlContent(content)}</textarea>
    </div>
    <div class="preview-pane">
      <div class="label">Preview</div>
      <div class="preview-content" id="preview">${preview}</div>
    </div>
    <div class="sidebar">
      <div class="sidebar-header">Saved Documents</div>
      <ul class="doc-list" id="doc-list">
        ${docs.length === 0
          ? '<li class="empty-state">No saved documents</li>'
          : docs
              .sort((a, b) => new Date(b.updatedAt).getTime() - new Date(a.updatedAt).getTime())
              .map(
                doc => `<li class="doc-item" data-doc-id="${doc.id}">
                  <div>
                    <div class="doc-item-title">${escapeHtmlContent(doc.title || 'Untitled')}</div>
                    <div class="doc-item-date">${formatDate(doc.updatedAt)}</div>
                  </div>
                  <button class="delete-btn" data-delete-id="${doc.id}" title="Delete">&times;</button>
                </li>`
              )
              .join('')
        }
      </ul>
    </div>
  </div>

  <script>
    const editor = document.getElementById('editor');
    const preview = document.getElementById('preview');
    const titleInput = document.getElementById('doc-title');
    const docIdInput = document.getElementById('doc-id');
    const toolbar = document.getElementById('toolbar');
    const saveBtn = document.getElementById('save-btn');
    const newBtn = document.getElementById('new-btn');
    const docList = document.getElementById('doc-list');

    const toolbarActions = ${JSON.stringify(toolbarActions)};

    // Live preview via server-side parse
    let debounceTimer;
    editor.addEventListener('input', () => {
      clearTimeout(debounceTimer);
      debounceTimer = setTimeout(async () => {
        const res = await fetch('/api/preview', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ content: editor.value }),
        });
        if (res.ok) {
          const data = await res.json();
          preview.innerHTML = data.html;
        }
      }, 150);
    });

    // Toolbar buttons
    toolbar.addEventListener('click', (e) => {
      const btn = e.target.closest('button[data-action]');
      if (!btn) return;
      const idx = parseInt(btn.dataset.action, 10);
      const action = toolbarActions[idx];
      if (!action) return;

      const start = editor.selectionStart;
      const end = editor.selectionEnd;
      const selected = editor.value.substring(start, end);
      const text = selected || action.defaultText;

      const before = editor.value.substring(0, start);
      const after = editor.value.substring(end);

      let insert = action.prefix + text + action.suffix;
      if (action.block && start > 0 && before[before.length - 1] !== '\\n') {
        insert = '\\n' + insert;
      }

      editor.value = before + insert + after;
      editor.focus();

      const newCursorPos = start + action.prefix.length + (action.block && start > 0 && before[before.length - 1] !== '\\n' ? 1 : 0);
      editor.setSelectionRange(newCursorPos, newCursorPos + text.length);
      editor.dispatchEvent(new Event('input'));
    });

    // Save document
    saveBtn.addEventListener('click', async () => {
      const id = docIdInput.value;
      const title = titleInput.value || 'Untitled';
      const content = editor.value;

      const url = id ? '/api/documents/' + id : '/api/documents';
      const method = id ? 'PUT' : 'POST';

      const res = await fetch(url, {
        method,
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ title, content }),
      });

      if (res.ok) {
        window.location.reload();
      }
    });

    // New document
    newBtn.addEventListener('click', () => {
      docIdInput.value = '';
      titleInput.value = '';
      editor.value = '';
      preview.innerHTML = '';
    });

    // Load document
    docList.addEventListener('click', async (e) => {
      const deleteBtn = e.target.closest('.delete-btn');
      if (deleteBtn) {
        e.stopPropagation();
        const id = deleteBtn.dataset.deleteId;
        if (confirm('Delete this document?')) {
          await fetch('/api/documents/' + id, { method: 'DELETE' });
          window.location.reload();
        }
        return;
      }

      const item = e.target.closest('.doc-item');
      if (!item) return;
      const id = item.dataset.docId;
      window.location.href = '/?doc=' + id;
    });
  </script>
</body>
</html>`
}

const escapeHtmlContent = (text: string): string =>
  text
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')

const escapeAttr = (text: string): string =>
  text
    .replace(/&/g, '&amp;')
    .replace(/"/g, '&quot;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')

const formatDate = (iso: string): string => {
  const d = new Date(iso)
  return d.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' })
}

// Main entry point — HTTP server with routes for the editor and API

import { renderEditorPage } from './editor'
import { parseMarkdown } from './markdown'
import {
  loadDocuments,
  createDocument,
  updateDocument,
  deleteDocument,
  getDocument,
} from './documents'

const PORT = parseInt(process.env.PORT ?? '3000', 10)

const jsonResponse = (data: unknown, status = 200): Response =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

const htmlResponse = (html: string, status = 200): Response =>
  new Response(html, {
    status,
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })

const server = Bun.serve({
  port: PORT,
  fetch: async (req) => {
    const url = new URL(req.url)
    const { pathname } = url

    // --- Pages ---

    if (pathname === '/' && req.method === 'GET') {
      const docs = await loadDocuments()
      const docId = url.searchParams.get('doc')
      const activeDoc = docId ? await getDocument(docId) : null
      return htmlResponse(renderEditorPage(docs, activeDoc))
    }

    // --- API: Live preview ---

    if (pathname === '/api/preview' && req.method === 'POST') {
      const body = (await req.json()) as { content: string }
      const html = parseMarkdown(body.content ?? '')
      return jsonResponse({ html })
    }

    // --- API: Documents CRUD ---

    if (pathname === '/api/documents' && req.method === 'GET') {
      const docs = await loadDocuments()
      return jsonResponse(docs)
    }

    if (pathname === '/api/documents' && req.method === 'POST') {
      const body = (await req.json()) as { title: string; content: string }
      const doc = await createDocument(body.title, body.content)
      return jsonResponse(doc, 201)
    }

    const docMatch = pathname.match(/^\/api\/documents\/([^/]+)$/)
    if (docMatch) {
      const id = docMatch[1]

      if (req.method === 'GET') {
        const doc = await getDocument(id)
        if (!doc) return jsonResponse({ error: 'Not found' }, 404)
        return jsonResponse(doc)
      }

      if (req.method === 'PUT') {
        const body = (await req.json()) as { title: string; content: string }
        const doc = await updateDocument(id, body.title, body.content)
        if (!doc) return jsonResponse({ error: 'Not found' }, 404)
        return jsonResponse(doc)
      }

      if (req.method === 'DELETE') {
        const deleted = await deleteDocument(id)
        if (!deleted) return jsonResponse({ error: 'Not found' }, 404)
        return jsonResponse({ ok: true })
      }
    }

    return jsonResponse({ error: 'Not found' }, 404)
  },
})

