const escapeHtml = (text: string): string =>
  text
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')

const parseInline = (text: string): string => {
  let result = text
  // Images (before links so ![...](...) isn't caught by link regex)
  result = result.replace(/!\[([^\]]*)\]\(([^)]+)\)/g, '<img src="$2" alt="$1" style="max-width:100%;" />')
  // Links
  result = result.replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<a href="$2">$1</a>')
  // Bold+Italic
  result = result.replace(/\*\*\*(.+?)\*\*\*/g, '<strong><em>$1</em></strong>')
  // Bold
  result = result.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
  // Italic
  result = result.replace(/\*(.+?)\*/g, '<em>$1</em>')
  // Strikethrough
  result = result.replace(/~~(.+?)~~/g, '<del>$1</del>')
  // Inline code
  result = result.replace(/`([^`]+)`/g, '<code>$1</code>')
  return result
}

const parseTable = (lines: string[]): string => {
  if (lines.length < 2) return ''
  const parseRow = (line: string): string[] =>
    line.split('|').map(cell => cell.trim()).filter(Boolean)

  const headers = parseRow(lines[0])
  const alignLine = parseRow(lines[1])
  const aligns = alignLine.map(cell => {
    if (cell.startsWith(':') && cell.endsWith(':')) return 'center'
    if (cell.endsWith(':')) return 'right'
    return 'left'
  })

  let html = '<table><thead><tr>'
  headers.forEach((header, i) => {
    html += `<th style="text-align:${aligns[i] ?? 'left'}">${parseInline(header)}</th>`
  })
  html += '</tr></thead><tbody>'

  for (let i = 2; i < lines.length; i++) {
    const cells = parseRow(lines[i])
    html += '<tr>'
    cells.forEach((cell, j) => {
      html += `<td style="text-align:${aligns[j] ?? 'left'}">${parseInline(cell)}</td>`
    })
    html += '</tr>'
  }
  html += '</tbody></table>'
  return html
}

export const renderMarkdown = (source: string): string => {
  const lines = source.split('\n')
  const output: string[] = []
  let i = 0

  while (i < lines.length) {
    const line = lines[i]

    // Fenced code block
    if (line.startsWith('```')) {
      const lang = line.slice(3).trim()
      const codeLines: string[] = []
      i++
      while (i < lines.length && !lines[i].startsWith('```')) {
        codeLines.push(escapeHtml(lines[i]))
        i++
      }
      i++ // skip closing ```
      const langAttr = lang ? ` class="language-${escapeHtml(lang)}"` : ''
      output.push(`<pre><code${langAttr}>${codeLines.join('\n')}</code></pre>`)
      continue
    }

    // Table detection
    if (
      i + 1 < lines.length &&
      line.includes('|') &&
      /^\s*\|?[\s:-]+\|[\s:-|]+$/.test(lines[i + 1])
    ) {
      const tableLines: string[] = [line]
      i++
      while (i < lines.length && lines[i].includes('|')) {
        tableLines.push(lines[i])
        i++
      }
      output.push(parseTable(tableLines))
      continue
    }

    // Horizontal rule
    if (/^(\*{3,}|-{3,}|_{3,})\s*$/.test(line)) {
      output.push('<hr />')
      i++
      continue
    }

    // Headings
    const headingMatch = line.match(/^(#{1,6})\s+(.+)$/)
    if (headingMatch) {
      const level = headingMatch[1].length
      output.push(`<h${level}>${parseInline(headingMatch[2])}</h${level}>`)
      i++
      continue
    }

    // Blockquote
    if (line.startsWith('> ')) {
      const quoteLines: string[] = []
      while (i < lines.length && lines[i].startsWith('> ')) {
        quoteLines.push(lines[i].slice(2))
        i++
      }
      output.push(`<blockquote>${renderMarkdown(quoteLines.join('\n'))}</blockquote>`)
      continue
    }

    // Unordered list
    if (/^[-*+]\s+/.test(line)) {
      const items: string[] = []
      while (i < lines.length && /^[-*+]\s+/.test(lines[i])) {
        items.push(lines[i].replace(/^[-*+]\s+/, ''))
        i++
      }
      output.push('<ul>' + items.map(item => `<li>${parseInline(item)}</li>`).join('') + '</ul>')
      continue
    }

    // Ordered list
    if (/^\d+\.\s+/.test(line)) {
      const items: string[] = []
      while (i < lines.length && /^\d+\.\s+/.test(lines[i])) {
        items.push(lines[i].replace(/^\d+\.\s+/, ''))
        i++
      }
      output.push('<ol>' + items.map(item => `<li>${parseInline(item)}</li>`).join('') + '</ol>')
      continue
    }

    // Blank line
    if (line.trim() === '') {
      i++
      continue
    }

    // Paragraph
    const paraLines: string[] = []
    while (i < lines.length && lines[i].trim() !== '' && !lines[i].startsWith('#') && !lines[i].startsWith('```') && !lines[i].startsWith('> ') && !/^[-*+]\s+/.test(lines[i]) && !/^\d+\.\s+/.test(lines[i]) && !/^(\*{3,}|-{3,}|_{3,})\s*$/.test(lines[i])) {
      paraLines.push(lines[i])
      i++
    }
    if (paraLines.length > 0) {
      output.push(`<p>${parseInline(paraLines.join('\n'))}</p>`)
    }
  }

  return output.join('\n')
}

import type { Document, DocumentList, SaveDocumentRequest } from './types'

const DATA_PATH = new URL('./data/documents.json', import.meta.url).pathname

const readDocuments = async (): Promise<DocumentList> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) return []
  const text = await file.text()
  return text.trim() ? JSON.parse(text) : []
}

const writeDocuments = async (docs: DocumentList): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(docs, null, 2))
}

export const listDocuments = async (): Promise<DocumentList> => {
  const docs = await readDocuments()
  return docs.sort((a, b) => new Date(b.updatedAt).getTime() - new Date(a.updatedAt).getTime())
}

export const getDocument = async (id: string): Promise<Document | undefined> => {
  const docs = await readDocuments()
  return docs.find(d => d.id === id)
}

export const saveDocument = async (req: SaveDocumentRequest): Promise<Document> => {
  const docs = await readDocuments()
  const now = new Date().toISOString()

  if (req.id) {
    const idx = docs.findIndex(d => d.id === req.id)
    if (idx !== -1) {
      docs[idx] = { ...docs[idx], title: req.title, content: req.content, updatedAt: now }
      await writeDocuments(docs)
      return docs[idx]
    }
  }

  const doc: Document = {
    id: crypto.randomUUID(),
    title: req.title,
    content: req.content,
    createdAt: now,
    updatedAt: now,
  }
  docs.push(doc)
  await writeDocuments(docs)
  return doc
}

export const deleteDocument = async (id: string): Promise<boolean> => {
  const docs = await readDocuments()
  const idx = docs.findIndex(d => d.id === id)
  if (idx === -1) return false
  docs.splice(idx, 1)
  await writeDocuments(docs)
  return true
}

