const renderClientScript = (content: string, previewHtml: string) =>
  h('script', {},
    `(function(){
  var insertionMap = ${JSON.stringify(insertionMap)};

  var preview = document.querySelector('[p-target="preview"]');
  var editor = document.querySelector('[p-target="editor"]');
  var titleInput = document.querySelector('[p-target="title-input"]');
  var docIdInput = document.querySelector('[p-target="doc-id"]');

  // Set initial preview
  preview.innerHTML = ${JSON.stringify(previewHtml)};

  // Debounced live preview
  var debounceTimer;
  editor.addEventListener('input', function() {
    clearTimeout(debounceTimer);
    debounceTimer = setTimeout(function() {
      fetch('/api/preview', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ content: editor.value })
      })
      .then(function(r) { return r.json(); })
      .then(function(data) { preview.innerHTML = data.html; });
    }, 150);
  });

  // Toolbar actions
  document.querySelector('[p-target="toolbar"]').addEventListener('click', function(e) {
    var btn = e.target.closest('[data-action]');
    if (!btn) return;
    var action = btn.getAttribute('data-action');
    var text = insertionMap[action];
    if (!text) return;
    var start = editor.selectionStart;
    var end = editor.selectionEnd;
    var before = editor.value.substring(0, start);
    var after = editor.value.substring(end);
    editor.value = before + text + after;
    editor.focus();
    editor.selectionStart = editor.selectionEnd = start + text.length;
    editor.dispatchEvent(new Event('input'));
  });

  // Save
  document.querySelector('[p-trigger="click:save-document"]').addEventListener('click', function() {
    var title = titleInput.value.trim() || 'Untitled';
    var body = { title: title, content: editor.value };
    var id = docIdInput.value;
    if (id) body.id = id;
    fetch('/api/documents', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(body)
    })
    .then(function(r) { return r.json(); })
    .then(function(doc) {
      docIdInput.value = doc.id;
      alert('Document saved!');
    });
  });

  // New document
  document.querySelector('[p-trigger="click:new-document"]').addEventListener('click', function() {
    editor.value = '';
    titleInput.value = '';
    docIdInput.value = '';
    preview.innerHTML = '';
  });

  // Document sidebar
  var sidebarOpen = false;
  var sidebarEl = null;

  document.querySelector('[p-trigger="click:toggle-sidebar"]').addEventListener('click', function() {
    if (sidebarOpen && sidebarEl) {
      sidebarEl.remove();
      sidebarEl = null;
      sidebarOpen = false;
      return;
    }
    fetch('/api/documents')
      .then(function(r) { return r.json(); })
      .then(function(docs) {
        var div = document.createElement('div');
        div.style.cssText = 'position:fixed;top:0;right:0;width:320px;height:100vh;background:#16213e;border-left:2px solid #0f3460;z-index:100;box-shadow:-4px 0 20px rgba(0,0,0,0.5);display:flex;flex-direction:column;';
        var header = '<div style="display:flex;justify-content:space-between;align-items:center;padding:12px 16px;border-bottom:1px solid #0f3460"><span style="font-size:16px;font-weight:bold;color:#e94560">Saved Documents</span><button id="close-sidebar" style="background:none;border:none;color:#e0e0e0;font-size:20px;cursor:pointer">\\u00D7</button></div>';
        var list = '<div style="flex:1;overflow:auto;padding:8px">';
        if (docs.length === 0) {
          list += '<div style="text-align:center;padding:40px 16px;color:#533483">No saved documents yet</div>';
        } else {
          docs.forEach(function(doc) {
            list += '<div class="doc-item" data-id="' + doc.id + '" style="padding:10px 12px;border-radius:4px;cursor:pointer;margin-bottom:4px;background:#1a1a2e;border:1px solid #0f3460">';
            list += '<button class="del-btn" data-id="' + doc.id + '" style="float:right;background:none;border:none;color:#e94560;cursor:pointer;font-size:14px">\\uD83D\\uDDD1</button>';
            list += '<div style="font-weight:bold;font-size:14px;color:#e0e0e0;margin-bottom:4px">' + doc.title + '</div>';
            list += '<div style="font-size:11px;color:#533483">' + new Date(doc.updatedAt).toLocaleDateString() + '</div></div>';
          });
        }
        list += '</div>';
        div.innerHTML = header + list;
        document.body.appendChild(div);
        sidebarEl = div;
        sidebarOpen = true;

        div.querySelector('#close-sidebar').addEventListener('click', function() {
          div.remove();
          sidebarEl = null;
          sidebarOpen = false;
        });

        div.querySelectorAll('.doc-item').forEach(function(item) {
          item.addEventListener('click', function(e) {
            if (e.target.classList.contains('del-btn')) return;
            var docId = item.getAttribute('data-id');
            fetch('/api/documents/' + docId)
              .then(function(r) { return r.json(); })
              .then(function(doc) {
                editor.value = doc.content;
                titleInput.value = doc.title;
                docIdInput.value = doc.id;
                editor.dispatchEvent(new Event('input'));
                div.remove();
                sidebarEl = null;
                sidebarOpen = false;
              });
          });
        });

        div.querySelectorAll('.del-btn').forEach(function(btn) {
          btn.addEventListener('click', function(e) {
            e.stopPropagation();
            var docId = btn.getAttribute('data-id');
            if (!confirm('Delete this document?')) return;
            fetch('/api/documents/' + docId, { method: 'DELETE' })
              .then(function() {
                btn.closest('.doc-item').remove();
                if (docIdInput.value === docId) {
                  editor.value = '';
                  titleInput.value = '';
                  docIdInput.value = '';
                  preview.innerHTML = '';
                }
              });
          });
        });
      });
  });
})();`)

