export default {
  fetch: async (req: Request): Promise<Response> => {
    const url = new URL(req.url)
    const { pathname } = url

    // Main editor page
    if (pathname === '/' && req.method === 'GET') {
      const content = defaultContent
      const previewHtml = renderMarkdown(content)
      const page = renderEditorPage(content, '', '', previewHtml)
      const html = ssr(page)
      return htmlResponse(html)
    }

    // Preview endpoint for live rendering
    if (pathname === '/api/preview' && req.method === 'POST') {
      const body = await req.json() as { content: string }
      const html = renderMarkdown(body.content)
      return jsonResponse({ html })
    }

    // List documents
    if (pathname === '/api/documents' && req.method === 'GET') {
      const docs = await listDocuments()
      return jsonResponse(docs)
    }

    // Save document
    if (pathname === '/api/documents' && req.method === 'POST') {
      const body = await req.json() as SaveDocumentRequest
      const doc = await saveDocument(body)
      return jsonResponse(doc)
    }

    // Get single document
    const docMatch = pathname.match(/^\/api\/documents\/([^/]+)$/)
    if (docMatch && req.method === 'GET') {
      const doc = await getDocument(docMatch[1])
      if (!doc) return jsonResponse({ error: 'Not found' }, 404)
      return jsonResponse(doc)
    }

    // Delete document
    if (docMatch && req.method === 'DELETE') {
      const deleted = await deleteDocument(docMatch[1])
      if (!deleted) return jsonResponse({ error: 'Not found' }, 404)
      return jsonResponse({ ok: true })
    }

    return jsonResponse({ error: 'Not found' }, 404)
  },
}

