const escapeHtml = (text: string): string =>
  text
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')

const parseInline = (text: string): string => {
  let result = text
  // Images (must come before links)
  result = result.replace(/!\[([^\]]*)\]\(([^)]+)\)/g, '<img src="$2" alt="$1" />')
  // Links
  result = result.replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<a href="$2">$1</a>')
  // Bold + italic
  result = result.replace(/\*\*\*(.+?)\*\*\*/g, '<strong><em>$1</em></strong>')
  // Bold
  result = result.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
  // Italic
  result = result.replace(/\*(.+?)\*/g, '<em>$1</em>')
  // Strikethrough
  result = result.replace(/~~(.+?)~~/g, '<del>$1</del>')
  // Inline code
  result = result.replace(/`([^`]+)`/g, '<code>$1</code>')
  return result
}

const parseTable = (lines: string[]): { html: string; consumed: number } => {
  if (lines.length < 2) return { html: '', consumed: 0 }

  const parseRow = (line: string): string[] =>
    line
      .replace(/^\|/, '')
      .replace(/\|$/, '')
      .split('|')
      .map((cell) => cell.trim())

  const headerCells = parseRow(lines[0])
  const separatorLine = lines[1]

  if (!/^\|?[\s-:|]+\|?$/.test(separatorLine)) return { html: '', consumed: 0 }

  const alignments = parseRow(separatorLine).map((cell) => {
    const left = cell.startsWith(':')
    const right = cell.endsWith(':')
    if (left && right) return 'center'
    if (right) return 'right'
    if (left) return 'left'
    return ''
  })

  const alignAttr = (i: number): string =>
    alignments[i] ? ` style="text-align:${alignments[i]}"` : ''

  let html = '<table>\n<thead>\n<tr>\n'
  headerCells.forEach((cell, i) => {
    html += `<th${alignAttr(i)}>${parseInline(escapeHtml(cell))}</th>\n`
  })
  html += '</tr>\n</thead>\n<tbody>\n'

  let consumed = 2
  for (let i = 2; i < lines.length; i++) {
    const line = lines[i]
    if (!line.includes('|')) break
    const cells = parseRow(line)
    html += '<tr>\n'
    cells.forEach((cell, ci) => {
      html += `<td${alignAttr(ci)}>${parseInline(escapeHtml(cell))}</td>\n`
    })
    html += '</tr>\n'
    consumed++
  }

  html += '</tbody>\n</table>'
  return { html, consumed }
}

export const parseMarkdown = (source: string): string => {
  const lines = source.split('\n')
  const output: string[] = []
  let i = 0
  let inList: 'ul' | 'ol' | null = null

  const closeList = () => {
    if (inList) {
      output.push(`</${inList}>`)
      inList = null
    }
  }

  while (i < lines.length) {
    const line = lines[i]

    // Fenced code block
    if (line.startsWith('```')) {
      closeList()
      const lang = line.slice(3).trim()
      const codeLines: string[] = []
      i++
      while (i < lines.length && !lines[i].startsWith('```')) {
        codeLines.push(escapeHtml(lines[i]))
        i++
      }
      i++ // skip closing ```
      const langAttr = lang ? ` class="language-${escapeHtml(lang)}"` : ''
      output.push(`<pre><code${langAttr}>${codeLines.join('\n')}</code></pre>`)
      continue
    }

    // Table
    if (line.includes('|') && i + 1 < lines.length && /^\|?[\s-:|]+\|?$/.test(lines[i + 1])) {
      closeList()
      const { html, consumed } = parseTable(lines.slice(i))
      if (consumed > 0) {
        output.push(html)
        i += consumed
        continue
      }
    }

    // Blank line
    if (line.trim() === '') {
      closeList()
      i++
      continue
    }

    // Headings
    const headingMatch = line.match(/^(#{1,6})\s+(.+)$/)
    if (headingMatch) {
      closeList()
      const level = headingMatch[1].length
      output.push(`<h${level}>${parseInline(escapeHtml(headingMatch[2]))}</h${level}>`)
      i++
      continue
    }

    // Horizontal rule
    if (/^(---|\*\*\*|___)(\s*)$/.test(line.trim())) {
      closeList()
      output.push('<hr />')
      i++
      continue
    }

    // Blockquote
    if (line.startsWith('>')) {
      closeList()
      const quoteLines: string[] = []
      while (i < lines.length && lines[i].startsWith('>')) {
        quoteLines.push(lines[i].replace(/^>\s?/, ''))
        i++
      }
      output.push(`<blockquote>${parseInline(escapeHtml(quoteLines.join('\n')))}</blockquote>`)
      continue
    }

    // Unordered list
    const ulMatch = line.match(/^[\s]*[-*+]\s+(.+)$/)
    if (ulMatch) {
      if (inList !== 'ul') {
        closeList()
        output.push('<ul>')
        inList = 'ul'
      }
      output.push(`<li>${parseInline(escapeHtml(ulMatch[1]))}</li>`)
      i++
      continue
    }

    // Ordered list
    const olMatch = line.match(/^[\s]*\d+\.\s+(.+)$/)
    if (olMatch) {
      if (inList !== 'ol') {
        closeList()
        output.push('<ol>')
        inList = 'ol'
      }
      output.push(`<li>${parseInline(escapeHtml(olMatch[1]))}</li>`)
      i++
      continue
    }

    // Paragraph
    closeList()
    const paraLines: string[] = []
    while (i < lines.length && lines[i].trim() !== '' && !lines[i].startsWith('#') && !lines[i].startsWith('>') && !lines[i].startsWith('```') && !/^[-*+]\s/.test(lines[i]) && !/^\d+\.\s/.test(lines[i]) && !/^(---|\*\*\*|___)/.test(lines[i].trim())) {
      paraLines.push(lines[i])
      i++
    }
    if (paraLines.length > 0) {
      output.push(`<p>${parseInline(escapeHtml(paraLines.join('\n')))}</p>`)
    }
  }

  closeList()
  return output.join('\n')
}

import type { Document, DocumentSortField, SortDirection } from './types'

const DATA_PATH = new URL('./data/documents.json', import.meta.url).pathname

const readDocuments = async (): Promise<Document[]> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) return []
  const text = await file.text()
  return text.trim() ? JSON.parse(text) : []
}

const writeDocuments = async (docs: Document[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(docs, null, 2))
}

export const listDocuments = async (
  sortField: DocumentSortField = 'updatedAt',
  sortDir: SortDirection = 'desc',
  filterText = '',
): Promise<Document[]> => {
  let docs = await readDocuments()
  if (filterText) {
    const lower = filterText.toLowerCase()
    docs = docs.filter(
      (d) => d.title.toLowerCase().includes(lower) || d.content.toLowerCase().includes(lower),
    )
  }
  docs.sort((a, b) => {
    const aVal = a[sortField]
    const bVal = b[sortField]
    const cmp = aVal < bVal ? -1 : aVal > bVal ? 1 : 0
    return sortDir === 'asc' ? cmp : -cmp
  })
  return docs
}

export const getDocument = async (id: string): Promise<Document | undefined> => {
  const docs = await readDocuments()
  return docs.find((d) => d.id === id)
}

export const saveDocument = async (
  title: string,
  content: string,
  id?: string,
): Promise<Document> => {
  const docs = await readDocuments()
  const now = new Date().toISOString()

  if (id) {
    const idx = docs.findIndex((d) => d.id === id)
    if (idx >= 0) {
      docs[idx].title = title
      docs[idx].content = content
      docs[idx].updatedAt = now
      await writeDocuments(docs)
      return docs[idx]
    }
  }

  const doc: Document = {
    id: crypto.randomUUID(),
    title,
    content,
    createdAt: now,
    updatedAt: now,
  }
  docs.push(doc)
  await writeDocuments(docs)
  return doc
}

export const deleteDocument = async (id: string): Promise<boolean> => {
  const docs = await readDocuments()
  const idx = docs.findIndex((d) => d.id === id)
  if (idx < 0) return false
  docs.splice(idx, 1)
  await writeDocuments(docs)
  return true
}

