const clientScript = (initialContent: string): string => `
  (function() {
    const editor = document.querySelector('[p-target="editor"]');
    const previewContent = document.querySelector('[p-target="preview-content"]');
    const titleInput = document.querySelector('[p-target="title-input"]');

    // Markdown parser (client-side minimal version)
    ${clientMarkdownParser()}

    // Update preview
    const updatePreview = () => {
      if (previewContent && editor) {
        previewContent.innerHTML = parseMarkdown(editor.value);
      }
    };

    // Initial render
    updatePreview();

    // Live preview on input
    if (editor) {
      editor.addEventListener('input', updatePreview);
    }

    // Toolbar actions
    const toolbarInserts = ${JSON.stringify(toolbarActions)};

    document.querySelectorAll('[data-action]').forEach(btn => {
      btn.addEventListener('click', () => {
        const action = btn.dataset.action;
        const insert = toolbarInserts[action];
        if (!insert || !editor) return;

        const start = editor.selectionStart;
        const end = editor.selectionEnd;
        const selected = editor.value.substring(start, end);
        const text = selected || insert.placeholder;

        let newText = insert.before + text + insert.after;
        if (insert.block && start > 0 && editor.value[start - 1] !== '\\n') {
          newText = '\\n' + newText;
        }

        editor.setRangeText(newText, start, end, 'select');
        editor.focus();
        updatePreview();
      });
    });

    // Save document
    document.querySelector('[p-trigger="save-document"]')?.addEventListener('click', async () => {
      const title = titleInput?.value || 'Untitled';
      const content = editor?.value || '';
      const docIdEl = document.querySelector('[p-target="document-id"]');
      const id = docIdEl?.value || '';

      const res = await fetch('/api/save', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ title, content, id: id || undefined }),
      });
      const doc = await res.json();

      // Update hidden doc ID
      if (!docIdEl) {
        const hidden = document.createElement('input');
        hidden.type = 'hidden';
        hidden.setAttribute('p-target', 'document-id');
        hidden.value = doc.id;
        titleInput.parentElement.appendChild(hidden);
      } else {
        docIdEl.value = doc.id;
      }
      alert('Document saved!');
    });

    // Load documents list
    document.querySelector('[p-trigger="load-documents"]')?.addEventListener('click', async () => {
      const res = await fetch('/api/documents');
      const docs = await res.json();
      showDocumentModal(docs);
    });

    // New document
    document.querySelector('[p-trigger="new-document"]')?.addEventListener('click', () => {
      if (editor) editor.value = '';
      if (titleInput) titleInput.value = '';
      const docIdEl = document.querySelector('[p-target="document-id"]');
      if (docIdEl) docIdEl.remove();
      updatePreview();
    });

    // Document modal
    function showDocumentModal(docs) {
      const existing = document.querySelector('[p-target="document-modal"]');
      if (existing) existing.remove();

      const overlay = document.createElement('div');
      overlay.setAttribute('p-target', 'document-modal');
      overlay.style.cssText = 'position:fixed;top:0;left:0;right:0;bottom:0;background:rgba(0,0,0,0.5);display:flex;align-items:center;justify-content:center;z-index:1000;';

      let listHtml = '';
      if (docs.length === 0) {
        listHtml = '<p style="color:#888;font-size:14px;">No saved documents yet.</p>';
      } else {
        listHtml = docs.map(doc =>
          '<div style="display:flex;justify-content:space-between;align-items:center;padding:10px 12px;border-bottom:1px solid #eee;cursor:pointer;" data-load-id="' + doc.id + '">' +
          '<div><div style="font-weight:500;font-size:14px;color:#333;">' + escapeHtmlClient(doc.title) + '</div>' +
          '<div style="font-size:12px;color:#888;">Updated: ' + new Date(doc.updatedAt).toLocaleDateString() + '</div></div>' +
          '<button data-delete-id="' + doc.id + '" style="padding:3px 8px;font-size:11px;border:1px solid #e55;border-radius:3px;cursor:pointer;background:transparent;color:#e55;">Delete</button>' +
          '</div>'
        ).join('');
      }

      overlay.innerHTML = '<div style="background:#fff;border-radius:8px;padding:24px;width:500px;max-height:70vh;overflow:auto;box-shadow:0 8px 32px rgba(0,0,0,0.2);">' +
        '<h3 style="margin:0 0 16px 0;font-size:18px;font-weight:600;color:#1a1a2e;">Saved Documents</h3>' +
        listHtml +
        '<button id="close-modal-btn" style="padding:6px 14px;font-size:13px;border:1px solid #ccc;border-radius:4px;cursor:pointer;background:#f8f9fa;color:#333;margin-top:12px;">Close</button>' +
        '</div>';

      document.body.appendChild(overlay);

      overlay.querySelector('#close-modal-btn')?.addEventListener('click', () => overlay.remove());
      overlay.addEventListener('click', (e) => { if (e.target === overlay) overlay.remove(); });

      overlay.querySelectorAll('[data-load-id]').forEach(el => {
        el.addEventListener('click', async (e) => {
          if (e.target.dataset?.deleteId) return;
          const id = el.dataset.loadId;
          const res = await fetch('/api/documents/' + id);
          const doc = await res.json();
          if (editor) editor.value = doc.content;
          if (titleInput) titleInput.value = doc.title;

          let docIdEl = document.querySelector('[p-target="document-id"]');
          if (!docIdEl) {
            docIdEl = document.createElement('input');
            docIdEl.type = 'hidden';
            docIdEl.setAttribute('p-target', 'document-id');
            titleInput.parentElement.appendChild(docIdEl);
          }
          docIdEl.value = doc.id;

          overlay.remove();
          updatePreview();
        });
      });

      overlay.querySelectorAll('[data-delete-id]').forEach(el => {
        el.addEventListener('click', async (e) => {
          e.stopPropagation();
          const id = el.dataset.deleteId;
          if (!confirm('Delete this document?')) return;
          await fetch('/api/documents/' + id, { method: 'DELETE' });
          overlay.remove();
          // Re-open refreshed list
          const res2 = await fetch('/api/documents');
          const docs2 = await res2.json();
          showDocumentModal(docs2);
        });
      });
    }

    function escapeHtmlClient(s) {
      const d = document.createElement('div');
      d.textContent = s;
      return d.innerHTML;
    }
  })();
`

const clientMarkdownParser = (): string => `
  function escapeHtml(t) {
    return t.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
  }
  function parseInline(t) {
    var r = t;
    r = r.replace(/!\\[([^\\]]*)\\]\\(([^)]+)\\)/g, '<img src="$2" alt="$1" />');
    r = r.replace(/\\[([^\\]]+)\\]\\(([^)]+)\\)/g, '<a href="$2">$1</a>');
    r = r.replace(/\\*\\*\\*(.+?)\\*\\*\\*/g, '<strong><em>$1</em></strong>');
    r = r.replace(/\\*\\*(.+?)\\*\\*/g, '<strong>$1</strong>');
    r = r.replace(/\\*(.+?)\\*/g, '<em>$1</em>');
    r = r.replace(/~~(.+?)~~/g, '<del>$1</del>');
    r = r.replace(/\`([^\`]+)\`/g, '<code>$1</code>');
    return r;
  }
  function parseTable(lines) {
    if (lines.length < 2) return { html: '', consumed: 0 };
    function parseRow(l) { return l.replace(/^\\|/,'').replace(/\\|$/,'').split('|').map(function(c){return c.trim();}); }
    var hc = parseRow(lines[0]);
    if (!/^\\|?[\\s\\-:|]+\\|?$/.test(lines[1])) return { html: '', consumed: 0 };
    var aligns = parseRow(lines[1]).map(function(c) {
      var left = c.startsWith(':'), right = c.endsWith(':');
      if (left && right) return 'center';
      if (right) return 'right';
      if (left) return 'left';
      return '';
    });
    function aa(i) { return aligns[i] ? ' style="text-align:'+aligns[i]+'"' : ''; }
    var h = '<table>\\n<thead>\\n<tr>\\n';
    hc.forEach(function(c,i){h+='<th'+aa(i)+'>'+parseInline(escapeHtml(c))+'</th>\\n';});
    h += '</tr>\\n</thead>\\n<tbody>\\n';
    var consumed = 2;
    for (var i=2; i<lines.length; i++) {
      if (!lines[i].includes('|')) break;
      var cells = parseRow(lines[i]);
      h += '<tr>\\n';
      cells.forEach(function(c,ci){h+='<td'+aa(ci)+'>'+parseInline(escapeHtml(c))+'</td>\\n';});
      h += '</tr>\\n';
      consumed++;
    }
    h += '</tbody>\\n</table>';
    return { html: h, consumed: consumed };
  }
  function parseMarkdown(src) {
    var lines = src.split('\\n'), out = [], i = 0, inList = null;
    function closeList() { if(inList){out.push('</'+inList+'>');inList=null;} }
    while (i < lines.length) {
      var line = lines[i];
      if (line.startsWith('\`\`\`')) {
        closeList();
        var lang = line.slice(3).trim();
        var cl = [];
        i++;
        while (i<lines.length && !lines[i].startsWith('\`\`\`')) { cl.push(escapeHtml(lines[i])); i++; }
        i++;
        var la = lang ? ' class="language-'+escapeHtml(lang)+'"' : '';
        out.push('<pre><code'+la+'>'+cl.join('\\n')+'</code></pre>');
        continue;
      }
      if (line.includes('|') && i+1<lines.length && /^\\|?[\\s\\-:|]+\\|?$/.test(lines[i+1])) {
        closeList();
        var tr = parseTable(lines.slice(i));
        if (tr.consumed > 0) { out.push(tr.html); i+=tr.consumed; continue; }
      }
      if (line.trim()==='') { closeList(); i++; continue; }
      var hm = line.match(/^(#{1,6})\\s+(.+)$/);
      if (hm) { closeList(); var lv=hm[1].length; out.push('<h'+lv+'>'+parseInline(escapeHtml(hm[2]))+'</h'+lv+'>'); i++; continue; }
      if (/^(---|\\*\\*\\*|___)(\\s*)$/.test(line.trim())) { closeList(); out.push('<hr />'); i++; continue; }
      if (line.startsWith('>')) {
        closeList();
        var ql = [];
        while (i<lines.length && lines[i].startsWith('>')) { ql.push(lines[i].replace(/^>\\s?/,'')); i++; }
        out.push('<blockquote>'+parseInline(escapeHtml(ql.join('\\n')))+'</blockquote>');
        continue;
      }
      var ulm = line.match(/^[\\s]*[-*+]\\s+(.+)$/);
      if (ulm) { if(inList!=='ul'){closeList();out.push('<ul>');inList='ul';} out.push('<li>'+parseInline(escapeHtml(ulm[1]))+'</li>'); i++; continue; }
      var olm = line.match(/^[\\s]*\\d+\\.\\s+(.+)$/);
      if (olm) { if(inList!=='ol'){closeList();out.push('<ol>');inList='ol';} out.push('<li>'+parseInline(escapeHtml(olm[1]))+'</li>'); i++; continue; }
      closeList();
      var pl = [];
      while (i<lines.length && lines[i].trim()!=='' && !lines[i].startsWith('#') && !lines[i].startsWith('>') && !lines[i].startsWith('\`\`\`') && !/^[-*+]\\s/.test(lines[i]) && !/^\\d+\\.\\s/.test(lines[i]) && !/^(---|\\*\\*\\*|___)/.test(lines[i].trim())) { pl.push(lines[i]); i++; }
      if (pl.length>0) out.push('<p>'+parseInline(escapeHtml(pl.join('\\n')))+'</p>');
    }
    closeList();
    return out.join('\\n');
  }
`

