const server = Bun.serve({
  port: 3000,
  fetch: async (req) => {
    const url = new URL(req.url)

    // API: Save document
    if (url.pathname === '/api/save' && req.method === 'POST') {
      const body = await req.json() as { title: string; content: string; id?: string }
      const doc = await saveDocument(body.title, body.content, body.id)
      return Response.json(doc)
    }

    // API: List documents
    if (url.pathname === '/api/documents' && req.method === 'GET') {
      const sort = (url.searchParams.get('sort') || 'updatedAt') as 'title' | 'updatedAt' | 'createdAt'
      const dir = (url.searchParams.get('dir') || 'desc') as 'asc' | 'desc'
      const filter = url.searchParams.get('filter') || ''
      const docs = await listDocuments(sort, dir, filter)
      return Response.json(docs)
    }

    // API: Get single document
    const docMatch = url.pathname.match(/^\/api\/documents\/([^/]+)$/)
    if (docMatch && req.method === 'GET') {
      const doc = await getDocument(docMatch[1])
      if (!doc) return Response.json({ error: 'Not found' }, { status: 404 })
      return Response.json(doc)
    }

    // API: Delete document
    if (docMatch && req.method === 'DELETE') {
      const ok = await deleteDocument(docMatch[1])
      if (!ok) return Response.json({ error: 'Not found' }, { status: 404 })
      return Response.json({ ok: true })
    }

    // API: Render markdown (for AJAX preview)
    if (url.pathname === '/api/render' && req.method === 'POST') {
      const { parseMarkdown } = await import('./markdown')
      const body = await req.json() as { content: string }
      return Response.json({ html: parseMarkdown(body.content) })
    }

    // Main page
