const DATA_PATH = './data/palettes.jsonl'

type SavedPalette = {
  baseColor: string
  mode: HarmonyMode
  colors: string[]
  createdAt: string
}

const savePalette = async (entry: SavedPalette): Promise<void> => {
  const file = Bun.file(DATA_PATH)
  const existing = (await file.exists()) ? await file.text() : ''
  await Bun.write(DATA_PATH, existing + JSON.stringify(entry) + '\n')
}

const loadPalettes = async (): Promise<SavedPalette[]> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) return []
  const text = await file.text()
  return text
    .trim()
    .split('\n')
    .filter(Boolean)
    .map((line) => JSON.parse(line) as SavedPalette)
}

export const createPalette = async (request: PaletteRequest): Promise<PaletteResponse> => {
  const { baseColor, mode = 'complementary' } = request

  if (!isValidHex(baseColor)) {
    throw new Error(`Invalid hex color: ${baseColor}`)
  }

  const normalized = normalizeHex(baseColor)
  const colors = generatePalette(normalized, mode)

  const html = renderPalette({
    baseColor: normalized,
    mode,
  })

  await savePalette({
    baseColor: normalized,
    mode,
    colors,
    createdAt: new Date().toISOString(),
  })

  return { baseColor: normalized, mode, colors, html }
}

export const getContrastReport = (
  hex1: string,
  hex2: string,
): ContrastResult => {
  if (!isValidHex(hex1) || !isValidHex(hex2)) {
    throw new Error(`Invalid hex color(s): ${hex1}, ${hex2}`)
  }
  return checkContrast(normalizeHex(hex1), normalizeHex(hex2))
}

export const renderPaletteView = (
  baseColor: string,
  mode: HarmonyMode = 'complementary',
  contrastColor1?: string,
  contrastColor2?: string,
): string => {
  if (!isValidHex(baseColor)) {
    throw new Error(`Invalid hex color: ${baseColor}`)
  }
  return renderPalette({
    baseColor: normalizeHex(baseColor),
    mode,
    contrastColor1: contrastColor1 ? normalizeHex(contrastColor1) : undefined,
    contrastColor2: contrastColor2 ? normalizeHex(contrastColor2) : undefined,
  })
}

