const clamp = (v: number, min: number, max: number): number =>
  Math.max(min, Math.min(max, v))

const round = (v: number, decimals = 1): number =>
  Math.round(v * 10 ** decimals) / 10 ** decimals

export const hexToRgb = (hex: string): RGB => {
  const clean = hex.replace(/^#/, '')
  const full =
    clean.length === 3
      ? clean
          .split('')
          .map((c) => c + c)
          .join('')
      : clean
  const num = parseInt(full, 16)
  return {
    r: (num >> 16) & 255,
    g: (num >> 8) & 255,
    b: num & 255,
  }
}

export const rgbToHex = ({ r, g, b }: RGB): string => {
  const toHex = (n: number) =>
    clamp(Math.round(n), 0, 255).toString(16).padStart(2, '0')
  return `#${toHex(r)}${toHex(g)}${toHex(b)}`
}

export const rgbToHsl = ({ r, g, b }: RGB): HSL => {
  const rn = r / 255
  const gn = g / 255
  const bn = b / 255
  const max = Math.max(rn, gn, bn)
  const min = Math.min(rn, gn, bn)
  const delta = max - min
  const l = (max + min) / 2

  if (delta === 0) {
    return { h: 0, s: 0, l: round(l * 100) }
  }

  const s = l > 0.5 ? delta / (2 - max - min) : delta / (max + min)

  let h = 0
  if (max === rn) {
    h = ((gn - bn) / delta + (gn < bn ? 6 : 0)) / 6
  } else if (max === gn) {
    h = ((bn - rn) / delta + 2) / 6
  } else {
    h = ((rn - gn) / delta + 4) / 6
  }

  return {
    h: round(h * 360),
    s: round(s * 100),
    l: round(l * 100),
  }
}

export const hslToRgb = ({ h, s, l }: HSL): RGB => {
  const sn = s / 100
  const ln = l / 100
  const hn = ((h % 360) + 360) % 360

  if (sn === 0) {
    const v = Math.round(ln * 255)
    return { r: v, g: v, b: v }
  }

  const hueToRgb = (p: number, q: number, t: number): number => {
    const tt = ((t % 1) + 1) % 1
    if (tt < 1 / 6) return p + (q - p) * 6 * tt
    if (tt < 1 / 2) return q
    if (tt < 2 / 3) return p + (q - p) * (2 / 3 - tt) * 6
    return p
  }

  const q = ln < 0.5 ? ln * (1 + sn) : ln + sn - ln * sn
  const p = 2 * ln - q
  const hNorm = hn / 360

  return {
    r: Math.round(hueToRgb(p, q, hNorm + 1 / 3) * 255),
    g: Math.round(hueToRgb(p, q, hNorm) * 255),
    b: Math.round(hueToRgb(p, q, hNorm - 1 / 3) * 255),
  }
}

export const createColor = (hex: string): Color => {
  const rgb = hexToRgb(hex)
  const hsl = rgbToHsl(rgb)
  return { hex: rgbToHex(rgb), rgb, hsl }
}

export const colorFromHsl = (hsl: HSL): Color => {
  const rgb = hslToRgb(hsl)
  return { hex: rgbToHex(rgb), rgb, hsl: { ...hsl, h: round(((hsl.h % 360) + 360) % 360) } }
}

