import { type Color, type HSL, colorFromHsl } from './color'

export type HarmonyType =
  | 'complementary'
  | 'analogous'
  | 'triadic'
  | 'split-complementary'
  | 'tetradic'

export type Palette = {
  harmony: HarmonyType
  base: Color
  colors: Color[]
}

const shiftHue = (hsl: HSL, degrees: number): HSL => ({
  h: (hsl.h + degrees + 360) % 360,
  s: hsl.s,
  l: hsl.l,
})

const harmonyOffsets: Record<HarmonyType, number[]> = {
  complementary: [0, 180],
  analogous: [0, -30, 30, -60, 60],
  triadic: [0, 120, 240],
  'split-complementary': [0, 150, 210],
  tetradic: [0, 90, 180, 270],
}

export const generatePalette = (base: Color, harmony: HarmonyType): Palette => {
  const offsets = harmonyOffsets[harmony]
  const colors = offsets.map((offset) => colorFromHsl(shiftHue(base.hsl, offset)))

  return { harmony, base, colors }
}

export const allHarmonies: HarmonyType[] = [
  'complementary',
  'analogous',
  'triadic',
  'split-complementary',
  'tetradic',
]

export const harmonyLabels: Record<HarmonyType, string> = {
