}

export const rgbToHsl = ({ r, g, b }: RGB): HSL => {
  const rn = r / 255
  const gn = g / 255
  const bn = b / 255
  const max = Math.max(rn, gn, bn)
  const min = Math.min(rn, gn, bn)
  const l = (max + min) / 2
  if (max === min) return { h: 0, s: 0, l }
  const d = max - min
  const s = l > 0.5 ? d / (2 - max - min) : d / (max + min)
  let h = 0
  if (max === rn) h = ((gn - bn) / d + (gn < bn ? 6 : 0)) / 6
  else if (max === gn) h = ((bn - rn) / d + 2) / 6
  else h = ((rn - gn) / d + 4) / 6
  return { h, s, l }
}

export const hslToRgb = ({ h, s, l }: HSL): RGB => {
  if (s === 0) {
    const v = Math.round(l * 255)
    return { r: v, g: v, b: v }
  }
  const hue2rgb = (p: number, q: number, t: number): number => {
    const tn = t < 0 ? t + 1 : t > 1 ? t - 1 : t
    if (tn < 1 / 6) return p + (q - p) * 6 * tn
    if (tn < 1 / 2) return q
    if (tn < 2 / 3) return p + (q - p) * (2 / 3 - tn) * 6
    return p
  }
  const q = l < 0.5 ? l * (1 + s) : l + s - l * s
  const p = 2 * l - q
  return {
    r: Math.round(hue2rgb(p, q, h + 1 / 3) * 255),
    g: Math.round(hue2rgb(p, q, h) * 255),
    b: Math.round(hue2rgb(p, q, h - 1 / 3) * 255),
  }
}

export const hexToHsl = (hex: string): HSL => rgbToHsl(hexToRgb(hex))

export const hslToHex = (hsl: HSL): string => rgbToHex(hslToRgb(hsl))

/** Normalize hue to [0, 1) */
export const normalizeHue = (h: number): number => ((h % 1) + 1) % 1

export const formatHsl = ({ h, s, l }: HSL): string =>
  `hsl(${Math.round(h * 360)}, ${Math.round(s * 100)}%, ${Math.round(l * 100)}%)`

export const formatRgb = ({ r, g, b }: RGB): string => `rgb(${r}, ${g}, ${b})`

export const isValidHex = (hex: string): boolean =>
  /^#?([0-9A-Fa-f]{3}|[0-9A-Fa-f]{6})$/.test(hex)

// Palette generation using color theory

import { type HSL, hexToHsl, hslToHex, hslToRgb, normalizeHue, formatHsl, formatRgb } from './color'

export type HarmonyMode =
  | 'complementary'
  | 'analogous'
  | 'triadic'
  | 'split-complementary'
  | 'tetradic'

export type PaletteColor = {
  hex: string
  rgb: string
  hsl: string
  hslRaw: HSL
  label: string
}

const HARMONY_OFFSETS: Record<HarmonyMode, { offsets: number[]; labels: string[] }> = {
  complementary: {
    offsets: [0, 0.5],
    labels: ['Base', 'Complement'],
  },
  analogous: {
    offsets: [-1 / 12, 0, 1 / 12],
    labels: ['Analogous -30°', 'Base', 'Analogous +30°'],
  },
  triadic: {
    offsets: [0, 1 / 3, 2 / 3],
    labels: ['Base', 'Triad 120°', 'Triad 240°'],
  },
  'split-complementary': {
    offsets: [0, 5 / 12, 7 / 12],
    labels: ['Base', 'Split 150°', 'Split 210°'],
  },
  tetradic: {
    offsets: [0, 1 / 6, 0.5, 2 / 3],
    labels: ['Base', 'Tetradic 60°', 'Tetradic 180°', 'Tetradic 240°'],
  },
}

export const HARMONY_MODES: HarmonyMode[] = [
  'complementary',
  'analogous',
  'triadic',
  'split-complementary',
  'tetradic',
]

export const generatePalette = (baseHex: string, mode: HarmonyMode): PaletteColor[] => {
  const baseHsl = hexToHsl(baseHex)
  const { offsets, labels } = HARMONY_OFFSETS[mode]

  return offsets.map((offset, i) => {
    const hsl: HSL = {
      h: normalizeHue(baseHsl.h + offset),
      s: baseHsl.s,
      l: baseHsl.l,
    }
    const hex = hslToHex(hsl)
    const rgb = hslToRgb(hsl)
    return {
      hex,
      rgb: formatRgb(rgb),
      hsl: formatHsl(hsl),
      hslRaw: hsl,
      label: labels[i],
    }
  })
}

// WCAG contrast ratio calculator

import { type RGB, hexToRgb } from './color'

export type WcagLevel = 'AAA' | 'AA' | 'Fail'

export type ContrastResult = {
  ratio: number
  ratioText: string
  normalTextAA: boolean
  normalTextAAA: boolean
  largeTextAA: boolean
  largeTextAAA: boolean
  normalLevel: WcagLevel
  largeLevel: WcagLevel
}

/** sRGB relative luminance per WCAG 2.1 */
const relativeLuminance = ({ r, g, b }: RGB): number => {
  const linearize = (c: number): number => {
    const srgb = c / 255
    return srgb <= 0.04045 ? srgb / 12.92 : Math.pow((srgb + 0.055) / 1.055, 2.4)
  }
  return 0.2126 * linearize(r) + 0.7152 * linearize(g) + 0.0722 * linearize(b)
}

/** WCAG contrast ratio between two colors */
export const contrastRatio = (hex1: string, hex2: string): number => {
  const l1 = relativeLuminance(hexToRgb(hex1))
  const l2 = relativeLuminance(hexToRgb(hex2))
  const lighter = Math.max(l1, l2)
  const darker = Math.min(l1, l2)
  return (lighter + 0.05) / (darker + 0.05)
}

/** Full WCAG compliance check */
export const checkContrast = (hex1: string, hex2: string): ContrastResult => {
  const ratio = contrastRatio(hex1, hex2)
  const normalTextAA = ratio >= 4.5
  const normalTextAAA = ratio >= 7
  const largeTextAA = ratio >= 3
  const largeTextAAA = ratio >= 4.5

  const normalLevel: WcagLevel = normalTextAAA ? 'AAA' : normalTextAA ? 'AA' : 'Fail'
  const largeLevel: WcagLevel = largeTextAAA ? 'AAA' : largeTextAA ? 'AA' : 'Fail'

  return {
    ratio,
    ratioText: `${ratio.toFixed(2)}:1`,
    normalTextAA,
    normalTextAAA,
    largeTextAA,
    largeTextAAA,
    normalLevel,
    largeLevel,
  }
}

