// Color Palette Generator — main entry point

import { createSSR } from 'plaited'
import { isValidHex } from './color'
import { type HarmonyMode, HARMONY_MODES, generatePalette } from './palette'
import { checkContrast, type ContrastResult } from './contrast'
import { renderPage } from './ui'

export type { HarmonyMode } from './palette'
export type { ContrastResult } from './contrast'
export { generatePalette } from './palette'
export { checkContrast, contrastRatio } from './contrast'
export { hexToRgb, rgbToHex, hexToHsl, hslToHex, formatHsl, formatRgb, isValidHex } from './color'

type AppState = {
  baseHex: string
  mode: HarmonyMode
  fgHex: string | null
  bgHex: string | null
}

const DEFAULT_STATE: AppState = {
  baseHex: '#6c5ce7',
  mode: 'complementary',
  fgHex: null,
  bgHex: null,
}

const dataDir = './data'
const stateFile = `${dataDir}/state.json`

const loadState = async (): Promise<AppState> => {
  const file = Bun.file(stateFile)
  if (await file.exists()) {
    return { ...DEFAULT_STATE, ...(await file.json()) }
  }
  return { ...DEFAULT_STATE }
}

const saveState = async (state: AppState): Promise<void> => {
  await Bun.write(stateFile, JSON.stringify(state, null, 2))
}

/** Save a generated palette to history */
const savePaletteToHistory = async (baseHex: string, mode: HarmonyMode): Promise<void> => {
  const historyFile = `${dataDir}/history.jsonl`
  const entry = JSON.stringify({
    baseHex,
    mode,
    timestamp: new Date().toISOString(),
    colors: generatePalette(baseHex, mode).map((c) => c.hex),
  })
  const file = Bun.file(historyFile)
  const existing = (await file.exists()) ? await file.text() : ''
  await Bun.write(historyFile, existing + entry + '\n')
}

/** Render the full page HTML */
export const render = async (overrides?: Partial<AppState>): Promise<string> => {
  const state = { ...(await loadState()), ...overrides }
  const palette = generatePalette(state.baseHex, state.mode)
  const fgHex = state.fgHex ?? palette[0]?.hex ?? '#000000'
  const bgHex = state.bgHex ?? palette[1]?.hex ?? '#ffffff'

  const ssr = createSSR()
  const template = renderPage(state.baseHex, state.mode, fgHex, bgHex)
  return ssr(template)
}

/** Handle incoming events from the UI */
export const handleEvent = async (
  event: string,
  data: Record<string, string>,
): Promise<{ html: string; state: AppState }> => {
  const state = await loadState()

  switch (event) {
    case 'color-pick':
    case 'hex-input': {
      const hex = data.value ?? ''
      if (isValidHex(hex)) {
        state.baseHex = hex.startsWith('#') ? hex : `#${hex}`
        state.fgHex = null
        state.bgHex = null
      }
      break
    }
    case 'change-mode': {
      const mode = data.mode as HarmonyMode
      if (HARMONY_MODES.includes(mode)) {
        state.mode = mode
        state.fgHex = null
        state.bgHex = null
        await savePaletteToHistory(state.baseHex, state.mode)
      }
      break
    }
    case 'select-fg': {
      if (isValidHex(data.value)) {
        state.fgHex = data.value
      }
      break
    }
    case 'select-bg': {
      if (isValidHex(data.value)) {
        state.bgHex = data.value
      }
      break
    }
  }

  await saveState(state)
  const html = await render(state)
  return { html, state }
}

/** CLI: render and print the palette for a given hex and mode */
const main = async () => {
  const args = process.argv.slice(2)
  const baseHex = args[0] ?? '#6c5ce7'
  const mode = (args[1] ?? 'complementary') as HarmonyMode

  if (!isValidHex(baseHex)) {
    console.error(`Invalid hex color: ${baseHex}`)
    process.exit(1)
  }

  if (!HARMONY_MODES.includes(mode)) {
    console.error(`Invalid mode: ${mode}. Use one of: ${HARMONY_MODES.join(', ')}`)
    process.exit(1)
  }

  const palette = generatePalette(baseHex, mode)

  console.log(`\nPalette: ${mode} from ${baseHex}\n`)
  console.log('─'.repeat(60))

  for (const color of palette) {
    console.log(`  ${color.label}`)
    console.log(`    HEX: ${color.hex}`)
    console.log(`    RGB: ${color.rgb}`)
    console.log(`    HSL: ${color.hsl}`)
    console.log('')
  }

  // Show contrast between first two colors
  if (palette.length >= 2) {
    const result = checkContrast(palette[0].hex, palette[1].hex)
    console.log('─'.repeat(60))
    console.log(`\nContrast: ${palette[0].hex} vs ${palette[1].hex}`)
    console.log(`  Ratio:          ${result.ratioText}`)
    console.log(`  Normal Text AA: ${result.normalTextAA ? 'PASS' : 'FAIL'}`)
    console.log(`  Normal Text AAA:${result.normalTextAAA ? ' PASS' : ' FAIL'}`)
    console.log(`  Large Text AA:  ${result.largeTextAA ? 'PASS' : 'FAIL'}`)
    console.log(`  Large Text AAA: ${result.largeTextAAA ? 'PASS' : 'FAIL'}`)
  }

  await savePaletteToHistory(baseHex, mode)
  await saveState({ baseHex, mode, fgHex: null, bgHex: null })

  // Also output HTML
  const html = await render({ baseHex, mode })
  await Bun.write(`${dataDir}/palette.html`, html)
  console.log(`\nHTML saved to ${dataDir}/palette.html`)
}

main().catch(console.error)

