  "version": "1.0.0",
  "description": "A responsive portfolio gallery with project cards, filtering, search, sorting, and lightbox detail views",
  "main": "src/index.ts",
  "modnet": {
    "contentType": "art",
    "structure": "collection",
    "mechanics": ["sort", "filter"],
    "boundary": "all",
    "scale": 2
  },
  "dependencies": {
    "plaited": "latest"
  }
}

import type { Project, GalleryFilters, SortMode } from './types'

const DATA_PATH = `${import.meta.dir}/../data/projects.json`

export const loadProjects = async (): Promise<Project[]> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) return []
  return file.json()
}

export const saveProjects = async (projects: Project[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(projects, null, 2))
}

export const getProjectById = async (id: string): Promise<Project | undefined> => {
  const projects = await loadProjects()
  return projects.find((p) => p.id === id)
}

export const getAllTags = async (): Promise<string[]> => {
  const projects = await loadProjects()
  const tagSet = new Set<string>()
  for (const project of projects) {
    for (const tag of project.tags) {
      tagSet.add(tag)
    }
  }
  return [...tagSet].sort()
}

const sortProjects = (projects: Project[], mode: SortMode): Project[] => {
  const sorted = [...projects]
  switch (mode) {
    case 'date-desc':
      return sorted.sort((a, b) => new Date(b.dateAdded).getTime() - new Date(a.dateAdded).getTime())
    case 'date-asc':
      return sorted.sort((a, b) => new Date(a.dateAdded).getTime() - new Date(b.dateAdded).getTime())
    case 'alpha-asc':
      return sorted.sort((a, b) => a.title.localeCompare(b.title))
    case 'alpha-desc':
      return sorted.sort((a, b) => b.title.localeCompare(a.title))
  }
}

export const filterProjects = async (filters: GalleryFilters): Promise<Project[]> => {
  let projects = await loadProjects()

  if (filters.tag) {
    projects = projects.filter((p) => p.tags.includes(filters.tag!))
  }

  if (filters.search) {
    const query = filters.search.toLowerCase()
    projects = projects.filter(
      (p) =>
        p.title.toLowerCase().includes(query) ||
        p.description.toLowerCase().includes(query),
    )
  }

  return sortProjects(projects, filters.sort)
}

import { h, Fragment } from 'plaited'
import type { Project, GalleryFilters } from './types'
import { styles } from './styles'

const styleAttr = (obj: Record<string, string | number>): string =>
  Object.entries(obj)
    .map(([k, v]) => {
      const prop = k.replace(/[A-Z]/g, (m) => `-${m.toLowerCase()}`)
      return `${prop}:${v}`
    })
    .join(';')

export const renderTagChip = (tag: string, isActive: boolean, baseUrl: string) => {
  const href = isActive ? baseUrl : `${baseUrl}${baseUrl.includes('?') ? '&' : '?'}tag=${encodeURIComponent(tag)}`
  return h('a', {
    href,
    style: styleAttr(isActive ? styles.tagChipActive : styles.tagChip),
  }, tag)
}

export const renderProjectCard = (project: Project) =>
  h('a', {
    href: `/project/${project.id}`,
    style: styleAttr(styles.card),
  },
    h('img', {
      src: project.thumbnail,
      alt: project.title,
      style: styleAttr(styles.cardThumb),
      loading: 'lazy',
    }),
    h('div', { style: styleAttr(styles.cardBody) },
      h('h3', { style: styleAttr(styles.cardTitle) }, project.title),
      h('p', { style: styleAttr(styles.cardDesc) }, project.description),
      h('div', { style: styleAttr(styles.cardTags) },
        ...project.tags.map((tag) =>
          h('span', { style: styleAttr(styles.cardTag) }, tag),
        ),
      ),
    ),
  )

export const renderControls = (filters: GalleryFilters, allTags: string[]) => {
  const baseUrl = '/'
  const buildSortUrl = (sort: string) => {
    const params = new URLSearchParams()
    if (filters.search) params.set('search', filters.search)
    if (filters.tag) params.set('tag', filters.tag)
    params.set('sort', sort)
    return `${baseUrl}?${params.toString()}`
  }

  return h('div', { style: styleAttr(styles.controls) },
    h('form', { method: 'GET', action: '/', style: 'display:contents' },
      filters.tag ? h('input', { type: 'hidden', name: 'tag', value: filters.tag }) : null,
      h('input', { type: 'hidden', name: 'sort', value: filters.sort }),
      h('input', {
        type: 'search',
        name: 'search',
        placeholder: 'Search projects by title...',
        value: filters.search || '',
        style: styleAttr(styles.searchInput),
      }),
    ),
    h('div', { style: 'display:flex;gap:0.5rem;flex-wrap:wrap;align-items:center' },
      h('span', { style: 'font-size:0.85rem;color:#64748b;font-weight:500' }, 'Sort:'),
      h('a', {
        href: buildSortUrl('date-desc'),
        style: styleAttr(filters.sort === 'date-desc' ? styles.tagChipActive : styles.tagChip),
      }, 'Newest'),
      h('a', {
        href: buildSortUrl('date-asc'),
        style: styleAttr(filters.sort === 'date-asc' ? styles.tagChipActive : styles.tagChip),
      }, 'Oldest'),
      h('a', {
        href: buildSortUrl('alpha-asc'),
        style: styleAttr(filters.sort === 'alpha-asc' ? styles.tagChipActive : styles.tagChip),
      }, 'A-Z'),
      h('a', {
        href: buildSortUrl('alpha-desc'),
        style: styleAttr(filters.sort === 'alpha-desc' ? styles.tagChipActive : styles.tagChip),
      }, 'Z-A'),
    ),
    h('div', { style: 'display:flex;gap:0.4rem;flex-wrap:wrap;align-items:center' },
      h('span', { style: 'font-size:0.85rem;color:#64748b;font-weight:500' }, 'Filter:'),
      ...allTags.map((tag) => {
        const isActive = filters.tag === tag
        const params = new URLSearchParams()
        if (filters.search) params.set('search', filters.search)
        if (!isActive) params.set('tag', tag)
        params.set('sort', filters.sort)
        const href = `${baseUrl}?${params.toString()}`
        return h('a', {
          href,
          style: styleAttr(isActive ? styles.tagChipActive : styles.tagChip),
        }, tag)
      }),
    ),
  )
}

export const renderGrid = (projects: Project[]) => {
  if (projects.length === 0) {
    return h('div', { style: styleAttr(styles.emptyState) },
      h('p', {}, 'No projects found matching your criteria.'),
    )
  }
  return h('div', { style: styleAttr(styles.grid) },
    ...projects.map(renderProjectCard),
  )
}

export const renderGalleryPage = (
  projects: Project[],
  filters: GalleryFilters,
  allTags: string[],
) =>
  h('html', { lang: 'en' },
    h('head', {},
      h('meta', { charset: 'UTF-8' }),
      h('meta', { name: 'viewport', content: 'width=device-width, initial-scale=1.0' }),
      h('title', {}, 'Portfolio Gallery'),
      h('style', {}, `
        * { box-sizing: border-box; margin: 0; padding: 0; }
        body { ${styleAttr(styles.page)} }
        a { text-decoration: none; }
        a.card:hover { transform: translateY(-4px); box-shadow: 0 8px 24px rgba(0,0,0,0.12); }
        input:focus { border-color: #6366f1 !important; }
      `),
    ),
    h('body', {},
      h('header', { style: styleAttr(styles.header) },
        h('h1', { style: styleAttr(styles.headerTitle) }, 'Portfolio Gallery'),
        h('p', { style: styleAttr(styles.headerSubtitle) }, 'A collection of projects and experiments'),
      ),
      renderControls(filters, allTags),
      renderGrid(projects),
    ),
  )

export const renderCarousel = (images: { src: string; alt: string }[], projectId: string) => {
  if (images.length === 0) return h(Fragment, {})

  return h('div', {
    style: styleAttr(styles.carousel),
    'p-target': 'carousel',
  },
    ...images.map((img, i) =>
      h('div', {
        style: `display:${i === 0 ? 'block' : 'none'}`,
        'data-slide': String(i),
        'p-target': `slide-${i}`,
      },
        h('img', {
          src: img.src,
          alt: img.alt,
          style: styleAttr(styles.carouselImage),
          'p-trigger': `click:openLightbox`,
          'data-index': String(i),
        }),
      ),
    ),
    images.length > 1
      ? h(Fragment, {},
          h('button', {
            style: `${styleAttr(styles.carouselBtn)};left:0.5rem`,
            'p-trigger': 'click:prevSlide',
            'aria-label': 'Previous image',
          }, '\u2039'),
          h('button', {
            style: `${styleAttr(styles.carouselBtn)};right:0.5rem`,
            'p-trigger': 'click:nextSlide',
            'aria-label': 'Next image',
          }, '\u203A'),
          h('div', { style: styleAttr(styles.carouselNav) },
            ...images.map((_, i) =>
              h('button', {
                style: styleAttr(i === 0 ? styles.carouselDotActive : styles.carouselDot),
                'p-trigger': `click:goToSlide`,
                'data-index': String(i),
                'aria-label': `Go to image ${i + 1}`,
              }),
            ),
          ),
        )
      : null,
  )
}

export const renderDetailPage = (project: Project) =>
  h('html', { lang: 'en' },
    h('head', {},
      h('meta', { charset: 'UTF-8' }),
      h('meta', { name: 'viewport', content: 'width=device-width, initial-scale=1.0' }),
      h('title', {}, `${project.title} - Portfolio`),
      h('style', {}, `
        * { box-sizing: border-box; margin: 0; padding: 0; }
        body { ${styleAttr(styles.page)} }
        a { text-decoration: none; }
        .lightbox { display: none; }
        .lightbox.active { display: flex; }
      `),
      h('script', { defer: true }, `
        document.addEventListener('DOMContentLoaded', () => {
          const slides = document.querySelectorAll('[data-slide]');
          const dots = document.querySelectorAll('[p-trigger*="goToSlide"]');
          const lightbox = document.getElementById('lightbox');
          const lightboxImg = document.getElementById('lightbox-img');
          let current = 0;
          const total = slides.length;

          const showSlide = (index) => {
            slides.forEach((s, i) => s.style.display = i === index ? 'block' : 'none');
            dots.forEach((d, i) => {
              d.style.background = i === index ? '#6366f1' : '#cbd5e1';
            });
            current = index;
          };

          document.querySelector('[p-trigger*="prevSlide"]')?.addEventListener('click', () => {
            showSlide((current - 1 + total) % total);
          });
          document.querySelector('[p-trigger*="nextSlide"]')?.addEventListener('click', () => {
            showSlide((current + 1) % total);
          });
          dots.forEach((dot) => {
            dot.addEventListener('click', () => showSlide(Number(dot.dataset.index)));
          });

          document.querySelectorAll('[p-trigger*="openLightbox"]').forEach((img) => {
            img.addEventListener('click', () => {
              if (lightbox && lightboxImg) {
                lightboxImg.src = img.src;
                lightboxImg.alt = img.alt;
                lightbox.classList.add('active');
              }
            });
          });

          document.getElementById('lightbox-close')?.addEventListener('click', () => {
            lightbox?.classList.remove('active');
          });
          lightbox?.addEventListener('click', (e) => {
            if (e.target === lightbox) lightbox.classList.remove('active');
          });

          document.addEventListener('keydown', (e) => {
            if (lightbox?.classList.contains('active') && e.key === 'Escape') {
              lightbox.classList.remove('active');
            }
            if (e.key === 'ArrowLeft') {
              showSlide((current - 1 + total) % total);
            }
            if (e.key === 'ArrowRight') {
              showSlide((current + 1) % total);
            }
          });
        });
      `),
    ),
    h('body', {},
      h('header', { style: styleAttr(styles.header) },
        h('h1', { style: styleAttr(styles.headerTitle) }, 'Portfolio Gallery'),
      ),
      h('div', { style: styleAttr(styles.detailContainer) },
        h('a', { href: '/', style: styleAttr(styles.backLink) }, '\u2190 Back to gallery'),
        h('h2', { style: styleAttr(styles.detailTitle) }, project.title),
        h('p', { style: styleAttr(styles.detailMeta) }, `Added ${project.dateAdded}`),
        h('div', { style: styleAttr(styles.detailLinks) },
          project.demoUrl
            ? h('a', {
                href: project.demoUrl,
                target: '_blank',
                rel: 'noopener noreferrer',
                style: `${styleAttr(styles.linkBtn)};${styleAttr(styles.linkBtnPrimary)}`,
              }, 'Live Demo \u2197')
            : null,
          project.sourceUrl
            ? h('a', {
                href: project.sourceUrl,
                target: '_blank',
                rel: 'noopener noreferrer',
                style: `${styleAttr(styles.linkBtn)};${styleAttr(styles.linkBtnSecondary)}`,
              }, 'Source Code \u2197')
            : null,
        ),
        h('div', { style: `display:flex;gap:0.4rem;flex-wrap:wrap;margin-bottom:1.5rem` },
          ...project.tags.map((tag) =>
            h('span', { style: styleAttr(styles.cardTag) }, tag),
          ),
        ),
        renderCarousel(project.images, project.id),
        h('div', { style: styleAttr(styles.detailDesc) },
          h('p', {}, project.fullDescription),
        ),
      ),
      // Lightbox overlay
      h('div', {
        id: 'lightbox',
        class: 'lightbox',
        style: styleAttr(styles.lightboxOverlay),
      },
        h('button', {
          id: 'lightbox-close',
          style: styleAttr(styles.lightboxClose),
          'aria-label': 'Close lightbox',
        }, '\u00D7'),
        h('img', {
          id: 'lightbox-img',
          src: '',
          alt: '',
          style: styleAttr(styles.lightboxImage),
        }),
      ),
    ),
  )

import { createSSR } from 'plaited'
import type { GalleryFilters, SortMode } from './types'
import { filterProjects, getAllTags, getProjectById } from './data'
import { renderGalleryPage, renderDetailPage } from './render'

const VALID_SORTS: SortMode[] = ['date-desc', 'date-asc', 'alpha-asc', 'alpha-desc']

const parseFilters = (url: URL): GalleryFilters => {
  const search = url.searchParams.get('search') ?? ''
  const tag = url.searchParams.get('tag') || null
  const sortParam = url.searchParams.get('sort') ?? 'date-desc'
  const sort: SortMode = VALID_SORTS.includes(sortParam as SortMode)
    ? (sortParam as SortMode)
    : 'date-desc'

  return { search, tag, sort }
}

const htmlResponse = (html: string, status = 200): Response =>
  new Response(`<!DOCTYPE html>${html}`, {
    status,
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })

export const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url)
  const { render } = createSSR()

  // Detail page: /project/:id
  const projectMatch = url.pathname.match(/^\/project\/([a-zA-Z0-9_-]+)$/)
  if (projectMatch) {
    const project = await getProjectById(projectMatch[1])
    if (!project) {
      return htmlResponse('<h1>Project not found</h1>', 404)
    }
    const html = render(renderDetailPage(project))
    return htmlResponse(html)
  }

  // Gallery listing: /
  if (url.pathname === '/' || url.pathname === '') {
    const filters = parseFilters(url)
    const [projects, allTags] = await Promise.all([
      filterProjects(filters),
      getAllTags(),
    ])
    const html = render(renderGalleryPage(projects, filters, allTags))
    return htmlResponse(html)
  }

  return new Response('Not Found', { status: 404 })
}

