import type { Project, GalleryFilters, SortField, SortDirection } from './types'

const DATA_PATH = `${import.meta.dir}/data/projects.json`

export const loadProjects = async (): Promise<Project[]> => {
  const file = Bun.file(DATA_PATH)
  const text = await file.text()
  return JSON.parse(text) as Project[]
}

export const saveProjects = async (projects: Project[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(projects, null, 2))
}

export const filterProjects = (
  projects: Project[],
  filters: GalleryFilters
): Project[] => {
  let result = [...projects]

  if (filters.search) {
    const query = filters.search.toLowerCase()
    result = result.filter(
      (p) =>
        p.title.toLowerCase().includes(query) ||
        p.description.toLowerCase().includes(query)
    )
  }

  if (filters.tag) {
    const tag = filters.tag
    result = result.filter((p) =>
      p.tags.some((t) => t.toLowerCase() === tag.toLowerCase())
    )
  }

  result.sort((a, b) => {
    let cmp: number
    if (filters.sortField === 'title') {
      cmp = a.title.localeCompare(b.title)
    } else {
      cmp = new Date(a.dateAdded).getTime() - new Date(b.dateAdded).getTime()
    }
    return filters.sortDirection === 'desc' ? -cmp : cmp
  })

  return result
}

export const getAllTags = (projects: Project[]): Map<string, number> => {
  const tagCounts = new Map<string, number>()
  for (const project of projects) {
    for (const tag of project.tags) {
      tagCounts.set(tag, (tagCounts.get(tag) ?? 0) + 1)
    }
  }
  return tagCounts
}

export const findProjectById = (
  projects: Project[],
  id: string
): Project | undefined => projects.find((p) => p.id === id)

export const parseFilters = (url: URL): GalleryFilters => ({
  search: url.searchParams.get('search') ?? '',
  tag: url.searchParams.get('tag') ?? null,
  sortField: (url.searchParams.get('sort') as SortField) ?? 'dateAdded',
  sortDirection: (url.searchParams.get('dir') as SortDirection) ?? 'desc',
})

import { h, Fragment } from 'plaited'
import { createSSR } from 'plaited/server'
import type { Project, GalleryFilters } from './types'
import * as s from './styles'

const styleObj = (obj: Record<string, string | number | undefined>): string =>
  Object.entries(obj)
    .filter(([, v]) => v !== undefined)
    .map(([k, v]) => {
      const prop = k.replace(/[A-Z]/g, (m) => `-${m.toLowerCase()}`)
      return `${prop}:${v}`
    })
    .join(';')

const buildUrl = (
  base: string,
  filters: GalleryFilters,
  overrides: Partial<GalleryFilters> = {}
): string => {
  const merged = { ...filters, ...overrides }
  const params = new URLSearchParams()
  if (merged.search) params.set('search', merged.search)
  if (merged.tag) params.set('tag', merged.tag)
  if (merged.sortField !== 'dateAdded') params.set('sort', merged.sortField)
  if (merged.sortDirection !== 'desc') params.set('dir', merged.sortDirection)
  const qs = params.toString()
  return qs ? `${base}?${qs}` : base
}

const renderTagPill = (
  tag: string,
  count: number,
  active: boolean,
  filters: GalleryFilters
) => {
  const href = active
    ? buildUrl('/', filters, { tag: null })
    : buildUrl('/', filters, { tag })
  return h(
    'a',
    { href, style: styleObj(s.tagPillStyles(active)) },
    `${tag} (${count})`
  )
}

