            h(
              'option',
              { value: 'title-desc', ...(sortValue === 'title-desc' ? { selected: '' } : {}) },
              'Z \u2192 A'
            )
          ),
          h(
            'button',
            {
              type: 'submit',
              style: `${styleObj(s.selectStyles)};cursor:pointer;background:var(--color-accent);color:#fff;border:none;font-weight:500`,
            },
            'Search'
          )
        ),
        h(
          'div',
          { style: styleObj(s.tagBarStyles) },
          ...[...allTags.entries()]
            .sort(([, a], [, b]) => b - a)
            .map(([tag, count]) =>
              renderTagPill(tag, count, filters.tag === tag, filters)
            )
        ),
        projects.length > 0
          ? h(
              'div',
              { class: 'grid', style: styleObj(s.gridStyles) },
              ...projects.map(renderCard)
            )
          : renderEmptyState(filters),
        h(
          'script',
          {},
          `
          document.querySelector('select[name="sortcombo"]').addEventListener('change', function(e) {
            const [sort, dir] = e.target.value.split('-');
            const form = e.target.closest('form');
            let sortInput = form.querySelector('input[name="sort"]');
            let dirInput = form.querySelector('input[name="dir"]');
            if (!sortInput) { sortInput = document.createElement('input'); sortInput.type = 'hidden'; sortInput.name = 'sort'; form.appendChild(sortInput); }
            if (!dirInput) { dirInput = document.createElement('input'); dirInput.type = 'hidden'; dirInput.name = 'dir'; form.appendChild(dirInput); }
            sortInput.value = sort;
            dirInput.value = dir;
            form.submit();
          });
          `
        )
      )
    )
  )

  const { render } = createSSR()
  return `<!DOCTYPE html>${render(page)}`
}

