                  class: 'detail-link',
                },
                'Live Demo \u2197'
              )
            : null,
          project.sourceUrl
            ? h(
                'a',
                {
                  href: project.sourceUrl,
                  target: '_blank',
                  rel: 'noopener',
                  style: styleObj(s.detailLinkBtnSecondaryStyles),
                  class: 'detail-link',
                },
                'Source Code \u2197'
              )
            : null
        ),
        h('p', { style: styleObj(s.detailDescStyles) }, project.fullDescription),
        project.images.length > 0
          ? h(
              'div',
              { style: styleObj(s.imageGalleryStyles) },
              ...project.images.map((src, i) =>
                h('img', {
                  src,
                  alt: `${project.title} screenshot ${i + 1}`,
                  style: styleObj(s.galleryImageStyles),
                  class: 'gallery-img',
                  loading: 'lazy',
                  'data-index': String(i),
                  onclick: `openLightbox(${i})`,
                })
              )
            )
          : null,
        h(
          'div',
          {
            id: 'lightbox',
            style: `${styleObj(s.lightboxOverlayStyles)};display:none`,
            onclick: 'closeLightbox(event)',
          },
          h(
            'button',
            {
              class: 'lightbox-btn',
              style: styleObj(s.lightboxCloseBtnStyles),
              onclick: 'closeLightbox(event, true)',
              'aria-label': 'Close lightbox',
            },
            '\u2715'
          ),
          h(
            'button',
            {
              class: 'lightbox-btn',
              style: `${styleObj(s.lightboxBtnStyles)};left:1rem`,
              onclick: 'prevImage(event)',
              'aria-label': 'Previous image',
            },
            '\u2039'
          ),
          h('img', {
            id: 'lightbox-img',
            style: styleObj(s.lightboxImgStyles),
            alt: 'Full size image',
          }),
          h(
            'button',
            {
              class: 'lightbox-btn',
              style: `${styleObj(s.lightboxBtnStyles)};right:1rem`,
              onclick: 'nextImage(event)',
              'aria-label': 'Next image',
            },
            '\u203A'
          ),
          h(
            'span',
            { id: 'lightbox-counter', style: styleObj(s.lightboxCounterStyles) },
            ''
          )
        ),
        h(
          'script',
          {},
          `
          const images = ${JSON.stringify(project.images)};
          let currentIndex = 0;
          const lightbox = document.getElementById('lightbox');
          const lightboxImg = document.getElementById('lightbox-img');
          const counter = document.getElementById('lightbox-counter');

          const openLightbox = (index) => {
            currentIndex = index;
            updateLightbox();
            lightbox.style.display = 'flex';
            document.body.style.overflow = 'hidden';
          };

          const closeLightbox = (e, force) => {
            if (force || e.target === lightbox) {
              lightbox.style.display = 'none';
              document.body.style.overflow = '';
            }
          };

          const updateLightbox = () => {
            lightboxImg.src = images[currentIndex];
            counter.textContent = (currentIndex + 1) + ' / ' + images.length;
          };

          const prevImage = (e) => {
            e.stopPropagation();
            currentIndex = (currentIndex - 1 + images.length) % images.length;
            updateLightbox();
          };

          const nextImage = (e) => {
            e.stopPropagation();
            currentIndex = (currentIndex + 1) % images.length;
            updateLightbox();
          };

          document.addEventListener('keydown', (e) => {
            if (lightbox.style.display === 'none') return;
            if (e.key === 'Escape') closeLightbox(e, true);
            if (e.key === 'ArrowLeft') prevImage(e);
            if (e.key === 'ArrowRight') nextImage(e);
          });
          `
        )
      )
    )
  )

  const { render } = createSSR()
  return `<!DOCTYPE html>${render(page)}`
}

import {
  loadProjects,
  filterProjects,
  getAllTags,
  findProjectById,
  parseFilters,
} from './gallery'
import { renderGalleryPage, renderDetailPage } from './render'
import type { SortField, SortDirection } from './types'

const parseSort = (
  url: URL
): { sortField: SortField; sortDirection: SortDirection } => {
  const combo = url.searchParams.get('sortcombo')
  if (combo) {
    const [field, dir] = combo.split('-')
    return {
      sortField: (field as SortField) || 'dateAdded',
      sortDirection: (dir as SortDirection) || 'desc',
    }
  }
  return {
    sortField: (url.searchParams.get('sort') as SortField) || 'dateAdded',
    sortDirection: (url.searchParams.get('dir') as SortDirection) || 'desc',
  }
}

const server = Bun.serve({
  port: Number(process.env.PORT) || 3000,

  fetch: async (req) => {
    const url = new URL(req.url)
    const path = url.pathname

    if (path === '/api/projects') {
      const projects = await loadProjects()
      const filters = { ...parseFilters(url), ...parseSort(url) }
      const filtered = filterProjects(projects, filters)
      return Response.json(filtered)
    }

    if (path === '/api/tags') {
      const projects = await loadProjects()
      const tags = getAllTags(projects)
      const result = Object.fromEntries(
        [...tags.entries()].sort(([, a], [, b]) => b - a)
      )
      return Response.json(result)
    }

    const projectMatch = path.match(/^\/project\/([a-z0-9-]+)$/)
    if (projectMatch) {
      const projects = await loadProjects()
      const project = findProjectById(projects, projectMatch[1])
      if (!project) {
        return new Response('Project not found', { status: 404 })
      }
      const html = renderDetailPage(project)
      return new Response(html, {
        headers: { 'content-type': 'text/html; charset=utf-8' },
      })
    }

    if (path === '/' || path === '/index.html') {
      const projects = await loadProjects()
      const filters = { ...parseFilters(url), ...parseSort(url) }
      const allTags = getAllTags(projects)
      const filtered = filterProjects(projects, filters)
      const html = renderGalleryPage(filtered, allTags, filters)
      return new Response(html, {
        headers: { 'content-type': 'text/html; charset=utf-8' },
      })
    }

    return new Response('Not found', { status: 404 })
  },
})

