import type { Project, GalleryFilters, SortField, SortDirection } from './types'

const DATA_PATH = './data/projects.json'

const loadProjects = async (): Promise<Project[]> => {
  const file = Bun.file(DATA_PATH)
  const text = await file.text()
  return JSON.parse(text) as Project[]
}

const saveProjects = async (projects: Project[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(projects, null, 2))
}

const sortProjects = (
  projects: Project[],
  field: SortField,
  direction: SortDirection,
): Project[] => {
  const sorted = [...projects]
  sorted.sort((a, b) => {
    if (field === 'title') {
      return a.title.localeCompare(b.title)
    }
    return new Date(a.dateAdded).getTime() - new Date(b.dateAdded).getTime()
  })
  if (direction === 'desc') {
    sorted.reverse()
  }
  return sorted
}

export const getProjects = async (filters: GalleryFilters): Promise<Project[]> => {
  let projects = await loadProjects()

  if (filters.search) {
    const query = filters.search.toLowerCase()
    projects = projects.filter((p) => p.title.toLowerCase().includes(query))
  }

  if (filters.tag) {
    const tag = filters.tag.toLowerCase()
    projects = projects.filter((p) =>
      p.tags.some((t) => t.toLowerCase() === tag),
    )
  }

  return sortProjects(projects, filters.sortField, filters.sortDirection)
}

export const getProjectById = async (id: string): Promise<Project | undefined> => {
  const projects = await loadProjects()
  return projects.find((p) => p.id === id)
}

export const getAllTags = async (): Promise<string[]> => {
  const projects = await loadProjects()
  const tagSet = new Set<string>()
  for (const p of projects) {
    for (const t of p.tags) {
      tagSet.add(t)
    }
  }
  return [...tagSet].sort()
}

export const addProject = async (project: Project): Promise<void> => {
  const projects = await loadProjects()
  projects.push(project)
  await saveProjects(projects)
}

