const flattenStyles = (styleGroups: Record<string, Record<string, string>>[]): string => {
  const rules: string[] = []
  for (const group of styleGroups) {
    for (const [selector, props] of Object.entries(group)) {
      const declarations = Object.entries(props)
        .map(([prop, val]) => {
          const cssP = prop.replace(/[A-Z]/g, (m) => `-${m.toLowerCase()}`)
          return `  ${cssP}: ${val};`
        })
        .join('\n')
      rules.push(`${selector} {\n${declarations}\n}`)
    }
  }
  return rules.join('\n\n')
}

