const renderTagChip = (tag: string, activeTag: string | null, search: string, sortField: string, sortDirection: string): string => {
  const isActive = activeTag?.toLowerCase() === tag.toLowerCase()
  const tagParam = isActive ? '' : tag
  const href = `/?search=${encodeURIComponent(search)}&tag=${encodeURIComponent(tagParam)}&sort=${sortField}&dir=${sortDirection}`
  const className = isActive ? 'tag-chip tag-chip--active' : 'tag-chip'
  return `<a class="${className}" href="${href}">${tag}</a>`
}

const renderProjectCard = (project: Project): string => {
  const tagsHtml = project.tags
    .map((t) => `<span class="card-tag">${t}</span>`)
    .join('')

  const linksHtml: string[] = []
  if (project.demoUrl) {
    linksHtml.push(`<a class="card-link" href="${project.demoUrl}" target="_blank" rel="noopener" onclick="event.stopPropagation()">&#9654; Live Demo</a>`)
  }
  if (project.sourceUrl) {
    linksHtml.push(`<a class="card-link" href="${project.sourceUrl}" target="_blank" rel="noopener" onclick="event.stopPropagation()">&#128193; Source</a>`)
  }

  return `<a class="project-card" href="/project/${project.id}">
    <img class="card-thumbnail" src="${project.thumbnail}" alt="${project.title} thumbnail" onerror="this.style.display='none'">
    <div class="card-body">
      <h3 class="card-title">${project.title}</h3>
      <p class="card-description">${project.shortDescription}</p>
      <div class="card-tags">${tagsHtml}</div>
      <div class="card-links">${linksHtml.join('')}</div>
    </div>
  </a>`
}

export const renderGallery = (
  projects: Project[],
  allTags: string[],
  filters: GalleryFilters,
): string => {
  const { search, tag, sortField, sortDirection } = filters

  const tagChips = allTags
    .map((t) => renderTagChip(t, tag, search, sortField, sortDirection))
    .join('\n      ')

  const sortValue = `${sortField}-${sortDirection}`

  const projectCards = projects.length > 0
    ? projects.map(renderProjectCard).join('\n    ')
    : `<div class="empty-state">
        <div class="empty-icon">&#128269;</div>
        <p class="empty-text">No projects match your filters.</p>
      </div>`

  const body = `
  <div class="page-wrapper">
    <header class="page-header">
      <h1 class="page-title">Portfolio</h1>
      <p class="page-subtitle">A showcase of projects and experiments</p>
    </header>

    <div class="controls">
      <input
        class="search-input"
        type="text"
        placeholder="Search projects..."
        value="${search}"
        oninput="handleSearch(this.value)"
      >
      <select class="sort-select" onchange="handleSort(this.value)">
        <option value="dateAdded-desc" ${sortValue === 'dateAdded-desc' ? 'selected' : ''}>Newest First</option>
        <option value="dateAdded-asc" ${sortValue === 'dateAdded-asc' ? 'selected' : ''}>Oldest First</option>
        <option value="title-asc" ${sortValue === 'title-asc' ? 'selected' : ''}>A &rarr; Z</option>
        <option value="title-desc" ${sortValue === 'title-desc' ? 'selected' : ''}>Z &rarr; A</option>
      </select>
    </div>

    <div class="tag-bar">
      ${tagChips}
    </div>

    <div class="project-grid">
      ${projectCards}
    </div>
  </div>

  <script>
    let searchTimeout;
    const handleSearch = (value) => {
      clearTimeout(searchTimeout);
      searchTimeout = setTimeout(() => {
        const url = new URL(window.location);
        url.searchParams.set('search', value);
        window.location = url.toString();
      }, 400);
    };

    const handleSort = (value) => {
      const [field, dir] = value.split('-');
      const url = new URL(window.location);
      url.searchParams.set('sort', field);
      url.searchParams.set('dir', dir);
      window.location = url.toString();
    };
  </script>`

  return htmlShell('Portfolio Gallery', body)
}

export const renderDetail = (project: Project): string => {
  const tagsHtml = project.tags
    .map((t) => `<span class="detail-tag">${t}</span>`)
    .join('')

  const linksHtml: string[] = []
  if (project.demoUrl) {
    linksHtml.push(`<a class="detail-link" href="${project.demoUrl}" target="_blank" rel="noopener">&#9654; Live Demo</a>`)
  }
  if (project.sourceUrl) {
    linksHtml.push(`<a class="detail-link" href="${project.sourceUrl}" target="_blank" rel="noopener">&#128193; Source Code</a>`)
  }

  const hasMultipleImages = project.images.length > 1

  const imagesJson = JSON.stringify(project.images)

  const dateFormatted = new Date(project.dateAdded).toLocaleDateString('en-US', {
    year: 'numeric',
    month: 'long',
    day: 'numeric',
  })

  const body = `
  <div class="detail-wrapper">
    <a class="detail-back" href="/">&larr; Back to Gallery</a>

    <h1 class="detail-title">${project.title}</h1>
    <p class="detail-date">Added ${dateFormatted}</p>

    <div class="detail-tags">${tagsHtml}</div>

    ${linksHtml.length > 0 ? `<div class="detail-links">${linksHtml.join('')}</div>` : ''}

    <div class="carousel" id="carousel">
      ${hasMultipleImages ? `<button class="carousel-btn carousel-prev" onclick="carouselNav(-1)">&lsaquo;</button>` : ''}
      <img class="carousel-image" id="carousel-img" src="${project.images[0]?.url ?? ''}" alt="${project.images[0]?.alt ?? ''}" onerror="this.alt='Image not available'; this.style.minHeight='200px'">
      ${hasMultipleImages ? `<button class="carousel-btn carousel-next" onclick="carouselNav(1)">&rsaquo;</button>` : ''}
      <p class="carousel-caption" id="carousel-caption">${project.images[0]?.alt ?? ''}</p>
      ${hasMultipleImages ? `
      <div class="carousel-dots" id="carousel-dots">
        ${project.images.map((_, i) => `<button class="carousel-dot ${i === 0 ? 'carousel-dot--active' : ''}" onclick="carouselGo(${i})"></button>`).join('')}
      </div>` : ''}
    </div>

    <div class="detail-description">${project.description}</div>
  </div>

  ${hasMultipleImages ? `<script>
    const images = ${imagesJson};
    let currentIdx = 0;

    const carouselGo = (idx) => {
      currentIdx = idx;
      const img = document.getElementById('carousel-img');
      const caption = document.getElementById('carousel-caption');
      img.src = images[currentIdx].url;
      img.alt = images[currentIdx].alt;
      caption.textContent = images[currentIdx].alt;

      document.querySelectorAll('.carousel-dot').forEach((dot, i) => {
        dot.className = i === currentIdx ? 'carousel-dot carousel-dot--active' : 'carousel-dot';
      });
    };

    const carouselNav = (delta) => {
      let next = currentIdx + delta;
      if (next < 0) next = images.length - 1;
      if (next >= images.length) next = 0;
      carouselGo(next);
    };

    document.addEventListener('keydown', (e) => {
      if (e.key === 'ArrowLeft') carouselNav(-1);
      if (e.key === 'ArrowRight') carouselNav(1);
    });
  </script>` : ''}`

  return htmlShell(`${project.title} — Portfolio`, body)
}

