import { getProjects, getProjectById, getAllTags } from './store'
import { renderGallery, renderDetail, render404 } from './render'
import type { SortField, SortDirection, GalleryFilters } from './types'

const parseFilters = (url: URL): GalleryFilters => {
  const search = url.searchParams.get('search') ?? ''
  const tag = url.searchParams.get('tag') || null
  const sortField = (url.searchParams.get('sort') ?? 'dateAdded') as SortField
  const sortDir = (url.searchParams.get('dir') ?? 'desc') as SortDirection

  return {
    search,
    tag,
    sortField: ['dateAdded', 'title'].includes(sortField) ? sortField : 'dateAdded',
    sortDirection: ['asc', 'desc'].includes(sortDir) ? sortDir : 'desc',
  }
}

const handleGallery = async (url: URL): Promise<Response> => {
  const filters = parseFilters(url)
  const [projects, tags] = await Promise.all([
    getProjects(filters),
    getAllTags(),
  ])
  const html = renderGallery(projects, tags, filters)
  return new Response(html, {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })
}

const handleDetail = async (id: string): Promise<Response> => {
  const project = await getProjectById(id)
  if (!project) {
    return new Response(render404(), {
      status: 404,
      headers: { 'Content-Type': 'text/html; charset=utf-8' },
    })
  }
  const html = renderDetail(project)
  return new Response(html, {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })
}

const server = Bun.serve({
  port: 3000,
  fetch: async (req) => {
    const url = new URL(req.url)
    const path = url.pathname

    if (path === '/' || path === '') {
      return handleGallery(url)
    }

    const detailMatch = path.match(/^\/project\/([a-z0-9-]+)$/)
    if (detailMatch) {
      return handleDetail(detailMatch[1])
    }

    return new Response(render404(), {
      status: 404,
      headers: { 'Content-Type': 'text/html; charset=utf-8' },
    })
  },
})

console.log(`Portfolio Gallery running at http://localhost:${server.port}`)

