import type { SavedDrawingMeta, Drawing } from './types'

const DATA_DIR = './data'

export const saveDrawing = async (drawing: Drawing, pngBase64: string): Promise<void> => {
  const meta: SavedDrawingMeta = {
    id: drawing.id,
    name: drawing.name,
    width: drawing.width,
    height: drawing.height,
    layerCount: drawing.layers.length,
    createdAt: drawing.createdAt,
    updatedAt: new Date().toISOString(),
  }

  const pngBuffer = Buffer.from(pngBase64.replace(/^data:image\/png;base64,/, ''), 'base64')
  await Bun.write(`${DATA_DIR}/${drawing.id}.png`, pngBuffer)
  await Bun.write(`${DATA_DIR}/${drawing.id}.json`, JSON.stringify(meta, null, 2))
}

export const loadDrawingMeta = async (id: string): Promise<SavedDrawingMeta | null> => {
  const file = Bun.file(`${DATA_DIR}/${id}.json`)
  if (!(await file.exists())) return null
  return file.json() as Promise<SavedDrawingMeta>
}

export const loadDrawingPng = async (id: string): Promise<ArrayBuffer | null> => {
  const file = Bun.file(`${DATA_DIR}/${id}.png`)
  if (!(await file.exists())) return null
  return file.arrayBuffer()
}

export const listDrawings = async (): Promise<SavedDrawingMeta[]> => {
  const glob = new Bun.Glob('*.json')
  const results: SavedDrawingMeta[] = []
  for await (const path of glob.scan(DATA_DIR)) {
    const file = Bun.file(`${DATA_DIR}/${path}`)
    const meta = (await file.json()) as SavedDrawingMeta
    results.push(meta)
  }
  return results.sort((a, b) => b.updatedAt.localeCompare(a.updatedAt))
}

export const deleteDrawing = async (id: string): Promise<boolean> => {
  const jsonFile = Bun.file(`${DATA_DIR}/${id}.json`)
  const pngFile = Bun.file(`${DATA_DIR}/${id}.png`)
  if (!(await jsonFile.exists())) return false
  const { unlinkSync } = await import('node:fs')
  try {
    unlinkSync(`${DATA_DIR}/${id}.json`)
    unlinkSync(`${DATA_DIR}/${id}.png`)
  } catch {
    return false
  }
  return true
}

