const clientScript = (): string => `
(function() {
  const mainCanvas = document.getElementById('drawing-canvas');
  const previewCanvas = document.getElementById('preview-canvas');
  const mainCtx = mainCanvas.getContext('2d');
  const previewCtx = previewCanvas.getContext('2d');
  const colorPicker = document.getElementById('color-picker');
  const brushSizeInput = document.getElementById('brush-size');
  const sizeLabel = document.getElementById('size-label');
  const layersPanel = document.getElementById('layers-panel');
  const fileInput = document.getElementById('file-input');

  // Position preview canvas over main canvas
  const positionPreview = () => {
    const rect = mainCanvas.getBoundingClientRect();
    const parent = mainCanvas.parentElement;
    const parentRect = parent.getBoundingClientRect();
    previewCanvas.style.left = (rect.left - parentRect.left) + 'px';
    previewCanvas.style.top = (rect.top - parentRect.top) + 'px';
  };
  window.addEventListener('resize', positionPreview);
  setTimeout(positionPreview, 0);

  let state = {
    tool: 'brush',
    color: '#000000',
    brushSize: 4,
    layers: [
      { id: 'layer-1', name: 'Layer 1', visible: true, canvas: null },
    ],
    activeLayerId: 'layer-1',
    undoStack: [],
    redoStack: [],
    isDrawing: false,
    startPoint: null,
    currentPoints: [],
    layerCounter: 1,
  };

  // Create offscreen canvas for each layer
  const createLayerCanvas = () => {
    const c = document.createElement('canvas');
    c.width = mainCanvas.width;
    c.height = mainCanvas.height;
    return c;
  };

  state.layers[0].canvas = createLayerCanvas();

  const getActiveLayer = () => state.layers.find(l => l.id === state.activeLayerId);

  // Composite all visible layers onto main canvas
  const compositeAll = () => {
    mainCtx.clearRect(0, 0, mainCanvas.width, mainCanvas.height);
    mainCtx.fillStyle = '#ffffff';
    mainCtx.fillRect(0, 0, mainCanvas.width, mainCanvas.height);
    for (const layer of state.layers) {
      if (layer.visible && layer.canvas) {
        mainCtx.drawImage(layer.canvas, 0, 0);
      }
    }
  };

  // Save state for undo
  const saveUndoState = () => {
    const snapshot = state.layers.map(l => {
      const c = createLayerCanvas();
      c.getContext('2d').drawImage(l.canvas, 0, 0);
      return { id: l.id, name: l.name, visible: l.visible, canvas: c };
    });
    state.undoStack.push({ layers: snapshot, activeLayerId: state.activeLayerId });
    state.redoStack = [];
    if (state.undoStack.length > 50) state.undoStack.shift();
  };

  const restoreSnapshot = (snapshot) => {
    state.layers = snapshot.layers.map(s => {
      const c = createLayerCanvas();
      c.getContext('2d').drawImage(s.canvas, 0, 0);
      return { id: s.id, name: s.name, visible: s.visible, canvas: c };
    });
    state.activeLayerId = snapshot.activeLayerId;
    compositeAll();
    renderLayers();
  };

  // Tool selection
  const toolButtons = document.querySelectorAll('.tool-btn');
  const selectTool = (toolId) => {
    state.tool = toolId;
    toolButtons.forEach(btn => {
      const isActive = btn.dataset.tool === toolId;
      btn.style.backgroundColor = isActive ? '#0f3460' : 'transparent';
      btn.style.color = isActive ? '#53d8fb' : '#a0a0c0';
    });
  };
  toolButtons.forEach(btn => {
    btn.addEventListener('click', () => selectTool(btn.dataset.tool));
  });
  selectTool('brush');

  // Color picker
  colorPicker.addEventListener('input', (e) => { state.color = e.target.value; });

  // Brush size
  brushSizeInput.addEventListener('input', (e) => {
    state.brushSize = parseInt(e.target.value);
    sizeLabel.textContent = e.target.value;
  });

  // Mouse position relative to canvas
  const getPos = (e) => {
    const rect = mainCanvas.getBoundingClientRect();
    return {
      x: (e.clientX - rect.left) * (mainCanvas.width / rect.width),
      y: (e.clientY - rect.top) * (mainCanvas.height / rect.height),
    };
  };

  // Drawing handlers
  mainCanvas.addEventListener('mousedown', (e) => {
    if (e.button !== 0) return;
    state.isDrawing = true;
    const pos = getPos(e);
    state.startPoint = pos;
    state.currentPoints = [pos];
    saveUndoState();

    if (state.tool === 'brush' || state.tool === 'eraser') {
      const layer = getActiveLayer();
      if (!layer || !layer.visible) return;
      const ctx = layer.canvas.getContext('2d');
      ctx.beginPath();
      ctx.moveTo(pos.x, pos.y);
      ctx.lineCap = 'round';
      ctx.lineJoin = 'round';
      ctx.lineWidth = state.brushSize;
      if (state.tool === 'eraser') {
        ctx.globalCompositeOperation = 'destination-out';
        ctx.strokeStyle = 'rgba(0,0,0,1)';
      } else {
        ctx.globalCompositeOperation = 'source-over';
        ctx.strokeStyle = state.color;
      }
    }
  });

  mainCanvas.addEventListener('mousemove', (e) => {
    if (!state.isDrawing) return;
    const pos = getPos(e);
    state.currentPoints.push(pos);
    const layer = getActiveLayer();
    if (!layer || !layer.visible) return;

    if (state.tool === 'brush' || state.tool === 'eraser') {
      const ctx = layer.canvas.getContext('2d');
      ctx.lineTo(pos.x, pos.y);
      ctx.stroke();
      compositeAll();
    } else {
      // Shape preview
      previewCtx.clearRect(0, 0, previewCanvas.width, previewCanvas.height);
      previewCtx.strokeStyle = state.color;
      previewCtx.lineWidth = state.brushSize;
      previewCtx.lineCap = 'round';
      const sp = state.startPoint;

      if (state.tool === 'rectangle') {
        previewCtx.strokeRect(sp.x, sp.y, pos.x - sp.x, pos.y - sp.y);
      } else if (state.tool === 'circle') {
        const rx = Math.abs(pos.x - sp.x) / 2;
        const ry = Math.abs(pos.y - sp.y) / 2;
        const cx = sp.x + (pos.x - sp.x) / 2;
        const cy = sp.y + (pos.y - sp.y) / 2;
        previewCtx.beginPath();
        previewCtx.ellipse(cx, cy, rx, ry, 0, 0, Math.PI * 2);
        previewCtx.stroke();
      } else if (state.tool === 'line') {
        previewCtx.beginPath();
        previewCtx.moveTo(sp.x, sp.y);
        previewCtx.lineTo(pos.x, pos.y);
        previewCtx.stroke();
      }
    }
  });

  const finishDrawing = (e) => {
    if (!state.isDrawing) return;
    state.isDrawing = false;
    const layer = getActiveLayer();
    if (!layer || !layer.visible) return;

    if (state.tool === 'brush' || state.tool === 'eraser') {
      const ctx = layer.canvas.getContext('2d');
      ctx.globalCompositeOperation = 'source-over';
    } else {
      // Commit shape to layer
      previewCtx.clearRect(0, 0, previewCanvas.width, previewCanvas.height);
      const ctx = layer.canvas.getContext('2d');
      ctx.strokeStyle = state.color;
      ctx.lineWidth = state.brushSize;
      ctx.lineCap = 'round';
      const sp = state.startPoint;
      const pos = state.currentPoints[state.currentPoints.length - 1] || sp;

      if (state.tool === 'rectangle') {
        ctx.strokeRect(sp.x, sp.y, pos.x - sp.x, pos.y - sp.y);
      } else if (state.tool === 'circle') {
        const rx = Math.abs(pos.x - sp.x) / 2;
        const ry = Math.abs(pos.y - sp.y) / 2;
        const cx = sp.x + (pos.x - sp.x) / 2;
        const cy = sp.y + (pos.y - sp.y) / 2;
        ctx.beginPath();
        ctx.ellipse(cx, cy, rx, ry, 0, 0, Math.PI * 2);
        ctx.stroke();
      } else if (state.tool === 'line') {
        ctx.beginPath();
        ctx.moveTo(sp.x, sp.y);
        ctx.lineTo(pos.x, pos.y);
        ctx.stroke();
      }
    }
    compositeAll();
    renderLayers();
  };

  mainCanvas.addEventListener('mouseup', finishDrawing);
  mainCanvas.addEventListener('mouseleave', finishDrawing);

  // Undo/Redo
  document.getElementById('btn-undo').addEventListener('click', () => {
    if (state.undoStack.length === 0) return;
    const current = {
      layers: state.layers.map(l => {
        const c = createLayerCanvas();
        c.getContext('2d').drawImage(l.canvas, 0, 0);
        return { id: l.id, name: l.name, visible: l.visible, canvas: c };
      }),
      activeLayerId: state.activeLayerId,
    };
    state.redoStack.push(current);
    restoreSnapshot(state.undoStack.pop());
  });

  document.getElementById('btn-redo').addEventListener('click', () => {
    if (state.redoStack.length === 0) return;
    const current = {
      layers: state.layers.map(l => {
        const c = createLayerCanvas();
        c.getContext('2d').drawImage(l.canvas, 0, 0);
        return { id: l.id, name: l.name, visible: l.visible, canvas: c };
      }),
      activeLayerId: state.activeLayerId,
    };
    state.undoStack.push(current);
    restoreSnapshot(state.redoStack.pop());
  });

  // Clear
  document.getElementById('btn-clear').addEventListener('click', () => {
    saveUndoState();
    state.layers.forEach(l => {
      l.canvas.getContext('2d').clearRect(0, 0, l.canvas.width, l.canvas.height);
    });
    compositeAll();
    renderLayers();
  });

  // Save PNG
  document.getElementById('btn-save').addEventListener('click', () => {
    compositeAll();
    const link = document.createElement('a');
    link.download = 'drawing.png';
    link.href = mainCanvas.toDataURL('image/png');
    link.click();

    // Also save to server
    fetch('/api/save', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        id: 'drawing-' + Date.now(),
        name: 'Drawing',
        width: mainCanvas.width,
        height: mainCanvas.height,
        layers: state.layers.map(l => ({ id: l.id, name: l.name, visible: l.visible })),
        createdAt: new Date().toISOString(),
        updatedAt: new Date().toISOString(),
        pngData: mainCanvas.toDataURL('image/png'),
      }),
    }).catch(() => {});
  });

  // Load PNG
  document.getElementById('btn-load').addEventListener('click', () => {
    fileInput.click();
  });

  fileInput.addEventListener('change', (e) => {
    const file = e.target.files[0];
    if (!file) return;
    saveUndoState();
    const img = new Image();
    img.onload = () => {
      const layer = getActiveLayer();
      if (!layer) return;
      const ctx = layer.canvas.getContext('2d');
      ctx.clearRect(0, 0, layer.canvas.width, layer.canvas.height);
      ctx.drawImage(img, 0, 0, mainCanvas.width, mainCanvas.height);
      compositeAll();
      renderLayers();
    };
    img.src = URL.createObjectURL(file);
    fileInput.value = '';
  });

  // Add layer
  document.getElementById('btn-add-layer').addEventListener('click', () => {
    state.layerCounter++;
    const newLayer = {
      id: 'layer-' + state.layerCounter,
      name: 'Layer ' + state.layerCounter,
      visible: true,
      canvas: createLayerCanvas(),
    };
    state.layers.unshift(newLayer);
    state.activeLayerId = newLayer.id;
    renderLayers();
  });

  // Render layers panel
  const renderLayers = () => {
    layersPanel.innerHTML = '';
    state.layers.forEach(layer => {
      const item = document.createElement('div');
      item.className = 'layer-item';
      item.style.cssText = 'display:flex;align-items:center;gap:8px;padding:6px 8px;border-radius:6px;cursor:pointer;font-size:13px;transition:background 0.15s;' +
        (layer.id === state.activeLayerId ? 'background-color:#0f3460;' : '');

      // Thumbnail
      const thumb = document.createElement('canvas');
      thumb.width = 32;
      thumb.height = 24;
      thumb.style.cssText = 'border:1px solid #444;border-radius:3px;flex-shrink:0;background:#fff';
      const thumbCtx = thumb.getContext('2d');
      thumbCtx.drawImage(layer.canvas, 0, 0, 32, 24);
      item.appendChild(thumb);

      // Name
      const name = document.createElement('span');
      name.textContent = layer.name;
      name.style.cssText = 'flex:1;overflow:hidden;text-overflow:ellipsis;white-space:nowrap';
      item.appendChild(name);

      // Visibility toggle
      const visBtn = document.createElement('button');
      visBtn.textContent = layer.visible ? '\\u{1F441}' : '\\u{1F441}\\u{200D}\\u{1F5E8}';
      visBtn.style.cssText = 'background:none;border:none;cursor:pointer;font-size:14px;padding:2px;color:' + (layer.visible ? '#53d8fb' : '#555');
      visBtn.title = layer.visible ? 'Hide layer' : 'Show layer';
      visBtn.addEventListener('click', (e) => {
        e.stopPropagation();
        layer.visible = !layer.visible;
        compositeAll();
        renderLayers();
      });
      item.appendChild(visBtn);

      item.addEventListener('click', () => {
        state.activeLayerId = layer.id;
        renderLayers();
      });

      layersPanel.appendChild(item);
    });
  };

  // Keyboard shortcuts
  document.addEventListener('keydown', (e) => {
    if (e.ctrlKey || e.metaKey) {
      if (e.key === 'z' && !e.shiftKey) {
        e.preventDefault();
        document.getElementById('btn-undo').click();
      } else if ((e.key === 'z' && e.shiftKey) || e.key === 'y') {
        e.preventDefault();
        document.getElementById('btn-redo').click();
      } else if (e.key === 's') {
        e.preventDefault();
        document.getElementById('btn-save').click();
      }
    }
  });

  // Initial render
  compositeAll();
  renderLayers();
})();
`

import { renderCanvas } from './canvas-ui'
import { saveDrawing, loadDrawingPng, listDrawings, deleteDrawing } from './storage'
import type { Drawing } from './types'

const PORT = 3000

const handleApiRequest = async (req: Request, pathname: string): Promise<Response> => {
  if (pathname === '/api/save' && req.method === 'POST') {
    const body = await req.json() as Drawing & { pngData: string }
    await saveDrawing(
      {
        id: body.id,
        name: body.name,
        width: body.width,
        height: body.height,
        layers: body.layers,
        createdAt: body.createdAt,
        updatedAt: body.updatedAt,
      },
      body.pngData,
    )
    return Response.json({ ok: true })
  }

  if (pathname === '/api/drawings' && req.method === 'GET') {
    const drawings = await listDrawings()
    return Response.json(drawings)
  }

  if (pathname.startsWith('/api/drawings/') && req.method === 'GET') {
    const id = pathname.replace('/api/drawings/', '')
    const png = await loadDrawingPng(id)
    if (!png) return new Response('Not found', { status: 404 })
    return new Response(png, {
      headers: { 'Content-Type': 'image/png' },
    })
  }

  if (pathname.startsWith('/api/drawings/') && req.method === 'DELETE') {
    const id = pathname.replace('/api/drawings/', '')
    const deleted = await deleteDrawing(id)
    return Response.json({ ok: deleted })
  }

  return new Response('Not found', { status: 404 })
}

const server = Bun.serve({
  port: PORT,
  fetch: async (req) => {
    const url = new URL(req.url)
    const pathname = url.pathname

    if (pathname.startsWith('/api/')) {
      return handleApiRequest(req, pathname)
    }

    if (pathname === '/' || pathname === '/index.html') {
      const html = renderCanvas()
      return new Response(html, {
        headers: { 'Content-Type': 'text/html; charset=utf-8' },
      })
    }

    return new Response('Not found', { status: 404 })
  },
})

console.log(`Drawing Canvas running at http://localhost:${server.port}`)

