export type DrawingTool = 'freehand' | 'rectangle' | 'circle' | 'line' | 'eraser'

export type Point = {
  x: number
  y: number
}

export type Stroke = {
  tool: 'freehand' | 'eraser'
  points: Point[]
  color: string
  size: number
}

export type Shape = {
  tool: 'rectangle' | 'circle' | 'line'
  start: Point
  end: Point
  color: string
  size: number
}

export type DrawElement = Stroke | Shape

export type Layer = {
  id: string
  name: string
  visible: boolean
  elements: DrawElement[]
  opacity: number
}

export type CanvasState = {
  layers: Layer[]
  activeLayerId: string
  currentTool: DrawingTool
  color: string
  brushSize: number
  width: number
  height: number
}

export type HistoryEntry = {
  layers: Layer[]
  activeLayerId: string
}

export type ProjectData = {
  version: 1
  state: CanvasState
  createdAt: string
  updatedAt: string
}

import type { Layer, DrawElement } from './types'

let layerCounter = 0

export const createLayer = (name?: string): Layer => {
  layerCounter += 1
  return {
    id: `layer-${Date.now()}-${layerCounter}`,
    name: name ?? `Layer ${layerCounter}`,
    visible: true,
    elements: [],
    opacity: 1,
  }
}

export const duplicateLayer = (layer: Layer): Layer => {
  layerCounter += 1
  return {
    ...layer,
    id: `layer-${Date.now()}-${layerCounter}`,
    name: `${layer.name} (copy)`,
    elements: layer.elements.map((el) => ({ ...el })),
  }
}

export const addElementToLayer = (layer: Layer, element: DrawElement): Layer => ({
  ...layer,
  elements: [...layer.elements, element],
})

export const toggleLayerVisibility = (layer: Layer): Layer => ({
  ...layer,
  visible: !layer.visible,
})

export const setLayerOpacity = (layer: Layer, opacity: number): Layer => ({
  ...layer,
  opacity: Math.max(0, Math.min(1, opacity)),
})

export const renameLayer = (layer: Layer, name: string): Layer => ({
  ...layer,
  name,
})

export const clearLayer = (layer: Layer): Layer => ({
  ...layer,
  elements: [],
})

export const reorderLayers = (layers: Layer[], fromIndex: number, toIndex: number): Layer[] => {
  const result = [...layers]
  const [moved] = result.splice(fromIndex, 1)
  result.splice(toIndex, 0, moved)
  return result
}

export const removeLayer = (layers: Layer[], layerId: string): Layer[] =>
  layers.filter((l) => l.id !== layerId)

export const findLayer = (layers: Layer[], layerId: string): Layer | undefined =>
  layers.find((l) => l.id === layerId)

export const updateLayer = (layers: Layer[], layerId: string, updater: (l: Layer) => Layer): Layer[] =>
  layers.map((l) => (l.id === layerId ? updater(l) : l))

import type { HistoryEntry, Layer } from './types'

export type HistoryManager = {
  push: (entry: HistoryEntry) => void
  undo: () => HistoryEntry | undefined
  redo: () => HistoryEntry | undefined
  canUndo: () => boolean
  canRedo: () => boolean
  clear: () => void
  current: () => HistoryEntry | undefined
}

const deepCopyLayers = (layers: Layer[]): Layer[] =>
  layers.map((l) => ({
    ...l,
    elements: l.elements.map((el) => ({
      ...el,
      ...('points' in el ? { points: el.points.map((p) => ({ ...p })) } : {}),
      ...('start' in el ? { start: { ...el.start }, end: { ...el.end } } : {}),
    })),
  }))

export const createHistoryManager = (maxSize = 50): HistoryManager => {
  const entries: HistoryEntry[] = []
  let index = -1

  const push = (entry: HistoryEntry) => {
    const snapshot: HistoryEntry = {
      layers: deepCopyLayers(entry.layers),
      activeLayerId: entry.activeLayerId,
    }
    // Discard any redo entries ahead of current position
    entries.splice(index + 1)
    entries.push(snapshot)
    if (entries.length > maxSize) {
      entries.shift()
    }
    index = entries.length - 1
  }

  const undo = (): HistoryEntry | undefined => {
    if (index <= 0) return undefined
    index -= 1
    const entry = entries[index]
    return {
      layers: deepCopyLayers(entry.layers),
      activeLayerId: entry.activeLayerId,
    }
  }

  const redo = (): HistoryEntry | undefined => {
    if (index >= entries.length - 1) return undefined
    index += 1
    const entry = entries[index]
    return {
      layers: deepCopyLayers(entry.layers),
      activeLayerId: entry.activeLayerId,
    }
  }

  const canUndo = () => index > 0
  const canRedo = () => index < entries.length - 1

  const clear = () => {
    entries.length = 0
    index = -1
  }

  const current = (): HistoryEntry | undefined =>
    index >= 0 ? entries[index] : undefined

  return { push, undo, redo, canUndo, canRedo, clear, current }
}

import type { Point, Stroke, Shape, DrawElement, DrawingTool } from './types'

export type DrawingContext = {
  tool: DrawingTool
  color: string
  brushSize: number
}

export type ActiveDraw = {
  element: DrawElement
  startPoint: Point
}

export const startDraw = (ctx: DrawingContext, point: Point): ActiveDraw => {
  if (ctx.tool === 'freehand' || ctx.tool === 'eraser') {
    const stroke: Stroke = {
      tool: ctx.tool,
      points: [point],
      color: ctx.tool === 'eraser' ? '#ffffff' : ctx.color,
      size: ctx.brushSize,
    }
    return { element: stroke, startPoint: point }
  }

  const shape: Shape = {
    tool: ctx.tool,
    start: point,
    end: point,
    color: ctx.color,
    size: ctx.brushSize,
  }
  return { element: shape, startPoint: point }
}

export const continueDraw = (active: ActiveDraw, point: Point): ActiveDraw => {
  const el = active.element
  if ('points' in el) {
    return {
      ...active,
      element: {
        ...el,
        points: [...el.points, point],
      },
    }
  }
  return {
    ...active,
    element: {
      ...el,
      end: point,
    },
  }
}

export const finishDraw = (active: ActiveDraw): DrawElement => active.element

export const renderElementToCanvas = (
  ctx: CanvasRenderingContext2D,
  element: DrawElement,
) => {
  ctx.save()

  if ('points' in element) {
    const { points, color, size, tool } = element
    if (points.length < 2) {
      // Draw a dot for single-point strokes
      ctx.fillStyle = color
      ctx.beginPath()
      ctx.arc(points[0].x, points[0].y, size / 2, 0, Math.PI * 2)
      ctx.fill()
      ctx.restore()
      return
    }

    ctx.strokeStyle = color
    ctx.lineWidth = size
    ctx.lineCap = 'round'
    ctx.lineJoin = 'round'

    if (tool === 'eraser') {
      ctx.globalCompositeOperation = 'destination-out'
    }

    ctx.beginPath()
    ctx.moveTo(points[0].x, points[0].y)

    // Smooth line using quadratic curves
    for (let i = 1; i < points.length - 1; i++) {
      const midX = (points[i].x + points[i + 1].x) / 2
      const midY = (points[i].y + points[i + 1].y) / 2
      ctx.quadraticCurveTo(points[i].x, points[i].y, midX, midY)
    }

    const last = points[points.length - 1]
    ctx.lineTo(last.x, last.y)
    ctx.stroke()
  } else {
    const { tool, start, end, color, size } = element
    ctx.strokeStyle = color
    ctx.lineWidth = size
    ctx.lineCap = 'round'
    ctx.lineJoin = 'round'

    if (tool === 'rectangle') {
      const x = Math.min(start.x, end.x)
      const y = Math.min(start.y, end.y)
      const w = Math.abs(end.x - start.x)
      const h = Math.abs(end.y - start.y)
      ctx.strokeRect(x, y, w, h)
    } else if (tool === 'circle') {
      const cx = (start.x + end.x) / 2
      const cy = (start.y + end.y) / 2
      const rx = Math.abs(end.x - start.x) / 2
      const ry = Math.abs(end.y - start.y) / 2
      ctx.beginPath()
      ctx.ellipse(cx, cy, rx, ry, 0, 0, Math.PI * 2)
      ctx.stroke()
    } else if (tool === 'line') {
      ctx.beginPath()
      ctx.moveTo(start.x, start.y)
      ctx.lineTo(end.x, end.y)
      ctx.stroke()
    }
  }

  ctx.restore()
}

export const renderLayerToCanvas = (
  ctx: CanvasRenderingContext2D,
  elements: DrawElement[],
) => {
  for (const element of elements) {
    renderElementToCanvas(ctx, element)
  }
}

import type { CanvasState, ProjectData } from './types'

const DATA_DIR = './data'
const PROJECTS_FILE = `${DATA_DIR}/projects.json`

type ProjectMeta = {
  id: string
  name: string
  createdAt: string
  updatedAt: string
  thumbnailPath: string
}

const ensureDataDir = async () => {
  const dir = Bun.file(DATA_DIR)
  try {
    await Bun.write(`${DATA_DIR}/.keep`, '')
  } catch {
    // directory exists
  }
}

const loadProjectIndex = async (): Promise<ProjectMeta[]> => {
  try {
    const file = Bun.file(PROJECTS_FILE)
    if (await file.exists()) {
      return await file.json()
    }
  } catch {
    // no index yet
  }
  return []
}

const saveProjectIndex = async (projects: ProjectMeta[]) => {
  await Bun.write(PROJECTS_FILE, JSON.stringify(projects, null, 2))
}

export const saveProject = async (
  id: string,
  name: string,
  state: CanvasState,
): Promise<ProjectMeta> => {
  await ensureDataDir()

  const now = new Date().toISOString()
  const projectData: ProjectData = {
    version: 1,
    state,
    createdAt: now,
    updatedAt: now,
  }

  const filePath = `${DATA_DIR}/${id}.json`
  await Bun.write(filePath, JSON.stringify(projectData, null, 2))

  const index = await loadProjectIndex()
  const existing = index.findIndex((p) => p.id === id)
  const meta: ProjectMeta = {
    id,
    name,
    createdAt: existing >= 0 ? index[existing].createdAt : now,
    updatedAt: now,
    thumbnailPath: `${DATA_DIR}/${id}-thumb.png`,
  }

  if (existing >= 0) {
    index[existing] = meta
  } else {
    index.push(meta)
  }

  await saveProjectIndex(index)
  return meta
}

export const loadProject = async (id: string): Promise<ProjectData | null> => {
  try {
    const file = Bun.file(`${DATA_DIR}/${id}.json`)
    if (await file.exists()) {
      return await file.json()
    }
  } catch {
    // not found
  }
  return null
}

export const listProjects = async (): Promise<ProjectMeta[]> => {
  return loadProjectIndex()
}

export const deleteProject = async (id: string): Promise<void> => {
  const index = await loadProjectIndex()
  const filtered = index.filter((p) => p.id !== id)
  await saveProjectIndex(filtered)

  try {
    const { unlink } = await import('node:fs/promises')
    await unlink(`${DATA_DIR}/${id}.json`)
    await unlink(`${DATA_DIR}/${id}-thumb.png`)
  } catch {
    // files may not exist
  }
}

export const savePng = async (id: string, pngBuffer: Uint8Array): Promise<string> => {
  await ensureDataDir()
  const path = `${DATA_DIR}/${id}.png`
  await Bun.write(path, pngBuffer)
  return path
}

export const loadPng = async (id: string): Promise<Uint8Array | null> => {
  try {
    const file = Bun.file(`${DATA_DIR}/${id}.png`)
    if (await file.exists()) {
      return new Uint8Array(await file.arrayBuffer())
    }
  } catch {
    // not found
  }
  return null
}

export const saveThumbnail = async (id: string, pngBuffer: Uint8Array): Promise<string> => {
  await ensureDataDir()
  const path = `${DATA_DIR}/${id}-thumb.png`
  await Bun.write(path, pngBuffer)
  return path
}

import type { CanvasState, DrawingTool, DrawElement, HistoryEntry, Layer } from './types'
import { createLayer, addElementToLayer, toggleLayerVisibility, updateLayer, removeLayer, clearLayer, reorderLayers } from './layers'
import { createHistoryManager, type HistoryManager } from './history'

export type CanvasStore = {
  getState: () => CanvasState
  setTool: (tool: DrawingTool) => void
  setColor: (color: string) => void
  setBrushSize: (size: number) => void
  addElement: (element: DrawElement) => void
  addLayer: (name?: string) => void
  removeLayerById: (layerId: string) => void
  setActiveLayer: (layerId: string) => void
  toggleVisibility: (layerId: string) => void
  clearActiveLayer: () => void
  clearAll: () => void
  moveLayer: (fromIndex: number, toIndex: number) => void
  undo: () => boolean
  redo: () => boolean
  canUndo: () => boolean
  canRedo: () => boolean
  getHistory: () => HistoryManager
}

export const createCanvasStore = (
  width = 800,
  height = 600,
  initialState?: CanvasState,
): CanvasStore => {
  const history = createHistoryManager()

  const defaultLayer = createLayer('Background')
  let state: CanvasState = initialState ?? {
    layers: [defaultLayer],
    activeLayerId: defaultLayer.id,
    currentTool: 'freehand',
    color: '#000000',
    brushSize: 3,
    width,
    height,
  }

  // Push initial state to history
  history.push({ layers: state.layers, activeLayerId: state.activeLayerId })

  const pushHistory = () => {
    history.push({ layers: state.layers, activeLayerId: state.activeLayerId })
  }

  const getState = () => state

  const setTool = (tool: DrawingTool) => {
    state = { ...state, currentTool: tool }
  }

  const setColor = (color: string) => {
    state = { ...state, color }
  }

  const setBrushSize = (size: number) => {
    state = { ...state, brushSize: Math.max(1, Math.min(50, size)) }
  }

  const addElement = (element: DrawElement) => {
    state = {
      ...state,
      layers: updateLayer(state.layers, state.activeLayerId, (l) =>
        addElementToLayer(l, element),
      ),
    }
    pushHistory()
  }

  const addLayer = (name?: string) => {
    const layer = createLayer(name)
    state = {
      ...state,
      layers: [...state.layers, layer],
      activeLayerId: layer.id,
    }
    pushHistory()
  }

  const removeLayerById = (layerId: string) => {
    if (state.layers.length <= 1) return // keep at least one layer
    const newLayers = removeLayer(state.layers, layerId)
    const needsNewActive = state.activeLayerId === layerId
    state = {
      ...state,
      layers: newLayers,
      activeLayerId: needsNewActive ? newLayers[newLayers.length - 1].id : state.activeLayerId,
    }
    pushHistory()
  }

  const setActiveLayer = (layerId: string) => {
    if (state.layers.some((l) => l.id === layerId)) {
      state = { ...state, activeLayerId: layerId }
    }
  }

  const toggleVisibility = (layerId: string) => {
    state = {
      ...state,
      layers: updateLayer(state.layers, layerId, toggleLayerVisibility),
    }
  }

  const clearActiveLayer = () => {
    state = {
      ...state,
      layers: updateLayer(state.layers, state.activeLayerId, clearLayer),
    }
    pushHistory()
  }

  const clearAll = () => {
    state = {
      ...state,
      layers: state.layers.map((l) => clearLayer(l)),
    }
    pushHistory()
  }

  const moveLayer = (fromIndex: number, toIndex: number) => {
    state = {
      ...state,
      layers: reorderLayers(state.layers, fromIndex, toIndex),
    }
    pushHistory()
  }

  const undo = (): boolean => {
    const entry = history.undo()
    if (!entry) return false
    state = { ...state, layers: entry.layers, activeLayerId: entry.activeLayerId }
    return true
  }

  const redo = (): boolean => {
    const entry = history.redo()
    if (!entry) return false
    state = { ...state, layers: entry.layers, activeLayerId: entry.activeLayerId }
    return true
  }

  return {
    getState,
    setTool,
    setColor,
    setBrushSize,
    addElement,
    addLayer,
    removeLayerById,
    setActiveLayer,
    toggleVisibility,
    clearActiveLayer,
    clearAll,
    moveLayer,
    undo,
    redo,
    canUndo: () => history.canUndo(),
    canRedo: () => history.canRedo(),
    getHistory: () => history,
  }
}

