const styleToString = (style: Record<string, string>): string =>
  Object.entries(style)
    .map(([k, v]) => `${k.replace(/([A-Z])/g, '-$1').toLowerCase()}:${v}`)
    .join(';')

export const renderToolbar = (state: CanvasState, canUndo: boolean, canRedo: boolean) => {
  const tools: DrawingTool[] = ['freehand', 'rectangle', 'circle', 'line', 'eraser']

  return h('div', { style: styleToString(styles.toolbar) },
    // Tool buttons
    ...tools.map((tool) =>
      h('button', {
        style: styleToString(state.currentTool === tool ? styles.toolButtonActive : styles.toolButton),
        'p-trigger': `tool-select:${tool}`,
        title: toolLabels[tool],
      }, `${toolIcons[tool]} ${toolLabels[tool]}`),
    ),

    // Separator
    h('div', { style: 'width:1px;height:24px;background:#45475a;margin:0 4px' }),

    // Undo/Redo
    h('button', {
      style: styleToString({ ...styles.actionButton, ...(canUndo ? {} : { opacity: '0.4' }) }),
      'p-trigger': 'undo',
      disabled: !canUndo ? 'true' : undefined,
    }, '\u21A9 Undo'),
    h('button', {
      style: styleToString({ ...styles.actionButton, ...(canRedo ? {} : { opacity: '0.4' }) }),
      'p-trigger': 'redo',
      disabled: !canRedo ? 'true' : undefined,
    }, '\u21AA Redo'),

    // Separator
    h('div', { style: 'width:1px;height:24px;background:#45475a;margin:0 4px' }),

    // Clear and Save/Load
    h('button', {
      style: styleToString(styles.actionButton),
      'p-trigger': 'clear',
    }, 'Clear'),
    h('button', {
      style: styleToString({ ...styles.actionButton, backgroundColor: '#89b4fa', color: '#1e1e2e', fontWeight: '600' }),
      'p-trigger': 'save-png',
    }, 'Save PNG'),
    h('button', {
      style: styleToString(styles.actionButton),
      'p-trigger': 'load-png',
    }, 'Load PNG'),
  )
}

