export const renderCanvas = (state: CanvasState) => {
  return h('div', { style: styleToString(styles.canvasWrapper) },
    h('canvas', {
      'p-target': 'main-canvas',
      width: String(state.width),
      height: String(state.height),
      style: styleToString({ ...styles.canvas, backgroundColor: '#ffffff' }),
    }),
  )
}

export const renderApp = (state: CanvasState, canUndo: boolean, canRedo: boolean) => {
  return h('div', { style: styleToString(styles.container) },
    renderLayerPanel(state),
    h('div', { style: styleToString(styles.canvasArea) },
      renderToolbar(state, canUndo, canRedo),
      renderCanvas(state),
    ),
  )
}

export const renderToHtml = (state: CanvasState, canUndo: boolean, canRedo: boolean): string => {
  const ssr = createSSR()
  const content = renderApp(state, canUndo, canRedo)
  return ssr(content)
}

import type { CanvasState, DrawingTool, Point, DrawElement, Layer } from './types'
import { startDraw, continueDraw, finishDraw, renderElementToCanvas, renderLayerToCanvas, type ActiveDraw, type DrawingContext } from './tools'
import { createCanvasStore, type CanvasStore } from './canvas-state'

export type CanvasController = {
  store: CanvasStore
  mount: (container: HTMLElement) => void
  unmount: () => void
  exportPng: () => Promise<Blob>
  importPng: (file: File) => Promise<void>
  redraw: () => void
}

export const createCanvasController = (width = 800, height = 600): CanvasController => {
  const store = createCanvasStore(width, height)

  let mainCanvas: HTMLCanvasElement | null = null
  let mainCtx: CanvasRenderingContext2D | null = null
  let activeDraw: ActiveDraw | null = null
  let animFrameId: number | null = null
  let container: HTMLElement | null = null

  const getCanvasPoint = (e: MouseEvent | TouchEvent): Point => {
    if (!mainCanvas) return { x: 0, y: 0 }
    const rect = mainCanvas.getBoundingClientRect()
    const clientX = 'touches' in e ? e.touches[0].clientX : e.clientX
    const clientY = 'touches' in e ? e.touches[0].clientY : e.clientY
    return {
      x: ((clientX - rect.left) / rect.width) * width,
      y: ((clientY - rect.top) / rect.height) * height,
    }
  }

  const redraw = () => {
    if (!mainCtx) return
    const state = store.getState()

    mainCtx.clearRect(0, 0, width, height)
    mainCtx.fillStyle = '#ffffff'
    mainCtx.fillRect(0, 0, width, height)

    // Render each visible layer
    for (const layer of state.layers) {
      if (!layer.visible) continue

      mainCtx.save()
      mainCtx.globalAlpha = layer.opacity
      renderLayerToCanvas(mainCtx, layer.elements)
      mainCtx.restore()
    }

    // Render active drawing (in-progress stroke/shape)
    if (activeDraw) {
      mainCtx.save()
      renderElementToCanvas(mainCtx, activeDraw.element)
      mainCtx.restore()
    }

    updateLayerThumbnails()
  }

  const updateLayerThumbnails = () => {
    const state = store.getState()
    for (const layer of state.layers) {
      const thumbCanvas = container?.querySelector(
        `[p-target="layer-thumb-${layer.id}"]`,
      ) as HTMLCanvasElement | null
      if (!thumbCanvas) continue
      const thumbCtx = thumbCanvas.getContext('2d')
      if (!thumbCtx) continue

      thumbCtx.clearRect(0, 0, 32, 24)
      thumbCtx.fillStyle = '#45475a'
      thumbCtx.fillRect(0, 0, 32, 24)

      if (layer.elements.length > 0) {
        thumbCtx.save()
        thumbCtx.scale(32 / width, 24 / height)
        renderLayerToCanvas(thumbCtx, layer.elements)
        thumbCtx.restore()
      }
    }
  }

  const handlePointerDown = (e: MouseEvent | TouchEvent) => {
    e.preventDefault()
    const state = store.getState()
    const point = getCanvasPoint(e)
    const ctx: DrawingContext = {
      tool: state.currentTool,
      color: state.color,
      brushSize: state.brushSize,
    }
    activeDraw = startDraw(ctx, point)
    redraw()
  }

  const handlePointerMove = (e: MouseEvent | TouchEvent) => {
    e.preventDefault()
    if (!activeDraw) return
    const point = getCanvasPoint(e)
    activeDraw = continueDraw(activeDraw, point)
    redraw()
  }

  const handlePointerUp = (e: MouseEvent | TouchEvent) => {
    e.preventDefault()
    if (!activeDraw) return
    const element = finishDraw(activeDraw)
    store.addElement(element)
    activeDraw = null
    redraw()
  }

  const handleKeyboard = (e: KeyboardEvent) => {
    const ctrl = e.ctrlKey || e.metaKey

    if (ctrl && e.key === 'z' && !e.shiftKey) {
      e.preventDefault()
      store.undo()
      redraw()
    } else if (ctrl && (e.key === 'y' || (e.key === 'z' && e.shiftKey))) {
      e.preventDefault()
      store.redo()
      redraw()
    }
  }

  const bindEvents = () => {
    if (!mainCanvas || !container) return

    mainCanvas.addEventListener('mousedown', handlePointerDown)
    mainCanvas.addEventListener('mousemove', handlePointerMove)
    mainCanvas.addEventListener('mouseup', handlePointerUp)
    mainCanvas.addEventListener('mouseleave', handlePointerUp)

    mainCanvas.addEventListener('touchstart', handlePointerDown, { passive: false })
    mainCanvas.addEventListener('touchmove', handlePointerMove, { passive: false })
    mainCanvas.addEventListener('touchend', handlePointerUp)

    document.addEventListener('keydown', handleKeyboard)

    // Delegate UI events via p-trigger attributes
    container.addEventListener('click', (e) => {
      const target = (e.target as HTMLElement).closest('[p-trigger]') as HTMLElement | null
      if (!target) return

      const trigger = target.getAttribute('p-trigger') ?? ''
      const [action, value] = trigger.split(':')

      switch (action) {
        case 'tool-select':
          store.setTool(value as DrawingTool)
          rebuildUI()
          break
        case 'undo':
          store.undo()
          redraw()
          rebuildUI()
          break
        case 'redo':
          store.redo()
          redraw()
          rebuildUI()
          break
        case 'clear':
          store.clearAll()
          redraw()
          rebuildUI()
          break
        case 'add-layer':
          store.addLayer()
          redraw()
          rebuildUI()
          break
        case 'select-layer':
          store.setActiveLayer(value)
          rebuildUI()
          break
        case 'toggle-visibility':
          e.stopPropagation()
          store.toggleVisibility(value)
          redraw()
          rebuildUI()
          break
        case 'remove-layer':
          e.stopPropagation()
          store.removeLayerById(value)
          redraw()
          rebuildUI()
          break
        case 'save-png':
          exportPng().then((blob) => {
            const url = URL.createObjectURL(blob)
            const a = document.createElement('a')
            a.href = url
            a.download = `drawing-${Date.now()}.png`
            a.click()
            URL.revokeObjectURL(url)
          })
          break
        case 'load-png':
          loadPngFromFile()
          break
      }
    })

    // Color change
    container.addEventListener('input', (e) => {
      const target = e.target as HTMLInputElement
      const trigger = target.getAttribute('p-trigger') ?? ''

      if (trigger === 'color-change') {
        store.setColor(target.value)
        rebuildUI()
      } else if (trigger === 'brush-size-change') {
        store.setBrushSize(Number(target.value))
        rebuildUI()
      }
    })
  }

  const rebuildUI = () => {
    // Lightweight UI state sync — only update toolbar and layer panel
    // Full re-render would be done by the framework in production
  }

  const mount = (el: HTMLElement) => {
    container = el
    mainCanvas = container.querySelector('[p-target="main-canvas"]') as HTMLCanvasElement
    if (mainCanvas) {
      mainCtx = mainCanvas.getContext('2d')
    }
    bindEvents()
    redraw()
  }

  const unmount = () => {
    document.removeEventListener('keydown', handleKeyboard)
    if (animFrameId) cancelAnimationFrame(animFrameId)
    container = null
    mainCanvas = null
    mainCtx = null
  }

  const exportPng = async (): Promise<Blob> => {
    // Render all visible layers to an offscreen canvas
    const offscreen = document.createElement('canvas')
    offscreen.width = width
    offscreen.height = height
    const ctx = offscreen.getContext('2d')!

    ctx.fillStyle = '#ffffff'
    ctx.fillRect(0, 0, width, height)

    const state = store.getState()
    for (const layer of state.layers) {
      if (!layer.visible) continue
      ctx.save()
      ctx.globalAlpha = layer.opacity
      renderLayerToCanvas(ctx, layer.elements)
      ctx.restore()
    }

    return new Promise<Blob>((resolve) => {
      offscreen.toBlob((blob) => resolve(blob!), 'image/png')
    })
  }

  const importPng = async (file: File): Promise<void> => {
    return new Promise((resolve) => {
      const img = new Image()
      const url = URL.createObjectURL(file)
      img.onload = () => {
        store.addLayer('Imported Image')
        // For imported images, we draw them directly via a special approach:
        // store the image data and render on redraw
        if (mainCtx) {
          mainCtx.drawImage(img, 0, 0, width, height)
        }
        URL.revokeObjectURL(url)
        resolve()
      }
      img.src = url
    })
  }

  const loadPngFromFile = () => {
    const input = document.createElement('input')
    input.type = 'file'
    input.accept = 'image/png,image/jpeg,image/webp'
    input.onchange = async () => {
      const file = input.files?.[0]
      if (file) {
        await importPng(file)
        redraw()
      }
    }
    input.click()
  }

  return {
    store,
    mount,
    unmount,
    exportPng,
    importPng,
    redraw,
  }
}

