</head>
<body>
  <div id="app">${body}</div>
  ${scripts}
</body>
</html>`

const store = createCanvasStore(DEFAULT_WIDTH, DEFAULT_HEIGHT)

const handleApi = async (req: Request, url: URL): Promise<Response> => {
  const path = url.pathname

  // Save project
  if (path === '/api/projects' && req.method === 'POST') {
    const body = await req.json() as { id: string; name: string }
    const meta = await saveProject(body.id, body.name, store.getState())
    return Response.json(meta)
  }

  // List projects
  if (path === '/api/projects' && req.method === 'GET') {
    const projects = await listProjects()
    return Response.json(projects)
  }

  // Load project
  if (path.startsWith('/api/projects/') && req.method === 'GET') {
    const id = path.split('/').pop()!
    const project = await loadProject(id)
    if (!project) return new Response('Not found', { status: 404 })
    return Response.json(project)
  }

  // Delete project
  if (path.startsWith('/api/projects/') && req.method === 'DELETE') {
    const id = path.split('/').pop()!
    await deleteProject(id)
    return new Response('OK')
  }

  // Save PNG
  if (path === '/api/png' && req.method === 'POST') {
    const id = url.searchParams.get('id') ?? `drawing-${Date.now()}`
    const buffer = new Uint8Array(await req.arrayBuffer())
    const filePath = await savePng(id, buffer)
    return Response.json({ path: filePath })
  }

  // Load PNG
  if (path.startsWith('/api/png/') && req.method === 'GET') {
    const id = path.split('/').pop()!
    const data = await loadPng(id)
    if (!data) return new Response('Not found', { status: 404 })
    return new Response(data, {
      headers: { 'Content-Type': 'image/png' },
    })
  }

  // Get current state
  if (path === '/api/state' && req.method === 'GET') {
    return Response.json(store.getState())
  }

  return new Response('Not found', { status: 404 })
}

const server = Bun.serve({
  port: 3000,
  fetch: async (req) => {
    const url = new URL(req.url)

    // API routes
    if (url.pathname.startsWith('/api/')) {
      return handleApi(req, url)
    }

    // Serve the app
    if (url.pathname === '/' || url.pathname === '/index.html') {
      const state = store.getState()
      const body = renderToHtml(state, store.canUndo(), store.canRedo())
      const html = htmlShell(body, '<script type="module" src="/client.js"></script>')
      return new Response(html, {
        headers: { 'Content-Type': 'text/html' },
      })
    }

    // Serve client bundle (in production this would be bundled)
    if (url.pathname === '/client.js') {
      const clientCode = `
import { createCanvasController } from './client.ts'

const controller = createCanvasController(800, 600)

document.addEventListener('DOMContentLoaded', () => {
  const app = document.getElementById('app')
  if (app) {
    controller.mount(app)
  }
})

// Expose for debugging
window.__drawingCanvas = controller
`
      return new Response(clientCode, {
        headers: { 'Content-Type': 'application/javascript' },
      })
    }

    return new Response('Not found', { status: 404 })
  },
})

