export type ToolType = 'pen' | 'rectangle' | 'circle' | 'line' | 'eraser'

export type Point = {
  x: number
  y: number
}

export type StrokeBase = {
  id: string
  color: string
  size: number
  layerId: string
}

export type FreehandStroke = StrokeBase & {
  type: 'freehand'
  points: Point[]
}

export type RectangleStroke = StrokeBase & {
  type: 'rectangle'
  start: Point
  end: Point
}

export type CircleStroke = StrokeBase & {
  type: 'circle'
  center: Point
  radius: number
}

export type LineStroke = StrokeBase & {
  type: 'line'
  start: Point
  end: Point
}

export type EraserStroke = StrokeBase & {
  type: 'eraser'
  points: Point[]
}

export type Stroke = FreehandStroke | RectangleStroke | CircleStroke | LineStroke | EraserStroke

export type Layer = {
  id: string
  name: string
  visible: boolean
  strokes: Stroke[]
}

export type CanvasState = {
  layers: Layer[]
  activeLayerId: string
  width: number
  height: number
}

export type HistoryEntry = {
  layers: Layer[]
  activeLayerId: string
}

export type DrawingData = {
  id: string
  name: string
