import type {
  CanvasState,
  HistoryEntry,
  Layer,
  Stroke,
  Point,
  ToolType,
  FreehandStroke,
  RectangleStroke,
  CircleStroke,
  LineStroke,
  EraserStroke,
} from './types'

const generateId = (): string => crypto.randomUUID()

const createLayer = (name: string): Layer => ({
  id: generateId(),
  name,
  visible: true,
  strokes: [],
})

const createInitialState = (width = 800, height = 600): CanvasState => {
  const layer = createLayer('Layer 1')
  return {
    layers: [layer],
    activeLayerId: layer.id,
    width,
    height,
  }
}

const cloneLayers = (layers: Layer[]): Layer[] =>
  layers.map((l) => ({
    ...l,
    strokes: l.strokes.map((s) => ({ ...s })),
  }))

const createHistory = () => {
  let undoStack: HistoryEntry[] = []
  let redoStack: HistoryEntry[] = []

  const push = (state: CanvasState) => {
    undoStack.push({
      layers: cloneLayers(state.layers),
      activeLayerId: state.activeLayerId,
    })
    redoStack = []
  }

  const undo = (current: CanvasState): CanvasState | null => {
    if (undoStack.length === 0) return null
    redoStack.push({
      layers: cloneLayers(current.layers),
      activeLayerId: current.activeLayerId,
    })
    const entry = undoStack.pop()!
    return { ...current, layers: entry.layers, activeLayerId: entry.activeLayerId }
  }

  const redo = (current: CanvasState): CanvasState | null => {
    if (redoStack.length === 0) return null
    undoStack.push({
      layers: cloneLayers(current.layers),
      activeLayerId: current.activeLayerId,
    })
    const entry = redoStack.pop()!
    return { ...current, layers: entry.layers, activeLayerId: entry.activeLayerId }
  }

  const clear = () => {
    undoStack = []
    redoStack = []
  }

  const canUndo = () => undoStack.length > 0
  const canRedo = () => redoStack.length > 0

  return { push, undo, redo, clear, canUndo, canRedo }
}

const createStroke = (
  tool: ToolType,
  color: string,
  size: number,
  layerId: string,
  startPoint: Point,
): Stroke => {
  const base = { id: generateId(), color, size, layerId }

  switch (tool) {
    case 'pen':
      return { ...base, type: 'freehand', points: [startPoint] } as FreehandStroke
    case 'eraser':
      return { ...base, type: 'eraser', color: '#ffffff', points: [startPoint] } as EraserStroke
    case 'rectangle':
      return { ...base, type: 'rectangle', start: startPoint, end: startPoint } as RectangleStroke
    case 'circle':
      return { ...base, type: 'circle', center: startPoint, radius: 0 } as CircleStroke
    case 'line':
      return { ...base, type: 'line', start: startPoint, end: startPoint } as LineStroke
  }
}

const updateStroke = (stroke: Stroke, point: Point): Stroke => {
  switch (stroke.type) {
    case 'freehand':
    case 'eraser':
      return { ...stroke, points: [...stroke.points, point] }
    case 'rectangle':
      return { ...stroke, end: point }
    case 'circle': {
      const dx = point.x - stroke.center.x
      const dy = point.y - stroke.center.y
      return { ...stroke, radius: Math.sqrt(dx * dx + dy * dy) }
    }
    case 'line':
      return { ...stroke, end: point }
  }
}

const addStrokeToLayer = (state: CanvasState, stroke: Stroke): CanvasState => ({
  ...state,
  layers: state.layers.map((layer) =>
    layer.id === state.activeLayerId
      ? { ...layer, strokes: [...layer.strokes, stroke] }
      : layer,
  ),
})

const addLayer = (state: CanvasState, name?: string): CanvasState => {
  const layer = createLayer(name ?? `Layer ${state.layers.length + 1}`)
  return {
    ...state,
    layers: [...state.layers, layer],
    activeLayerId: layer.id,
  }
}

const removeLayer = (state: CanvasState, layerId: string): CanvasState => {
  if (state.layers.length <= 1) return state
  const filtered = state.layers.filter((l) => l.id !== layerId)
  const activeLayerId = state.activeLayerId === layerId ? filtered[0].id : state.activeLayerId
  return { ...state, layers: filtered, activeLayerId }
}

const toggleLayerVisibility = (state: CanvasState, layerId: string): CanvasState => ({
  ...state,
  layers: state.layers.map((l) =>
    l.id === layerId ? { ...l, visible: !l.visible } : l,
  ),
})

const setActiveLayer = (state: CanvasState, layerId: string): CanvasState => ({
  ...state,
  activeLayerId: layerId,
})

const clearCanvas = (state: CanvasState): CanvasState => ({
  ...state,
  layers: state.layers.map((l) => ({ ...l, strokes: [] })),
})

export {
  createInitialState,
  createHistory,
  createStroke,
  updateStroke,
  addStrokeToLayer,
  addLayer,
  removeLayer,
  toggleLayerVisibility,
  setActiveLayer,
  clearCanvas,
  cloneLayers,
}

import type { CanvasState, DrawingData } from './types'

const DATA_DIR = './data'
const DRAWINGS_FILE = `${DATA_DIR}/drawings.json`

const ensureDataDir = async () => {
  const dir = Bun.file(DATA_DIR)
  try {
    await Bun.write(`${DATA_DIR}/.keep`, '')
  } catch {
    // directory already exists
  }
}

const loadDrawings = async (): Promise<DrawingData[]> => {
  try {
    const file = Bun.file(DRAWINGS_FILE)
    if (await file.exists()) {
      return await file.json()
    }
  } catch {
    // file doesn't exist yet
  }
  return []
}

const saveDrawings = async (drawings: DrawingData[]): Promise<void> => {
  await ensureDataDir()
  await Bun.write(DRAWINGS_FILE, JSON.stringify(drawings, null, 2))
}

const saveDrawing = async (name: string, state: CanvasState): Promise<DrawingData> => {
  const drawings = await loadDrawings()
  const now = new Date().toISOString()
  const existing = drawings.find((d) => d.name === name)

  if (existing) {
    existing.state = state
    existing.updatedAt = now
    await saveDrawings(drawings)
    return existing
  }

  const drawing: DrawingData = {
    id: crypto.randomUUID(),
    name,
    state,
    createdAt: now,
    updatedAt: now,
  }
  drawings.push(drawing)
  await saveDrawings(drawings)
  return drawing
}

const loadDrawing = async (id: string): Promise<DrawingData | null> => {
  const drawings = await loadDrawings()
  return drawings.find((d) => d.id === id) ?? null
}

const deleteDrawing = async (id: string): Promise<boolean> => {
  const drawings = await loadDrawings()
  const filtered = drawings.filter((d) => d.id !== id)
  if (filtered.length === drawings.length) return false
  await saveDrawings(filtered)
  return true
}

const listDrawings = async (): Promise<DrawingData[]> => {
  return loadDrawings()
}

export { saveDrawing, loadDrawing, deleteDrawing, listDrawings, loadDrawings }

import type { Stroke, Layer, CanvasState } from './types'

const renderStrokeToPath = (stroke: Stroke): string => {
  switch (stroke.type) {
    case 'freehand':
    case 'eraser': {
      if (stroke.points.length === 0) return ''
      const [first, ...rest] = stroke.points
      const d = `M ${first.x} ${first.y} ` + rest.map((p) => `L ${p.x} ${p.y}`).join(' ')
      return `<path d="${d}" stroke="${stroke.color}" stroke-width="${stroke.size}" fill="none" stroke-linecap="round" stroke-linejoin="round"/>`
    }
    case 'rectangle': {
      const x = Math.min(stroke.start.x, stroke.end.x)
      const y = Math.min(stroke.start.y, stroke.end.y)
      const w = Math.abs(stroke.end.x - stroke.start.x)
      const h = Math.abs(stroke.end.y - stroke.start.y)
      return `<rect x="${x}" y="${y}" width="${w}" height="${h}" stroke="${stroke.color}" stroke-width="${stroke.size}" fill="none"/>`
    }
    case 'circle':
      return `<circle cx="${stroke.center.x}" cy="${stroke.center.y}" r="${stroke.radius}" stroke="${stroke.color}" stroke-width="${stroke.size}" fill="none"/>`
    case 'line':
      return `<line x1="${stroke.start.x}" y1="${stroke.start.y}" x2="${stroke.end.x}" y2="${stroke.end.y}" stroke="${stroke.color}" stroke-width="${stroke.size}" stroke-linecap="round"/>`
  }
}

const renderLayerToSvg = (layer: Layer, width: number, height: number): string => {
  if (!layer.visible) return ''
  const strokes = layer.strokes.map(renderStrokeToPath).join('\n  ')
  return `<g data-layer-id="${layer.id}">\n  ${strokes}\n</g>`
}

const renderCanvasToSvg = (state: CanvasState): string => {
  const layers = state.layers.map((l) => renderLayerToSvg(l, state.width, state.height)).join('\n')
  return `<svg xmlns="http://www.w3.org/2000/svg" width="${state.width}" height="${state.height}" viewBox="0 0 ${state.width} ${state.height}">
<rect width="${state.width}" height="${state.height}" fill="white"/>
${layers}
</svg>`
}

const renderLayerThumbnailSvg = (layer: Layer, width: number, height: number, thumbWidth = 60, thumbHeight = 45): string => {
  const scaleX = thumbWidth / width
  const scaleY = thumbHeight / height
  const strokes = layer.strokes.map(renderStrokeToPath).join('\n  ')
  return `<svg xmlns="http://www.w3.org/2000/svg" width="${thumbWidth}" height="${thumbHeight}" viewBox="0 0 ${width} ${height}">
<rect width="${width}" height="${height}" fill="white"/>
<g>${strokes}</g>
</svg>`
}

export { renderStrokeToPath, renderLayerToSvg, renderCanvasToSvg, renderLayerThumbnailSvg }

