import type { CanvasState, ToolbarState, ToolType, Point, Stroke } from './types'
import {
  createInitialState,
  createHistory,
  createStroke,
  updateStroke,
  addStrokeToLayer,
  addLayer,
  removeLayer,
  toggleLayerVisibility,
  setActiveLayer,
  clearCanvas,
} from './drawing'
import { renderCanvasToSvg } from './renderer'
import { renderToHtml } from './canvas'
import { saveDrawing, loadDrawing, listDrawings } from './storage'

let canvasState: CanvasState = createInitialState(800, 600)
let toolbarState: ToolbarState = {
  activeTool: 'pen',
  color: '#000000',
  brushSize: 3,
}
const history = createHistory()
let currentStroke: Stroke | null = null

const handleToolSelect = (toolType: ToolType) => {
  toolbarState = { ...toolbarState, activeTool: toolType }
}

const handleColorChange = (color: string) => {
  toolbarState = { ...toolbarState, color }
}

const handleSizeChange = (size: number) => {
  toolbarState = { ...toolbarState, brushSize: Math.max(1, Math.min(50, size)) }
}

const handlePointerDown = (point: Point) => {
  history.push(canvasState)
  currentStroke = createStroke(
    toolbarState.activeTool,
    toolbarState.color,
    toolbarState.brushSize,
    canvasState.activeLayerId,
    point,
  )
}

const handlePointerMove = (point: Point) => {
  if (!currentStroke) return
  currentStroke = updateStroke(currentStroke, point)
}

const handlePointerUp = () => {
  if (!currentStroke) return
  canvasState = addStrokeToLayer(canvasState, currentStroke)
  currentStroke = null
}

const handleUndo = () => {
  const restored = history.undo(canvasState)
  if (restored) canvasState = restored
}

const handleRedo = () => {
  const restored = history.redo(canvasState)
  if (restored) canvasState = restored
}

const handleClear = () => {
  history.push(canvasState)
  canvasState = clearCanvas(canvasState)
}

const handleAddLayer = () => {
  history.push(canvasState)
  canvasState = addLayer(canvasState)
}

const handleRemoveLayer = (layerId: string) => {
  history.push(canvasState)
  canvasState = removeLayer(canvasState, layerId)
}

const handleToggleLayerVisibility = (layerId: string) => {
  canvasState = toggleLayerVisibility(canvasState, layerId)
}

const handleSetActiveLayer = (layerId: string) => {
  canvasState = setActiveLayer(canvasState, layerId)
}

const handleSave = async (name: string) => {
  return saveDrawing(name, canvasState)
}

const handleLoad = async (id: string) => {
  const drawing = await loadDrawing(id)
  if (drawing) {
    history.push(canvasState)
    canvasState = drawing.state
  }
  return drawing
}

const handleExportPng = (): string => {
  const svg = renderCanvasToSvg(canvasState)
  const base64 = btoa(svg)
  return `data:image/svg+xml;base64,${base64}`
}

const getState = () => canvasState
const getToolbar = () => toolbarState
const getHtml = () => renderToHtml(canvasState, toolbarState)
const getSvg = () => renderCanvasToSvg(canvasState)
const canUndo = () => history.canUndo()
const canRedo = () => history.canRedo()

const serve = () => {
  return Bun.serve({
    port: 3000,
    fetch: async (req) => {
      const url = new URL(req.url)
      const method = req.method

      if (url.pathname === '/' && method === 'GET') {
        return new Response(getHtml(), {
          headers: { 'Content-Type': 'text/html' },
        })
      }

      if (url.pathname === '/api/state' && method === 'GET') {
        return Response.json({
          canvas: canvasState,
          toolbar: toolbarState,
          canUndo: canUndo(),
          canRedo: canRedo(),
        })
      }

      if (url.pathname === '/api/tool' && method === 'POST') {
        const { tool } = await req.json() as { tool: ToolType }
        handleToolSelect(tool)
        return Response.json({ ok: true, toolbar: toolbarState })
      }

      if (url.pathname === '/api/color' && method === 'POST') {
        const { color } = await req.json() as { color: string }
        handleColorChange(color)
        return Response.json({ ok: true, toolbar: toolbarState })
      }

      if (url.pathname === '/api/size' && method === 'POST') {
        const { size } = await req.json() as { size: number }
        handleSizeChange(size)
        return Response.json({ ok: true, toolbar: toolbarState })
      }

      if (url.pathname === '/api/draw/start' && method === 'POST') {
        const { point } = await req.json() as { point: Point }
        handlePointerDown(point)
        return Response.json({ ok: true })
      }

      if (url.pathname === '/api/draw/move' && method === 'POST') {
        const { point } = await req.json() as { point: Point }
        handlePointerMove(point)
        return Response.json({ ok: true, stroke: currentStroke })
      }

      if (url.pathname === '/api/draw/end' && method === 'POST') {
        handlePointerUp()
        return Response.json({ ok: true, canvas: canvasState })
      }

      if (url.pathname === '/api/undo' && method === 'POST') {
        handleUndo()
        return Response.json({ ok: true, canvas: canvasState })
      }

      if (url.pathname === '/api/redo' && method === 'POST') {
        handleRedo()
        return Response.json({ ok: true, canvas: canvasState })
      }

      if (url.pathname === '/api/clear' && method === 'POST') {
        handleClear()
        return Response.json({ ok: true, canvas: canvasState })
      }

      if (url.pathname === '/api/layers/add' && method === 'POST') {
        handleAddLayer()
        return Response.json({ ok: true, canvas: canvasState })
      }

      if (url.pathname === '/api/layers/remove' && method === 'POST') {
        const { layerId } = await req.json() as { layerId: string }
        handleRemoveLayer(layerId)
        return Response.json({ ok: true, canvas: canvasState })
      }

      if (url.pathname === '/api/layers/toggle' && method === 'POST') {
        const { layerId } = await req.json() as { layerId: string }
        handleToggleLayerVisibility(layerId)
        return Response.json({ ok: true, canvas: canvasState })
      }

      if (url.pathname === '/api/layers/select' && method === 'POST') {
        const { layerId } = await req.json() as { layerId: string }
        handleSetActiveLayer(layerId)
        return Response.json({ ok: true, canvas: canvasState })
      }

      if (url.pathname === '/api/save' && method === 'POST') {
        const { name } = await req.json() as { name: string }
        const drawing = await handleSave(name)
        return Response.json({ ok: true, drawing })
      }

      if (url.pathname === '/api/load' && method === 'POST') {
        const { id } = await req.json() as { id: string }
        const drawing = await handleLoad(id)
        return drawing
          ? Response.json({ ok: true, drawing, canvas: canvasState })
          : Response.json({ ok: false, error: 'Drawing not found' }, { status: 404 })
      }

      if (url.pathname === '/api/drawings' && method === 'GET') {
        const drawings = await listDrawings()
        return Response.json({ drawings })
      }

      if (url.pathname === '/api/export/svg' && method === 'GET') {
        return new Response(getSvg(), {
          headers: {
            'Content-Type': 'image/svg+xml',
            'Content-Disposition': 'attachment; filename="drawing.svg"',
          },
        })
      }

      if (url.pathname === '/api/export/png' && method === 'GET') {
        const dataUrl = handleExportPng()
        return Response.json({ dataUrl })
      }

      return Response.json({ error: 'Not found' }, { status: 404 })
    },
  })
}

export {
  serve,
  getState,
  getToolbar,
  getHtml,
  getSvg,
  handleToolSelect,
  handleColorChange,
  handleSizeChange,
  handlePointerDown,
  handlePointerMove,
  handlePointerUp,
  handleUndo,
  handleRedo,
  handleClear,
  handleAddLayer,
  handleRemoveLayer,
  handleToggleLayerVisibility,
  handleSetActiveLayer,
  handleSave,
  handleLoad,
  handleExportPng,
}

{
  "name": "@node/playlist-manager",
  "version": "1.0.0",
  "modnet": {
    "contentType": "entertainment",
    "structure": "list",
    "mechanics": ["sort", "track"],
    "boundary": "none",
    "scale": 2
  },
  "dependencies": {
    "plaited": "latest"
  }
}

export type Song = {
  id: string;
  title: string;
  artist: string;
  album: string;
  duration: number; // seconds
  albumArtUrl: string;
};

export type Playlist = {
  id: string;
  name: string;
  description: string;
  coverUrl: string;
  songs: Song[];
  createdAt: string;
  updatedAt: string;
};

export type RepeatMode = "none" | "all" | "one";

export type ShuffleState = {
  enabled: boolean;
  shuffledIndices: number[];
};

export type PlayerState = {
  currentPlaylistId: string | null;
  currentSongIndex: number;
  isPlaying: boolean;
  progress: number; // 0-1
  elapsed: number; // seconds
  repeatMode: RepeatMode;
  shuffle: ShuffleState;
};

export type AppState = {
  playlists: Playlist[];
  player: PlayerState;
  activeView: "library" | "playlist" | "now-playing";
  activePlaylistId: string | null;
};

export type DragPayload = {
  playlistId: string;
  fromIndex: number;
  toIndex: number;
};

import type { Playlist, Song, PlayerState, AppState, RepeatMode, DragPayload } from "./types";

const DATA_PATH = "./data/playlists.json";

const generateId = (prefix: string): string =>
  `${prefix}-${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 7)}`;

const defaultPlayerState: PlayerState = {
  currentPlaylistId: null,
  currentSongIndex: 0,
  isPlaying: false,
  progress: 0,
  elapsed: 0,
  repeatMode: "none",
  shuffle: { enabled: false, shuffledIndices: [] },
};

const loadPlaylists = async (): Promise<Playlist[]> => {
  const file = Bun.file(DATA_PATH);
  if (await file.exists()) {
    return file.json();
  }
  return [];
};

const savePlaylists = async (playlists: Playlist[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(playlists, null, 2));
};

export const createStore = async (): Promise<{
  getState: () => AppState;
  getPlaylists: () => Playlist[];
  getPlaylist: (id: string) => Playlist | undefined;
  createPlaylist: (name: string, description?: string, coverUrl?: string) => Promise<Playlist>;
  deletePlaylist: (id: string) => Promise<void>;
  addSong: (playlistId: string, song: Omit<Song, "id">) => Promise<Song | null>;
  removeSong: (playlistId: string, songId: string) => Promise<void>;
  reorderSong: (payload: DragPayload) => Promise<void>;
  play: (playlistId: string, songIndex?: number) => void;
  pause: () => void;
  resume: () => void;
  skipNext: () => void;
  skipPrev: () => void;
  seek: (progress: number) => void;
  toggleShuffle: () => void;
  cycleRepeat: () => void;
  tick: () => void;
  getCurrentSong: () => Song | null;
}> => {
  let playlists = await loadPlaylists();
  let player: PlayerState = { ...defaultPlayerState };
  let activeView: AppState["activeView"] = "library";
  let activePlaylistId: string | null = null;

  const generateShuffleIndices = (length: number, currentIndex: number): number[] => {
    const indices = Array.from({ length }, (_, i) => i).filter((i) => i !== currentIndex);
    for (let i = indices.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1));
      [indices[i], indices[j]] = [indices[j], indices[i]];
    }
    return [currentIndex, ...indices];
  };

  const resolveIndex = (logicalIndex: number): number => {
    if (player.shuffle.enabled && player.shuffle.shuffledIndices.length > 0) {
      return player.shuffle.shuffledIndices[logicalIndex % player.shuffle.shuffledIndices.length];
    }
    return logicalIndex;
  };

  const getCurrentPlaylist = (): Playlist | undefined =>
    playlists.find((p) => p.id === player.currentPlaylistId);

  return {
    getState: (): AppState => ({
      playlists,
      player: { ...player },
      activeView,
      activePlaylistId,
    }),

    getPlaylists: () => playlists,

    getPlaylist: (id: string) => playlists.find((p) => p.id === id),

    createPlaylist: async (name, description = "", coverUrl = "") => {
      const now = new Date().toISOString();
      const playlist: Playlist = {
        id: generateId("pl"),
        name,
        description,
        coverUrl: coverUrl || `https://picsum.photos/seed/${encodeURIComponent(name)}/300/300`,
        songs: [],
        createdAt: now,
        updatedAt: now,
      };
      playlists = [...playlists, playlist];
      await savePlaylists(playlists);
      return playlist;
    },

    deletePlaylist: async (id) => {
      playlists = playlists.filter((p) => p.id !== id);
      if (player.currentPlaylistId === id) {
        player = { ...defaultPlayerState };
      }
      await savePlaylists(playlists);
    },

    addSong: async (playlistId, songData) => {
      const playlist = playlists.find((p) => p.id === playlistId);
      if (!playlist) return null;
      const song: Song = { ...songData, id: generateId("s") };
      playlist.songs = [...playlist.songs, song];
      playlist.updatedAt = new Date().toISOString();
      await savePlaylists(playlists);
      return song;
    },

    removeSong: async (playlistId, songId) => {
      const playlist = playlists.find((p) => p.id === playlistId);
      if (!playlist) return;
      playlist.songs = playlist.songs.filter((s) => s.id !== songId);
      playlist.updatedAt = new Date().toISOString();
      await savePlaylists(playlists);
    },

    reorderSong: async ({ playlistId, fromIndex, toIndex }) => {
      const playlist = playlists.find((p) => p.id === playlistId);
      if (!playlist) return;
      const songs = [...playlist.songs];
      const [moved] = songs.splice(fromIndex, 1);
      songs.splice(toIndex, 0, moved);
      playlist.songs = songs;
      playlist.updatedAt = new Date().toISOString();
      await savePlaylists(playlists);
    },

    play: (playlistId, songIndex = 0) => {
      player.currentPlaylistId = playlistId;
      player.currentSongIndex = songIndex;
      player.isPlaying = true;
      player.progress = 0;
      player.elapsed = 0;
      if (player.shuffle.enabled) {
        const playlist = playlists.find((p) => p.id === playlistId);
        if (playlist) {
          player.shuffle.shuffledIndices = generateShuffleIndices(playlist.songs.length, songIndex);
        }
      }
    },

    pause: () => {
      player.isPlaying = false;
    },

    resume: () => {
      if (player.currentPlaylistId) {
        player.isPlaying = true;
      }
    },

    skipNext: () => {
      const playlist = getCurrentPlaylist();
      if (!playlist || playlist.songs.length === 0) return;

      if (player.repeatMode === "one") {
        player.progress = 0;
        player.elapsed = 0;
        return;
      }

      const nextLogical = player.currentSongIndex + 1;
      if (nextLogical >= playlist.songs.length) {
        if (player.repeatMode === "all") {
          player.currentSongIndex = 0;
          if (player.shuffle.enabled) {
            player.shuffle.shuffledIndices = generateShuffleIndices(playlist.songs.length, 0);
          }
        } else {
          player.isPlaying = false;
          player.currentSongIndex = 0;
        }
      } else {
        player.currentSongIndex = nextLogical;
      }
      player.progress = 0;
      player.elapsed = 0;
    },

    skipPrev: () => {
      const playlist = getCurrentPlaylist();
      if (!playlist || playlist.songs.length === 0) return;

      if (player.elapsed > 3) {
        player.progress = 0;
        player.elapsed = 0;
        return;
      }

      const prevLogical = player.currentSongIndex - 1;
      if (prevLogical < 0) {
        if (player.repeatMode === "all") {
          player.currentSongIndex = playlist.songs.length - 1;
        } else {
          player.currentSongIndex = 0;
        }
      } else {
        player.currentSongIndex = prevLogical;
      }
      player.progress = 0;
      player.elapsed = 0;
    },

    seek: (progress) => {
      player.progress = Math.max(0, Math.min(1, progress));
      const song = (() => {
        const playlist = getCurrentPlaylist();
        if (!playlist) return null;
        const idx = resolveIndex(player.currentSongIndex);
        return playlist.songs[idx] ?? null;
      })();
      if (song) {
        player.elapsed = Math.round(song.duration * player.progress);
      }
    },

    toggleShuffle: () => {
      player.shuffle.enabled = !player.shuffle.enabled;
      if (player.shuffle.enabled) {
        const playlist = getCurrentPlaylist();
        if (playlist) {
          player.shuffle.shuffledIndices = generateShuffleIndices(
            playlist.songs.length,
            player.currentSongIndex
          );
        }
      } else {
        player.shuffle.shuffledIndices = [];
      }
    },

    cycleRepeat: () => {
      const modes: RepeatMode[] = ["none", "all", "one"];
      const idx = modes.indexOf(player.repeatMode);
      player.repeatMode = modes[(idx + 1) % modes.length];
    },

    tick: () => {
      if (!player.isPlaying) return;
      const playlist = getCurrentPlaylist();
      if (!playlist) return;
      const idx = resolveIndex(player.currentSongIndex);
      const song = playlist.songs[idx];
      if (!song) return;

      player.elapsed += 1;
      player.progress = player.elapsed / song.duration;

      if (player.elapsed >= song.duration) {
        // Auto-advance
        const nextLogical = player.currentSongIndex + 1;
        if (player.repeatMode === "one") {
          player.progress = 0;
          player.elapsed = 0;
        } else if (nextLogical >= playlist.songs.length) {
          if (player.repeatMode === "all") {
            player.currentSongIndex = 0;
            player.progress = 0;
            player.elapsed = 0;
          } else {
            player.isPlaying = false;
            player.progress = 1;
          }
        } else {
          player.currentSongIndex = nextLogical;
          player.progress = 0;
          player.elapsed = 0;
        }
      }
    },

    getCurrentSong: () => {
      const playlist = getCurrentPlaylist();
      if (!playlist) return null;
      const idx = resolveIndex(player.currentSongIndex);
      return playlist.songs[idx] ?? null;
    },
  };
};

