const iconPlay = () => h("span", {}, "\u25B6");
const iconPause = () => h("span", {}, "\u23F8");
const iconSkipNext = () => h("span", {}, "\u23ED");
const iconSkipPrev = () => h("span", {}, "\u23EE");
const iconShuffle = () => h("span", {}, "\u{1F500}");
const iconRepeatNone = () => h("span", {}, "\u{1F501}");
const iconRepeatOne = () => h("span", {}, "\u{1F502}");
