export const renderApp = (
  playlists: Playlist[],
  activePlaylist: Playlist | null,
  currentSong: Song | null,
  player: PlayerState,
  activeView: "library" | "playlist" | "now-playing",
  modal: "create-playlist" | "add-song" | null,
  modalPlaylistId?: string,
) => {
  const content = (() => {
    if (activeView === "now-playing" && currentSong) {
      return h(Fragment, {},
        h("div", { style: s.headerStyle },
          h("button", {
            style: s.btnIcon,
            "p-trigger": "close-now-playing",
          }, iconBack()),
          h("span", { style: { fontSize: "14px", color: s.colors.textMuted, fontWeight: "600" } }, "Now Playing"),
          h("span", { style: { width: "36px" } }),
        ),
        renderNowPlayingView(currentSong, player),
      );
    }
    if (activeView === "playlist" && activePlaylist) {
      return renderPlaylistView(activePlaylist, player);
    }
    return renderLibrary(playlists);
  })();

  return h("div", { style: s.containerStyle },
    content,
    activeView !== "now-playing" ? renderPlayerBar(currentSong, player) : h(Fragment, {}),
    modal === "create-playlist" ? renderCreatePlaylistModal() : h(Fragment, {}),
    modal === "add-song" && modalPlaylistId ? renderAddSongModal(modalPlaylistId) : h(Fragment, {}),
  );
};

import { createSSR } from "plaited";
import { createStore } from "./store";
import { renderApp } from "./templates";
import type { AppState, Song } from "./types";

export type ModalState = "create-playlist" | "add-song" | null;

export const createApp = async () => {
  const store = await createStore();
  let modal: ModalState = null;
  let modalPlaylistId: string | undefined;
  let activeView: AppState["activeView"] = "library";
  let activePlaylistId: string | null = null;
  let tickInterval: ReturnType<typeof setInterval> | null = null;

  const startTick = () => {
    if (tickInterval) return;
    tickInterval = setInterval(() => {
      store.tick();
    }, 1000);
  };

  const stopTick = () => {
    if (tickInterval) {
      clearInterval(tickInterval);
      tickInterval = null;
    }
  };

  const render = (): string => {
    const state = store.getState();
    const activePlaylist = activePlaylistId ? store.getPlaylist(activePlaylistId) ?? null : null;
    const currentSong = store.getCurrentSong();

    const tree = renderApp(
      state.playlists,
      activePlaylist,
      currentSong,
      state.player,
      activeView,
      modal,
      modalPlaylistId,
    );

    const ssr = createSSR();
    return ssr(tree);
  };

  // --- Event handlers ---

  const handleEvent = async (trigger: string, data?: Record<string, string>): Promise<string> => {
    switch (trigger) {
      case "create-playlist": {
        modal = "create-playlist";
        break;
      }
      case "submit-create-playlist": {
        const name = data?.["playlist-name"] ?? "Untitled";
        const desc = data?.["playlist-desc"] ?? "";
        const cover = data?.["playlist-cover"] ?? "";
        await store.createPlaylist(name, desc, cover);
        modal = null;
        break;
      }
      case "open-playlist": {
        activePlaylistId = data?.["playlist-id"] ?? null;
        activeView = "playlist";
        break;
      }
      case "back-to-library": {
        activeView = "library";
        activePlaylistId = null;
        break;
      }
      case "add-song": {
        modal = "add-song";
        modalPlaylistId = data?.["playlist-id"];
        break;
      }
      case "submit-add-song": {
        const playlistId = data?.["playlist-id"] ?? modalPlaylistId ?? "";
        const title = data?.["song-title"] ?? "Untitled";
        const artist = data?.["song-artist"] ?? "Unknown";
        const album = data?.["song-album"] ?? "Unknown";
        const duration = parseInt(data?.["song-duration"] ?? "240", 10);
        const albumArtUrl = data?.["song-art"] ?? `https://picsum.photos/seed/${encodeURIComponent(title)}/300/300`;

        await store.addSong(playlistId, { title, artist, album, duration, albumArtUrl });
        modal = null;
        modalPlaylistId = undefined;
        break;
      }
      case "remove-song": {
        const plId = data?.["playlist-id"] ?? "";
        const songId = data?.["song-id"] ?? "";
        await store.removeSong(plId, songId);
        break;
      }
      case "play-playlist": {
        const plId = data?.["playlist-id"] ?? "";
        store.play(plId, 0);
        startTick();
        break;
      }
      case "play-song": {
        const plId = data?.["playlist-id"] ?? activePlaylistId ?? "";
        const songIndex = parseInt(data?.["song-index"] ?? "0", 10);
        store.play(plId, songIndex);
        startTick();
        break;
      }
      case "pause": {
        store.pause();
        stopTick();
        break;
      }
      case "resume": {
        store.resume();
        startTick();
        break;
      }
      case "skip-next": {
        store.skipNext();
        break;
      }
      case "skip-prev": {
        store.skipPrev();
        break;
      }
      case "seek": {
        const progress = parseFloat(data?.["progress"] ?? "0");
        store.seek(progress);
        break;
      }
      case "toggle-shuffle": {
        store.toggleShuffle();
        break;
      }
      case "cycle-repeat": {
        store.cycleRepeat();
        break;
      }
      case "open-now-playing": {
        activeView = "now-playing";
        break;
      }
      case "close-now-playing": {
        activeView = activePlaylistId ? "playlist" : "library";
        break;
      }
      case "close-modal": {
        modal = null;
        modalPlaylistId = undefined;
        break;
      }
      case "reorder-song": {
        const plId = data?.["playlist-id"] ?? "";
        const fromIndex = parseInt(data?.["from-index"] ?? "0", 10);
        const toIndex = parseInt(data?.["to-index"] ?? "0", 10);
        await store.reorderSong({ playlistId: plId, fromIndex, toIndex });
        break;
      }
      case "delete-playlist": {
        const plId = data?.["playlist-id"] ?? "";
        await store.deletePlaylist(plId);
        if (activePlaylistId === plId) {
          activeView = "library";
          activePlaylistId = null;
        }
        break;
      }
    }
    return render();
  };

  return {
    render,
    handleEvent,
    getStore: () => store,
    destroy: () => stopTick(),
  };
};

