const serve = async () => {
  const app = await createApp();

  const html = (body: string) => `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <title>Playlist Manager</title>
  <style>
    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
    body { background: #121212; color: #fff; font-family: 'Segoe UI', Roboto, Helvetica, Arial, sans-serif; }
    img { display: block; }
    button { font-family: inherit; }
    input { font-family: inherit; }

    /* Drag-and-drop styles */
    [draggable="true"] { transition: opacity 0.2s; }
    [draggable="true"].dragging { opacity: 0.4; }
    .drag-over { background-color: #2d4a35 !important; }

    /* Hover effects */
    button:hover { opacity: 0.85; }

    /* Scrollbar */
    ::-webkit-scrollbar { width: 6px; }
    ::-webkit-scrollbar-track { background: transparent; }
    ::-webkit-scrollbar-thumb { background: #535353; border-radius: 3px; }
  </style>
</head>
<body>
  <div id="app">${body}</div>

  <script>
    // Audio placeholder - simulates playback timing
    const audio = new Audio();
    audio.volume = 0;

    // Drag and drop for song reordering
    let dragSrcIndex = null;
    let dragPlaylistId = null;

    document.addEventListener('dragstart', (e) => {
      const row = e.target.closest('[draggable="true"]');
      if (!row) return;
      dragSrcIndex = row.dataset.songIndex;
      dragPlaylistId = row.dataset.playlistId;
      row.classList.add('dragging');
      e.dataTransfer.effectAllowed = 'move';
      e.dataTransfer.setData('text/plain', dragSrcIndex);
    });

    document.addEventListener('dragover', (e) => {
      e.preventDefault();
      e.dataTransfer.dropEffect = 'move';
      const row = e.target.closest('[draggable="true"]');
      if (row) row.classList.add('drag-over');
    });

    document.addEventListener('dragleave', (e) => {
      const row = e.target.closest('[draggable="true"]');
      if (row) row.classList.remove('drag-over');
    });

    document.addEventListener('dragend', (e) => {
      document.querySelectorAll('.dragging, .drag-over').forEach(el => {
        el.classList.remove('dragging', 'drag-over');
      });
    });

    document.addEventListener('drop', async (e) => {
      e.preventDefault();
      const row = e.target.closest('[draggable="true"]');
      if (!row || dragSrcIndex === null) return;

      const toIndex = row.dataset.songIndex;
      if (dragSrcIndex !== toIndex && dragPlaylistId) {
        const params = new URLSearchParams({
          trigger: 'reorder-song',
          'playlist-id': dragPlaylistId,
          'from-index': dragSrcIndex,
          'to-index': toIndex,
        });
        const resp = await fetch('/event?' + params);
        if (resp.ok) {
          document.getElementById('app').innerHTML = await resp.text();
        }
      }
      dragSrcIndex = null;
      dragPlaylistId = null;
    });

    // Click-based event delegation
    document.addEventListener('click', async (e) => {
      const btn = e.target.closest('[p-trigger]');
      if (!btn) return;
      e.preventDefault();
      e.stopPropagation();

      const trigger = btn.getAttribute('p-trigger');

      // Handle seek on progress bar
      if (trigger === 'seek') {
        const rect = btn.getBoundingClientRect();
        const x = e.clientX - rect.left;
        const progress = x / rect.width;
        const params = new URLSearchParams({ trigger: 'seek', progress: String(progress) });
        const resp = await fetch('/event?' + params);
        if (resp.ok) {
          document.getElementById('app').innerHTML = await resp.text();
        }
        return;
      }

      // Gather form data if modal submit
      const data = {};
      if (trigger.startsWith('submit-')) {
        const form = btn.closest('div')?.parentElement;
        if (form) {
          form.querySelectorAll('input').forEach(input => {
            if (input.name) data[input.name] = input.value;
          });
        }
      }

      // Collect data attributes
      for (const [key, val] of Object.entries(btn.dataset)) {
        data[key.replace(/([A-Z])/g, '-$1').toLowerCase()] = val;
      }

      const params = new URLSearchParams({ trigger, ...data });
      const resp = await fetch('/event?' + params);
      if (resp.ok) {
        document.getElementById('app').innerHTML = await resp.text();
      }
    });

    // Auto-tick for playback progress
    setInterval(async () => {
      const resp = await fetch('/tick');
      if (resp.ok) {
        const html = await resp.text();
        if (html) {
          document.getElementById('app').innerHTML = html;
        }
      }
    }, 1000);
  </script>
</body>
</html>`;

  Bun.serve({
    port: 3000,
    fetch: async (req) => {
      const url = new URL(req.url);

      if (url.pathname === "/event") {
        const trigger = url.searchParams.get("trigger") ?? "";
        const data: Record<string, string> = {};
        for (const [key, val] of url.searchParams.entries()) {
          if (key !== "trigger") data[key] = val;
        }
        const body = await app.handleEvent(trigger, data);
        return new Response(body, { headers: { "Content-Type": "text/html" } });
      }

      if (url.pathname === "/tick") {
        const state = app.getStore().getState();
        if (state.player.isPlaying) {
          app.getStore().tick();
          return new Response(app.render(), { headers: { "Content-Type": "text/html" } });
        }
        return new Response("", { headers: { "Content-Type": "text/html" } });
      }

      return new Response(html(app.render()), { headers: { "Content-Type": "text/html" } });
    },
  });

  console.log("Playlist Manager running at http://localhost:3000");
};

serve();

