import type { Playlist, PlaybackState } from './types'

const DATA_PATH = import.meta.dir + '/data/playlists.json'

export const loadPlaylists = async (): Promise<Playlist[]> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) return []
  const text = await file.text()
  return text.trim() ? JSON.parse(text) : []
}

export const savePlaylists = async (playlists: Playlist[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(playlists, null, 2))
}

const generateId = (): string =>
  Math.random().toString(36).slice(2, 10) + Date.now().toString(36)

export { generateId }

// In-memory playback state (not persisted across restarts)
let playbackState: PlaybackState = {
  currentPlaylistId: null,
  currentSongIndex: 0,
  isPlaying: false,
  elapsed: 0,
  shuffle: false,
  repeat: 'off',
  shuffleOrder: [],
}

export const getPlayback = (): PlaybackState => ({ ...playbackState })

export const setPlayback = (update: Partial<PlaybackState>): PlaybackState => {
  playbackState = { ...playbackState, ...update }
  return { ...playbackState }
}

export const generateShuffleOrder = (length: number): number[] => {
  const order = Array.from({ length }, (_, i) => i)
  for (let i = order.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1))
    ;[order[i], order[j]] = [order[j], order[i]]
  }
  return order
}

import type { Playlist, Song } from './types'
import { loadPlaylists, savePlaylists, generateId } from './store'

export const getAllPlaylists = async (): Promise<Playlist[]> => {
  return loadPlaylists()
}

export const createPlaylist = async (name: string): Promise<Playlist> => {
  const playlists = await loadPlaylists()
  const playlist: Playlist = {
    id: generateId(),
    name,
    createdAt: new Date().toISOString(),
    songs: [],
  }
  playlists.push(playlist)
  await savePlaylists(playlists)
  return playlist
}

export const deletePlaylist = async (id: string): Promise<boolean> => {
  const playlists = await loadPlaylists()
  const idx = playlists.findIndex((p) => p.id === id)
  if (idx === -1) return false
  playlists.splice(idx, 1)
  await savePlaylists(playlists)
  return true
}

export const getPlaylist = async (id: string): Promise<Playlist | null> => {
  const playlists = await loadPlaylists()
  return playlists.find((p) => p.id === id) ?? null
}

export const addSong = async (
  playlistId: string,
  song: Omit<Song, 'id'>
): Promise<Song | null> => {
  const playlists = await loadPlaylists()
  const playlist = playlists.find((p) => p.id === playlistId)
  if (!playlist) return null
  const newSong: Song = { ...song, id: generateId() }
  playlist.songs.push(newSong)
  await savePlaylists(playlists)
  return newSong
}

export const removeSong = async (
  playlistId: string,
  songId: string
): Promise<boolean> => {
  const playlists = await loadPlaylists()
  const playlist = playlists.find((p) => p.id === playlistId)
  if (!playlist) return false
  const idx = playlist.songs.findIndex((s) => s.id === songId)
  if (idx === -1) return false
  playlist.songs.splice(idx, 1)
  await savePlaylists(playlists)
  return true
}

export const reorderSongs = async (
  playlistId: string,
  songIds: string[]
): Promise<boolean> => {
  const playlists = await loadPlaylists()
  const playlist = playlists.find((p) => p.id === playlistId)
  if (!playlist) return false
  const songMap = new Map(playlist.songs.map((s) => [s.id, s]))
  const reordered: Song[] = []
  for (const id of songIds) {
    const song = songMap.get(id)
    if (!song) return false
    reordered.push(song)
  }
  playlist.songs = reordered
  await savePlaylists(playlists)
  return true
}

import type { PlaybackState, RepeatMode, Song } from './types'
import { getPlayback, setPlayback, generateShuffleOrder } from './store'
import { getPlaylist } from './playlist'

type PlaybackAction =
  | 'play'
  | 'pause'
  | 'next'
  | 'prev'
  | 'shuffle'
  | 'repeat'
  | 'seek'

type PlaybackCommand = {
  action: PlaybackAction
  playlistId?: string
  songIndex?: number
  seekTo?: number
}

type NowPlaying = {
  song: Song | null
  playback: PlaybackState
}

const resolveIndex = (state: PlaybackState, index: number): number => {
  if (state.shuffle && state.shuffleOrder.length > 0) {
    return state.shuffleOrder[index % state.shuffleOrder.length]
  }
  return index
}

export const getNowPlaying = async (): Promise<NowPlaying> => {
  const state = getPlayback()
  if (!state.currentPlaylistId) return { song: null, playback: state }
  const playlist = await getPlaylist(state.currentPlaylistId)
  if (!playlist || playlist.songs.length === 0) return { song: null, playback: state }
  const realIndex = resolveIndex(state, state.currentSongIndex)
  const song = playlist.songs[realIndex] ?? null
  return { song, playback: state }
}

export const executePlayback = async (cmd: PlaybackCommand): Promise<NowPlaying> => {
  let state = getPlayback()

  switch (cmd.action) {
    case 'play': {
      if (cmd.playlistId) {
        const playlist = await getPlaylist(cmd.playlistId)
        if (!playlist || playlist.songs.length === 0) break
        const startIndex = cmd.songIndex ?? 0
        const shuffleOrder = state.shuffle
          ? generateShuffleOrder(playlist.songs.length)
          : []
        state = setPlayback({
          currentPlaylistId: cmd.playlistId,
          currentSongIndex: startIndex,
          isPlaying: true,
          elapsed: 0,
          shuffleOrder,
        })
      } else {
        state = setPlayback({ isPlaying: true })
      }
      break
    }
    case 'pause': {
      state = setPlayback({ isPlaying: false })
      break
    }
    case 'next': {
      if (!state.currentPlaylistId) break
      const playlist = await getPlaylist(state.currentPlaylistId)
      if (!playlist) break
      const total = playlist.songs.length
      if (total === 0) break
      if (state.repeat === 'one') {
        state = setPlayback({ elapsed: 0, isPlaying: true })
      } else {
        let nextIndex = state.currentSongIndex + 1
        if (nextIndex >= total) {
          if (state.repeat === 'all') {
            nextIndex = 0
            if (state.shuffle) {
              setPlayback({ shuffleOrder: generateShuffleOrder(total) })
            }
          } else {
            state = setPlayback({ isPlaying: false, elapsed: 0 })
            break
          }
        }
        state = setPlayback({ currentSongIndex: nextIndex, elapsed: 0, isPlaying: true })
      }
      break
    }
    case 'prev': {
      if (!state.currentPlaylistId) break
      if (state.elapsed > 3) {
        state = setPlayback({ elapsed: 0 })
      } else {
        const prevIndex = Math.max(0, state.currentSongIndex - 1)
        state = setPlayback({ currentSongIndex: prevIndex, elapsed: 0 })
      }
      break
    }
    case 'shuffle': {
      const newShuffle = !state.shuffle
      if (newShuffle && state.currentPlaylistId) {
        const playlist = await getPlaylist(state.currentPlaylistId)
        if (playlist) {
          state = setPlayback({
            shuffle: true,
            shuffleOrder: generateShuffleOrder(playlist.songs.length),
          })
        }
      } else {
        state = setPlayback({ shuffle: false, shuffleOrder: [] })
      }
      break
    }
    case 'repeat': {
      const modes: RepeatMode[] = ['off', 'all', 'one']
      const currentIdx = modes.indexOf(state.repeat)
      const nextMode = modes[(currentIdx + 1) % modes.length]
      state = setPlayback({ repeat: nextMode })
      break
    }
    case 'seek': {
      if (typeof cmd.seekTo === 'number') {
        state = setPlayback({ elapsed: Math.max(0, cmd.seekTo) })
      }
      break
    }
  }

  return getNowPlaying()
}

