  const currentRealIndex =
    playback.shuffle && playback.shuffleOrder.length > 0
      ? playback.shuffleOrder[playback.currentSongIndex % playback.shuffleOrder.length]
      : playback.currentSongIndex
  const progressPct =
    nowPlayingSong && nowPlayingSong.duration > 0
      ? Math.min(100, (playback.elapsed / nowPlayingSong.duration) * 100)
      : 0

  return `<!DOCTYPE html>
