          <input type="text" name="artist" placeholder="Artist" style="${s(styles.input)}" required>
          <input type="text" name="album" placeholder="Album" style="${s(styles.input)}">
          <input type="number" name="duration" placeholder="Sec" style="${s(styles.input)}" required min="1">
          <input type="url" name="albumArtUrl" placeholder="Album art URL" style="${s(styles.input)}">
