            <span></span>
            <span></span>
            <span>TITLE</span>
            <span>ALBUM</span>
            <span style="text-align: right">TIME</span>
            <span></span>
          </div>
          ${activePlaylist.songs
            .map((song, i) => {
              const isPlaying =
                playback.currentPlaylistId === activePlaylist.id && currentRealIndex === i
              return renderSongRow(song, i, activePlaylist.id, isPlaying)
