        <div style="${s(styles.nowPlayingArtist)}">${nowPlayingSong.artist}</div>
      </div>
    `
        : `
      <div style="${s({ ...styles.nowPlayingArt, display: 'flex', alignItems: 'center', justifyContent: 'center', color: '#666', fontSize: '24px' })}">&#9835;</div>
      <div style="${s(styles.nowPlayingInfo)}">
        <div style="${s({ ...styles.nowPlayingTitle, color: '#666' })}">Not playing</div>
      </div>
    `
    }
  </div>

  <div style="${s(styles.controls)}">
    <div style="${s(styles.controlButtons)}">
      <button style="${s(playback.shuffle ? { ...styles.controlBtn, ...styles.controlBtnActive } : styles.controlBtn)}"
        onclick="playbackAction('shuffle')" title="Shuffle${playback.shuffle ? ' (on)' : ''}">
        &#8645;
      </button>
