      <span style="${s(styles.progressTime)}">${formatDuration(playback.elapsed)}</span>
      <div class="progress-bar" style="${s(styles.progressBar)}" onclick="seekProgress(event, ${nowPlayingSong?.duration ?? 0})">
        <div class="progress-fill" style="${s({ ...styles.progressFill, width: `${progressPct}%` })}"></div>
      </div>
      <span style="${s(styles.progressTime)}">${nowPlayingSong ? formatDuration(nowPlayingSong.duration) : '0:00'}</span>
    </div>
  </div>

  <div style="${s(styles.volumeArea)}">
    <span style="color: #888; font-size: 12px;">
      ${playback.shuffle ? 'Shuffle ' : ''}${playback.repeat !== 'off' ? `Repeat: ${playback.repeat}` : ''}
    </span>
  </div>
</div>

<!-- Placeholder audio element -->
<audio id="audio-placeholder" preload="none"></audio>

<script>
  let dragSourceIndex = null;

  const handleDragStart = (e) => {
    dragSourceIndex = parseInt(e.currentTarget.dataset.index);
    e.dataTransfer.effectAllowed = 'move';
    e.dataTransfer.setData('text/plain', e.currentTarget.dataset.songId);
    e.currentTarget.style.opacity = '0.5';
  };

  const handleDragOver = (e) => {
    e.preventDefault();
    e.dataTransfer.dropEffect = 'move';
    document.querySelectorAll('.song-row').forEach(el => el.classList.remove('drag-over'));
    e.currentTarget.classList.add('drag-over');
  };

  const handleDrop = async (e, playlistId) => {
    e.preventDefault();
    document.querySelectorAll('.song-row').forEach(el => {
      el.classList.remove('drag-over');
      el.style.opacity = '1';
    });
    const targetIndex = parseInt(e.currentTarget.dataset.index);
    if (dragSourceIndex === null || dragSourceIndex === targetIndex) return;

    const rows = [...document.querySelectorAll('.song-row')];
    const songIds = rows.map(r => r.dataset.songId);
    const [moved] = songIds.splice(dragSourceIndex, 1);
    songIds.splice(targetIndex, 0, moved);

    const res = await fetch('/api/playlists/' + playlistId + '/reorder', {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ songIds })
    });
    if (res.ok) location.reload();
  };

  const selectPlaylist = (id) => {
    const url = new URL(window.location);
    url.searchParams.set('playlist', id);
    window.location = url;
  };

  const createPlaylist = async (e) => {
    e.preventDefault();
    const name = document.getElementById('new-playlist-name').value.trim();
    if (!name) return;
    const res = await fetch('/api/playlists', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ name })
    });
    if (res.ok) {
      const playlist = await res.json();
      selectPlaylist(playlist.id);
    }
  };

  const deletePlaylist = async (id) => {
    if (!confirm('Delete this playlist?')) return;
    await fetch('/api/playlists/' + id, { method: 'DELETE' });
    window.location = '/';
  };

  const addSong = async (e, playlistId) => {
    e.preventDefault();
    const form = e.target;
    const data = {
      title: form.title.value,
      artist: form.artist.value,
      album: form.album.value || 'Unknown',
      duration: parseInt(form.duration.value),
      albumArtUrl: form.albumArtUrl.value || ''
    };
    const res = await fetch('/api/playlists/' + playlistId + '/songs', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data)
    });
    if (res.ok) location.reload();
  };

  const removeSong = async (playlistId, songId) => {
    await fetch('/api/playlists/' + playlistId + '/songs/' + songId, { method: 'DELETE' });
    location.reload();
  };

  const playAll = (playlistId) => {
    fetch('/api/playback/action', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ action: 'play', playlistId, songIndex: 0 })
    }).then(() => location.reload());
  };

  const playbackAction = (action) => {
    fetch('/api/playback/action', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ action })
    }).then(() => location.reload());
  };

  const seekProgress = (e, duration) => {
    if (!duration) return;
    const rect = e.currentTarget.getBoundingClientRect();
    const pct = (e.clientX - rect.left) / rect.width;
    const seekTo = Math.round(pct * duration);
    fetch('/api/playback/action', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ action: 'seek', seekTo })
    }).then(() => location.reload());
  };

  // Simulated playback timer
  ${
    playback.isPlaying && nowPlayingSong
      ? `
  let elapsed = ${playback.elapsed};
  const duration = ${nowPlayingSong.duration};
  const timerEl = document.querySelector('.progress-bar')?.previousElementSibling;
  const fillEl = document.querySelector('.progress-fill');
  setInterval(() => {
    elapsed++;
    if (elapsed >= duration) {
      playbackAction('next');
      return;
    }
    if (timerEl) timerEl.textContent = Math.floor(elapsed/60) + ':' + String(Math.floor(elapsed%60)).padStart(2,'0');
    if (fillEl) fillEl.style.width = (elapsed/duration*100) + '%';
    fetch('/api/playback/action', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ action: 'seek', seekTo: elapsed })
    });
  }, 1000);
  `
      : ''
  }
</script>
</body>
</html>`
}

import { getAllPlaylists, createPlaylist, deletePlaylist, addSong, removeSong, reorderSongs } from './playlist'
import { getNowPlaying, executePlayback } from './playback'
import { renderPage } from './render'

const json = (data: unknown, status = 200) =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

const html = (content: string) =>
  new Response(content, {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })

export const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url)
  const path = url.pathname
  const method = req.method

  // Serve the main page
  if (path === '/' && method === 'GET') {
    const playlists = await getAllPlaylists()
    const activePlaylistId = url.searchParams.get('playlist')
    const { song, playback } = await getNowPlaying()
    return html(renderPage(playlists, activePlaylistId, song, playback))
  }

  // List playlists
  if (path === '/api/playlists' && method === 'GET') {
    const playlists = await getAllPlaylists()
    return json(playlists)
  }

  // Create playlist
  if (path === '/api/playlists' && method === 'POST') {
    const body = await req.json()
    const name = body.name?.trim()
    if (!name) return json({ error: 'Name is required' }, 400)
    const playlist = await createPlaylist(name)
    return json(playlist, 201)
  }

  // Delete playlist
  const deleteMatch = path.match(/^\/api\/playlists\/([^/]+)$/)
  if (deleteMatch && method === 'DELETE') {
    const ok = await deletePlaylist(deleteMatch[1])
    return ok ? json({ ok: true }) : json({ error: 'Not found' }, 404)
  }

  // Add song to playlist
  const addSongMatch = path.match(/^\/api\/playlists\/([^/]+)\/songs$/)
  if (addSongMatch && method === 'POST') {
    const body = await req.json()
    const { title, artist, album, duration, albumArtUrl } = body
    if (!title || !artist || !duration) {
      return json({ error: 'title, artist, and duration are required' }, 400)
    }
    const song = await addSong(addSongMatch[1], {
      title,
      artist,
      album: album || 'Unknown',
      duration: Number(duration),
      albumArtUrl: albumArtUrl || '',
    })
    return song ? json(song, 201) : json({ error: 'Playlist not found' }, 404)
  }

  // Remove song from playlist
  const removeSongMatch = path.match(/^\/api\/playlists\/([^/]+)\/songs\/([^/]+)$/)
  if (removeSongMatch && method === 'DELETE') {
    const ok = await removeSong(removeSongMatch[1], removeSongMatch[2])
    return ok ? json({ ok: true }) : json({ error: 'Not found' }, 404)
  }

  // Reorder songs
  const reorderMatch = path.match(/^\/api\/playlists\/([^/]+)\/reorder$/)
  if (reorderMatch && method === 'PUT') {
    const body = await req.json()
    const ok = await reorderSongs(reorderMatch[1], body.songIds)
    return ok ? json({ ok: true }) : json({ error: 'Reorder failed' }, 400)
  }

  // Get playback state
  if (path === '/api/playback' && method === 'GET') {
    const state = await getNowPlaying()
    return json(state)
  }

  // Playback action
  if (path === '/api/playback/action' && method === 'POST') {
    const body = await req.json()
    const result = await executePlayback(body)
    return json(result)
  }

  return json({ error: 'Not found' }, 404)
}

{
  "name": "@node/playlist-manager",
  "version": "1.0.0",
  "description": "Music playlist manager with playback controls, shuffle, repeat, and drag-to-reorder",
  "modnet": {
    "contentType": "entertainment",
    "structure": "list",
    "mechanics": ["sort", "track"],
    "boundary": "none",
    "scale": 2
  },
  "dependencies": {
    "plaited": "latest"
  }
}

import type { Playlist, Song, AppState, PlayerState, AddSongPayload, ReorderPayload, RepeatMode } from './types'

const DATA_PATH = `${import.meta.dir}/data/playlists.json`

const defaultPlayerState: PlayerState = {
  currentPlaylistId: null,
  currentSongIndex: 0,
  isPlaying: false,
  elapsedMs: 0,
  shuffleEnabled: false,
  repeatMode: 'off',
  shuffleQueue: [],
  shuffleIndex: 0,
}

const generateId = (prefix: string): string =>
  `${prefix}-${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 7)}`

const loadPlaylists = async (): Promise<Playlist[]> => {
  const file = Bun.file(DATA_PATH)
  if (await file.exists()) {
    return file.json()
  }
  return []
}

const savePlaylists = async (playlists: Playlist[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(playlists, null, 2))
}

const buildShuffleQueue = (length: number, currentIndex: number): number[] => {
  const indices = Array.from({ length }, (_, i) => i).filter((i) => i !== currentIndex)
  for (let i = indices.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1))
    ;[indices[i], indices[j]] = [indices[j], indices[i]]
  }
  return [currentIndex, ...indices]
}

export const createStore = async (): Promise<{
  getState: () => AppState
  createPlaylist: (name: string) => Promise<Playlist>
  deletePlaylist: (id: string) => Promise<void>
  renamePlaylist: (id: string, name: string) => Promise<void>
  addSong: (payload: AddSongPayload) => Promise<Song>
  removeSong: (playlistId: string, songId: string) => Promise<void>
  reorderSong: (payload: ReorderPayload) => Promise<void>
  setActivePlaylist: (id: string) => void
  play: (playlistId?: string, songIndex?: number) => void
  pause: () => void
  resume: () => void
  skipNext: () => void
  skipPrev: () => void
  seek: (ms: number) => void
  toggleShuffle: () => void
  cycleRepeat: () => void
  tick: (deltaMs: number) => void
}> => {
  const playlists = await loadPlaylists()

  const state: AppState = {
    playlists,
    player: { ...defaultPlayerState },
    activePlaylistId: playlists[0]?.id ?? null,
  }

  const getActivePlaylist = (): Playlist | undefined =>
    state.playlists.find((p) => p.id === state.player.currentPlaylistId)

  const getCurrentSong = (): Song | undefined => {
    const pl = getActivePlaylist()
    if (!pl) return undefined
    const idx = state.player.shuffleEnabled
      ? state.player.shuffleQueue[state.player.shuffleIndex]
      : state.player.currentSongIndex
    return pl.songs[idx]
  }

  const getState = (): AppState => state

  const createPlaylist = async (name: string): Promise<Playlist> => {
    const now = new Date().toISOString()
    const playlist: Playlist = {
      id: generateId('pl'),
      name,
      songs: [],
      createdAt: now,
      updatedAt: now,
    }
    state.playlists.push(playlist)
    await savePlaylists(state.playlists)
    return playlist
  }

  const deletePlaylist = async (id: string): Promise<void> => {
    state.playlists = state.playlists.filter((p) => p.id !== id)
    if (state.player.currentPlaylistId === id) {
      state.player = { ...defaultPlayerState }
    }
    if (state.activePlaylistId === id) {
      state.activePlaylistId = state.playlists[0]?.id ?? null
    }
    await savePlaylists(state.playlists)
  }

  const renamePlaylist = async (id: string, name: string): Promise<void> => {
    const pl = state.playlists.find((p) => p.id === id)
    if (pl) {
      pl.name = name
      pl.updatedAt = new Date().toISOString()
      await savePlaylists(state.playlists)
    }
  }

  const addSong = async (payload: AddSongPayload): Promise<Song> => {
    const pl = state.playlists.find((p) => p.id === payload.playlistId)
    if (!pl) throw new Error(`Playlist ${payload.playlistId} not found`)
    const song: Song = {
      id: generateId('s'),
      title: payload.title,
      artist: payload.artist,
      album: payload.album,
      durationMs: payload.durationMs,
      albumArtUrl: payload.albumArtUrl,
    }
    pl.songs.push(song)
    pl.updatedAt = new Date().toISOString()
    await savePlaylists(state.playlists)
    return song
  }

  const removeSong = async (playlistId: string, songId: string): Promise<void> => {
    const pl = state.playlists.find((p) => p.id === playlistId)
    if (!pl) return
    pl.songs = pl.songs.filter((s) => s.id !== songId)
    pl.updatedAt = new Date().toISOString()
    await savePlaylists(state.playlists)
  }

  const reorderSong = async (payload: ReorderPayload): Promise<void> => {
    const pl = state.playlists.find((p) => p.id === payload.playlistId)
    if (!pl) return
    const { fromIndex, toIndex } = payload
    if (fromIndex < 0 || fromIndex >= pl.songs.length) return
    if (toIndex < 0 || toIndex >= pl.songs.length) return
    const [song] = pl.songs.splice(fromIndex, 1)
    pl.songs.splice(toIndex, 0, song)
    pl.updatedAt = new Date().toISOString()
    await savePlaylists(state.playlists)
  }

  const setActivePlaylist = (id: string): void => {
    state.activePlaylistId = id
  }

  const play = (playlistId?: string, songIndex?: number): void => {
    const plId = playlistId ?? state.activePlaylistId
    if (!plId) return
    const pl = state.playlists.find((p) => p.id === plId)
    if (!pl || pl.songs.length === 0) return

    state.player.currentPlaylistId = plId
    state.player.currentSongIndex = songIndex ?? 0
    state.player.isPlaying = true
    state.player.elapsedMs = 0

    if (state.player.shuffleEnabled) {
      state.player.shuffleQueue = buildShuffleQueue(pl.songs.length, state.player.currentSongIndex)
      state.player.shuffleIndex = 0
    }
  }

  const pause = (): void => {
    state.player.isPlaying = false
  }

  const resume = (): void => {
    if (state.player.currentPlaylistId) {
      state.player.isPlaying = true
    }
  }

  const advanceTrack = (direction: 1 | -1): void => {
    const pl = getActivePlaylist()
    if (!pl || pl.songs.length === 0) return

    if (state.player.shuffleEnabled) {
      const nextShuffleIdx = state.player.shuffleIndex + direction
      if (nextShuffleIdx < 0) {
        state.player.shuffleIndex = 0
      } else if (nextShuffleIdx >= state.player.shuffleQueue.length) {
        if (state.player.repeatMode === 'all') {
          state.player.shuffleQueue = buildShuffleQueue(pl.songs.length, state.player.shuffleQueue[0])
          state.player.shuffleIndex = 0
        } else {
          state.player.isPlaying = false
          state.player.shuffleIndex = state.player.shuffleQueue.length - 1
          return
        }
      } else {
        state.player.shuffleIndex = nextShuffleIdx
      }
      state.player.currentSongIndex = state.player.shuffleQueue[state.player.shuffleIndex]
    } else {
      const nextIdx = state.player.currentSongIndex + direction
      if (nextIdx < 0) {
        state.player.currentSongIndex = 0
      } else if (nextIdx >= pl.songs.length) {
        if (state.player.repeatMode === 'all') {
          state.player.currentSongIndex = 0
        } else {
          state.player.isPlaying = false
          return
        }
      } else {
        state.player.currentSongIndex = nextIdx
      }
    }
    state.player.elapsedMs = 0
  }

  const skipNext = (): void => {
    if (state.player.repeatMode === 'one') {
      state.player.elapsedMs = 0
      return
    }
    advanceTrack(1)
  }

  const skipPrev = (): void => {
    if (state.player.elapsedMs > 3000) {
      state.player.elapsedMs = 0
      return
    }
    advanceTrack(-1)
  }

  const seek = (ms: number): void => {
    const song = getCurrentSong()
    if (!song) return
    state.player.elapsedMs = Math.max(0, Math.min(ms, song.durationMs))
  }

  const toggleShuffle = (): void => {
    state.player.shuffleEnabled = !state.player.shuffleEnabled
    if (state.player.shuffleEnabled) {
      const pl = getActivePlaylist()
      if (pl) {
        state.player.shuffleQueue = buildShuffleQueue(pl.songs.length, state.player.currentSongIndex)
        state.player.shuffleIndex = 0
      }
    }
  }

  const cycleRepeat = (): void => {
    const modes: RepeatMode[] = ['off', 'all', 'one']
    const idx = modes.indexOf(state.player.repeatMode)
    state.player.repeatMode = modes[(idx + 1) % modes.length]
  }

  const tick = (deltaMs: number): void => {
    if (!state.player.isPlaying) return
    const song = getCurrentSong()
    if (!song) return

    state.player.elapsedMs += deltaMs
    if (state.player.elapsedMs >= song.durationMs) {
      if (state.player.repeatMode === 'one') {
        state.player.elapsedMs = 0
      } else {
        advanceTrack(1)
      }
    }
  }

  return {
    getState,
    createPlaylist,
    deletePlaylist,
    renamePlaylist,
    addSong,
    removeSong,
    reorderSong,
    setActivePlaylist,
    play,
    pause,
    resume,
    skipNext,
    skipPrev,
    seek,
    toggleShuffle,
    cycleRepeat,
    tick,
  }
}

import { createSSR } from 'plaited'
import { createStore } from './store'
import { renderApp } from './render'
import type { AddSongPayload, ReorderPayload } from './types'

const store = await createStore()

const parseDuration = (input: string): number => {
  const [mins, secs] = input.split(':').map(Number)
  return (mins * 60 + secs) * 1000
}

const TICK_INTERVAL_MS = 1000
let tickTimer: ReturnType<typeof setInterval> | null = null

const startTick = (): void => {
  if (tickTimer) return
  tickTimer = setInterval(() => {
    store.tick(TICK_INTERVAL_MS)
  }, TICK_INTERVAL_MS)
}

const stopTick = (): void => {
  if (tickTimer) {
    clearInterval(tickTimer)
    tickTimer = null
  }
}

export const handleEvent = async (
  eventType: string,
  payload: Record<string, string>,
): Promise<string> => {
  switch (eventType) {
    case 'playlist-select': {
      store.setActivePlaylist(payload.playlistId)
      break
    }
    case 'playlist-create': {
      const name = payload.name || `Playlist ${store.getState().playlists.length + 1}`
      await store.createPlaylist(name)
      break
    }
    case 'playlist-delete': {
      await store.deletePlaylist(payload.playlistId)
      break
    }
    case 'song-add': {
      const addPayload: AddSongPayload = {
        playlistId: store.getState().activePlaylistId ?? '',
        title: payload.title,
        artist: payload.artist,
        album: payload.album || 'Unknown Album',
        durationMs: parseDuration(payload.duration || '3:30'),
        albumArtUrl: payload.albumArtUrl || `https://picsum.photos/seed/${encodeURIComponent(payload.title)}/300/300`,
      }
      await store.addSong(addPayload)
      break
    }
    case 'song-remove': {
      await store.removeSong(payload.playlistId, payload.songId)
      break
    }
    case 'song-drag-start': {
      // Drag state managed client-side; store fromIndex in payload
      break
    }
    case 'song-drag-over': {
      // Prevent default handled client-side
      break
    }
    case 'song-drop': {
      const reorder: ReorderPayload = {
        playlistId: payload.playlistId,
        fromIndex: parseInt(payload.fromIndex, 10),
        toIndex: parseInt(payload.toIndex, 10),
      }
      await store.reorderSong(reorder)
      break
    }
    case 'song-play': {
      const pl = store.getState().activePlaylistId
      if (pl) {
        store.play(pl, parseInt(payload.index ?? '0', 10))
        startTick()
      }
      break
    }
    case 'player-play-pause': {
      const { player } = store.getState()
      if (player.isPlaying) {
        store.pause()
        stopTick()
      } else if (player.currentPlaylistId) {
        store.resume()
        startTick()
      } else {
        const activeId = store.getState().activePlaylistId
        if (activeId) {
          store.play(activeId, 0)
          startTick()
        }
      }
      break
    }
    case 'player-next': {
      store.skipNext()
      break
    }
    case 'player-prev': {
      store.skipPrev()
      break
    }
    case 'player-seek': {
      const { player, playlists } = store.getState()
      const pl = playlists.find((p) => p.id === player.currentPlaylistId)
      const idx = player.shuffleEnabled
        ? player.shuffleQueue[player.shuffleIndex]
        : player.currentSongIndex
      const song = pl?.songs[idx]
      if (song && payload.percent) {
        const seekMs = (parseFloat(payload.percent) / 100) * song.durationMs
        store.seek(seekMs)
      }
      break
    }
    case 'player-shuffle': {
      store.toggleShuffle()
      break
    }
    case 'player-repeat': {
      store.cycleRepeat()
      break
    }
  }

  return render()
}

export const render = (): string => {
  const state = store.getState()
  const vdom = renderApp(state)
  const ssr = createSSR()
  return ssr(vdom)
}

export const getState = () => store.getState()

// Client-side drag-and-drop support script
export const clientScript = `
<script>
  let dragFromIndex = null;

  document.addEventListener('dragstart', (e) => {
    const row = e.target.closest('[data-index]');
    if (row) {
      dragFromIndex = row.dataset.index;
      e.dataTransfer.effectAllowed = 'move';
      row.style.opacity = '0.5';
    }
  });

  document.addEventListener('dragover', (e) => {
    const row = e.target.closest('[data-index]');
    if (row) {
      e.preventDefault();
      e.dataTransfer.dropEffect = 'move';
    }
  });

  document.addEventListener('dragend', (e) => {
    const row = e.target.closest('[data-index]');
    if (row) row.style.opacity = '1';
  });

  document.addEventListener('drop', (e) => {
    e.preventDefault();
    const row = e.target.closest('[data-index]');
    if (row && dragFromIndex !== null) {
      const toIndex = row.dataset.index;
      const playlistId = row.dataset.playlistId;
      fetch('/event', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          eventType: 'song-drop',
          payload: { playlistId, fromIndex: dragFromIndex, toIndex }
        })
      }).then(r => r.text()).then(html => {
        document.querySelector('[p-target="app-root"]').outerHTML = html;
      });
      dragFromIndex = null;
    }
  });

  // Progress bar seek
  document.addEventListener('click', (e) => {
    const bar = e.target.closest('[p-target="progress-bar"]');
    if (bar) {
      const rect = bar.getBoundingClientRect();
      const percent = ((e.clientX - rect.left) / rect.width) * 100;
      fetch('/event', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          eventType: 'player-seek',
          payload: { percent: String(percent) }
        })
      });
    }
  });

  // Auto-refresh now playing every second when playing
  setInterval(() => {
    fetch('/state').then(r => r.json()).then(state => {
      if (state.player.isPlaying) {
        fetch('/render').then(r => r.text()).then(html => {
          const parser = new DOMParser();
          const doc = parser.parseFromString(html, 'text/html');
          const newBar = doc.querySelector('[style*="position: fixed"]');
          const oldBar = document.querySelector('[style*="position: fixed"]');
          if (newBar && oldBar) oldBar.outerHTML = newBar.outerHTML;
        });
      }
    });
  }, 1000);
</script>
`

