import type {
  PendulumParams,
  PendulumState,
  ProjectileParams,
  ProjectileState,
  SpringParams,
  SpringState,
  Vec2,
} from './types'

const DT = 1 / 60

export const createPendulumState = (params: PendulumParams): PendulumState => {
  const { length, initialAngle } = params
  return {
    angle: initialAngle,
    angularVelocity: 0,
    angularAcceleration: -(params.gravity / length) * Math.sin(initialAngle),
    position: {
      x: length * Math.sin(initialAngle),
      y: -length * Math.cos(initialAngle),
    },
  }
}

export const stepPendulum = (
  state: PendulumState,
  params: PendulumParams,
  speed: number,
): PendulumState => {
  const dt = DT * speed
  const { length, gravity, damping } = params

  const angularAcceleration =
    -(gravity / length) * Math.sin(state.angle) - damping * state.angularVelocity

  const angularVelocity = state.angularVelocity + angularAcceleration * dt
  const angle = state.angle + angularVelocity * dt

  const position: Vec2 = {
    x: length * Math.sin(angle),
    y: -length * Math.cos(angle),
  }

  return { angle, angularVelocity, angularAcceleration, position }
}

export const createProjectileState = (params: ProjectileParams): ProjectileState => {
  const angleRad = (params.angle * Math.PI) / 180
  return {
    position: { x: 0, y: 0 },
    velocity: {
      x: params.initialVelocity * Math.cos(angleRad),
      y: params.initialVelocity * Math.sin(angleRad),
    },
    acceleration: { x: 0, y: -params.gravity },
    trajectory: [{ x: 0, y: 0 }],
    landed: false,
  }
}

export const stepProjectile = (
  state: ProjectileState,
  params: ProjectileParams,
  speed: number,
): ProjectileState => {
  if (state.landed) return state

  const dt = DT * speed
  const { gravity } = params

  const velocity: Vec2 = {
    x: state.velocity.x,
    y: state.velocity.y - gravity * dt,
  }

  const position: Vec2 = {
    x: state.position.x + velocity.x * dt,
    y: state.position.y + velocity.y * dt,
  }

  const landed = position.y <= 0 && state.position.y > 0

  if (landed) {
    const tGround = state.position.y / (state.position.y - position.y)
    position.x = state.position.x + velocity.x * dt * tGround
    position.y = 0
  }

  const trajectory = [...state.trajectory, { x: position.x, y: position.y }]

  return {
    position,
    velocity: landed ? { x: 0, y: 0 } : velocity,
    acceleration: { x: 0, y: landed ? 0 : -gravity },
    trajectory,
    landed,
  }
}

export const createSpringState = (params: SpringParams): SpringState => {
  const { springConstant, mass, initialDisplacement } = params
  return {
    displacement: initialDisplacement,
    velocity: 0,
    acceleration: -(springConstant / mass) * initialDisplacement,
  }
}

export const stepSpring = (
  state: SpringState,
  params: SpringParams,
  speed: number,
): SpringState => {
  const dt = DT * speed
  const { springConstant, mass, damping } = params

  const acceleration =
    -(springConstant / mass) * state.displacement - (damping / mass) * state.velocity

  const velocity = state.velocity + acceleration * dt
  const displacement = state.displacement + velocity * dt

  return { displacement, velocity, acceleration }
}

