    h('rect', { width: String(w), height: String(hh), fill: 'url(#grid)' }),
    // Pivot mount
    h('rect', { x: String(pivotX - 30), y: '0', width: '60', height: '12', rx: '2', fill: colors.pivot }),
    // String
    h('line', {
      x1: String(pivotX),
      y1: String(pivotY),
      x2: String(bobX),
      y2: String(bobY),
      stroke: colors.text,
      'stroke-width': '2',
      'stroke-dasharray': '4,3',
    }),
    // Pivot point
    h('circle', { cx: String(pivotX), cy: String(pivotY), r: '5', fill: colors.pivot }),
    // Arc showing angle
    h('path', {
      d: `M ${pivotX} ${pivotY + 40} A 40 40 0 0 ${state.angle >= 0 ? 1 : 0} ${pivotX + 40 * Math.sin(state.angle)} ${pivotY + 40 * Math.cos(state.angle)}`,
      fill: 'none',
      stroke: colors.accent,
      'stroke-width': '1.5',
      opacity: '0.6',
