      fill: colors.accent,
      'font-size': '13',
      'font-family': "'JetBrains Mono', monospace",
    }, `${((state.angle * 180) / Math.PI).toFixed(1)}°`),
  )
}

const renderProjectileCanvas = (state: ProjectileState, _params: ProjectileParams) => {
  const w = 750
  const hh = 450
  const margin = 50
  const groundY = hh - margin

  // Compute scale from trajectory bounds
  let maxX = 1
  let maxY = 1
  for (const p of state.trajectory) {
    if (p.x > maxX) maxX = p.x
    if (p.y > maxY) maxY = p.y
  }
  const scaleX = (w - 2 * margin) / (maxX * 1.1 || 1)
  const scaleY = (hh - 2 * margin) / (maxY * 1.1 || 1)
  const scale = Math.min(scaleX, scaleY, 5)

  const toScreen = (p: { x: number; y: number }) => ({
    sx: margin + p.x * scale,
    sy: groundY - p.y * scale,
  })

  const pathPoints = state.trajectory.map((p) => {
    const { sx, sy } = toScreen(p)
    return `${sx},${sy}`
  })

  const currentPos = toScreen(state.position)

  // Axis ticks
  const xTicks: number[] = []
  const xStep = Math.pow(10, Math.floor(Math.log10(maxX || 1)))
  for (let v = 0; v <= maxX * 1.1; v += xStep) xTicks.push(v)

  const yTicks: number[] = []
  const yStep = Math.pow(10, Math.floor(Math.log10(maxY || 1)))
  for (let v = 0; v <= maxY * 1.1; v += yStep) yTicks.push(v)

  return h('svg', {
    viewBox: `0 0 ${w} ${hh}`,
    style: styleToStr(baseStyles.svg),
    xmlns: 'http://www.w3.org/2000/svg',
  },
    // Grid
    h('defs', {},
      h('pattern', { id: 'pgrid', width: '50', height: '50', patternUnits: 'userSpaceOnUse' },
        h('path', { d: 'M 50 0 L 0 0 0 50', fill: 'none', stroke: colors.border, 'stroke-width': '0.5' }),
      ),
    ),
    h('rect', { width: String(w), height: String(hh), fill: 'url(#pgrid)' }),
    // Ground
    h('line', {
      x1: String(margin),
      y1: String(groundY),
      x2: String(w - margin),
      y2: String(groundY),
      stroke: colors.success,
      'stroke-width': '2',
    }),
    // Ground hatching
    ...Array.from({ length: 20 }, (_, i) =>
      h('line', {
        x1: String(margin + i * 35),
        y1: String(groundY),
        x2: String(margin + i * 35 - 10),
        y2: String(groundY + 10),
        stroke: colors.success,
        'stroke-width': '1',
        opacity: '0.5',
      }),
    ),
    // Y axis
    h('line', {
      x1: String(margin),
      y1: String(margin),
      x2: String(margin),
      y2: String(groundY),
      stroke: colors.muted,
      'stroke-width': '1',
    }),
    // Axis labels
    ...xTicks.slice(1, 6).map((v) => {
      const { sx } = toScreen({ x: v, y: 0 })
      return h('text', {
        x: String(sx),
        y: String(groundY + 20),
        fill: colors.muted,
        'font-size': '10',
        'text-anchor': 'middle',
        'font-family': "'JetBrains Mono', monospace",
      }, `${v.toFixed(0)}m`)
    }),
    ...yTicks.slice(1, 6).map((v) => {
      const { sy } = toScreen({ x: 0, y: v })
      return h('text', {
        x: String(margin - 8),
        y: String(sy + 4),
        fill: colors.muted,
        'font-size': '10',
        'text-anchor': 'end',
        'font-family': "'JetBrains Mono', monospace",
      }, `${v.toFixed(0)}m`)
    }),
    // Trajectory path
    pathPoints.length > 1
      ? h('polyline', {
          points: pathPoints.join(' '),
          fill: 'none',
          stroke: colors.trajectory,
          'stroke-width': '2.5',
          'stroke-linecap': 'round',
          'stroke-linejoin': 'round',
          opacity: '0.8',
        })
      : null,
    // Trajectory dots
    ...state.trajectory
      .filter((_, i) => i % 4 === 0)
      .map((p) => {
        const { sx, sy } = toScreen(p)
        return h('circle', {
          cx: String(sx),
          cy: String(sy),
          r: '2',
          fill: colors.trajectory,
          opacity: '0.5',
        })
      }),
    // Velocity vector at current position
    !state.landed
      ? h('line', {
          x1: String(currentPos.sx),
          y1: String(currentPos.sy),
          x2: String(currentPos.sx + state.velocity.x * 0.8),
          y2: String(currentPos.sy - state.velocity.y * 0.8),
          stroke: colors.accent,
          'stroke-width': '2',
          'marker-end': 'url(#arrowhead)',
        })
      : null,
    // Arrowhead definition
    h('defs', {},
      h('marker', {
        id: 'arrowhead',
        markerWidth: '8',
        markerHeight: '6',
        refX: '8',
        refY: '3',
        orient: 'auto',
      },
        h('polygon', { points: '0 0, 8 3, 0 6', fill: colors.accent }),
      ),
    ),
    // Projectile
    h('circle', {
      cx: String(currentPos.sx),
      cy: String(currentPos.sy),
      r: '8',
      fill: colors.mass,
      stroke: colors.trajectory,
      'stroke-width': '2',
    }),
    // Launch point
    h('circle', {
      cx: String(margin),
      cy: String(groundY),
      r: '5',
      fill: colors.success,
    }),
  )
}

const renderSpringCanvas = (state: SpringState, params: SpringParams) => {
  const w = 750
  const hh = 450
  const centerX = w / 2
  const centerY = hh / 2
  const equilibX = centerX
  const wallX = 80
  const scale = 100
  const massX = equilibX + state.displacement * scale
  const massSize = 36

  // Generate spring coils between wall and mass
  const springStartX = wallX + 10
  const springEndX = massX - massSize / 2
  const numCoils = 12
  const coilAmplitude = 18
  const springLen = springEndX - springStartX
  const coilWidth = springLen / numCoils

  const springPoints: string[] = [`${springStartX},${centerY}`]
  for (let i = 0; i < numCoils; i++) {
    const x1 = springStartX + (i + 0.25) * coilWidth
    const x2 = springStartX + (i + 0.75) * coilWidth
    const dir = i % 2 === 0 ? -1 : 1
    springPoints.push(`${x1},${centerY + dir * coilAmplitude}`)
    springPoints.push(`${x2},${centerY - dir * coilAmplitude}`)
  }
  springPoints.push(`${springEndX},${centerY}`)

  // Equilibrium position marker
  const eqLineY1 = centerY - 60
  const eqLineY2 = centerY + 60

  return h('svg', {
    viewBox: `0 0 ${w} ${hh}`,
    style: styleToStr(baseStyles.svg),
    xmlns: 'http://www.w3.org/2000/svg',
  },
    // Grid
    h('defs', {},
      h('pattern', { id: 'sgrid', width: '50', height: '50', patternUnits: 'userSpaceOnUse' },
        h('path', { d: 'M 50 0 L 0 0 0 50', fill: 'none', stroke: colors.border, 'stroke-width': '0.5' }),
      ),
    ),
    h('rect', { width: String(w), height: String(hh), fill: 'url(#sgrid)' }),
    // Surface/track
    h('line', {
      x1: String(wallX),
      y1: String(centerY + massSize / 2 + 2),
      x2: String(w - 40),
      y2: String(centerY + massSize / 2 + 2),
      stroke: colors.muted,
      'stroke-width': '1.5',
    }),
    // Wall
    h('rect', { x: String(wallX - 8), y: String(centerY - 80), width: '10', height: '160', fill: colors.pivot, rx: '2' }),
    // Wall hatching
    ...Array.from({ length: 8 }, (_, i) =>
      h('line', {
        x1: String(wallX - 8),
        y1: String(centerY - 80 + i * 22),
        x2: String(wallX - 18),
        y2: String(centerY - 80 + i * 22 + 14),
        stroke: colors.muted,
        'stroke-width': '1',
      }),
    ),
    // Spring
    h('polyline', {
      points: springPoints.join(' '),
      fill: 'none',
      stroke: colors.spring,
      'stroke-width': '2.5',
      'stroke-linecap': 'round',
      'stroke-linejoin': 'round',
    }),
    // Equilibrium marker
    h('line', {
      x1: String(equilibX),
      y1: String(eqLineY1),
      x2: String(equilibX),
      y2: String(eqLineY2),
      stroke: colors.accent,
      'stroke-width': '1',
      'stroke-dasharray': '5,4',
      opacity: '0.5',
    }),
    h('text', {
      x: String(equilibX),
      y: String(eqLineY1 - 8),
      fill: colors.accent,
      'font-size': '11',
      'text-anchor': 'middle',
      'font-family': "'JetBrains Mono', monospace",
      opacity: '0.7',
    }, 'x=0'),
    // Displacement arrow
    state.displacement !== 0
      ? h(Fragment, {},
          h('line', {
            x1: String(equilibX),
            y1: String(centerY + massSize / 2 + 20),
            x2: String(massX),
            y2: String(centerY + massSize / 2 + 20),
            stroke: colors.warning,
            'stroke-width': '2',
            'marker-end': 'url(#sarrow)',
          }),
          h('text', {
            x: String((equilibX + massX) / 2),
            y: String(centerY + massSize / 2 + 38),
            fill: colors.warning,
            'font-size': '12',
            'text-anchor': 'middle',
            'font-family': "'JetBrains Mono', monospace",
          }, `x = ${state.displacement.toFixed(2)} m`),
        )
      : null,
    // Arrow marker
    h('defs', {},
      h('marker', {
        id: 'sarrow',
        markerWidth: '8',
        markerHeight: '6',
        refX: '8',
        refY: '3',
        orient: 'auto',
      },
        h('polygon', { points: '0 0, 8 3, 0 6', fill: colors.warning }),
      ),
    ),
    // Mass block
    h('rect', {
      x: String(massX - massSize / 2),
      y: String(centerY - massSize / 2),
      width: String(massSize),
      height: String(massSize),
      rx: '6',
      fill: colors.mass,
      stroke: '#fff',
      'stroke-width': '2',
    }),
    // Mass label
    h('text', {
      x: String(massX),
      y: String(centerY + 5),
      fill: '#fff',
      'font-size': '13',
      'font-weight': 'bold',
      'text-anchor': 'middle',
      'font-family': "'JetBrains Mono', monospace",
    }, `${params.mass}kg`),
    // Force arrow (spring force direction)
    Math.abs(state.displacement) > 0.05
      ? h('line', {
          x1: String(massX),
          y1: String(centerY - massSize / 2 - 15),
          x2: String(massX - state.displacement * 30),
          y2: String(centerY - massSize / 2 - 15),
          stroke: colors.success,
          'stroke-width': '2.5',
          'marker-end': 'url(#farrow)',
        })
      : null,
    h('defs', {},
      h('marker', {
        id: 'farrow',
        markerWidth: '8',
        markerHeight: '6',
        refX: '8',
        refY: '3',
        orient: 'auto',
      },
        h('polygon', { points: '0 0, 8 3, 0 6', fill: colors.success }),
      ),
    ),
    Math.abs(state.displacement) > 0.05
      ? h('text', {
          x: String(massX - state.displacement * 15),
          y: String(centerY - massSize / 2 - 22),
          fill: colors.success,
          'font-size': '11',
          'text-anchor': 'middle',
          'font-family': "'JetBrains Mono', monospace",
        }, 'F')
      : null,
  )
}

