export {
  renderPendulumCanvas,
  renderProjectileCanvas,
  renderSpringCanvas,
}

import { createSSR } from 'plaited'
import type {
  SimulationType,
  PendulumParams,
  PendulumState,
  ProjectileParams,
  ProjectileState,
  SpringParams,
  SpringState,
  SimState,
} from './types'
import {
  createPendulumState,
  stepPendulum,
  createProjectileState,
  stepProjectile,
  createSpringState,
  stepSpring,
} from './physics'
import {
  renderPage,
  renderPendulumCanvas,
  renderProjectileCanvas,
  renderSpringCanvas,
  renderPendulumControls,
  renderProjectileControls,
  renderSpringControls,
  renderPendulumReadout,
  renderProjectileReadout,
  renderSpringReadout,
} from './renderer'

const loadDefaults = async () => {
  const file = Bun.file('./data/defaults.json')
  return await file.json()
}

type AppState = {
  sim: SimState
  activeTab: SimulationType
  pendulumParams: PendulumParams
  pendulumState: PendulumState
  projectileParams: ProjectileParams
  projectileState: ProjectileState
  springParams: SpringParams
  springState: SpringState
}

const createAppState = (defaults: Record<string, unknown>): AppState => {
  const pendulumParams = defaults.pendulum as PendulumParams
  const projectileParams = defaults.projectile as ProjectileParams
  const springParams = defaults.spring as SpringParams

  return {
    sim: { time: 0, running: false, speed: 1 },
    activeTab: 'pendulum',
    pendulumParams,
    pendulumState: createPendulumState(pendulumParams),
    projectileParams,
    projectileState: createProjectileState(projectileParams),
    springParams,
    springState: createSpringState(springParams),
  }
}

const stepSimulation = (state: AppState): AppState => {
  if (!state.sim.running) return state

  const dt = 1 / 60
  const nextTime = state.sim.time + dt * state.sim.speed

  const next = { ...state, sim: { ...state.sim, time: nextTime } }

  switch (state.activeTab) {
    case 'pendulum':
      next.pendulumState = stepPendulum(state.pendulumState, state.pendulumParams, state.sim.speed)
      break
    case 'projectile':
      next.projectileState = stepProjectile(state.projectileState, state.projectileParams, state.sim.speed)
      break
    case 'spring':
      next.springState = stepSpring(state.springState, state.springParams, state.sim.speed)
      break
  }

  return next
}

const renderApp = (state: AppState): string => {
  let canvas
  let controls
  let readout

  switch (state.activeTab) {
    case 'pendulum':
      canvas = renderPendulumCanvas(state.pendulumState, state.pendulumParams)
      controls = renderPendulumControls(state.pendulumParams)
      readout = renderPendulumReadout(state.pendulumState)
      break
    case 'projectile':
      canvas = renderProjectileCanvas(state.projectileState, state.projectileParams)
      controls = renderProjectileControls(state.projectileParams)
      readout = renderProjectileReadout(state.projectileState)
      break
    case 'spring':
      canvas = renderSpringCanvas(state.springState, state.springParams)
      controls = renderSpringControls(state.springParams)
      readout = renderSpringReadout(state.springState)
      break
  }

  const page = renderPage(
    state.activeTab,
    state.sim.running,
    state.sim.speed,
    canvas,
    controls,
    readout,
    state.sim.time,
  )

  const { render } = createSSR()
  return render(page)
}

const handleAction = (state: AppState, action: string, value?: string): AppState => {
  switch (action) {
    case 'toggle-play':
      return { ...state, sim: { ...state.sim, running: !state.sim.running } }

    case 'reset': {
      const next = { ...state }
      next.sim = { ...state.sim, time: 0, running: false }
      next.pendulumState = createPendulumState(state.pendulumParams)
      next.projectileState = createProjectileState(state.projectileParams)
      next.springState = createSpringState(state.springParams)
      return next
    }

    case 'speed-change':
      return { ...state, sim: { ...state.sim, speed: parseFloat(value ?? '1') } }

    case 'tab-pendulum':
      return { ...state, activeTab: 'pendulum' }
    case 'tab-projectile':
      return { ...state, activeTab: 'projectile' }
    case 'tab-spring':
      return { ...state, activeTab: 'spring' }

    // Pendulum params
    case 'pendulum-length-change': {
      const params = { ...state.pendulumParams, length: parseFloat(value ?? '2') }
      return { ...state, pendulumParams: params, pendulumState: createPendulumState(params), sim: { ...state.sim, time: 0, running: false } }
    }
    case 'pendulum-gravity-change': {
      const params = { ...state.pendulumParams, gravity: parseFloat(value ?? '9.81') }
      return { ...state, pendulumParams: params, pendulumState: createPendulumState(params), sim: { ...state.sim, time: 0, running: false } }
    }
    case 'pendulum-angle-change': {
      const angleDeg = parseFloat(value ?? '45')
      const params = { ...state.pendulumParams, initialAngle: (angleDeg * Math.PI) / 180 }
      return { ...state, pendulumParams: params, pendulumState: createPendulumState(params), sim: { ...state.sim, time: 0, running: false } }
    }

    // Projectile params
    case 'projectile-angle-change': {
      const params = { ...state.projectileParams, angle: parseFloat(value ?? '45') }
      return { ...state, projectileParams: params, projectileState: createProjectileState(params), sim: { ...state.sim, time: 0, running: false } }
    }
    case 'projectile-velocity-change': {
      const params = { ...state.projectileParams, initialVelocity: parseFloat(value ?? '30') }
      return { ...state, projectileParams: params, projectileState: createProjectileState(params), sim: { ...state.sim, time: 0, running: false } }
    }
    case 'projectile-gravity-change': {
      const params = { ...state.projectileParams, gravity: parseFloat(value ?? '9.81') }
      return { ...state, projectileParams: params, projectileState: createProjectileState(params), sim: { ...state.sim, time: 0, running: false } }
    }

    // Spring params
    case 'spring-constant-change': {
      const params = { ...state.springParams, springConstant: parseFloat(value ?? '20') }
      return { ...state, springParams: params, springState: createSpringState(params), sim: { ...state.sim, time: 0, running: false } }
    }
    case 'spring-mass-change': {
      const params = { ...state.springParams, mass: parseFloat(value ?? '1') }
      return { ...state, springParams: params, springState: createSpringState(params), sim: { ...state.sim, time: 0, running: false } }
    }
    case 'spring-displacement-change': {
      const params = { ...state.springParams, initialDisplacement: parseFloat(value ?? '1') }
      return { ...state, springParams: params, springState: createSpringState(params), sim: { ...state.sim, time: 0, running: false } }
    }

    default:
      return state
  }
}

