        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ action, value })
      });
      const data = await res.json();
      document.getElementById('app').innerHTML = data.html;
      running = data.running;
      speed = data.speed;
      rebindEvents();
      if (running && !animFrame) tick();
      if (!running && animFrame) { cancelAnimationFrame(animFrame); animFrame = null; }
    };

    const tick = async () => {
      if (!running) { animFrame = null; return; }
      const res = await fetch('/tick', { method: 'POST' });
      const data = await res.json();
      document.getElementById('app').innerHTML = data.html;
      running = data.running;
      rebindEvents();
      if (running) animFrame = requestAnimationFrame(tick);
      else animFrame = null;
    };

    const rebindEvents = () => {
      document.querySelectorAll('[p-trigger]').forEach(el => {
        const triggers = el.getAttribute('p-trigger').split(' ');
        triggers.forEach(t => {
          const [event, action] = t.split(':');
          el.addEventListener(event, (e) => {
            post(action, e.target?.value);
          }, { once: true });
        });
      });
    };

    rebindEvents();
  </script>
</body>
</html>`
        return new Response(html, { headers: { 'Content-Type': 'text/html' } })
      }

      if (url.pathname === '/action' && req.method === 'POST') {
        const body = await req.json() as { action: string; value?: string }
        appState = handleAction(appState, body.action, body.value)
        const html = renderApp(appState)
        return Response.json({ html, running: appState.sim.running, speed: appState.sim.speed })
      }

      if (url.pathname === '/tick' && req.method === 'POST') {
        appState = stepSimulation(appState)
        const html = renderApp(appState)
        return Response.json({ html, running: appState.sim.running, speed: appState.sim.speed })
      }

      return new Response('Not Found', { status: 404 })
    },
  })

  console.log(`Physics Simulator running at http://localhost:${server.port}`)
}

