import type {
  PendulumParams,
  PendulumState,
  ProjectileParams,
  ProjectileState,
  SpringParams,
  SpringState,
  Vec2,
} from './types'

// --- RK4 integration helper ---

type DerivativeFn = (state: [number, number], t: number) => [number, number]

const rk4Step = (
  state: [number, number],
  t: number,
  dt: number,
  deriv: DerivativeFn
): [number, number] => {
  const k1 = deriv(state, t)
  const k2 = deriv(
    [state[0] + k1[0] * dt * 0.5, state[1] + k1[1] * dt * 0.5],
    t + dt * 0.5
  )
  const k3 = deriv(
    [state[0] + k2[0] * dt * 0.5, state[1] + k2[1] * dt * 0.5],
    t + dt * 0.5
  )
  const k4 = deriv(
    [state[0] + k3[0] * dt, state[1] + k3[1] * dt],
    t + dt
  )
  return [
    state[0] + (dt / 6) * (k1[0] + 2 * k2[0] + 2 * k3[0] + k4[0]),
    state[1] + (dt / 6) * (k1[1] + 2 * k2[1] + 2 * k3[1] + k4[1]),
  ]
}

// --- Pendulum ---

export const createPendulumState = (params: PendulumParams): PendulumState => {
  const { length, gravity, initialAngle } = params
  const theta = initialAngle
  const omega = 0
  const acc = -(gravity / length) * Math.sin(theta)
  return {
    theta,
    omega,
    time: 0,
    position: {
      x: length * Math.sin(theta),
      y: -length * Math.cos(theta),
    },
    velocity: { x: 0, y: 0 },
    acceleration: {
      x: length * acc * Math.cos(theta),
      y: length * acc * Math.sin(theta),
    },
  }
}

export const stepPendulum = (
  state: PendulumState,
  params: PendulumParams,
  dt: number
): PendulumState => {
  const { length, gravity, damping } = params

  const deriv: DerivativeFn = ([theta, omega]) => {
    const alpha = -(gravity / length) * Math.sin(theta) - damping * omega
    return [omega, alpha]
  }

  const [newTheta, newOmega] = rk4Step([state.theta, state.omega], state.time, dt, deriv)
  const newAlpha = -(gravity / length) * Math.sin(newTheta) - damping * newOmega
  const newTime = state.time + dt

  const x = length * Math.sin(newTheta)
  const y = -length * Math.cos(newTheta)

  const tangentialVel = length * newOmega
  const vx = tangentialVel * Math.cos(newTheta)
  const vy = tangentialVel * Math.sin(newTheta)

  const tangentialAcc = length * newAlpha
  const centripetalAcc = length * newOmega * newOmega
  const ax = tangentialAcc * Math.cos(newTheta) - centripetalAcc * Math.sin(newTheta)
  const ay = tangentialAcc * Math.sin(newTheta) + centripetalAcc * Math.cos(newTheta)

  return {
    theta: newTheta,
    omega: newOmega,
    time: newTime,
    position: { x, y },
    velocity: { x: vx, y: vy },
    acceleration: { x: ax, y: ay },
  }
}

// --- Projectile ---

export const createProjectileState = (params: ProjectileParams): ProjectileState => {
  const angleRad = (params.angle * Math.PI) / 180
  const vx = params.initialVelocity * Math.cos(angleRad)
  const vy = params.initialVelocity * Math.sin(angleRad)
  return {
    position: { x: 0, y: 0 },
    velocity: { x: vx, y: vy },
    acceleration: { x: 0, y: -params.gravity },
    time: 0,
    trajectory: [{ x: 0, y: 0 }],
    landed: false,
  }
}

export const stepProjectile = (
  state: ProjectileState,
  params: ProjectileParams,
  dt: number
): ProjectileState => {
  if (state.landed) return state

  const { gravity } = params
  const newTime = state.time + dt

  const angleRad = (params.angle * Math.PI) / 180
  const v0x = params.initialVelocity * Math.cos(angleRad)
  const v0y = params.initialVelocity * Math.sin(angleRad)

  const x = v0x * newTime
  const y = v0y * newTime - 0.5 * gravity * newTime * newTime

  const vx = v0x
  const vy = v0y - gravity * newTime

  const landed = y <= 0 && newTime > 0.01

  const clampedY = landed ? 0 : y
  const finalX = landed
    ? (2 * v0x * v0y) / gravity
    : x

  const newPoint: Vec2 = { x: finalX, y: clampedY }
  const trajectory = [...state.trajectory, newPoint]

  return {
    position: { x: finalX, y: clampedY },
    velocity: { x: landed ? 0 : vx, y: landed ? 0 : vy },
    acceleration: { x: 0, y: landed ? 0 : -gravity },
    time: newTime,
    trajectory,
    landed,
  }
}

// --- Spring-Mass ---

export const createSpringState = (params: SpringParams): SpringState => {
  const { springConstant, mass, initialDisplacement } = params
  const acc = -(springConstant / mass) * initialDisplacement
  return {
    displacement: initialDisplacement,
    velocity: 0,
    acceleration: acc,
    time: 0,
    position: { x: initialDisplacement, y: 0 },
    velocityVec: { x: 0, y: 0 },
    accelerationVec: { x: acc, y: 0 },
  }
}

export const stepSpring = (
  state: SpringState,
  params: SpringParams,
  dt: number
): SpringState => {
  const { springConstant, mass, damping } = params

  const deriv: DerivativeFn = ([x, v]) => {
    const a = -(springConstant / mass) * x - (damping / mass) * v
    return [v, a]
  }

  const [newX, newV] = rk4Step([state.displacement, state.velocity], state.time, dt, deriv)
  const newA = -(springConstant / mass) * newX - (damping / mass) * newV
  const newTime = state.time + dt

  return {
    displacement: newX,
    velocity: newV,
    acceleration: newA,
    time: newTime,
    position: { x: newX, y: 0 },
    velocityVec: { x: newV, y: 0 },
    accelerationVec: { x: newA, y: 0 },
  }
}

// --- Utility ---

export const magnitude = (v: Vec2): number =>
  Math.sqrt(v.x * v.x + v.y * v.y)

export const formatNum = (n: number, decimals = 3): string =>
  n.toFixed(decimals)

