export const renderPendulumSVG = (state: PendulumState, params: PendulumParams) => {
  const svgW = 600
  const svgH = 420
  const pivotX = svgW / 2
  const pivotY = 60
  const scale = 120

  const bobX = pivotX + state.position.x * scale
  const bobY = pivotY - state.position.y * scale

  const trailPoints: string[] = []
  for (let i = -20; i <= 20; i++) {
    const angle = params.initialAngle * Math.cos((i / 20) * Math.PI * 0.5)
    const tx = pivotX + params.length * Math.sin(angle) * scale
    const ty = pivotY + params.length * Math.cos(angle) * scale
    trailPoints.push(`${tx},${ty}`)
  }

  return h('svg', {
    width: String(svgW),
    height: String(svgH),
    viewBox: `0 0 ${svgW} ${svgH}`,
    style: 'width:100%;height:auto;',
  },
    // Background grid
    ...Array.from({ length: 7 }, (_, i) =>
      h('line', {
