  const v0x = params.initialVelocity * Math.cos(angleRad)
  const v0y = params.initialVelocity * Math.sin(angleRad)
  const maxRange = (2 * v0x * v0y) / params.gravity
  const maxHeight = (v0y * v0y) / (2 * params.gravity)

  const scaleX = maxRange > 0 ? (svgW - 2 * padX) / (maxRange * 1.1) : 1
  const scaleY = maxHeight > 0 ? (svgH - 2 * padY) / (maxHeight * 1.3) : 1
  const scale = Math.min(scaleX, scaleY, 15)

  const groundY = svgH - padY

  const toScreen = (p: Vec2): Vec2 => ({
    x: padX + p.x * scale,
    y: groundY - p.y * scale,
  })

  const trajectoryStr = state.trajectory
    .map(p => {
      const s = toScreen(p)
      return `${s.x},${s.y}`
    })
    .join(' ')

  const currentPos = toScreen(state.position)

  // Generate ideal curve
  const idealPoints: string[] = []
  const totalTime = maxRange > 0 ? (2 * v0y) / params.gravity : 1
  for (let i = 0; i <= 50; i++) {
    const t = (i / 50) * totalTime
    const ix = v0x * t
    const iy = v0y * t - 0.5 * params.gravity * t * t
    if (iy < 0) break
    const s = toScreen({ x: ix, y: iy })
    idealPoints.push(`${s.x},${s.y}`)
  }

  return h('svg', {
    width: String(svgW),
    height: String(svgH),
    viewBox: `0 0 ${svgW} ${svgH}`,
    style: 'width:100%;height:auto;',
  },
    // Background grid
    ...Array.from({ length: 7 }, (_, i) =>
      h('line', {
        x1: '0', y1: String(i * 70),
        x2: String(svgW), y2: String(i * 70),
        stroke: colors.gridLine, 'stroke-width': '1',
      })
    ),
    ...Array.from({ length: 9 }, (_, i) =>
      h('line', {
        x1: String(i * 75), y1: '0',
        x2: String(i * 75), y2: String(svgH),
        stroke: colors.gridLine, 'stroke-width': '1',
      })
    ),

    // Ground
    h('line', {
      x1: '0', y1: String(groundY),
      x2: String(svgW), y2: String(groundY),
      stroke: colors.ground, 'stroke-width': '2',
    }),

    // Ideal trajectory (dashed)
    h('polyline', {
      points: idealPoints.join(' '),
      fill: 'none',
      stroke: colors.path,
      'stroke-width': '1.5',
      'stroke-dasharray': '6,4',
      opacity: '0.3',
    }),

    // Actual trajectory path
    h('polyline', {
      points: trajectoryStr,
      fill: 'none',
      stroke: colors.path,
      'stroke-width': '2.5',
      'stroke-linecap': 'round',
      'stroke-linejoin': 'round',
    }),

    // Launch angle indicator
    h('line', {
      x1: String(padX), y1: String(groundY),
      x2: String(padX + 50 * Math.cos(angleRad)),
      y2: String(groundY - 50 * Math.sin(angleRad)),
      stroke: colors.pivot,
      'stroke-width': '1.5',
      'stroke-dasharray': '3,3',
    }),

    // Arrow defs
    h('defs', {},
      h('marker', {
        id: 'arrowGreen', markerWidth: '8', markerHeight: '8',
        refX: '6', refY: '4', orient: 'auto',
      },
        h('path', { d: 'M0,0 L8,4 L0,8 Z', fill: colors.positive })
      ),
    ),

    // Projectile
    h('circle', {
      cx: String(currentPos.x), cy: String(currentPos.y),
      r: '10',
      fill: colors.mass,
      stroke: '#ff8a8a',
      'stroke-width': '2',
    }),

    // Velocity vector
    ...(state.landed ? [] : [
      h('line', {
        x1: String(currentPos.x), y1: String(currentPos.y),
        x2: String(currentPos.x + state.velocity.x * 1.5),
        y2: String(currentPos.y - state.velocity.y * 1.5),
        stroke: colors.positive,
        'stroke-width': '2',
        'marker-end': 'url(#arrowGreen)',
      }),
    ]),

    // Labels
    h('text', {
      x: String(padX + 5), y: String(groundY + 18),
      fill: colors.textDim, 'font-size': '11',
      'font-family': 'monospace',
    }, '0'),

    h('text', {
      x: '12', y: String(svgH - 10),
      fill: colors.textDim, 'font-size': '12',
      'font-family': 'monospace',
    }, `t = ${formatNum(state.time, 2)}s`),

    h('text', {
      x: String(padX + 55), y: String(groundY - 5),
      fill: colors.pivot, 'font-size': '12',
      'font-family': 'monospace',
    }, `${params.angle}°`),

    ...(maxRange > 0 ? [
      h('text', {
        x: String(Math.min(padX + maxRange * scale, svgW - 60)),
        y: String(groundY + 18),
        fill: colors.textDim, 'font-size': '11',
        'font-family': 'monospace',
      }, `${formatNum(maxRange, 1)}m`),
    ] : []),
  )
}

export const renderSpringSVG = (state: SpringState, params: SpringParams) => {
  const svgW = 600
  const svgH = 420
  const centerY = svgH / 2
  const wallX = 50
  const restX = 300
  const scale = 80

  const massX = restX + state.displacement * scale
  const massW = 50
  const massH = 50

  // Generate spring coils
  const coilCount = 12
  const springStartX = wallX + 10
  const springEndX = massX - massW / 2
  const springLen = springEndX - springStartX
  const coilPoints: string[] = [`${springStartX},${centerY}`]

  for (let i = 1; i < coilCount * 2; i++) {
    const progress = i / (coilCount * 2)
    const px = springStartX + springLen * progress
    const py = centerY + (i % 2 === 0 ? -14 : 14)
    coilPoints.push(`${px},${py}`)
  }
  coilPoints.push(`${springEndX},${centerY}`)

  // Energy bars
  const omega = Math.sqrt(params.springConstant / params.mass)
  const amplitude = params.initialDisplacement
  const maxKE = 0.5 * params.springConstant * amplitude * amplitude
  const currentKE = 0.5 * params.mass * state.velocity * state.velocity
  const currentPE = 0.5 * params.springConstant * state.displacement * state.displacement
  const barMaxW = 150
  const keBarW = maxKE > 0 ? (currentKE / maxKE) * barMaxW : 0
  const peBarW = maxKE > 0 ? (currentPE / maxKE) * barMaxW : 0

  return h('svg', {
    width: String(svgW),
    height: String(svgH),
    viewBox: `0 0 ${svgW} ${svgH}`,
    style: 'width:100%;height:auto;',
  },
    // Background grid
    ...Array.from({ length: 7 }, (_, i) =>
      h('line', {
        x1: '0', y1: String(i * 70),
        x2: String(svgW), y2: String(i * 70),
        stroke: colors.gridLine, 'stroke-width': '1',
      })
    ),
    ...Array.from({ length: 9 }, (_, i) =>
      h('line', {
        x1: String(i * 75), y1: '0',
        x2: String(i * 75), y2: String(svgH),
        stroke: colors.gridLine, 'stroke-width': '1',
      })
    ),

    // Wall
    h('rect', {
      x: String(wallX - 8), y: String(centerY - 60),
      width: '10', height: '120',
      fill: colors.ground, rx: '2',
    }),
    // Wall hatch marks
    ...Array.from({ length: 8 }, (_, i) =>
      h('line', {
        x1: String(wallX - 8), y1: String(centerY - 50 + i * 15),
        x2: String(wallX - 16), y2: String(centerY - 40 + i * 15),
        stroke: colors.ground, 'stroke-width': '1.5',
      })
    ),

    // Equilibrium line
    h('line', {
      x1: String(restX), y1: String(centerY - 80),
      x2: String(restX), y2: String(centerY + 80),
      stroke: colors.textDim, 'stroke-width': '1',
      'stroke-dasharray': '4,4',
      opacity: '0.4',
    }),
    h('text', {
      x: String(restX - 8), y: String(centerY - 85),
      fill: colors.textDim, 'font-size': '10',
      'font-family': 'monospace',
    }, 'x=0'),

    // Spring coils
    h('polyline', {
      points: coilPoints.join(' '),
      fill: 'none',
      stroke: colors.spring,
      'stroke-width': '2.5',
      'stroke-linejoin': 'round',
      'stroke-linecap': 'round',
    }),

    // Mass block
    h('rect', {
      x: String(massX - massW / 2), y: String(centerY - massH / 2),
      width: String(massW), height: String(massH),
      rx: '6',
      fill: colors.mass,
      stroke: '#ff8a8a',
      'stroke-width': '2',
    }),
    h('text', {
      x: String(massX), y: String(centerY + 5),
      fill: '#fff', 'font-size': '14', 'font-weight': 'bold',
      'text-anchor': 'middle', 'font-family': 'monospace',
    }, `${params.mass}kg`),

    // Arrow defs
    h('defs', {},
      h('marker', {
        id: 'arrowGreen', markerWidth: '8', markerHeight: '8',
        refX: '6', refY: '4', orient: 'auto',
      },
        h('path', { d: 'M0,0 L8,4 L0,8 Z', fill: colors.positive })
      ),
      h('marker', {
        id: 'arrowRed', markerWidth: '8', markerHeight: '8',
        refX: '6', refY: '4', orient: 'auto',
      },
        h('path', { d: 'M0,0 L8,4 L0,8 Z', fill: colors.negative })
      ),
    ),

    // Velocity arrow
    ...(Math.abs(state.velocity) > 0.01 ? [
      h('line', {
        x1: String(massX), y1: String(centerY + massH / 2 + 15),
        x2: String(massX + state.velocity * 15),
        y2: String(centerY + massH / 2 + 15),
        stroke: colors.positive,
        'stroke-width': '2',
        'marker-end': 'url(#arrowGreen)',
      }),
      h('text', {
        x: String(massX + state.velocity * 7.5),
        y: String(centerY + massH / 2 + 30),
        fill: colors.positive, 'font-size': '10',
        'text-anchor': 'middle', 'font-family': 'monospace',
      }, 'v'),
    ] : []),

    // Force arrow (F = -kx)
    ...(Math.abs(state.acceleration) > 0.01 ? [
      h('line', {
        x1: String(massX), y1: String(centerY - massH / 2 - 15),
        x2: String(massX + state.acceleration * 5),
        y2: String(centerY - massH / 2 - 15),
        stroke: colors.negative,
        'stroke-width': '2',
        'marker-end': 'url(#arrowRed)',
      }),
      h('text', {
        x: String(massX + state.acceleration * 2.5),
        y: String(centerY - massH / 2 - 22),
        fill: colors.negative, 'font-size': '10',
        'text-anchor': 'middle', 'font-family': 'monospace',
      }, 'F'),
    ] : []),

    // Energy bars
    h('text', {
      x: String(svgW - 165), y: '30',
      fill: colors.textDim, 'font-size': '11',
      'font-family': 'monospace',
    }, 'Energy'),
    h('rect', {
      x: String(svgW - 165), y: '38',
      width: String(keBarW), height: '10', rx: '3',
      fill: colors.positive, opacity: '0.8',
    }),
    h('text', {
      x: String(svgW - 165 + barMaxW + 5), y: '48',
      fill: colors.positive, 'font-size': '10',
      'font-family': 'monospace',
    }, 'KE'),
    h('rect', {
      x: String(svgW - 165), y: '54',
      width: String(peBarW), height: '10', rx: '3',
      fill: colors.accent, opacity: '0.8',
    }),
    h('text', {
      x: String(svgW - 165 + barMaxW + 5), y: '64',
      fill: colors.accent, 'font-size': '10',
      'font-family': 'monospace',
    }, 'PE'),

    // Time
    h('text', {
      x: '12', y: String(svgH - 10),
      fill: colors.textDim, 'font-size': '12',
      'font-family': 'monospace',
    }, `t = ${formatNum(state.time, 2)}s`),
  )
}

