import { h, Fragment, createSSR } from 'plaited'
import type {
  SimulationState,
  SimulationType,
  SpeedMultiplier,
  PendulumParams,
  ProjectileParams,
  SpringParams,
} from './types'
import {
  createPendulumState,
  stepPendulum,
  createProjectileState,
  stepProjectile,
  createSpringState,
  stepSpring,
  magnitude,
} from './physics'
import {
  renderPendulumSVG,
  renderProjectileSVG,
  renderSpringSVG,
  renderReadout,
  renderSlider,
  renderControls,
  renderPage,
} from './renderer'

// --- Default parameters ---

const defaultPendulumParams: PendulumParams = {
  length: 1.5,
  gravity: 9.81,
  initialAngle: Math.PI / 4,
  damping: 0,
}

const defaultProjectileParams: ProjectileParams = {
  angle: 45,
  initialVelocity: 20,
  gravity: 9.81,
}

const defaultSpringParams: SpringParams = {
  springConstant: 20,
  mass: 1.0,
  initialDisplacement: 1.0,
  damping: 0,
}

// --- State management ---

const createInitialState = (): SimulationState => ({
  status: 'stopped',
  speed: 1,
  activeSimulation: 'pendulum',
  pendulum: {
    params: { ...defaultPendulumParams },
    state: createPendulumState(defaultPendulumParams),
  },
  projectile: {
    params: { ...defaultProjectileParams },
    state: createProjectileState(defaultProjectileParams),
  },
  spring: {
    params: { ...defaultSpringParams },
    state: createSpringState(defaultSpringParams),
  },
})

let state = createInitialState()

// --- Simulation step ---

const BASE_DT = 1 / 60

const tick = (): SimulationState => {
  if (state.status !== 'playing') return state

  const dt = BASE_DT * state.speed

  switch (state.activeSimulation) {
    case 'pendulum':
      state.pendulum.state = stepPendulum(
        state.pendulum.state,
        state.pendulum.params,
        dt
      )
      break
    case 'projectile':
      state.projectile.state = stepProjectile(
        state.projectile.state,
        state.projectile.params,
        dt
      )
      break
    case 'spring':
      state.spring.state = stepSpring(
        state.spring.state,
        state.spring.params,
        dt
      )
      break
  }

  return state
}

// --- Event handlers ---

const handlePlayPause = () => {
  state.status = state.status === 'playing' ? 'paused' : 'playing'
}

const handleReset = () => {
  state.status = 'stopped'
  switch (state.activeSimulation) {
    case 'pendulum':
      state.pendulum.state = createPendulumState(state.pendulum.params)
      break
    case 'projectile':
      state.projectile.state = createProjectileState(state.projectile.params)
      break
    case 'spring':
      state.spring.state = createSpringState(state.spring.params)
      break
  }
}

const handleSetSpeed = (speed: SpeedMultiplier) => {
  state.speed = speed
}

const handleSwitchTab = (tab: SimulationType) => {
  state.activeSimulation = tab
  state.status = 'stopped'
}

const handlePendulumParam = (key: keyof PendulumParams, value: number) => {
  state.pendulum.params[key] = value
  if (state.status === 'stopped') {
    state.pendulum.state = createPendulumState(state.pendulum.params)
  }
}

const handleProjectileParam = (key: keyof ProjectileParams, value: number) => {
  state.projectile.params[key] = value
  if (state.status === 'stopped') {
    state.projectile.state = createProjectileState(state.projectile.params)
  }
}

const handleSpringParam = (key: keyof SpringParams, value: number) => {
  state.spring.params[key] = value
  if (state.status === 'stopped') {
    state.spring.state = createSpringState(state.spring.params)
  }
}

// --- Render helpers ---

const styleStr = (s: Record<string, string | number>): string =>
  Object.entries(s)
    .map(([k, v]) => `${k.replace(/[A-Z]/g, m => `-${m.toLowerCase()}`)}:${v}`)
    .join(';')

const cardStyle = {
  background: '#1a2340',
  borderRadius: '12px',
  border: '1px solid #2a3a5c',
  padding: '16px',
}

const cardTitleStyle = {
  fontSize: '13px',
  fontWeight: '600',
  textTransform: 'uppercase',
  letterSpacing: '0.8px',
  color: '#8899bb',
  margin: '0 0 12px 0',
}

const renderPendulumSliders = () =>
  h('div', { style: styleStr(cardStyle) },
    h('div', { style: styleStr(cardTitleStyle) }, 'Parameters'),
    renderSlider('Length', state.pendulum.params.length, 0.5, 3.0, 0.1, 'm', 'pendulum-length'),
    renderSlider('Gravity', state.pendulum.params.gravity, 1.0, 20.0, 0.1, 'm/s\u00B2', 'pendulum-gravity'),
    renderSlider('Initial Angle', (state.pendulum.params.initialAngle * 180) / Math.PI, 5, 85, 1, '\u00B0', 'pendulum-angle'),
  )

const renderProjectileSliders = () =>
  h('div', { style: styleStr(cardStyle) },
    h('div', { style: styleStr(cardTitleStyle) }, 'Parameters'),
    renderSlider('Launch Angle', state.projectile.params.angle, 1, 89, 1, '\u00B0', 'projectile-angle'),
    renderSlider('Initial Velocity', state.projectile.params.initialVelocity, 1, 50, 0.5, 'm/s', 'projectile-velocity'),
    renderSlider('Gravity', state.projectile.params.gravity, 1.0, 20.0, 0.1, 'm/s\u00B2', 'projectile-gravity'),
  )

const renderSpringSliders = () =>
  h('div', { style: styleStr(cardStyle) },
    h('div', { style: styleStr(cardTitleStyle) }, 'Parameters'),
    renderSlider('Spring Constant (k)', state.spring.params.springConstant, 1, 100, 1, 'N/m', 'spring-k'),
    renderSlider('Mass', state.spring.params.mass, 0.1, 10.0, 0.1, 'kg', 'spring-mass'),
    renderSlider('Initial Displacement', state.spring.params.initialDisplacement, 0.1, 2.0, 0.1, 'm', 'spring-displacement'),
  )

// --- Main render ---

const render = (): string => {
  let svgContent: ReturnType<typeof h>
  let readoutContent: ReturnType<typeof h>
  let slidersContent: ReturnType<typeof h>

  switch (state.activeSimulation) {
    case 'pendulum': {
      const s = state.pendulum.state
      svgContent = renderPendulumSVG(s, state.pendulum.params)
      readoutContent = renderReadout(s.position, s.velocity, s.acceleration)
      slidersContent = renderPendulumSliders()
      break
    }
    case 'projectile': {
      const s = state.projectile.state
      svgContent = renderProjectileSVG(s, state.projectile.params)
      readoutContent = renderReadout(s.position, s.velocity, s.acceleration)
      slidersContent = renderProjectileSliders()
      break
    }
    case 'spring': {
      const s = state.spring.state
      svgContent = renderSpringSVG(s, state.spring.params)
      readoutContent = renderReadout(s.position, s.velocityVec, s.accelerationVec)
      slidersContent = renderSpringSliders()
      break
    }
  }

  const controlsContent = renderControls(state.status, state.speed)
  const page = renderPage(
    state.activeSimulation,
    svgContent!,
    readoutContent!,
    slidersContent!,
    controlsContent,
  )

  const ssr = createSSR()
  return ssr(page)
}

// --- Data persistence ---

const DATA_DIR = './data'

const saveState = async () => {
  const snapshot = {
    activeSimulation: state.activeSimulation,
    speed: state.speed,
    pendulumParams: state.pendulum.params,
    projectileParams: state.projectile.params,
    springParams: state.spring.params,
    savedAt: new Date().toISOString(),
  }
  await Bun.write(`${DATA_DIR}/session.json`, JSON.stringify(snapshot, null, 2))
}

const loadState = async () => {
  const file = Bun.file(`${DATA_DIR}/session.json`)
  if (await file.exists()) {
    const snapshot = await file.json()
    state.activeSimulation = snapshot.activeSimulation ?? 'pendulum'
    state.speed = snapshot.speed ?? 1
    if (snapshot.pendulumParams) {
      state.pendulum.params = { ...defaultPendulumParams, ...snapshot.pendulumParams }
      state.pendulum.state = createPendulumState(state.pendulum.params)
    }
    if (snapshot.projectileParams) {
      state.projectile.params = { ...defaultProjectileParams, ...snapshot.projectileParams }
      state.projectile.state = createProjectileState(state.projectile.params)
    }
    if (snapshot.springParams) {
      state.spring.params = { ...defaultSpringParams, ...snapshot.springParams }
      state.spring.state = createSpringState(state.spring.params)
    }
  }
}

// --- Event dispatch ---

const dispatch = async (event: string, payload?: number) => {
  switch (event) {
    case 'playPause':
      handlePlayPause()
      break
    case 'reset':
      handleReset()
      break
    case 'speed-0.25':
      handleSetSpeed(0.25)
      break
    case 'speed-0.5':
      handleSetSpeed(0.5)
      break
    case 'speed-1':
      handleSetSpeed(1)
      break
    case 'speed-2':
      handleSetSpeed(2)
      break
    case 'speed-4':
      handleSetSpeed(4)
      break
    case 'tab-pendulum':
      handleSwitchTab('pendulum')
      break
    case 'tab-projectile':
      handleSwitchTab('projectile')
      break
    case 'tab-spring':
      handleSwitchTab('spring')
      break
    case 'pendulum-length':
      if (payload !== undefined) handlePendulumParam('length', payload)
      break
    case 'pendulum-gravity':
      if (payload !== undefined) handlePendulumParam('gravity', payload)
      break
    case 'pendulum-angle':
      if (payload !== undefined) handlePendulumParam('initialAngle', (payload * Math.PI) / 180)
      break
    case 'projectile-angle':
      if (payload !== undefined) handleProjectileParam('angle', payload)
      break
    case 'projectile-velocity':
      if (payload !== undefined) handleProjectileParam('initialVelocity', payload)
      break
    case 'projectile-gravity':
      if (payload !== undefined) handleProjectileParam('gravity', payload)
      break
    case 'spring-k':
      if (payload !== undefined) handleSpringParam('springConstant', payload)
      break
    case 'spring-mass':
      if (payload !== undefined) handleSpringParam('mass', payload)
      break
    case 'spring-displacement':
      if (payload !== undefined) handleSpringParam('initialDisplacement', payload)
      break
  }
  await saveState()
}

// --- Server ---

const startServer = async () => {
  await loadState()

  const server = Bun.serve({
    port: 3000,
    fetch: async (req) => {
      const url = new URL(req.url)

      if (url.pathname === '/api/tick' && req.method === 'POST') {
        tick()
        const html = render()
        return new Response(html, {
          headers: { 'Content-Type': 'text/html' },
        })
      }

      if (url.pathname === '/api/event' && req.method === 'POST') {
        const body = await req.json() as { event: string; value?: number }
        await dispatch(body.event, body.value)
        const html = render()
        return new Response(html, {
          headers: { 'Content-Type': 'text/html' },
        })
      }

      if (url.pathname === '/api/state') {
        return Response.json({
          status: state.status,
          speed: state.speed,
          activeSimulation: state.activeSimulation,
        })
      }

      // Main page
      const appHtml = render()
      const fullPage = `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <title>Newton's Laws Simulator</title>
  <style>
    * { margin: 0; padding: 0; box-sizing: border-box; }
    body { background: #0f1729; overflow-x: hidden; }
    input[type="range"] {
      -webkit-appearance: none;
      height: 6px;
      border-radius: 3px;
      background: #2a3a5c;
      outline: none;
    }
    input[type="range"]::-webkit-slider-thumb {
      -webkit-appearance: none;
      width: 16px;
      height: 16px;
      border-radius: 50%;
      background: #4f8cff;
      cursor: pointer;
      border: 2px solid #0f1729;
    }
    button { font-family: inherit; }
    button:hover { opacity: 0.85; }
  </style>
</head>
<body>
  <div id="app">${appHtml}</div>
  <script>
    const app = document.getElementById('app');
    let isPlaying = false;
    let animFrame = null;

    const postEvent = async (event, value) => {
      const res = await fetch('/api/event', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ event, value }),
      });
      const html = await res.text();
      app.innerHTML = html;
      bindEvents();
    };

    const tickLoop = async () => {
      if (!isPlaying) return;
      const res = await fetch('/api/tick', { method: 'POST' });
      const html = await res.text();
      app.innerHTML = html;
      bindEvents();
      animFrame = requestAnimationFrame(tickLoop);
    };

    const bindEvents = () => {
      // Buttons with p-trigger
      app.querySelectorAll('[p-trigger]').forEach(el => {
        const trigger = el.getAttribute('p-trigger');
        if (el.tagName === 'BUTTON') {
          el.onclick = async () => {
            if (trigger === 'playPause') {
              await postEvent(trigger);
              const stateRes = await fetch('/api/state');
              const st = await stateRes.json();
              isPlaying = st.status === 'playing';
              if (isPlaying) tickLoop();
              else if (animFrame) cancelAnimationFrame(animFrame);
            } else if (trigger === 'reset') {
              isPlaying = false;
              if (animFrame) cancelAnimationFrame(animFrame);
              await postEvent(trigger);
            } else {
              await postEvent(trigger);
              if (trigger.startsWith('tab-')) {
                isPlaying = false;
                if (animFrame) cancelAnimationFrame(animFrame);
              }
            }
          };
        } else if (el.tagName === 'INPUT') {
          el.oninput = () => postEvent(trigger, parseFloat(el.value));
        }
      });
    };

    bindEvents();
  </script>
</body>
</html>`;
      return new Response(fullPage, {
        headers: { 'Content-Type': 'text/html' },
      })
    },
  })

  console.log(\`Newton's Laws Simulator running at http://localhost:\${server.port}\`)
}

// --- Exports ---

export {
  state,
  tick,
  render,
  dispatch,
  startServer,
  createInitialState,
  handlePlayPause,
  handleReset,
  handleSetSpeed,
  handleSwitchTab,
}

// Auto-start if run directly
startServer()

