const buildCellStyle = (el: Element): Record<string, string> => ({
  'grid-row': String(el.gridRow),
  'grid-column': String(el.gridCol),
  'background-color': CATEGORY_COLORS[el.category] ?? '#555',
  color: '#fff',
})

const styleObjToStr = (s: Record<string, string>): string =>
  Object.entries(s).map(([k, v]) => `${k}:${v}`).join(';')

export const renderPeriodicTable = (elements: Element[]): string => {
  const elementCells = elements.map((el) =>
    h('div', {
      class: `element-cell cat-${el.category}`,
      'data-num': String(el.atomicNumber),
      style: styleObjToStr(buildCellStyle(el)),
      'p-trigger': 'click:selectElement',
    },
      h('span', { class: 'atomic-num' }, String(el.atomicNumber)),
      h('span', { class: 'symbol' }, el.symbol),
      h('span', { class: 'name' }, el.name),
      h('span', { class: 'mass' }, String(el.atomicMass)),
    )
  )

  const lanthanideLabel = h('div', {
    class: 'spacer-label',
    style: 'grid-row:9;grid-column:1/4',
  }, '57-71 Lanthanides')

  const actinideLabel = h('div', {
    class: 'spacer-label',
    style: 'grid-row:10;grid-column:1/4',
  }, '89-103 Actinides')

  const categoryButtons = Object.entries(CATEGORY_LABELS).map(([cat, label]) =>
    h('button', {
      class: 'filter-btn',
      'data-category': cat,
      style: `border-color:${CATEGORY_COLORS[cat]}`,
    }, label)
  )

  const template = h('html', { lang: 'en' },
    h('head', null,
      h('meta', { charset: 'utf-8' }),
      h('meta', { name: 'viewport', content: 'width=device-width,initial-scale=1' }),
      h('title', null, 'Periodic Table Explorer'),
      h('style', null, css),
    ),
    h('body', null,
      h('div', { class: 'header' },
        h('h1', null, 'Periodic Table of Elements'),
        h('input', {
          class: 'search-box',
          type: 'search',
          placeholder: 'Search by name, symbol, or number\u2026',
          'p-trigger': 'input:searchElements',
          'p-target': 'search',
        }),
      ),
      h('div', { class: 'filters' },
        h('button', { class: 'filter-btn active', 'data-category': 'all' }, 'All'),
        ...categoryButtons,
      ),
      h('div', { class: 'table-wrap' },
        h('div', { class: 'periodic-table' },
          ...elementCells,
          lanthanideLabel,
          actinideLabel,
        ),
      ),
      h('div', { class: 'detail-overlay', id: 'detail-overlay' },
        h('div', { class: 'detail-panel', id: 'detail-panel' },
          h('button', { class: 'detail-close', id: 'detail-close' }, '\u00d7'),
          h('div', { id: 'detail-content' }),
        ),
      ),
      h('script', null, clientScript(elements)),
    ),
  )

  return createSSR(template)
}

const clientScript = (elements: Element[]): string => `
(function(){
var E=${JSON.stringify(elements.map((e) => ({
  n: e.atomicNumber,
  s: e.symbol,
  nm: e.name,
  m: e.atomicMass,
  c: e.category,
  ec: e.electronConfiguration,
  ox: e.oxidationStates,
  mp: e.meltingPoint,
  bp: e.boilingPoint,
  dy: e.discoveryYear,
  d: e.description,
})))};
var CC=${JSON.stringify(CATEGORY_COLORS)};
var CL=${JSON.stringify(CATEGORY_LABELS)};
var overlay=document.getElementById('detail-overlay');
var content=document.getElementById('detail-content');
var cells=document.querySelectorAll('.element-cell');
var filterBtns=document.querySelectorAll('.filter-btn');
var search=document.querySelector('.search-box');
var activeFilter='all';
var searchTerm='';

function findEl(num){for(var i=0;i<E.length;i++){if(E[i].n===num)return E[i]}return null}

function fmtTemp(k){if(k===null||k===undefined)return'Unknown';return k.toFixed(1)+' K ('+(k-273.15).toFixed(1)+' \\u00b0C)'}

function showDetail(num){
  var el=findEl(num);if(!el)return;
  var bg=CC[el.c]||'#555';
  content.innerHTML=
    '<div class="detail-header">'+
      '<div class="detail-symbol" style="background:'+bg+'">'+el.s+'</div>'+
      '<div class="detail-info"><h2>'+el.nm+'</h2>'+
      '<div class="subtitle">Element '+el.n+' \\u2022 '+CL[el.c]+'</div></div>'+
    '</div>'+
    '<div class="detail-body">'+
      '<div class="detail-field"><div class="label">Atomic Mass</div><div class="value">'+el.m+' u</div></div>'+
      '<div class="detail-field"><div class="label">Electron Config</div><div class="value">'+el.ec+'</div></div>'+
      '<div class="detail-field"><div class="label">Oxidation States</div><div class="value">'+el.ox.map(function(x){return x>0?'+'+x:x}).join(', ')+'</div></div>'+
      '<div class="detail-field"><div class="label">Discovery Year</div><div class="value">'+(el.dy||'Ancient')+'</div></div>'+
      '<div class="detail-field"><div class="label">Melting Point</div><div class="value">'+fmtTemp(el.mp)+'</div></div>'+
      '<div class="detail-field"><div class="label">Boiling Point</div><div class="value">'+fmtTemp(el.bp)+'</div></div>'+
      '<div class="detail-desc">'+el.d+'</div>'+
    '</div>';
  overlay.classList.add('open');
}

document.getElementById('detail-close').addEventListener('click',function(){overlay.classList.remove('open')});
overlay.addEventListener('click',function(e){if(e.target===overlay)overlay.classList.remove('open')});
document.addEventListener('keydown',function(e){if(e.key==='Escape')overlay.classList.remove('open')});

cells.forEach(function(cell){
  cell.addEventListener('click',function(){showDetail(parseInt(cell.getAttribute('data-num')))});
});

function applyFilters(){
  var q=searchTerm.toLowerCase();
  cells.forEach(function(cell){
    var num=parseInt(cell.getAttribute('data-num'));
    var el=findEl(num);if(!el)return;
    var catMatch=activeFilter==='all'||el.c===activeFilter;
    var searchMatch=!q||el.nm.toLowerCase().indexOf(q)!==-1||el.s.toLowerCase().indexOf(q)!==-1||String(el.n).indexOf(q)!==-1;
    cell.classList.toggle('dimmed',!(catMatch&&searchMatch));
  });
}

filterBtns.forEach(function(btn){
  btn.addEventListener('click',function(){
    filterBtns.forEach(function(b){b.classList.remove('active')});
    btn.classList.add('active');
    activeFilter=btn.getAttribute('data-category');
    applyFilters();
  });
});

search.addEventListener('input',function(){searchTerm=search.value;applyFilters()});
})();
`

import { loadElements } from './data'
import { renderPeriodicTable } from './render'

const PORT = Number(process.env.PORT) || 3000

const elements = await loadElements()
const html = renderPeriodicTable(elements)

const server = Bun.serve({
  port: PORT,
  fetch: (req) => {
    const url = new URL(req.url)

    if (url.pathname === '/' || url.pathname === '/index.html') {
      return new Response(html, {
        headers: { 'Content-Type': 'text/html; charset=utf-8' },
      })
    }

    if (url.pathname === '/api/elements') {
      return Response.json(elements)
    }

    if (url.pathname.startsWith('/api/element/')) {
      const num = parseInt(url.pathname.split('/').pop() ?? '', 10)
      const el = elements.find((e) => e.atomicNumber === num)
      if (el) return Response.json(el)
      return Response.json({ error: 'Element not found' }, { status: 404 })
    }

    return new Response('Not Found', { status: 404 })
  },
})

console.log(`Periodic Table Explorer running at http://localhost:${server.port}`)

