import { h, Fragment } from 'plaited';
import type { Element, Category } from './types.ts';
import { categories, categoryColorMap, css } from './styles.ts';

const categoryColor = (cat: Category): string => categoryColorMap[cat] ?? '#555';

const renderElementCell = (el: Element) =>
  h('div', {
    class: 'element-cell',
    style: `grid-row:${el.row};grid-column:${el.col};background:${categoryColor(el.category)}`,
    'data-num': String(el.atomicNumber),
    'data-name': el.name.toLowerCase(),
    'data-symbol': el.symbol.toLowerCase(),
    'data-category': el.category,
    'p-trigger': 'click:selectElement',
  },
    h('span', { class: 'atomic-number' }, String(el.atomicNumber)),
    h('span', { class: 'symbol' }, el.symbol),
    h('span', { class: 'el-name' }, el.name),
    h('span', { class: 'atomic-mass' }, el.atomicMass),
  );

const renderSeriesLabel = (row: number, col: number, label: string, color: string) =>
  h('div', {
    class: 'series-label',
    style: `grid-row:${row};grid-column:${col};border-color:${color}`,
  }, label);

const renderFilterButtons = () =>
  h('div', { class: 'legend' },
    h('button', {
      class: 'filter-btn active',
      style: 'background:#555;color:#fff',
      'data-category': 'all',
    }, 'All'),
    ...categories.map((cat) =>
      h('button', {
        class: 'filter-btn',
        style: `background:${cat.color};color:${cat.textColor}`,
        'data-category': cat.id,
      }, cat.label)
    ),
  );

const renderDetailPanel = () =>
  h('div', { class: 'detail-overlay', id: 'detail-overlay' },
    h('div', { class: 'detail-panel' },
      h('button', { class: 'detail-close', id: 'detail-close' }, '\u00D7'),
      h('div', { class: 'detail-header' },
        h('div', { class: 'detail-symbol', id: 'detail-symbol' }, ''),
        h('div', { class: 'detail-title' },
          h('h2', { id: 'detail-name' }, ''),
          h('div', { class: 'detail-num', id: 'detail-num' }, ''),
        ),
      ),
      h('div', { class: 'detail-grid' },
        ...['Electron Config.', 'Oxidation States', 'Melting Point', 'Boiling Point', 'Discovery Year', 'Atomic Mass'].map((label, i) =>
          h('div', { class: 'detail-item' },
            h('div', { class: 'detail-label' }, label),
            h('div', {
              class: 'detail-value',
              id: `detail-field-${i}`,
            }, ''),
          )
        ),
      ),
      h('div', { class: 'detail-desc', id: 'detail-desc' }, ''),
    ),
  );

const clientScript = `
(function() {
  var elements = window.__ELEMENTS__;
  var elMap = {};
  elements.forEach(function(el) { elMap[el.atomicNumber] = el; });

  var overlay = document.getElementById('detail-overlay');
  var closeBtn = document.getElementById('detail-close');
  var activeFilter = 'all';
  var searchTerm = '';

  // Category filter
  document.querySelectorAll('.filter-btn').forEach(function(btn) {
    btn.addEventListener('click', function() {
      document.querySelectorAll('.filter-btn').forEach(function(b) { b.classList.remove('active'); });
      btn.classList.add('active');
      activeFilter = btn.dataset.category;
      applyFilters();
    });
  });

  // Search
  var searchInput = document.getElementById('search-input');
  searchInput.addEventListener('input', function() {
    searchTerm = searchInput.value.toLowerCase().trim();
    applyFilters();
  });

  function applyFilters() {
    document.querySelectorAll('.element-cell').forEach(function(cell) {
      var matchesCategory = activeFilter === 'all' || cell.dataset.category === activeFilter;
      var matchesSearch = !searchTerm ||
        cell.dataset.name.includes(searchTerm) ||
        cell.dataset.symbol.includes(searchTerm) ||
        cell.dataset.num === searchTerm;
      cell.classList.toggle('dimmed', !(matchesCategory && matchesSearch));
    });
  }

  // Element click
  document.querySelectorAll('.element-cell').forEach(function(cell) {
    cell.addEventListener('click', function() {
      var el = elMap[parseInt(cell.dataset.num)];
      if (!el) return;
      var catColor = getComputedStyle(cell).backgroundColor;
      document.getElementById('detail-symbol').textContent = el.symbol;
      document.getElementById('detail-symbol').style.background = cell.style.background;
      document.getElementById('detail-name').textContent = el.name;
      document.getElementById('detail-num').textContent = 'Atomic Number ' + el.atomicNumber + ' \\u2022 ' + el.category.split('-').map(function(w) { return w[0].toUpperCase() + w.slice(1); }).join(' ');
      var fields = [el.electronConfiguration, el.oxidationStates, el.meltingPoint, el.boilingPoint, el.discoveryYear, el.atomicMass];
      fields.forEach(function(val, i) {
        document.getElementById('detail-field-' + i).textContent = val;
      });
      document.getElementById('detail-desc').textContent = el.description;
      overlay.classList.add('open');
    });
  });

  // Close detail
  closeBtn.addEventListener('click', function() { overlay.classList.remove('open'); });
  overlay.addEventListener('click', function(e) {
    if (e.target === overlay) overlay.classList.remove('open');
  });
  document.addEventListener('keydown', function(e) {
    if (e.key === 'Escape') overlay.classList.remove('open');
  });
})();
`;

