// ---------------------------------------------------------------------------
// Pure statistics functions — no side-effects, no IO
// ---------------------------------------------------------------------------

export type Stats = {
  mean: number
  median: number
  mode: number[]
  standardDeviation: number
  variance: number
  min: number
  max: number
  range: number
  q1: number
  q3: number
  iqr: number
  count: number
}

/** Sort a numeric array ascending (returns new array). */
const sortAsc = (data: number[]): number[] => [...data].sort((a, b) => a - b)

/** Arithmetic mean. */
const mean = (data: number[]): number =>
  data.reduce((s, v) => s + v, 0) / data.length

/** Median of a *sorted* array. */
const medianSorted = (sorted: number[]): number => {
  const mid = Math.floor(sorted.length / 2)
  return sorted.length % 2 === 0
    ? (sorted[mid - 1] + sorted[mid]) / 2
    : sorted[mid]
}

/** Quartile value using the inclusive (Tukey) method on a *sorted* array. */
const quartile = (sorted: number[], q: 0.25 | 0.75): number => {
  const pos = q * (sorted.length - 1)
  const lo = Math.floor(pos)
  const hi = Math.ceil(pos)
  return lo === hi ? sorted[lo] : sorted[lo] + (sorted[hi] - sorted[lo]) * (pos - lo)
}

/** Mode — may return multiple values if tied. */
const mode = (data: number[]): number[] => {
  const freq = new Map<number, number>()
  for (const v of data) {
    freq.set(v, (freq.get(v) ?? 0) + 1)
  }
  let maxFreq = 0
  for (const count of freq.values()) {
    if (count > maxFreq) maxFreq = count
  }
  if (maxFreq === 1) return [] // no repeating value
  const modes: number[] = []
  for (const [val, count] of freq) {
    if (count === maxFreq) modes.push(val)
  }
  return modes.sort((a, b) => a - b)
}

/** Population variance. */
const variance = (data: number[], avg: number): number =>
  data.reduce((s, v) => s + (v - avg) ** 2, 0) / data.length

/** Compute all descriptive statistics for a dataset. */
export const computeStats = (data: number[]): Stats => {
  if (data.length === 0) {
    return {
      mean: NaN, median: NaN, mode: [], standardDeviation: NaN,
      variance: NaN, min: NaN, max: NaN, range: NaN,
      q1: NaN, q3: NaN, iqr: NaN, count: 0,
    }
  }

  const sorted = sortAsc(data)
  const avg = mean(sorted)
  const v = variance(sorted, avg)
  const q1Val = quartile(sorted, 0.25)
  const q3Val = quartile(sorted, 0.75)

  return {
    mean: avg,
    median: medianSorted(sorted),
    mode: mode(sorted),
    standardDeviation: Math.sqrt(v),
    variance: v,
    min: sorted[0],
    max: sorted[sorted.length - 1],
    range: sorted[sorted.length - 1] - sorted[0],
    q1: q1Val,
    q3: q3Val,
    iqr: q3Val - q1Val,
    count: sorted.length,
  }
}

// ---------------------------------------------------------------------------
// Dataset parsing — CSV string or JSON array → number[]
// ---------------------------------------------------------------------------

/** Parse a dataset from a comma-separated string or a JSON array. */
export const parseDataset = (input: string | number[]): number[] => {
  if (Array.isArray(input)) return input.filter((v) => typeof v === "number" && !Number.isNaN(v))

  const trimmed = input.trim()

  // Try JSON array first
  if (trimmed.startsWith("[")) {
    try {
      const parsed: unknown = JSON.parse(trimmed)
      if (Array.isArray(parsed)) {
        return parsed
          .map(Number)
          .filter((v) => !Number.isNaN(v))
      }
    } catch {
      // fall through to CSV parsing
    }
  }

  // Comma-separated values
  return trimmed
    .split(",")
    .map((s) => s.trim())
    .filter((s) => s.length > 0)
    .map(Number)
    .filter((v) => !Number.isNaN(v))
}

