// ---- helpers ---------------------------------------------------------------

const COLORS = [
  "#4e79a7", "#f28e2b", "#e15759", "#76b7b2",
  "#59a14f", "#edc948", "#b07aa1", "#ff9da7",
]

const colorFor = (i: number): string => COLORS[i % COLORS.length]

const fmt = (n: number, decimals = 4): string =>
  Number.isNaN(n) ? "—" : Number.isInteger(n) ? String(n) : n.toFixed(decimals)

// ---- summary table ---------------------------------------------------------

export const renderSummaryTable = (entries: DatasetEntry[]): string => {
  const labels: { key: keyof Stats; label: string }[] = [
    { key: "count", label: "Count" },
    { key: "mean", label: "Mean" },
