    { key: "mode", label: "Mode" },
    { key: "standardDeviation", label: "Std Dev" },
    { key: "variance", label: "Variance" },
    { key: "min", label: "Min" },
    { key: "max", label: "Max" },
    { key: "range", label: "Range" },
    { key: "q1", label: "Q1" },
    { key: "q3", label: "Q3" },
    { key: "iqr", label: "IQR" },
  ]

  const headerCells = [
    h("th", { style: "padding:6px 12px;border:1px solid #ccc;background:#f5f5f5;text-align:left" }, "Statistic"),
    ...entries.map((e, i) =>
      h("th", {
        style: `padding:6px 12px;border:1px solid #ccc;background:${colorFor(i)}22;text-align:right`,
      }, e.name),
    ),
  ]

  const rows = labels.map(({ key, label }) =>
    h("tr", {},
      h("td", { style: "padding:6px 12px;border:1px solid #ccc;font-weight:600" }, label),
      ...entries.map((e) => {
        const val = e.stats[key]
