          ? val.length === 0 ? "none" : val.map((v) => fmt(v)).join(", ")
          : fmt(val as number)
        return h("td", { style: "padding:6px 12px;border:1px solid #ccc;text-align:right;font-variant-numeric:tabular-nums" }, display)
      }),
    ),
  )

  return h(
    "table",
    { style: "border-collapse:collapse;font-family:system-ui,sans-serif;font-size:14px;margin:16px 0" },
    h("thead", {}, h("tr", {}, ...headerCells)),
    h("tbody", {}, ...rows),
  ) as unknown as string
}

// ---- box plot (SVG) --------------------------------------------------------

export const renderBoxPlot = (entries: DatasetEntry[]): string => {
  const plotW = 600
  const plotH = 40
  const padding = 60
  const labelW = 100
  const svgH = entries.length * (plotH + 16) + padding
  const svgW = plotW + labelW + 40

  // global scale across all datasets
  const allMin = Math.min(...entries.map((e) => e.stats.min))
  const allMax = Math.max(...entries.map((e) => e.stats.max))
  const span = allMax - allMin || 1
  const scale = (v: number) => labelW + ((v - allMin) / span) * plotW

  const plotElements = entries.flatMap((entry, i) => {
    const { stats } = entry
    const y = i * (plotH + 16) + 24
    const mid = y + plotH / 2
    const color = colorFor(i)
    const whiskerLo = Math.max(stats.min, stats.q1 - 1.5 * stats.iqr)
    const whiskerHi = Math.min(stats.max, stats.q3 + 1.5 * stats.iqr)

    const outliers = entry.data.filter((v) => v < whiskerLo || v > whiskerHi)

    return [
      // label
      h("text", { x: String(labelW - 8), y: String(mid + 4), "text-anchor": "end", "font-size": "13", fill: "#333", "font-family": "system-ui,sans-serif" }, entry.name),
      // whisker line
      h("line", { x1: String(scale(whiskerLo)), x2: String(scale(whiskerHi)), y1: String(mid), y2: String(mid), stroke: color, "stroke-width": "1.5" }),
      // whisker caps
      h("line", { x1: String(scale(whiskerLo)), x2: String(scale(whiskerLo)), y1: String(y + 8), y2: String(y + plotH - 8), stroke: color, "stroke-width": "1.5" }),
      h("line", { x1: String(scale(whiskerHi)), x2: String(scale(whiskerHi)), y1: String(y + 8), y2: String(y + plotH - 8), stroke: color, "stroke-width": "1.5" }),
      // box
      h("rect", {
        x: String(scale(stats.q1)), y: String(y),
        width: String(scale(stats.q3) - scale(stats.q1)), height: String(plotH),
        fill: `${color}33`, stroke: color, "stroke-width": "2", rx: "3",
      }),
      // median line
      h("line", { x1: String(scale(stats.median)), x2: String(scale(stats.median)), y1: String(y), y2: String(y + plotH), stroke: color, "stroke-width": "2.5" }),
      // outliers
      ...outliers.map((v) =>
        h("circle", { cx: String(scale(v)), cy: String(mid), r: "4", fill: "none", stroke: color, "stroke-width": "1.5" }),
      ),
    ]
  })

  // axis ticks
  const tickCount = 8
  const ticks = Array.from({ length: tickCount + 1 }, (_, i) => allMin + (span * i) / tickCount)
  const axisY = entries.length * (plotH + 16) + 20
  const axisElements = [
    h("line", { x1: String(labelW), x2: String(labelW + plotW), y1: String(axisY), y2: String(axisY), stroke: "#999", "stroke-width": "1" }),
    ...ticks.map((t) =>
      h("g", {},
        h("line", { x1: String(scale(t)), x2: String(scale(t)), y1: String(axisY), y2: String(axisY + 5), stroke: "#999", "stroke-width": "1" }),
        h("text", { x: String(scale(t)), y: String(axisY + 18), "text-anchor": "middle", "font-size": "11", fill: "#666", "font-family": "system-ui,sans-serif" }, fmt(t, 1)),
      ),
    ),
  ]

  return h(
    "svg",
    { xmlns: "http://www.w3.org/2000/svg", width: String(svgW), height: String(svgH), viewBox: `0 0 ${svgW} ${svgH}`, style: "margin:16px 0" },
    ...plotElements,
    ...axisElements,
  ) as unknown as string
}

// ---- histogram (SVG) -------------------------------------------------------

export const renderHistogram = (entries: DatasetEntry[]): string => {
  const plotW = 600
  const plotH = 260
  const labelW = 60
  const bottomPad = 40
  const topPad = 24
  const svgW = plotW + labelW + 20
  const svgH = plotH + bottomPad + topPad

  // bins — Sturges' rule based on largest dataset
  const maxCount = Math.max(...entries.map((e) => e.data.length))
  const binCount = Math.max(5, Math.ceil(Math.log2(maxCount) + 1))

  const allMin = Math.min(...entries.map((e) => e.stats.min))
  const allMax = Math.max(...entries.map((e) => e.stats.max))
  const span = allMax - allMin || 1
  const binWidth = span / binCount

  // compute frequencies per dataset
  const allFreqs = entries.map((entry) => {
    const freq = new Array<number>(binCount).fill(0)
    for (const v of entry.data) {
      let idx = Math.floor((v - allMin) / binWidth)
      if (idx >= binCount) idx = binCount - 1
      freq[idx]++
    }
    return freq
  })

  const globalMaxFreq = Math.max(...allFreqs.flat(), 1)

  const xScale = (bin: number) => labelW + (bin / binCount) * plotW
  const yScale = (freq: number) => topPad + plotH - (freq / globalMaxFreq) * plotH

  const barW = plotW / binCount
  const subBarW = barW / entries.length

  const bars = entries.flatMap((entry, di) =>
    allFreqs[di].map((freq, bi) =>
      h("rect", {
        x: String(xScale(bi) + di * subBarW),
        y: String(yScale(freq)),
        width: String(Math.max(subBarW - 1, 1)),
        height: String(plotH - (yScale(freq) - topPad)),
        fill: `${colorFor(di)}aa`,
        rx: "1",
      }),
    ),
  )

  // x-axis
  const xTicks = Array.from({ length: binCount + 1 }, (_, i) => allMin + binWidth * i)
  const xAxisY = topPad + plotH
  const xAxis = [
    h("line", { x1: String(labelW), x2: String(labelW + plotW), y1: String(xAxisY), y2: String(xAxisY), stroke: "#999" }),
    ...xTicks.map((t, i) =>
      h("g", {},
        h("line", { x1: String(xScale(i)), x2: String(xScale(i)), y1: String(xAxisY), y2: String(xAxisY + 5), stroke: "#999" }),
        h("text", { x: String(xScale(i)), y: String(xAxisY + 18), "text-anchor": "middle", "font-size": "11", fill: "#666", "font-family": "system-ui,sans-serif" }, fmt(t, 1)),
      ),
    ),
  ]

  // y-axis
  const yTickCount = 5
  const yTicks = Array.from({ length: yTickCount + 1 }, (_, i) => Math.round((globalMaxFreq * i) / yTickCount))
  const yAxis = [
    h("line", { x1: String(labelW), x2: String(labelW), y1: String(topPad), y2: String(xAxisY), stroke: "#999" }),
    ...yTicks.map((t) =>
      h("g", {},
        h("line", { x1: String(labelW - 4), x2: String(labelW), y1: String(yScale(t)), y2: String(yScale(t)), stroke: "#999" }),
        h("text", { x: String(labelW - 8), y: String(yScale(t) + 4), "text-anchor": "end", "font-size": "11", fill: "#666", "font-family": "system-ui,sans-serif" }, String(t)),
      ),
    ),
  ]

  // legend
  const legend = entries.map((entry, i) =>
    h("g", { transform: `translate(${labelW + 8 + i * 120}, ${topPad - 8})` },
      h("rect", { x: "0", y: "-8", width: "12", height: "12", fill: colorFor(i), rx: "2" }),
      h("text", { x: "16", y: "2", "font-size": "12", fill: "#333", "font-family": "system-ui,sans-serif" }, entry.name),
    ),
  )

  return h(
    "svg",
    { xmlns: "http://www.w3.org/2000/svg", width: String(svgW), height: String(svgH), viewBox: `0 0 ${svgW} ${svgH}`, style: "margin:16px 0" },
    ...bars,
    ...xAxis,
    ...yAxis,
    ...legend,
  ) as unknown as string
}

// ---- full page -------------------------------------------------------------

export const renderPage = (entries: DatasetEntry[]): string => {
  if (entries.length === 0) {
    return h("p", { style: "font-family:system-ui,sans-serif;color:#666" }, "No datasets loaded. Add a dataset to begin.") as unknown as string
  }

  const heading = h("h2", { style: "font-family:system-ui,sans-serif;margin:16px 0 4px" }, "Statistics Summary")
  const boxLabel = h("h3", { style: "font-family:system-ui,sans-serif;margin:24px 0 4px" }, "Box Plot")
  const histLabel = h("h3", { style: "font-family:system-ui,sans-serif;margin:24px 0 4px" }, "Histogram")

  return [
    heading,
    renderSummaryTable(entries),
    boxLabel,
    renderBoxPlot(entries),
    histLabel,
    renderHistogram(entries),
  ].join("\n")
}

// ---------------------------------------------------------------------------
// Statistics Calculator — public API
// ---------------------------------------------------------------------------

import { computeStats, type Stats } from "./stats"
import { parseDataset } from "./parse"
import { renderPage, renderSummaryTable, renderBoxPlot, renderHistogram } from "./render"

// ---- types -----------------------------------------------------------------

export type Dataset = {
  name: string
  data: number[]
  stats: Stats
}

export type DatasetResult = {
  name: string
  stats: Stats
}

// ---- state -----------------------------------------------------------------

const DATA_PATH = "data/datasets.json"

const datasets: Map<string, Dataset> = new Map()

// ---- persistence -----------------------------------------------------------

const persist = async (): Promise<void> => {
  const serializable = [...datasets.entries()].map(([name, ds]) => ({
    name,
    data: ds.data,
  }))
  await Bun.write(DATA_PATH, JSON.stringify(serializable, null, 2))
}

const load = async (): Promise<void> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) return
  try {
    const raw: { name: string; data: number[] }[] = JSON.parse(await file.text())
    for (const entry of raw) {
      const data = entry.data.filter((v) => typeof v === "number" && !Number.isNaN(v))
      datasets.set(entry.name, { name: entry.name, data, stats: computeStats(data) })
    }
  } catch {
    // ignore corrupt file
  }
}

// ---- public API ------------------------------------------------------------

/** Add (or replace) a named dataset. Input can be CSV string, JSON array string, or number[]. */
export const addDataset = async (name: string, input: string | number[]): Promise<Dataset> => {
  const data = parseDataset(input)
  if (data.length === 0) throw new Error(`Dataset "${name}" produced no valid numbers.`)
  const stats = computeStats(data)
  const ds: Dataset = { name, data, stats }
  datasets.set(name, ds)
  await persist()
  return ds
}

/** Remove a dataset by name. */
export const removeDataset = async (name: string): Promise<boolean> => {
  const removed = datasets.delete(name)
  if (removed) await persist()
  return removed
}

/** Get all current datasets with their stats. */
export const getResults = (): DatasetResult[] =>
  [...datasets.values()].map(({ name, stats }) => ({ name, stats }))

/** Get a single dataset by name. */
export const getDataset = (name: string): Dataset | undefined => datasets.get(name)

/** List all dataset names. */
export const listDatasets = (): string[] => [...datasets.keys()]

/** Clear all datasets. */
export const clearAll = async (): Promise<void> => {
  datasets.clear()
  await persist()
}

/** Render the full HTML view (table + box plot + histogram). */
export const renderView = (): string => {
  const entries = [...datasets.values()]
  return renderPage(entries)
}

/** Render only the summary table. */
export const renderTable = (): string => {
  const entries = [...datasets.values()]
  return renderSummaryTable(entries)
}

/** Render only the box plot SVG. */
export const renderBoxPlotView = (): string => {
  const entries = [...datasets.values()]
  return renderBoxPlot(entries)
}

/** Render only the histogram SVG. */
export const renderHistogramView = (): string => {
  const entries = [...datasets.values()]
  return renderHistogram(entries)
}

/** Initialize — load persisted datasets from disk. */
export const init = async (): Promise<void> => {
  await load()
}

