// ── Box Plot (SVG) ───────────────────────────────────────────────────────────
const BOX_PLOT_W = 600;
const BOX_PLOT_ROW_H = 50;
const BOX_PLOT_PAD = { top: 30, bottom: 40, left: 80, right: 20 };

export const renderBoxPlot = (datasets: NamedDataset[]) => {
  const allMin = Math.min(...datasets.map((d) => d.stats.min));
  const allMax = Math.max(...datasets.map((d) => d.stats.max));
  const padding = (allMax - allMin) * 0.05 || 1;
  const domainMin = allMin - padding;
  const domainMax = allMax + padding;
  const plotW = BOX_PLOT_W - BOX_PLOT_PAD.left - BOX_PLOT_PAD.right;
  const height = BOX_PLOT_PAD.top + datasets.length * BOX_PLOT_ROW_H + BOX_PLOT_PAD.bottom;

  const x = (v: number) =>
    BOX_PLOT_PAD.left + ((v - domainMin) / (domainMax - domainMin)) * plotW;

  // Tick marks
  const tickCount = 8;
  const tickStep = (domainMax - domainMin) / tickCount;
  const ticks = Array.from({ length: tickCount + 1 }, (_, i) => domainMin + i * tickStep);

  const tickElements = ticks.map((t) =>
    h(Fragment, {},
      h('line', {
        x1: String(x(t)), y1: String(BOX_PLOT_PAD.top - 5),
        x2: String(x(t)), y2: String(height - BOX_PLOT_PAD.bottom),
        stroke: '#e0e0e0', 'stroke-width': '1',
      }),
      h('text', {
        x: String(x(t)), y: String(height - BOX_PLOT_PAD.bottom + 16),
        'text-anchor': 'middle', 'font-size': '11', fill: '#666',
      }, String(round(t, 2))),
    ),
  );

  const boxes = datasets.map((ds, i) => {
    const cy = BOX_PLOT_PAD.top + i * BOX_PLOT_ROW_H + BOX_PLOT_ROW_H / 2;
    const boxH = BOX_PLOT_ROW_H * 0.55;
    const { min, max, q1, q3, median, iqr } = ds.stats;
    const whiskerLo = Math.max(min, q1 - 1.5 * iqr);
    const whiskerHi = Math.min(max, q3 + 1.5 * iqr);
    const color = colorFor(i);

    // Outliers
    const outliers = ds.data.filter((v) => v < whiskerLo || v > whiskerHi);

    return h(Fragment, {},
      // Dataset label
      h('text', {
        x: String(BOX_PLOT_PAD.left - 8), y: String(cy + 4),
        'text-anchor': 'end', 'font-size': '12', fill: '#333', 'font-weight': '500',
      }, ds.name),
      // Whisker line
      h('line', {
        x1: String(x(whiskerLo)), y1: String(cy),
        x2: String(x(whiskerHi)), y2: String(cy),
        stroke: color, 'stroke-width': '1.5',
      }),
      // Whisker caps
      h('line', {
        x1: String(x(whiskerLo)), y1: String(cy - boxH / 4),
        x2: String(x(whiskerLo)), y2: String(cy + boxH / 4),
        stroke: color, 'stroke-width': '1.5',
      }),
      h('line', {
        x1: String(x(whiskerHi)), y1: String(cy - boxH / 4),
        x2: String(x(whiskerHi)), y2: String(cy + boxH / 4),
        stroke: color, 'stroke-width': '1.5',
      }),
      // Box
      h('rect', {
        x: String(x(q1)), y: String(cy - boxH / 2),
        width: String(x(q3) - x(q1)), height: String(boxH),
        fill: color, 'fill-opacity': '0.25', stroke: color, 'stroke-width': '1.5', rx: '2',
      }),
      // Median line
      h('line', {
        x1: String(x(median)), y1: String(cy - boxH / 2),
        x2: String(x(median)), y2: String(cy + boxH / 2),
        stroke: color, 'stroke-width': '2.5',
      }),
      // Outliers
      ...outliers.map((v) =>
        h('circle', {
          cx: String(x(v)), cy: String(cy), r: '3',
          fill: 'none', stroke: color, 'stroke-width': '1.5',
        }),
      ),
    );
  });

  return h(
    'div',
    { style: { marginBottom: '24px' } },
    h('h3', { style: { fontFamily: 'system-ui, sans-serif', margin: '0 0 8px', fontSize: '15px' } }, 'Box Plot'),
    h(
      'svg',
      {
        viewBox: `0 0 ${BOX_PLOT_W} ${height}`,
        width: String(BOX_PLOT_W),
        height: String(height),
        style: { background: '#fff', border: '1px solid #e0e0e0', borderRadius: '6px' },
      },
      ...tickElements,
      ...boxes,
    ),
  );
};

// ── Histogram (SVG) ──────────────────────────────────────────────────────────
const HIST_W = 600;
const HIST_H = 300;
const HIST_PAD = { top: 20, bottom: 45, left: 55, right: 20 };

export const renderHistogram = (datasets: NamedDataset[]) => {
  const allValues = datasets.flatMap((d) => d.data);
  const globalMin = Math.min(...allValues);
  const globalMax = Math.max(...allValues);
  const binCount = Math.max(5, Math.min(30, Math.ceil(Math.sqrt(allValues.length))));
  const binWidth = (globalMax - globalMin) / binCount || 1;

  const binsPerDataset = datasets.map((ds) => {
    const bins = new Array<number>(binCount).fill(0);
    for (const v of ds.data) {
      let idx = Math.floor((v - globalMin) / binWidth);
      if (idx >= binCount) idx = binCount - 1;
      if (idx < 0) idx = 0;
      bins[idx]++;
    }
    return bins;
  });

  const maxCount = Math.max(...binsPerDataset.flat());
  const plotW = HIST_W - HIST_PAD.left - HIST_PAD.right;
  const plotH = HIST_H - HIST_PAD.top - HIST_PAD.bottom;
  const groupWidth = plotW / binCount;
  const barWidth = groupWidth / datasets.length;

  const x = (bin: number, dsIdx: number) =>
    HIST_PAD.left + bin * groupWidth + dsIdx * barWidth;
  const yScale = (count: number) => (count / (maxCount || 1)) * plotH;

  // Y-axis ticks
  const yTickCount = 5;
  const yTicks = Array.from({ length: yTickCount + 1 }, (_, i) =>
    Math.round((maxCount / yTickCount) * i),
  );

  const yTickEls = yTicks.map((t) => {
    const yy = HIST_PAD.top + plotH - yScale(t);
    return h(Fragment, {},
      h('line', {
        x1: String(HIST_PAD.left), y1: String(yy),
        x2: String(HIST_W - HIST_PAD.right), y2: String(yy),
        stroke: '#e8e8e8', 'stroke-width': '1',
      }),
      h('text', {
        x: String(HIST_PAD.left - 8), y: String(yy + 4),
        'text-anchor': 'end', 'font-size': '11', fill: '#666',
      }, String(t)),
    );
  });

  // X-axis labels (bin edges)
  const xLabelStep = Math.max(1, Math.floor(binCount / 8));
  const xLabels = Array.from({ length: binCount + 1 }, (_, i) => i)
    .filter((i) => i % xLabelStep === 0)
    .map((i) => {
      const val = globalMin + i * binWidth;
      const xx = HIST_PAD.left + i * groupWidth;
      return h('text', {
        x: String(xx), y: String(HIST_H - HIST_PAD.bottom + 18),
        'text-anchor': 'middle', 'font-size': '11', fill: '#666',
      }, String(round(val, 2)));
    });

  const bars = binsPerDataset.flatMap((bins, dsIdx) =>
    bins.map((count, binIdx) => {
      if (count === 0) return h(Fragment, {});
      const bx = x(binIdx, dsIdx);
      const bh = yScale(count);
      const by = HIST_PAD.top + plotH - bh;
      return h('rect', {
        x: String(bx), y: String(by),
        width: String(Math.max(barWidth - 1, 1)), height: String(bh),
        fill: colorFor(dsIdx), 'fill-opacity': '0.7', rx: '1',
      });
    }),
  );

  // Legend
  const legend = datasets.map((ds, i) =>
    h(Fragment, {},
      h('rect', {
        x: String(HIST_PAD.left + i * 100), y: '4',
        width: '12', height: '12', fill: colorFor(i), rx: '2',
      }),
      h('text', {
        x: String(HIST_PAD.left + i * 100 + 16), y: '14',
        'font-size': '12', fill: '#333',
      }, ds.name),
    ),
  );

  return h(
    'div',
    { style: { marginBottom: '24px' } },
    h('h3', { style: { fontFamily: 'system-ui, sans-serif', margin: '0 0 8px', fontSize: '15px' } }, 'Histogram'),
    h(
      'svg',
      {
        viewBox: `0 0 ${HIST_W} ${HIST_H}`,
        width: String(HIST_W),
        height: String(HIST_H),
        style: { background: '#fff', border: '1px solid #e0e0e0', borderRadius: '6px' },
      },
      ...yTickEls,
      ...xLabels,
      ...bars,
      ...legend,
    ),
  );
};

import { h } from 'plaited';
import { createSSR } from 'plaited/server';
import { parseDataset } from './parse.js';
import { computeStats, type NamedDataset, type Stats } from './stats.js';
import { renderSummaryTable, renderBoxPlot, renderHistogram } from './render.js';

// ── Persistent storage ───────────────────────────────────────────────────────
const DATA_PATH = new URL('../data/datasets.json', import.meta.url).pathname;

type StoredDatasets = Record<string, number[]>;

const loadDatasets = async (): Promise<StoredDatasets> => {
  const file = Bun.file(DATA_PATH);
  if (await file.exists()) {
    return (await file.json()) as StoredDatasets;
  }
  return {};
};

const saveDatasets = async (datasets: StoredDatasets): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(datasets, null, 2));
};

// ── Public API ───────────────────────────────────────────────────────────────

/** Add or replace a named dataset. Input can be CSV string or JSON array string. */
export const addDataset = async (name: string, raw: string): Promise<NamedDataset> => {
  const data = parseDataset(raw);
  const stored = await loadDatasets();
  stored[name] = data;
  await saveDatasets(stored);
  const stats = computeStats(data);
  return { name, data, stats };
};

/** Remove a named dataset. */
export const removeDataset = async (name: string): Promise<void> => {
  const stored = await loadDatasets();
  delete stored[name];
  await saveDatasets(stored);
};

/** List all stored dataset names. */
export const listDatasets = async (): Promise<string[]> => {
  const stored = await loadDatasets();
  return Object.keys(stored);
};

/** Get a single dataset with computed stats. */
export const getDataset = async (name: string): Promise<NamedDataset | null> => {
  const stored = await loadDatasets();
  const data = stored[name];
  if (!data) return null;
  return { name, data, stats: computeStats(data) };
};

/** Get all datasets with computed stats. */
export const getAllDatasets = async (): Promise<NamedDataset[]> => {
  const stored = await loadDatasets();
  return Object.entries(stored).map(([name, data]) => ({
    name,
    data,
    stats: computeStats(data),
  }));
};

/** Compute stats for raw input without saving. */
export const analyzeRaw = (raw: string, name = 'Dataset'): NamedDataset => {
  const data = parseDataset(raw);
  const stats = computeStats(data);
  return { name, data, stats };
};

