// ── CLI entry point ──────────────────────────────────────────────────────────
const [command, ...args] = Bun.argv.slice(2);

const printHelp = () => {
  console.log(`Usage:
  bun src/index.ts add <name> <values>    Add a dataset (CSV or JSON array)
  bun src/index.ts remove <name>          Remove a dataset
  bun src/index.ts list                   List all datasets
  bun src/index.ts stats [name]           Show stats for one or all datasets
  bun src/index.ts analyze <values>       Analyze values without saving
  bun src/index.ts render                 Render HTML page to stdout`);
};

const formatStats = (stats: Stats, label: string) => {
  console.log(`\n── ${label} ──`);
  console.log(`  Count:     ${stats.count}`);
  console.log(`  Mean:      ${stats.mean}`);
  console.log(`  Median:    ${stats.median}`);
  console.log(`  Mode:      ${stats.mode.length > 0 ? stats.mode.join(', ') : 'N/A (all unique)'}`);
  console.log(`  Std Dev:   ${stats.stdDev}`);
  console.log(`  Variance:  ${stats.variance}`);
  console.log(`  Min:       ${stats.min}`);
  console.log(`  Max:       ${stats.max}`);
  console.log(`  Range:     ${stats.range}`);
  console.log(`  Q1:        ${stats.q1}`);
  console.log(`  Q3:        ${stats.q3}`);
  console.log(`  IQR:       ${stats.iqr}`);
};

if (command === 'add' && args.length >= 2) {
  const [name, ...rest] = args;
  const ds = await addDataset(name, rest.join(','));
  formatStats(ds.stats, ds.name);
} else if (command === 'remove' && args[0]) {
  await removeDataset(args[0]);
  console.log(`Removed dataset "${args[0]}"`);
} else if (command === 'list') {
  const names = await listDatasets();
  console.log(names.length > 0 ? names.join('\n') : '(no datasets)');
} else if (command === 'stats') {
  if (args[0]) {
    const ds = await getDataset(args[0]);
    if (ds) formatStats(ds.stats, ds.name);
    else console.error(`Dataset "${args[0]}" not found`);
  } else {
    const all = await getAllDatasets();
    if (all.length === 0) console.log('(no datasets)');
    else all.forEach((ds) => formatStats(ds.stats, ds.name));
  }
} else if (command === 'analyze' && args.length > 0) {
  const ds = analyzeRaw(args.join(','));
  formatStats(ds.stats, ds.name);
} else if (command === 'render') {
  console.log(await renderPage());
} else {
  printHelp();
}

