  iqr: number
}

export type Dataset = {
  name: string
  values: number[]
}

export type StoredData = {
  datasets: Record<string, number[]>
}

const sortAsc = (arr: number[]): number[] => [...arr].sort((a, b) => a - b)

const calcMean = (values: number[]): number =>
  values.reduce((sum, v) => sum + v, 0) / values.length

const calcMedian = (sorted: number[]): number => {
  const mid = Math.floor(sorted.length / 2)
  return sorted.length % 2 === 0
    ? (sorted[mid - 1] + sorted[mid]) / 2
    : sorted[mid]
}

const calcMode = (values: number[]): number[] => {
  const freq = new Map<number, number>()
  for (const v of values) {
    freq.set(v, (freq.get(v) ?? 0) + 1)
  }
  const maxFreq = Math.max(...freq.values())
  if (maxFreq === 1) return []
  const modes: number[] = []
  for (const [val, count] of freq) {
    if (count === maxFreq) modes.push(val)
  }
  return modes.sort((a, b) => a - b)
}

const calcVariance = (values: number[], mean: number): number =>
  values.reduce((sum, v) => sum + (v - mean) ** 2, 0) / values.length

const calcQuartile = (sorted: number[], q: 0.25 | 0.75): number => {
  const pos = (sorted.length - 1) * q
  const lower = Math.floor(pos)
  const upper = Math.ceil(pos)
  if (lower === upper) return sorted[lower]
  return sorted[lower] + (sorted[upper] - sorted[lower]) * (pos - lower)
}

export const parseInput = (input: string): number[] => {
  const trimmed = input.trim()

  if (trimmed.startsWith('[') && trimmed.endsWith(']')) {
    const parsed = JSON.parse(trimmed) as unknown[]
    return parsed.map(Number).filter((n) => !Number.isNaN(n))
  }

  return trimmed
    .split(',')
    .map((s) => s.trim())
    .filter((s) => s.length > 0)
    .map(Number)
    .filter((n) => !Number.isNaN(n))
}

export const computeStats = (dataset: Dataset): DatasetStats => {
  const sorted = sortAsc(dataset.values)
  const mean = calcMean(sorted)
  const variance = calcVariance(sorted, mean)
  const q1 = calcQuartile(sorted, 0.25)
  const q3 = calcQuartile(sorted, 0.75)

  return {
    name: dataset.name,
    values: sorted,
    count: sorted.length,
    mean,
    median: calcMedian(sorted),
    mode: calcMode(sorted),
    standardDeviation: Math.sqrt(variance),
    variance,
    min: sorted[0],
    max: sorted[sorted.length - 1],
    range: sorted[sorted.length - 1] - sorted[0],
    q1,
    q3,
    iqr: q3 - q1,
  }
}

const DATA_PATH = new URL('../data/datasets.json', import.meta.url).pathname

export const loadDatasets = async (): Promise<StoredData> => {
  try {
    const file = Bun.file(DATA_PATH)
    return (await file.json()) as StoredData
  } catch {
    return { datasets: {} }
  }
}

export const saveDatasets = async (data: StoredData): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(data, null, 2))
}

export const addDataset = async (name: string, values: number[]): Promise<StoredData> => {
  const data = await loadDatasets()
  data.datasets[name] = values
  await saveDatasets(data)
  return data
}

export const removeDataset = async (name: string): Promise<StoredData> => {
  const data = await loadDatasets()
  delete data.datasets[name]
  await saveDatasets(data)
  return data
}

export const getAllStats = async (): Promise<DatasetStats[]> => {
  const data = await loadDatasets()
  return Object.entries(data.datasets).map(([name, values]) =>
    computeStats({ name, values })
  )
}

