const COLORS = [
  '#4285f4', '#ea4335', '#34a853', '#fbbc05',
  '#8e24aa', '#00acc1', '#ff7043', '#9ccc65',
]

const colorFor = (index: number): string => COLORS[index % COLORS.length]

const fmt = (n: number): string =>
  Number.isInteger(n) ? String(n) : n.toFixed(4)

const STAT_KEYS: { key: keyof DatasetStats; label: string }[] = [
  { key: 'count', label: 'Count' },
  { key: 'mean', label: 'Mean' },
  { key: 'median', label: 'Median' },
  { key: 'mode', label: 'Mode' },
  { key: 'standardDeviation', label: 'Std Dev' },
  { key: 'variance', label: 'Variance' },
  { key: 'min', label: 'Min' },
  { key: 'max', label: 'Max' },
  { key: 'range', label: 'Range' },
  { key: 'q1', label: 'Q1' },
  { key: 'q3', label: 'Q3' },
  { key: 'iqr', label: 'IQR' },
]

const formatStatValue = (stat: DatasetStats, key: keyof DatasetStats): string => {
  const val = stat[key]
  if (key === 'mode') {
    const modes = val as number[]
    return modes.length === 0 ? 'None' : modes.map(fmt).join(', ')
  }
  return fmt(val as number)
}

