const renderBoxPlot = (stats: DatasetStats[]) => {
  const globalMin = Math.min(...stats.map((s) => s.min))
  const globalMax = Math.max(...stats.map((s) => s.max))
  const padding = (globalMax - globalMin) * 0.08 || 1
  const domainMin = globalMin - padding
  const domainMax = globalMax + padding
  const domainRange = domainMax - domainMin

  const chartW = 700
  const chartH = stats.length * 60 + 40
  const marginLeft = 100
  const marginRight = 30
  const marginTop = 10
  const marginBottom = 30
  const plotW = chartW - marginLeft - marginRight
  const plotH = chartH - marginTop - marginBottom

  const x = (val: number) => marginLeft + ((val - domainMin) / domainRange) * plotW
  const bandH = plotH / stats.length
  const boxH = bandH * 0.5

  const tickCount = 6
  const tickStep = domainRange / (tickCount - 1)
  const ticks = Array.from({ length: tickCount }, (_, i) => domainMin + i * tickStep)

  const elements = stats.flatMap((s, i) => {
    const cy = marginTop + i * bandH + bandH / 2
    const lowerFence = Math.max(s.q1 - 1.5 * s.iqr, s.min)
    const upperFence = Math.min(s.q3 + 1.5 * s.iqr, s.max)
    const outliers = s.values.filter((v) => v < lowerFence || v > upperFence)
    const color = colorFor(i)

    return [
      h('text', { x: marginLeft - 8, y: cy + 4, 'text-anchor': 'end', 'font-size': '12', fill: '#333' }, s.name),
      h('line', { x1: x(lowerFence), x2: x(upperFence), y1: cy, y2: cy, stroke: color, 'stroke-width': '1' }),
      h('line', { x1: x(lowerFence), x2: x(lowerFence), y1: cy - boxH / 2, y2: cy + boxH / 2, stroke: color, 'stroke-width': '2' }),
      h('line', { x1: x(upperFence), x2: x(upperFence), y1: cy - boxH / 2, y2: cy + boxH / 2, stroke: color, 'stroke-width': '2' }),
      h('rect', {
        x: x(s.q1), y: cy - boxH / 2,
        width: x(s.q3) - x(s.q1), height: boxH,
        fill: color, 'fill-opacity': '0.25', stroke: color, 'stroke-width': '2',
      }),
      h('line', { x1: x(s.median), x2: x(s.median), y1: cy - boxH / 2, y2: cy + boxH / 2, stroke: color, 'stroke-width': '3' }),
      ...outliers.map((v) =>
        h('circle', { cx: x(v), cy, r: '3', fill: color, 'fill-opacity': '0.6' })
      ),
    ]
  })

  const tickElements = ticks.flatMap((t) => [
    h('line', { x1: x(t), x2: x(t), y1: marginTop, y2: marginTop + plotH, stroke: '#e0e0e0', 'stroke-width': '1' }),
    h('text', { x: x(t), y: chartH - 4, 'text-anchor': 'middle', 'font-size': '10', fill: '#666' }, fmt(t)),
  ])

  return h('div', {},
    h('h2', {}, 'Box Plot'),
    h('svg', { class: 'svg-chart', viewBox: `0 0 ${chartW} ${chartH}`, xmlns: 'http://www.w3.org/2000/svg' },
      ...tickElements,
      ...elements,
    ),
  )
}

const renderHistogram = (stats: DatasetStats[]) => {
  const globalMin = Math.min(...stats.map((s) => s.min))
  const globalMax = Math.max(...stats.map((s) => s.max))
  const binCount = Math.max(5, Math.min(20, Math.ceil(Math.sqrt(Math.max(...stats.map((s) => s.count))))))
  const binWidth = (globalMax - globalMin) / binCount || 1

  const bins = stats.map((s) => {
    const counts = new Array<number>(binCount).fill(0)
    for (const v of s.values) {
      let idx = Math.floor((v - globalMin) / binWidth)
      if (idx >= binCount) idx = binCount - 1
      if (idx < 0) idx = 0
      counts[idx]++
    }
    return counts
  })

  const maxCount = Math.max(...bins.flat())

  const chartW = 700
  const chartH = 300
  const marginLeft = 50
  const marginRight = 20
  const marginTop = 10
  const marginBottom = 40
  const plotW = chartW - marginLeft - marginRight
  const plotH = chartH - marginTop - marginBottom

  const barGroupW = plotW / binCount
  const barW = (barGroupW * 0.8) / stats.length
  const gapW = barGroupW * 0.2

  const bars = bins.flatMap((counts, si) =>
    counts.map((count, bi) => {
      const barH = maxCount > 0 ? (count / maxCount) * plotH : 0
      const bx = marginLeft + bi * barGroupW + gapW / 2 + si * barW
      const by = marginTop + plotH - barH
      return h('rect', {
        x: bx, y: by, width: barW, height: barH,
        fill: colorFor(si), 'fill-opacity': '0.7',
      })
    })
  )

  const xLabels = Array.from({ length: binCount }, (_, i) => {
    const lo = globalMin + i * binWidth
    const hi = lo + binWidth
    const cx = marginLeft + i * barGroupW + barGroupW / 2
    return h('text', { x: cx, y: chartH - 6, 'text-anchor': 'middle', 'font-size': '9', fill: '#666' },
      `${fmt(lo)}-${fmt(hi)}`)
  })

  const yTickCount = 5
  const yStep = maxCount / (yTickCount - 1) || 1
  const yLabels = Array.from({ length: yTickCount }, (_, i) => {
    const val = Math.round(i * yStep)
    const yy = marginTop + plotH - (maxCount > 0 ? (val / maxCount) * plotH : 0)
    return h(Fragment, {},
      h('line', { x1: marginLeft, x2: marginLeft + plotW, y1: yy, y2: yy, stroke: '#e8e8e8', 'stroke-width': '1' }),
      h('text', { x: marginLeft - 6, y: yy + 3, 'text-anchor': 'end', 'font-size': '10', fill: '#666' }, String(val)),
    )
  })

  const legend = stats.map((s, i) =>
    h('g', { transform: `translate(${marginLeft + i * 120}, ${chartH - 18})` },
      h('rect', { x: 0, y: -8, width: 10, height: 10, fill: colorFor(i), 'fill-opacity': '0.7' }),
      h('text', { x: 14, y: 0, 'font-size': '10', fill: '#333' }, s.name),
    )
  )

  return h('div', {},
    h('h2', {}, 'Histogram'),
    h('svg', { class: 'svg-chart', viewBox: `0 0 ${chartW} ${chartH}`, xmlns: 'http://www.w3.org/2000/svg' },
      ...yLabels,
      ...bars,
      ...xLabels,
      ...legend,
    ),
  )
}

