}

import { createSSR } from 'plaited'
import {
  parseInput,
  addDataset,
  removeDataset,
  getAllStats,
  loadDatasets,
  saveDatasets,
} from './stats.js'
import { renderPage } from './render.js'
import type { StoredData } from './stats.js'

const PORT = Number(process.env.PORT) || 3000

const renderHTML = async (): Promise<string> => {
  const stats = await getAllStats()
  const template = renderPage(stats)
  const ssr = createSSR()
  return ssr(template)
}

const handleAddDataset = async (formData: FormData): Promise<Response> => {
  const name = (formData.get('datasetName') as string)?.trim()
  const raw = (formData.get('datasetValues') as string)?.trim()

  if (!name || !raw) {
    return new Response('Missing name or values', { status: 400 })
  }

  const values = parseInput(raw)
  if (values.length === 0) {
    return new Response('No valid numbers found', { status: 400 })
  }

  await addDataset(name, values)
  return Response.redirect('/', 303)
}

const handleRemoveDataset = async (name: string): Promise<Response> => {
  await removeDataset(name)
  return Response.redirect('/', 303)
}

const handleAPIGet = async (): Promise<Response> => {
  const stats = await getAllStats()
  return Response.json(stats)
}

const handleAPIPost = async (body: unknown): Promise<Response> => {
  const { name, values } = body as { name?: string; values?: string | number[] }

  if (!name || !values) {
    return Response.json({ error: 'Missing name or values' }, { status: 400 })
  }

  const parsed = Array.isArray(values) ? values.map(Number).filter((n) => !Number.isNaN(n)) : parseInput(String(values))

  if (parsed.length === 0) {
    return Response.json({ error: 'No valid numbers found' }, { status: 400 })
  }

  await addDataset(name, parsed)
  const stats = await getAllStats()
  return Response.json(stats)
}

const handleAPIDelete = async (url: URL): Promise<Response> => {
  const name = url.searchParams.get('name')
  if (!name) {
    return Response.json({ error: 'Missing dataset name' }, { status: 400 })
  }
  await removeDataset(name)
  const stats = await getAllStats()
  return Response.json(stats)
}

const handleAPIClear = async (): Promise<Response> => {
  const empty: StoredData = { datasets: {} }
  await saveDatasets(empty)
  return Response.json({ datasets: {} })
}

const server = Bun.serve({
  port: PORT,
  fetch: async (req) => {
    const url = new URL(req.url)
    const method = req.method.toUpperCase()

    if (url.pathname === '/' && method === 'GET') {
      const html = await renderHTML()
      return new Response(html, {
        headers: { 'Content-Type': 'text/html; charset=utf-8' },
      })
    }

    if (url.pathname === '/' && method === 'POST') {
      const contentType = req.headers.get('content-type') ?? ''
      if (contentType.includes('application/x-www-form-urlencoded') || contentType.includes('multipart/form-data')) {
        const formData = await req.formData()
        return handleAddDataset(formData)
      }
    }

    if (url.pathname.startsWith('/remove/') && method === 'POST') {
      const name = decodeURIComponent(url.pathname.slice('/remove/'.length))
      return handleRemoveDataset(name)
    }

    if (url.pathname === '/api/stats' && method === 'GET') {
      return handleAPIGet()
    }

    if (url.pathname === '/api/stats' && method === 'POST') {
      const body = await req.json()
      return handleAPIPost(body)
    }

    if (url.pathname === '/api/stats' && method === 'DELETE') {
      return handleAPIDelete(url)
    }

    if (url.pathname === '/api/clear' && method === 'POST') {
      return handleAPIClear()
    }

    return new Response('Not Found', { status: 404 })
  },
})

console.log(`Statistics Calculator running at http://localhost:${server.port}`)
